INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('5c57e15f-5ba4-4e03-afb5-0ff868462da6-ex1', '5c57e15f-5ba4-4e03-afb5-0ff868462da6', 'the', 'The sun is very bright today.', '今天的太阳很耀眼。'),
  ('5c57e15f-5ba4-4e03-afb5-0ff868462da6-ex2', '5c57e15f-5ba4-4e03-afb5-0ff868462da6', 'the', 'The committee reviewed the proposal that the engineering team had submitted earlier in the week.', '委员会审阅了工程团队本周早些时候提交的提案。'),
  ('e6064587-ff09-4772-8501-6c58c67ba22a-ex1', 'e6064587-ff09-4772-8501-6c58c67ba22a', 'be', 'I want to be a teacher.', '我想成为一名老师。'),
  ('e6064587-ff09-4772-8501-6c58c67ba22a-ex2', 'e6064587-ff09-4772-8501-6c58c67ba22a', 'be', 'To be considered for the position, candidates must be fluent in at least two languages.', '要获得该职位的考虑资格，候选人必须至少精通两门语言。'),
  ('0717ac87-428e-40c4-8acd-e9d3e72c3b9b-ex1', '0717ac87-428e-40c4-8acd-e9d3e72c3b9b', 'and', 'I like tea and coffee.', '我喜欢茶和咖啡。'),
  ('0717ac87-428e-40c4-8acd-e9d3e72c3b9b-ex2', '0717ac87-428e-40c4-8acd-e9d3e72c3b9b', 'and', 'The report was thorough and persuasive, and the board approved the budget without further debate.', '这份报告全面而有说服力，董事会未经进一步讨论便批准了预算。'),
  ('f3a9480b-e6be-4a38-b416-e5e9fcf51e75-ex1', 'f3a9480b-e6be-4a38-b416-e5e9fcf51e75', 'of', 'She is a friend of mine.', '她是我的一个朋友。'),
  ('f3a9480b-e6be-4a38-b416-e5e9fcf51e75-ex2', 'f3a9480b-e6be-4a38-b416-e5e9fcf51e75', 'of', 'The success of the project depends largely on the cooperation of several independent departments.', '项目的成功在很大程度上取决于几个独立部门之间的合作。'),
  ('da4a8ea2-c411-4ea4-86a7-e99c1d922d68-ex1', 'da4a8ea2-c411-4ea4-86a7-e99c1d922d68', 'a', 'I bought a new phone yesterday.', '我昨天买了一部新手机。'),
  ('da4a8ea2-c411-4ea4-86a7-e99c1d922d68-ex2', 'da4a8ea2-c411-4ea4-86a7-e99c1d922d68', 'a', 'A comprehensive analysis of the data revealed a pattern that previous studies had overlooked.', '对数据的全面分析揭示了一个以往研究忽视的模式。'),
  ('45fa5e95-bdee-4f12-ae08-784880742345-ex1', '45fa5e95-bdee-4f12-ae08-784880742345', 'in', 'The keys are in my bag.', '钥匙在我的包里。'),
  ('45fa5e95-bdee-4f12-ae08-784880742345-ex2', '45fa5e95-bdee-4f12-ae08-784880742345', 'in', 'In recent decades, remarkable progress has been made in the treatment of chronic diseases.', '近几十年来，慢性疾病的治疗取得了显著进展。'),
  ('0f30d33c-dd6c-4bdb-a51d-cf10512f5a16-ex1', '0f30d33c-dd6c-4bdb-a51d-cf10512f5a16', 'to', 'We walked to the park.', '我们走路去了公园。'),
  ('0f30d33c-dd6c-4bdb-a51d-cf10512f5a16-ex2', '0f30d33c-dd6c-4bdb-a51d-cf10512f5a16', 'to', 'The government has pledged to allocate additional funding to schools in underserved regions.', '政府已承诺向欠发达地区的学校拨付额外资金。'),
  ('a36d9552-4da8-4a2b-a50a-ee471ae52f7c-ex1', 'a36d9552-4da8-4a2b-a50a-ee471ae52f7c', 'have', 'I have two brothers.', '我有两个兄弟。'),
  ('a36d9552-4da8-4a2b-a50a-ee471ae52f7c-ex2', 'a36d9552-4da8-4a2b-a50a-ee471ae52f7c', 'have', 'Researchers have demonstrated that regular exercise can have a measurable effect on cognitive performance.', '研究人员已经证明，规律运动会对认知能力产生可衡量的影响。'),
  ('16a6a532-ed32-4bf3-9aae-dc46cfdc7926-ex1', '16a6a532-ed32-4bf3-9aae-dc46cfdc7926', 'it', 'It is raining outside.', '外面正在下雨。'),
  ('16a6a532-ed32-4bf3-9aae-dc46cfdc7926-ex2', '16a6a532-ed32-4bf3-9aae-dc46cfdc7926', 'it', 'Although the proposal seemed promising at first, it ultimately failed to secure sufficient support.', '尽管这项提案起初看起来很有前景，但最终未能获得足够的支持。'),
  ('b2e18132-1366-45ab-a3f9-3648f77efce4-ex1', 'b2e18132-1366-45ab-a3f9-3648f77efce4', 'I', 'I love listening to music.', '我喜欢听音乐。'),
  ('b2e18132-1366-45ab-a3f9-3648f77efce4-ex2', 'b2e18132-1366-45ab-a3f9-3648f77efce4', 'I', 'I would like to express my sincere gratitude to everyone who contributed to this initiative.', '我谨向所有为这项计划做出贡献的人表示诚挚的感谢。'),
  ('8c1ed485-33b9-4f0f-9fe0-d1479ff0b6c3-ex1', '8c1ed485-33b9-4f0f-9fe0-d1479ff0b6c3', 'that', 'That book belongs to me.', '那本书是我的。'),
  ('8c1ed485-33b9-4f0f-9fe0-d1479ff0b6c3-ex2', '8c1ed485-33b9-4f0f-9fe0-d1479ff0b6c3', 'that', 'The study concluded that early intervention significantly improves long-term outcomes for patients.', '该研究得出结论：早期干预能显著改善患者的长期疗效。'),
  ('171ee44e-ac87-4b3b-aeff-cfb6b4b90d30-ex1', '171ee44e-ac87-4b3b-aeff-cfb6b4b90d30', 'for', 'This gift is for you.', '这份礼物是给你的。'),
  ('171ee44e-ac87-4b3b-aeff-cfb6b4b90d30-ex2', '171ee44e-ac87-4b3b-aeff-cfb6b4b90d30', 'for', 'For reasons that remain unclear, the negotiations were suspended for an indefinite period.', '由于尚不明确的原因，谈判被无限期中止。'),
  ('34958e28-a010-40b1-aec4-2b3e1db87426-ex1', '34958e28-a010-40b1-aec4-2b3e1db87426', 'you', 'You look great today.', '你今天看起来很棒。'),
  ('34958e28-a010-40b1-aec4-2b3e1db87426-ex2', '34958e28-a010-40b1-aec4-2b3e1db87426', 'you', 'Should you require any further assistance, please do not hesitate to contact our office.', '如您需要任何进一步的协助，请随时与我们的办公室联系。'),
  ('627c8731-c2c3-43fb-ba9f-6619f5c5cb53-ex1', '627c8731-c2c3-43fb-ba9f-6619f5c5cb53', 'he', 'He works in a hospital.', '他在一家医院工作。'),
  ('627c8731-c2c3-43fb-ba9f-6619f5c5cb53-ex2', '627c8731-c2c3-43fb-ba9f-6619f5c5cb53', 'he', 'He maintained that the evidence presented at the hearing had been taken entirely out of context.', '他坚称听证会上出示的证据完全被断章取义了。'),
  ('ac7657da-76e7-4ae5-a035-10afd4802c7f-ex1', 'ac7657da-76e7-4ae5-a035-10afd4802c7f', 'with', 'I went shopping with my mom.', '我和妈妈一起去购物了。'),
  ('ac7657da-76e7-4ae5-a035-10afd4802c7f-ex2', 'ac7657da-76e7-4ae5-a035-10afd4802c7f', 'with', 'With the support of international partners, the organization expanded its operations across three continents.', '在国际合作伙伴的支持下，该组织将业务扩展到了三大洲。'),
  ('0abca149-b99a-4c70-a650-8fe801c171ac-ex1', '0abca149-b99a-4c70-a650-8fe801c171ac', 'on', 'Your phone is on the table.', '你的手机在桌子上。'),
  ('0abca149-b99a-4c70-a650-8fe801c171ac-ex2', '0abca149-b99a-4c70-a650-8fe801c171ac', 'on', 'The panel will deliver its final verdict on the matter once all testimony has been heard.', '待所有证词听取完毕后，专家组将就此事做出最终裁决。'),
  ('c2f9dc5e-e568-488b-970c-67de4a1de9bb-ex1', 'c2f9dc5e-e568-488b-970c-67de4a1de9bb', 'do', 'What do you do on weekends?', '你周末都做什么？'),
  ('c2f9dc5e-e568-488b-970c-67de4a1de9bb-ex2', 'c2f9dc5e-e568-488b-970c-67de4a1de9bb', 'do', 'Employees are expected to do their utmost to uphold the standards outlined in the code of conduct.', '员工应尽最大努力维护行为准则中规定的标准。'),
  ('ead161b2-2911-483c-90b6-c3ca6fdcfe2a-ex1', 'ead161b2-2911-483c-90b6-c3ca6fdcfe2a', 'say', 'What did she say to you?', '她跟你说了什么？'),
  ('ead161b2-2911-483c-90b6-c3ca6fdcfe2a-ex2', 'ead161b2-2911-483c-90b6-c3ca6fdcfe2a', 'say', 'Critics say the new regulations, however well intentioned, will impose a heavy burden on small businesses.', '批评者表示，新法规无论初衷多好，都会给小企业带来沉重负担。'),
  ('742bb0c8-b065-4640-82e8-796284c10e56-ex1', '742bb0c8-b065-4640-82e8-796284c10e56', 'this', 'This is my favorite song.', '这是我最喜欢的歌。'),
  ('742bb0c8-b065-4640-82e8-796284c10e56-ex2', '742bb0c8-b065-4640-82e8-796284c10e56', 'this', 'This phenomenon, first documented in the 1970s, has since attracted considerable scholarly attention.', '这一现象最早记录于二十世纪七十年代，此后引起了学术界的广泛关注。'),
  ('8236e3cc-a83e-41de-bffb-e772179df2a3-ex1', '8236e3cc-a83e-41de-bffb-e772179df2a3', 'they', 'They are playing football outside.', '他们正在外面踢足球。'),
  ('8236e3cc-a83e-41de-bffb-e772179df2a3-ex2', '8236e3cc-a83e-41de-bffb-e772179df2a3', 'they', 'They argued that the existing framework was inadequate to address the challenges posed by rapid urbanization.', '他们认为现有框架不足以应对快速城市化带来的挑战。'),
  ('fa6a1723-742c-41b5-acb5-4f64888d0f91-ex1', 'fa6a1723-742c-41b5-acb5-4f64888d0f91', 'at', 'Let''s meet at the station.', '我们在车站见面吧。'),
  ('fa6a1723-742c-41b5-acb5-4f64888d0f91-ex2', 'fa6a1723-742c-41b5-acb5-4f64888d0f91', 'at', 'At the conclusion of the conference, delegates adopted a resolution calling for immediate action.', '会议结束时，代表们通过了一项呼吁立即采取行动的决议。'),
  ('259ea144-ae48-421c-8f6a-a56c22f50844-ex1', '259ea144-ae48-421c-8f6a-a56c22f50844', 'but', 'I tried, but I failed.', '我试过了，但是失败了。'),
  ('259ea144-ae48-421c-8f6a-a56c22f50844-ex2', '259ea144-ae48-421c-8f6a-a56c22f50844', 'but', 'The initiative was ambitious, but its implementation was hampered by persistent funding shortfalls.', '这项计划雄心勃勃，但其实施一直受到资金短缺的阻碍。'),
  ('f9f03c1a-7770-4977-bf4c-88cf3dadc1eb-ex1', 'f9f03c1a-7770-4977-bf4c-88cf3dadc1eb', 'we', 'We are going home now.', '我们现在要回家了。'),
  ('f9f03c1a-7770-4977-bf4c-88cf3dadc1eb-ex2', 'f9f03c1a-7770-4977-bf4c-88cf3dadc1eb', 'we', 'We firmly believe that sustainable development requires the collective effort of every sector of society.', '我们坚信，可持续发展需要社会各界的共同努力。'),
  ('7d8df026-73e0-47a7-910a-c2fa6926866d-ex1', '7d8df026-73e0-47a7-910a-c2fa6926866d', 'his', 'His car is parked outside.', '他的车停在外面。'),
  ('7d8df026-73e0-47a7-910a-c2fa6926866d-ex2', '7d8df026-73e0-47a7-910a-c2fa6926866d', 'his', 'His contribution to the field of molecular biology earned him international recognition and numerous awards.', '他对分子生物学领域的贡献为他赢得了国际声誉和众多奖项。'),
  ('cd7a1a78-594e-417e-a74a-6a1c74d7bd5c-ex1', 'cd7a1a78-594e-417e-a74a-6a1c74d7bd5c', 'from', 'She comes from Canada.', '她来自加拿大。'),
  ('cd7a1a78-594e-417e-a74a-6a1c74d7bd5c-ex2', 'cd7a1a78-594e-417e-a74a-6a1c74d7bd5c', 'from', 'The conclusions drawn from the survey differ markedly from those of earlier investigations.', '从这次调查得出的结论与早期研究的结论明显不同。'),
  ('09f1031d-971e-45d2-986d-5a02ea3a3de1-ex1', '09f1031d-971e-45d2-986d-5a02ea3a3de1', 'not', 'I am not tired yet.', '我还不累。'),
  ('09f1031d-971e-45d2-986d-5a02ea3a3de1-ex2', '09f1031d-971e-45d2-986d-5a02ea3a3de1', 'not', 'The committee did not consider the evidence sufficient to warrant a formal investigation.', '委员会认为证据不足以启动正式调查。'),
  ('894aa2bd-ea7c-41a1-b5fe-3df21ff27894-ex1', '894aa2bd-ea7c-41a1-b5fe-3df21ff27894', 'by', 'This song was written by my friend.', '这首歌是我朋友写的。'),
  ('894aa2bd-ea7c-41a1-b5fe-3df21ff27894-ex2', '894aa2bd-ea7c-41a1-b5fe-3df21ff27894', 'by', 'By the end of the decade, the company had expanded its market share by nearly thirty percent.', '到这个十年结束时，该公司的市场份额扩大了近百分之三十。'),
  ('8c692246-a6c7-4b7e-a74a-3c109b4baafe-ex1', '8c692246-a6c7-4b7e-a74a-3c109b4baafe', 'she', 'She likes reading novels.', '她喜欢读小说。'),
  ('8c692246-a6c7-4b7e-a74a-3c109b4baafe-ex2', '8c692246-a6c7-4b7e-a74a-3c109b4baafe', 'she', 'She emphasized that the findings should be interpreted with caution given the limited sample size.', '她强调，鉴于样本量有限，这些发现应谨慎解读。'),
  ('a6253cfa-dbed-4283-a8b4-8d70cdd3aee5-ex1', 'a6253cfa-dbed-4283-a8b4-8d70cdd3aee5', 'or', 'Do you want tea or coffee?', '你想要茶还是咖啡？'),
  ('a6253cfa-dbed-4283-a8b4-8d70cdd3aee5-ex2', 'a6253cfa-dbed-4283-a8b4-8d70cdd3aee5', 'or', 'Applicants must submit the required documents by Friday, or their applications will not be processed.', '申请人必须在周五前提交所需文件，否则其申请将不予受理。'),
  ('e1647f50-df1d-4320-b73a-df1acaae0d93-ex1', 'e1647f50-df1d-4320-b73a-df1acaae0d93', 'as', 'She works as a nurse.', '她是一名护士。'),
  ('e1647f50-df1d-4320-b73a-df1acaae0d93-ex2', 'e1647f50-df1d-4320-b73a-df1acaae0d93', 'as', 'As the global economy becomes increasingly interconnected, regional crises can rapidly assume international dimensions.', '随着全球经济日益互联互通，区域性危机可能迅速演变为国际性问题。'),
  ('661a41ff-1a80-4d4c-827f-ac8609e77058-ex1', '661a41ff-1a80-4d4c-827f-ac8609e77058', 'what', 'What is your name?', '你叫什么名字？'),
  ('661a41ff-1a80-4d4c-827f-ac8609e77058-ex2', '661a41ff-1a80-4d4c-827f-ac8609e77058', 'what', 'What distinguishes this study from its predecessors is the unprecedented scale of its data collection.', '这项研究区别于以往研究之处在于其前所未有的数据收集规模。'),
  ('c6b479ae-a44e-4cc6-9d0b-223fd4307227-ex1', 'c6b479ae-a44e-4cc6-9d0b-223fd4307227', 'go', 'I go to school by bus.', '我坐公交车去上学。'),
  ('c6b479ae-a44e-4cc6-9d0b-223fd4307227-ex2', 'c6b479ae-a44e-4cc6-9d0b-223fd4307227', 'go', 'The chairman insisted that the negotiations go forward despite the objections raised by several members.', '尽管有几位成员提出异议，主席仍坚持谈判继续进行。'),
  ('11816640-1fa2-4ea2-99a5-d184bf067659-ex1', '11816640-1fa2-4ea2-99a5-d184bf067659', 'their', 'The children love their new toys.', '孩子们很喜欢他们的新玩具。'),
  ('11816640-1fa2-4ea2-99a5-d184bf067659-ex2', '11816640-1fa2-4ea2-99a5-d184bf067659', 'their', 'Many residents expressed concern that their interests had been overlooked during the planning process.', '许多居民表示担忧，认为他们的利益在规划过程中被忽视了。'),
  ('a587ab36-ae0c-40bd-afc0-1d1677629d95-ex1', 'a587ab36-ae0c-40bd-afc0-1d1677629d95', 'can', 'I can swim very well.', '我游泳游得很好。'),
  ('a587ab36-ae0c-40bd-afc0-1d1677629d95-ex2', 'a587ab36-ae0c-40bd-afc0-1d1677629d95', 'can', 'Properly designed policies can mitigate the adverse effects of economic restructuring on vulnerable communities.', '设计得当的政策能够缓解经济结构调整对弱势群体的不利影响。'),
  ('5117fd49-f3ec-4323-837a-5d3d87d24a30-ex1', '5117fd49-f3ec-4323-837a-5d3d87d24a30', 'who', 'Who is that man over there?', '那边那个男人是谁？'),
  ('5117fd49-f3ec-4323-837a-5d3d87d24a30-ex2', '5117fd49-f3ec-4323-837a-5d3d87d24a30', 'who', 'The award honors scientists who have made exceptional contributions to public health research.', '该奖项表彰在公共卫生研究领域做出杰出贡献的科学家。'),
  ('4705c001-1f09-4756-95a6-9f2dd2be68bb-ex1', '4705c001-1f09-4756-95a6-9f2dd2be68bb', 'get', 'Did you get my message?', '你收到我的消息了吗？'),
  ('4705c001-1f09-4756-95a6-9f2dd2be68bb-ex2', '4705c001-1f09-4756-95a6-9f2dd2be68bb', 'get', 'Small enterprises often struggle to get access to the credit they need to expand their operations.', '小企业往往难以获得扩大经营所需的信贷。'),
  ('6208b58f-63ad-421c-a376-ffbd8b1d7bf5-ex1', '6208b58f-63ad-421c-a376-ffbd8b1d7bf5', 'if', 'Call me if you need help.', '如果你需要帮助就给我打电话。'),
  ('6208b58f-63ad-421c-a376-ffbd8b1d7bf5-ex2', '6208b58f-63ad-421c-a376-ffbd8b1d7bf5', 'if', 'If the current trends persist, the region could face severe water shortages within two decades.', '如果当前趋势持续下去，该地区可能在二十年内面临严重的水资源短缺。'),
  ('08479857-616e-41fe-88fd-789ce8e4746b-ex1', '08479857-616e-41fe-88fd-789ce8e4746b', 'would', 'I would love a cup of tea.', '我想来杯茶。'),
  ('08479857-616e-41fe-88fd-789ce8e4746b-ex2', '08479857-616e-41fe-88fd-789ce8e4746b', 'would', 'The administration indicated that it would reconsider its position if new evidence were to emerge.', '行政当局表示，如果出现新证据，将重新考虑其立场。'),
  ('7e4780f7-6213-46f7-90f1-5566501a16fb-ex1', '7e4780f7-6213-46f7-90f1-5566501a16fb', 'her', 'I saw her at the mall.', '我在商场看到她了。'),
  ('7e4780f7-6213-46f7-90f1-5566501a16fb-ex2', '7e4780f7-6213-46f7-90f1-5566501a16fb', 'her', 'Her dedication to improving rural education has inspired a generation of young teachers.', '她致力于改善乡村教育的精神激励了一代年轻教师。'),
  ('4bf5ad74-f573-47b1-96fd-568a99c4b635-ex1', '4bf5ad74-f573-47b1-96fd-568a99c4b635', 'all', 'All the students passed the exam.', '所有学生都通过了考试。'),
  ('4bf5ad74-f573-47b1-96fd-568a99c4b635-ex2', '4bf5ad74-f573-47b1-96fd-568a99c4b635', 'all', 'All parties to the agreement must ratify the amendments before they can take legal effect.', '协议各方必须批准修正案，修正案方可产生法律效力。'),
  ('b0712817-f9e9-419e-81c3-e52d50d8fbfd-ex1', 'b0712817-f9e9-419e-81c3-e52d50d8fbfd', 'my', 'My phone is out of battery.', '我的手机没电了。'),
  ('b0712817-f9e9-419e-81c3-e52d50d8fbfd-ex2', 'b0712817-f9e9-419e-81c3-e52d50d8fbfd', 'my', 'My principal objection to the proposal concerns its disregard for long-term environmental consequences.', '我对该提案的主要异议在于它忽视了长期的环境后果。'),
  ('4750f35f-fd8e-433d-812d-7ae941e3f7c8-ex1', '4750f35f-fd8e-433d-812d-7ae941e3f7c8', 'make', 'Can you make dinner tonight?', '今晚你能做晚饭吗？'),
  ('4750f35f-fd8e-433d-812d-7ae941e3f7c8-ex2', '4750f35f-fd8e-433d-812d-7ae941e3f7c8', 'make', 'The new regulations are intended to make financial institutions more accountable to their shareholders.', '新法规旨在使金融机构对其股东更加负责。'),
  ('06114fb8-7bfb-4315-b59c-1f2f662e0eee-ex1', '06114fb8-7bfb-4315-b59c-1f2f662e0eee', 'about', 'We talked about the movie.', '我们聊了聊那部电影。'),
  ('06114fb8-7bfb-4315-b59c-1f2f662e0eee-ex2', '06114fb8-7bfb-4315-b59c-1f2f662e0eee', 'about', 'There remains considerable uncertainty about the long-term implications of the policy shift.', '关于这一政策转变的长期影响仍存在相当大的不确定性。'),
  ('3dc7f898-80bc-4153-9131-414031962642-ex1', '3dc7f898-80bc-4153-9131-414031962642', 'know', 'I know the answer.', '我知道答案。'),
  ('3dc7f898-80bc-4153-9131-414031962642-ex2', '3dc7f898-80bc-4153-9131-414031962642', 'know', 'Policy makers need to know precisely how these measures will affect different income groups.', '政策制定者需要确切了解这些措施将如何影响不同收入群体。'),
  ('1eee71e8-c03b-43b1-a9e0-0e36297dada2-ex1', '1eee71e8-c03b-43b1-a9e0-0e36297dada2', 'will', 'I will call you tomorrow.', '我明天给你打电话。'),
  ('1eee71e8-c03b-43b1-a9e0-0e36297dada2-ex2', '1eee71e8-c03b-43b1-a9e0-0e36297dada2', 'will', 'The foundation will allocate substantial resources to research on renewable energy technologies.', '该基金会将为可再生能源技术研究拨付大量资源。'),
  ('b3e4d456-8bd2-45f7-a1ca-25631c65c745-ex1', 'b3e4d456-8bd2-45f7-a1ca-25631c65c745', 'up', 'Please stand up now.', '请现在站起来。'),
  ('b3e4d456-8bd2-45f7-a1ca-25631c65c745-ex2', 'b3e4d456-8bd2-45f7-a1ca-25631c65c745', 'up', 'Housing prices have gone up considerably, putting home ownership beyond the reach of many young families.', '房价大幅上涨，使许多年轻家庭无力购房。'),
  ('336e9068-584a-43e0-954b-75644fd4a6ee-ex1', '336e9068-584a-43e0-954b-75644fd4a6ee', 'one', 'I have one question for you.', '我有一个问题要问你。'),
  ('336e9068-584a-43e0-954b-75644fd4a6ee-ex2', '336e9068-584a-43e0-954b-75644fd4a6ee', 'one', 'One of the most significant challenges facing modern medicine is the rise of antibiotic resistance.', '现代医学面临的最重大挑战之一是抗生素耐药性的上升。'),
  ('a0276b04-5faa-4a54-a06d-877c5aa0c1b4-ex1', 'a0276b04-5faa-4a54-a06d-877c5aa0c1b4', 'time', 'What time is it now?', '现在几点了？'),
  ('a0276b04-5faa-4a54-a06d-877c5aa0c1b4-ex2', 'a0276b04-5faa-4a54-a06d-877c5aa0c1b4', 'time', 'The committee requested additional time to evaluate the financial implications of the merger.', '委员会要求更多时间来评估此次合并的财务影响。'),
  ('660b3a5c-ca71-45ee-a44f-fc47eb4a4123-ex1', '660b3a5c-ca71-45ee-a44f-fc47eb4a4123', 'there', 'There is a cat on the roof.', '屋顶上有一只猫。'),
  ('660b3a5c-ca71-45ee-a44f-fc47eb4a4123-ex2', '660b3a5c-ca71-45ee-a44f-fc47eb4a4123', 'there', 'There exists a substantial body of evidence linking air pollution to respiratory illness.', '已有大量证据表明空气污染与呼吸系统疾病相关。'),
  ('f512d968-d8ec-4bd7-90cb-dba2007c30e2-ex1', 'f512d968-d8ec-4bd7-90cb-dba2007c30e2', 'year', 'I started this job last year.', '我去年开始做这份工作。'),
  ('f512d968-d8ec-4bd7-90cb-dba2007c30e2-ex2', 'f512d968-d8ec-4bd7-90cb-dba2007c30e2', 'year', 'Over the past fiscal year, the corporation reported an unprecedented increase in overseas revenue.', '在过去一个财政年度，该公司海外收入实现了前所未有的增长。'),
  ('8ddb2692-329c-41a2-aaf1-82dd8b0975a0-ex1', '8ddb2692-329c-41a2-aaf1-82dd8b0975a0', 'so', 'I was tired, so I went to bed.', '我累了，所以就去睡觉了。'),
  ('8ddb2692-329c-41a2-aaf1-82dd8b0975a0-ex2', '8ddb2692-329c-41a2-aaf1-82dd8b0975a0', 'so', 'The evidence was so compelling that even the most skeptical reviewers endorsed the conclusions.', '证据如此有力，连最持怀疑态度的评审人也认可了这些结论。'),
  ('69cbc285-7de8-46e0-ad93-8fd7eaf259a9-ex1', '69cbc285-7de8-46e0-ad93-8fd7eaf259a9', 'think', 'I think you are right.', '我认为你是对的。'),
  ('69cbc285-7de8-46e0-ad93-8fd7eaf259a9-ex2', '69cbc285-7de8-46e0-ad93-8fd7eaf259a9', 'think', 'Many economists think that premature tightening of monetary policy could stall the fragile recovery.', '许多经济学家认为，过早收紧货币政策可能使脆弱的复苏陷入停滞。'),
  ('6ed2c123-6a87-4b9a-9402-508a15bdfdd5-ex1', '6ed2c123-6a87-4b9a-9402-508a15bdfdd5', 'when', 'When do you usually wake up?', '你通常什么时候起床？'),
  ('6ed2c123-6a87-4b9a-9402-508a15bdfdd5-ex2', '6ed2c123-6a87-4b9a-9402-508a15bdfdd5', 'when', 'When the results were finally published, they prompted a thorough reassessment of existing guidelines.', '结果最终公布时，引发了对现行指南的全面重新评估。'),
  ('6fb791a2-d553-437b-9b2c-98909ea02c1f-ex1', '6fb791a2-d553-437b-9b2c-98909ea02c1f', 'which', 'Which color do you like best?', '你最喜欢哪种颜色？'),
  ('6fb791a2-d553-437b-9b2c-98909ea02c1f-ex2', '6fb791a2-d553-437b-9b2c-98909ea02c1f', 'which', 'The report identifies several factors which have contributed to the steady decline in voter turnout.', '报告指出了导致投票率持续下降的若干因素。'),
  ('5470a9cd-b03a-47e7-9fb9-fd2b4a0814cd-ex1', '5470a9cd-b03a-47e7-9fb9-fd2b4a0814cd', 'them', 'I bought apples and washed them.', '我买了苹果并把它们洗了。'),
  ('5470a9cd-b03a-47e7-9fb9-fd2b4a0814cd-ex2', '5470a9cd-b03a-47e7-9fb9-fd2b4a0814cd', 'them', 'The new measures are designed to protect consumers rather than burden them with additional costs.', '新措施旨在保护消费者，而不是给他们增加额外负担。'),
  ('f8d7b65c-c435-4c96-b11d-75a1b6cff263-ex1', 'f8d7b65c-c435-4c96-b11d-75a1b6cff263', 'some', 'Would you like some water?', '你想喝点水吗？'),
  ('f8d7b65c-c435-4c96-b11d-75a1b6cff263-ex2', 'f8d7b65c-c435-4c96-b11d-75a1b6cff263', 'some', 'Some analysts contend that the market correction reflects deeper structural weaknesses in the economy.', '一些分析人士认为，此次市场回调反映了经济中更深层的结构性弱点。'),
  ('8e3d0b17-9556-40fd-8874-38dd6ad63cf5-ex1', '8e3d0b17-9556-40fd-8874-38dd6ad63cf5', 'me', 'Please give me a minute.', '请给我一分钟。'),
  ('8e3d0b17-9556-40fd-8874-38dd6ad63cf5-ex2', '8e3d0b17-9556-40fd-8874-38dd6ad63cf5', 'me', 'It seems to me that the objections raised during the consultation deserve more serious consideration.', '在我看来，磋商期间提出的异议值得更认真的考虑。'),
  ('9f170a7b-9469-42bf-9a52-a2f06de7d697-ex1', '9f170a7b-9469-42bf-9a52-a2f06de7d697', 'people', 'Many people enjoy traveling.', '许多人喜欢旅行。'),
  ('9f170a7b-9469-42bf-9a52-a2f06de7d697-ex2', '9f170a7b-9469-42bf-9a52-a2f06de7d697', 'people', 'The policy is expected to benefit millions of people living in remote and underdeveloped areas.', '预计这项政策将惠及生活在偏远落后地区的数百万民众。'),
  ('feb51a5d-e902-44bf-af59-9cc0eb8e4c94-ex1', 'feb51a5d-e902-44bf-af59-9cc0eb8e4c94', 'take', 'Take an umbrella with you.', '带把伞吧。'),
  ('feb51a5d-e902-44bf-af59-9cc0eb8e4c94-ex2', 'feb51a5d-e902-44bf-af59-9cc0eb8e4c94', 'take', 'The committee agreed to take immediate steps to address the deficiencies identified in the audit.', '委员会同意立即采取措施解决审计中发现的缺陷。'),
  ('00cb53fa-3511-42c9-ab1b-891428155fac-ex1', '00cb53fa-3511-42c9-ab1b-891428155fac', 'out', 'Let''s eat out tonight.', '今晚我们出去吃吧。'),
  ('00cb53fa-3511-42c9-ab1b-891428155fac-ex2', '00cb53fa-3511-42c9-ab1b-891428155fac', 'out', 'The investigation was carried out over eighteen months by a team of independent experts.', '这项调查由一个独立专家团队历时十八个月完成。'),
  ('716244ed-c316-4862-b554-b9e56cfbbf68-ex1', '716244ed-c316-4862-b554-b9e56cfbbf68', 'into', 'She walked into the room.', '她走进了房间。'),
  ('716244ed-c316-4862-b554-b9e56cfbbf68-ex2', '716244ed-c316-4862-b554-b9e56cfbbf68', 'into', 'The inquiry into the company''s accounting practices uncovered irregularities spanning nearly a decade.', '针对该公司会计操作的调查发现了跨越近十年的违规行为。'),
  ('6a1a32b4-08e6-4ed6-9547-8aeae5f63050-ex1', '6a1a32b4-08e6-4ed6-9547-8aeae5f63050', 'just', 'I just finished my homework.', '我刚做完作业。'),
  ('6a1a32b4-08e6-4ed6-9547-8aeae5f63050-ex2', '6a1a32b4-08e6-4ed6-9547-8aeae5f63050', 'just', 'The reforms are not just administrative adjustments; they represent a fundamental shift in governance philosophy.', '这些改革不仅仅是行政调整，更代表着治理理念的根本转变。'),
  ('71191060-924f-426f-8a24-8f017f0972c4-ex1', '71191060-924f-426f-8a24-8f017f0972c4', 'see', 'Did you see that movie?', '你看过那部电影吗？'),
  ('71191060-924f-426f-8a24-8f017f0972c4-ex2', '71191060-924f-426f-8a24-8f017f0972c4', 'see', 'Analysts see the recent merger as an attempt to consolidate market dominance in the region.', '分析人士将近期的合并视为巩固该地区市场主导地位的举措。'),
  ('70a474e1-1ad6-4d72-a857-6e70648cd8f6-ex1', '70a474e1-1ad6-4d72-a857-6e70648cd8f6', 'him', 'I met him at the party.', '我在聚会上认识了他。'),
  ('70a474e1-1ad6-4d72-a857-6e70648cd8f6-ex2', '70a474e1-1ad6-4d72-a857-6e70648cd8f6', 'him', 'The board appointed him chief executive in recognition of his outstanding record of leadership.', '鉴于他出色的领导业绩，董事会任命他为首席执行官。'),
  ('f7effa2b-d0ca-4622-b2de-cf42cd90e68d-ex1', 'f7effa2b-d0ca-4622-b2de-cf42cd90e68d', 'your', 'Is this your umbrella?', '这是你的伞吗？'),
  ('f7effa2b-d0ca-4622-b2de-cf42cd90e68d-ex2', 'f7effa2b-d0ca-4622-b2de-cf42cd90e68d', 'your', 'Please ensure that your application includes all the supporting documents listed in the guidelines.', '请确保您的申请包含指南中列出的所有证明文件。'),
  ('e8901134-06f7-4775-99c6-26b667ef378a-ex1', 'e8901134-06f7-4775-99c6-26b667ef378a', 'come', 'Come here and sit down.', '过来坐下。'),
  ('e8901134-06f7-4775-99c6-26b667ef378a-ex2', 'e8901134-06f7-4775-99c6-26b667ef378a', 'come', 'Delegates from over forty countries will come together to negotiate a new climate accord.', '来自四十多个国家的代表将齐聚一堂，谈判一项新的气候协议。'),
  ('647f0fd7-619c-4c43-ab80-7f7df3ed1718-ex1', '647f0fd7-619c-4c43-ab80-7f7df3ed1718', 'could', 'Could you help me, please?', '请问你能帮我一下吗？'),
  ('647f0fd7-619c-4c43-ab80-7f7df3ed1718-ex2', '647f0fd7-619c-4c43-ab80-7f7df3ed1718', 'could', 'Experts warned that prolonged drought could undermine food security across the entire region.', '专家警告说，持续干旱可能危及整个地区的粮食安全。'),
  ('c036f1dc-b00d-4edf-8c4d-6419481b8ea4-ex1', 'c036f1dc-b00d-4edf-8c4d-6419481b8ea4', 'now', 'I am busy now.', '我现在很忙。'),
  ('c036f1dc-b00d-4edf-8c4d-6419481b8ea4-ex2', 'c036f1dc-b00d-4edf-8c4d-6419481b8ea4', 'now', 'Now that the legislation has been enacted, attention turns to the practical challenges of enforcement.', '既然立法已经颁布，人们的注意力转向了执行层面的实际挑战。'),
  ('65740fa4-fb03-4e9d-95fe-c3218045f0f0-ex1', '65740fa4-fb03-4e9d-95fe-c3218045f0f0', 'than', 'She is taller than me.', '她比我高。'),
  ('65740fa4-fb03-4e9d-95fe-c3218045f0f0-ex2', '65740fa4-fb03-4e9d-95fe-c3218045f0f0', 'than', 'The actual cost of the project proved substantially higher than the initial estimates had suggested.', '项目的实际成本远高于最初估算所显示的水平。'),
  ('6cb011f4-46e1-4c0a-811c-e0972d79967a-ex1', '6cb011f4-46e1-4c0a-811c-e0972d79967a', 'like', 'I like chocolate ice cream.', '我喜欢巧克力冰淇淋。'),
  ('6cb011f4-46e1-4c0a-811c-e0972d79967a-ex2', '6cb011f4-46e1-4c0a-811c-e0972d79967a', 'like', 'Emerging economies like Brazil and India are playing an increasingly prominent role in global trade.', '像巴西和印度这样的新兴经济体在全球贸易中发挥着日益重要的作用。'),
  ('1a8ff589-dafa-433a-a48c-15b4d7a53630-ex1', '1a8ff589-dafa-433a-a48c-15b4d7a53630', 'other', 'Where are the other students?', '其他学生在哪里？'),
  ('1a8ff589-dafa-433a-a48c-15b4d7a53630-ex2', '1a8ff589-dafa-433a-a48c-15b4d7a53630', 'other', 'The findings are consistent with those of other studies conducted in comparable urban settings.', '这些发现与在类似城市环境中开展的其他研究结果一致。'),
  ('1858a734-1095-4b00-8ac2-63cf48cd82a8-ex1', '1858a734-1095-4b00-8ac2-63cf48cd82a8', 'how', 'How do you spell your name?', '你的名字怎么拼写？'),
  ('1858a734-1095-4b00-8ac2-63cf48cd82a8-ex2', '1858a734-1095-4b00-8ac2-63cf48cd82a8', 'how', 'The seminar examined how technological innovation has transformed traditional manufacturing industries.', '研讨会探讨了技术创新如何改变了传统制造业。'),
  ('1a5d0a28-f3db-4b3e-96ce-1a163bab4087-ex1', '1a5d0a28-f3db-4b3e-96ce-1a163bab4087', 'then', 'We had dinner, then watched TV.', '我们吃了晚饭，然后看了电视。'),
  ('1a5d0a28-f3db-4b3e-96ce-1a163bab4087-ex2', '1a5d0a28-f3db-4b3e-96ce-1a163bab4087', 'then', 'The prototype is tested under laboratory conditions; only then is it approved for field trials.', '原型机先在实验室条件下测试，之后才被批准进行实地试验。'),
  ('5114e495-0b11-47e9-9b42-c84ed2268033-ex1', '5114e495-0b11-47e9-9b42-c84ed2268033', 'its', 'The dog wagged its tail.', '那只狗摇了摇尾巴。'),
  ('5114e495-0b11-47e9-9b42-c84ed2268033-ex2', '5114e495-0b11-47e9-9b42-c84ed2268033', 'its', 'The university owes its reputation largely to the quality of its research faculty.', '这所大学的声誉在很大程度上归功于其科研师资的水平。'),
  ('05e4d391-6ddd-4501-abe8-b8e39b6cd426-ex1', '05e4d391-6ddd-4501-abe8-b8e39b6cd426', 'our', 'Our house has a small garden.', '我们家有一个小花园。'),
  ('05e4d391-6ddd-4501-abe8-b8e39b6cd426-ex2', '05e4d391-6ddd-4501-abe8-b8e39b6cd426', 'our', 'It is our collective responsibility to preserve these resources for future generations.', '为子孙后代保护这些资源是我们共同的责任。'),
  ('1f8f373a-af90-48f8-abf9-de65f4afd697-ex1', '1f8f373a-af90-48f8-abf9-de65f4afd697', 'two', 'I have two tickets for the show.', '我有两张演出票。'),
  ('1f8f373a-af90-48f8-abf9-de65f4afd697-ex2', '1f8f373a-af90-48f8-abf9-de65f4afd697', 'two', 'The two delegations met privately for several hours before issuing a joint statement.', '两国代表团私下会晤数小时后发表了联合声明。'),
  ('a11c6f65-18ca-426f-a945-ad4471232014-ex1', 'a11c6f65-18ca-426f-a945-ad4471232014', 'more', 'Can I have more rice, please?', '请再给我一些米饭好吗？'),
  ('a11c6f65-18ca-426f-a945-ad4471232014-ex2', 'a11c6f65-18ca-426f-a945-ad4471232014', 'more', 'The crisis has made governments more attentive to the structural vulnerabilities of global supply chains.', '这场危机使各国政府更加关注全球供应链的结构性弱点。'),
  ('c59db013-b008-446d-b136-d889d0777b5c-ex1', 'c59db013-b008-446d-b136-d889d0777b5c', 'these', 'These shoes are too small.', '这双鞋太小了。'),
  ('c59db013-b008-446d-b136-d889d0777b5c-ex2', 'c59db013-b008-446d-b136-d889d0777b5c', 'these', 'These developments underscore the urgent need for a coordinated international response.', '这些事态发展凸显了开展协调一致的国际应对的迫切需要。'),
  ('34337a5d-2deb-4f81-919b-e5dfad41bf37-ex1', '34337a5d-2deb-4f81-919b-e5dfad41bf37', 'want', 'I want a glass of water.', '我想要一杯水。'),
  ('34337a5d-2deb-4f81-919b-e5dfad41bf37-ex2', '34337a5d-2deb-4f81-919b-e5dfad41bf37', 'want', 'Shareholders want greater transparency regarding the company''s exposure to environmental risk.', '股东希望公司在环境风险敞口方面提高透明度。'),
  ('bd477cff-193f-46ee-b0dd-b1f0e47db909-ex1', 'bd477cff-193f-46ee-b0dd-b1f0e47db909', 'way', 'Is this the way to the station?', '去车站是走这条路吗？'),
  ('bd477cff-193f-46ee-b0dd-b1f0e47db909-ex2', 'bd477cff-193f-46ee-b0dd-b1f0e47db909', 'way', 'The commission proposed an alternative way of allocating funds that rewards measurable outcomes.', '委员会提出了一种以可衡量成果为导向的资金分配新方式。'),
  ('5e31eaf2-05c9-4c6f-a1ea-e2b9d17fb860-ex1', '5e31eaf2-05c9-4c6f-a1ea-e2b9d17fb860', 'look', 'Look at that beautiful bird!', '看那只美丽的鸟！'),
  ('5e31eaf2-05c9-4c6f-a1ea-e2b9d17fb860-ex2', '5e31eaf2-05c9-4c6f-a1ea-e2b9d17fb860', 'look', 'Regulators have begun to look more closely at the lending practices of regional banks.', '监管机构已开始更密切地审视地区性银行的放贷行为。'),
  ('6a25c65d-8e89-464b-9236-1b6cba0dcd4f-ex1', '6a25c65d-8e89-464b-9236-1b6cba0dcd4f', 'first', 'This is my first visit to Beijing.', '这是我第一次来北京。'),
  ('6a25c65d-8e89-464b-9236-1b6cba0dcd4f-ex2', '6a25c65d-8e89-464b-9236-1b6cba0dcd4f', 'first', 'The first comprehensive assessment of the program revealed both notable achievements and significant shortcomings.', '对该项目的首次全面评估既揭示了显著成就，也暴露了重大不足。'),
  ('639ab37b-22d5-456c-b3a7-9e9171742c81-ex1', '639ab37b-22d5-456c-b3a7-9e9171742c81', 'also', 'She sings and also plays piano.', '她唱歌，也弹钢琴。'),
  ('639ab37b-22d5-456c-b3a7-9e9171742c81-ex2', '639ab37b-22d5-456c-b3a7-9e9171742c81', 'also', 'The legislation not only strengthens enforcement but also establishes new channels for public oversight.', '该立法不仅加强了执法力度，还建立了新的公众监督渠道。'),
  ('b3540aa6-5611-4aa0-8ecc-08ecc7b0ec8a-ex1', 'b3540aa6-5611-4aa0-8ecc-08ecc7b0ec8a', 'new', 'I need a new pair of shoes.', '我需要一双新鞋。'),
  ('b3540aa6-5611-4aa0-8ecc-08ecc7b0ec8a-ex2', 'b3540aa6-5611-4aa0-8ecc-08ecc7b0ec8a', 'new', 'The institute unveiled a new framework for evaluating the societal impact of emerging technologies.', '该研究所发布了一个评估新兴技术社会影响的新框架。'),
  ('bda72ae0-a0cf-4106-be5c-4edc093da63b-ex1', 'bda72ae0-a0cf-4106-be5c-4edc093da63b', 'because', 'I stayed home because it rained.', '因为下雨，我待在家里。'),
  ('bda72ae0-a0cf-4106-be5c-4edc093da63b-ex2', 'bda72ae0-a0cf-4106-be5c-4edc093da63b', 'because', 'The initiative succeeded largely because it secured the early support of local community leaders.', '这项计划之所以成功，主要是因为及早获得了当地社区领袖的支持。'),
  ('2dbac45e-9f16-48fc-b4ed-d98b0fd32cd0-ex1', '2dbac45e-9f16-48fc-b4ed-d98b0fd32cd0', 'day', 'Have a nice day!', '祝你今天愉快！'),
  ('2dbac45e-9f16-48fc-b4ed-d98b0fd32cd0-ex2', '2dbac45e-9f16-48fc-b4ed-d98b0fd32cd0', 'day', 'On the day the agreement was signed, markets responded with a surge of cautious optimism.', '协议签署当天，市场反应出一种审慎的乐观情绪。'),
  ('c901ca68-ac2d-4003-a26c-ba55af4114c6-ex1', 'c901ca68-ac2d-4003-a26c-ba55af4114c6', 'use', 'Can I use your pen?', '我能用一下你的笔吗？'),
  ('c901ca68-ac2d-4003-a26c-ba55af4114c6-ex2', 'c901ca68-ac2d-4003-a26c-ba55af4114c6', 'use', 'The guidelines restrict the use of personal data collected through commercial applications.', '该指南限制使用通过商业应用程序收集的个人数据。'),
  ('24d664a2-58da-4e84-ae1a-c3590e3f0854-ex1', '24d664a2-58da-4e84-ae1a-c3590e3f0854', 'no', 'There is no milk in the fridge.', '冰箱里没有牛奶了。'),
  ('24d664a2-58da-4e84-ae1a-c3590e3f0854-ex2', '24d664a2-58da-4e84-ae1a-c3590e3f0854', 'no', 'The tribunal found no evidence that the defendants had acted with deliberate intent.', '法庭没有发现任何证据表明被告存在蓄意行为。'),
  ('777bde5a-6e02-4f3a-b0e2-98f4ae123dc5-ex1', '777bde5a-6e02-4f3a-b0e2-98f4ae123dc5', 'man', 'That man is my uncle.', '那个男人是我叔叔。'),
  ('777bde5a-6e02-4f3a-b0e2-98f4ae123dc5-ex2', '777bde5a-6e02-4f3a-b0e2-98f4ae123dc5', 'man', 'The exhibition traces how early man adapted to dramatic shifts in climate and landscape.', '展览追溯了早期人类如何适应气候和地貌的剧烈变迁。'),
  ('3bbcf411-38e3-4c43-bc4d-3ac736f24aa9-ex1', '3bbcf411-38e3-4c43-bc4d-3ac736f24aa9', 'find', 'I can''t find my keys.', '我找不到我的钥匙了。'),
  ('3bbcf411-38e3-4c43-bc4d-3ac736f24aa9-ex2', '3bbcf411-38e3-4c43-bc4d-3ac736f24aa9', 'find', 'Auditors were unable to find documentation supporting several of the reported transactions.', '审计人员未能找到支持其中几笔已申报交易的文件。'),
  ('ec3632c8-549c-44d0-bcdf-5be9322dec03-ex1', 'ec3632c8-549c-44d0-bcdf-5be9322dec03', 'here', 'Come here, please.', '请过来。'),
  ('ec3632c8-549c-44d0-bcdf-5be9322dec03-ex2', 'ec3632c8-549c-44d0-bcdf-5be9322dec03', 'here', 'It is worth noting here that the data were collected before the policy took effect.', '在此值得指出的是，这些数据是在政策生效之前收集的。'),
  ('9c77ac16-dbea-4d69-b375-3c5ec76ebf8d-ex1', '9c77ac16-dbea-4d69-b375-3c5ec76ebf8d', 'thing', 'What is that thing on the table?', '桌子上那个东西是什么？'),
  ('9c77ac16-dbea-4d69-b375-3c5ec76ebf8d-ex2', '9c77ac16-dbea-4d69-b375-3c5ec76ebf8d', 'thing', 'The most remarkable thing about the discovery is its potential to reshape our understanding of early evolution.', '这一发现最引人注目之处在于它可能重塑我们对早期演化的认识。'),
  ('8ed0f8d7-fd39-4063-aafa-780df78a55e2-ex1', '8ed0f8d7-fd39-4063-aafa-780df78a55e2', 'give', 'Please give me the salt.', '请把盐递给我。'),
  ('8ed0f8d7-fd39-4063-aafa-780df78a55e2-ex2', '8ed0f8d7-fd39-4063-aafa-780df78a55e2', 'give', 'The foundation agreed to give substantial grants to laboratories pursuing vaccine research.', '该基金会同意向从事疫苗研究的实验室提供巨额资助。'),
  ('fe8d8b8f-4693-4800-bca4-2a820249100b-ex1', 'fe8d8b8f-4693-4800-bca4-2a820249100b', 'many', 'Many students like this class.', '很多学生喜欢这门课。'),
  ('fe8d8b8f-4693-4800-bca4-2a820249100b-ex2', 'fe8d8b8f-4693-4800-bca4-2a820249100b', 'many', 'Many of the challenges identified in the report stem from decades of underinvestment in infrastructure.', '报告中指出的许多挑战源于数十年来基础设施投资不足。'),
  ('f41e3a75-fe5f-416b-879e-f082807f02ea-ex1', 'f41e3a75-fe5f-416b-879e-f082807f02ea', 'well', 'She speaks English very well.', '她英语说得很好。'),
  ('f41e3a75-fe5f-416b-879e-f082807f02ea-ex2', 'f41e3a75-fe5f-416b-879e-f082807f02ea', 'well', 'The transition was managed so well that operations continued without any measurable disruption.', '这次过渡管理得非常妥善，运营没有受到任何明显干扰。'),
  ('a913fbd3-5dd9-475d-b0a1-a03dc7980b10-ex1', 'a913fbd3-5dd9-475d-b0a1-a03dc7980b10', 'only', 'I only have five dollars.', '我只有五美元。'),
  ('a913fbd3-5dd9-475d-b0a1-a03dc7980b10-ex2', 'a913fbd3-5dd9-475d-b0a1-a03dc7980b10', 'only', 'Only after extensive peer review were the findings deemed suitable for publication.', '只有经过广泛的同行评审，这些研究结果才被认为适合发表。'),
  ('0ce8b81d-9065-4218-997e-6169d6621ed2-ex1', '0ce8b81d-9065-4218-997e-6169d6621ed2', 'those', 'Those flowers are beautiful.', '那些花真漂亮。'),
  ('0ce8b81d-9065-4218-997e-6169d6621ed2-ex2', '0ce8b81d-9065-4218-997e-6169d6621ed2', 'those', 'Priority will be given to those applicants who demonstrate both financial need and academic merit.', '将优先考虑既有经济需要又有优异学业表现的申请者。'),
  ('df81a19b-8252-474d-8b3b-beac88725b50-ex1', 'df81a19b-8252-474d-8b3b-beac88725b50', 'tell', 'Tell me about your day.', '跟我说说你今天过得怎么样。'),
  ('df81a19b-8252-474d-8b3b-beac88725b50-ex2', 'df81a19b-8252-474d-8b3b-beac88725b50', 'tell', 'Preliminary results tell a more complicated story than the initial headlines suggested.', '初步结果所揭示的情况比最初的新闻标题所暗示的更为复杂。'),
  ('cbaa6224-55f4-4438-a185-4e8cfd9d56d3-ex1', 'cbaa6224-55f4-4438-a185-4e8cfd9d56d3', 'very', 'This soup is very hot.', '这汤很烫。'),
  ('cbaa6224-55f4-4438-a185-4e8cfd9d56d3-ex2', 'cbaa6224-55f4-4438-a185-4e8cfd9d56d3', 'very', 'The committee was very explicit that the funds must be used exclusively for educational purposes.', '委员会非常明确地指出，这笔资金必须专门用于教育目的。'),
  ('eb38b2b3-0733-4f1b-9279-92ba1ef448ca-ex1', 'eb38b2b3-0733-4f1b-9279-92ba1ef448ca', 'even', 'Even a child can do this.', '连小孩都会做这个。'),
  ('eb38b2b3-0733-4f1b-9279-92ba1ef448ca-ex2', 'eb38b2b3-0733-4f1b-9279-92ba1ef448ca', 'even', 'Even the most conservative projections indicate that demand will double within the next decade.', '即使是最保守的预测也表明，需求将在未来十年内翻一番。'),
  ('27e8101b-9eff-48c9-b0a8-88250767df05-ex1', '27e8101b-9eff-48c9-b0a8-88250767df05', 'back', 'I will be back in five minutes.', '我五分钟后回来。'),
  ('27e8101b-9eff-48c9-b0a8-88250767df05-ex2', '27e8101b-9eff-48c9-b0a8-88250767df05', 'back', 'The committee pushed the deadline back to allow stakeholders adequate time for consultation.', '委员会将截止日期推后，以便利益相关方有充足的时间进行磋商。'),
  ('86e74381-1ac3-4ddd-bda0-c7468c467693-ex1', '86e74381-1ac3-4ddd-bda0-c7468c467693', 'any', 'Do you have any questions?', '你有什么问题吗？'),
  ('86e74381-1ac3-4ddd-bda0-c7468c467693-ex2', '86e74381-1ac3-4ddd-bda0-c7468c467693', 'any', 'The auditors did not uncover any irregularities in the company''s financial statements.', '审计人员未在该公司的财务报表中发现任何违规之处。'),
  ('9fdf8403-e5cd-4592-b001-fff8136dee3c-ex1', '9fdf8403-e5cd-4592-b001-fff8136dee3c', 'good', 'This cake tastes really good.', '这个蛋糕真好吃。'),
  ('9fdf8403-e5cd-4592-b001-fff8136dee3c-ex2', '9fdf8403-e5cd-4592-b001-fff8136dee3c', 'good', 'A good regulatory framework balances consumer protection with incentives for innovation.', '良好的监管框架能在保护消费者与激励创新之间取得平衡。'),
  ('b623384f-6d49-4f75-8fb5-dd6f488eb16e-ex1', 'b623384f-6d49-4f75-8fb5-dd6f488eb16e', 'woman', 'That woman is my teacher.', '那位女士是我的老师。'),
  ('b623384f-6d49-4f75-8fb5-dd6f488eb16e-ex2', 'b623384f-6d49-4f75-8fb5-dd6f488eb16e', 'woman', 'She became the first woman to be appointed to the nation''s highest judicial office.', '她成为首位被任命为该国最高司法职位的女性。'),
  ('dd50cc3f-bfa1-4ce3-81cb-a28a945e537c-ex1', 'dd50cc3f-bfa1-4ce3-81cb-a28a945e537c', 'through', 'We walked through the forest.', '我们穿过了森林。'),
  ('dd50cc3f-bfa1-4ce3-81cb-a28a945e537c-ex2', 'dd50cc3f-bfa1-4ce3-81cb-a28a945e537c', 'through', 'Lasting reform can only be achieved through sustained dialogue among all interested parties.', '只有通过各相关方持续对话，才能实现持久的改革。'),
  ('63686f42-f5f5-4c28-927e-cd712f0e7dd9-ex1', '63686f42-f5f5-4c28-927e-cd712f0e7dd9', 'us', 'Please join us for dinner.', '请和我们一起吃晚饭吧。'),
  ('63686f42-f5f5-4c28-927e-cd712f0e7dd9-ex2', '63686f42-f5f5-4c28-927e-cd712f0e7dd9', 'us', 'The findings compel us to reconsider several long-held assumptions about consumer behavior.', '这些发现迫使我们重新审视若干长期持有的关于消费者行为的假设。'),
  ('35753522-bf28-4d08-8f53-c6351d8eb27e-ex1', '35753522-bf28-4d08-8f53-c6351d8eb27e', 'life', 'I enjoy my life in this city.', '我喜欢在这座城市的生活。'),
  ('35753522-bf28-4d08-8f53-c6351d8eb27e-ex2', '35753522-bf28-4d08-8f53-c6351d8eb27e', 'life', 'Improvements in sanitation have dramatically extended average life expectancy across the region.', '卫生条件的改善显著延长了该地区的平均预期寿命。'),
  ('f302ac0c-fa3e-4237-86b7-9fd4d0081065-ex1', 'f302ac0c-fa3e-4237-86b7-9fd4d0081065', 'child', 'The child is playing in the yard.', '那个孩子正在院子里玩。'),
  ('f302ac0c-fa3e-4237-86b7-9fd4d0081065-ex2', 'f302ac0c-fa3e-4237-86b7-9fd4d0081065', 'child', 'Every child, regardless of background, is entitled to free and equitable access to basic education.', '每个孩子，无论出身背景如何，都有权免费、公平地接受基础教育。'),
  ('c0015b96-99fd-4d63-88aa-4a30f3a9e8f5-ex1', 'c0015b96-99fd-4d63-88aa-4a30f3a9e8f5', 'work', 'I have a lot of work today.', '我今天有很多工作。'),
  ('c0015b96-99fd-4d63-88aa-4a30f3a9e8f5-ex2', 'c0015b96-99fd-4d63-88aa-4a30f3a9e8f5', 'work', 'Their pioneering work on gene editing laid the foundation for an entirely new field of therapy.', '他们在基因编辑方面的开创性工作为一个全新的治疗领域奠定了基础。'),
  ('467565ec-c394-4c5b-8eb8-02674c30d3ba-ex1', '467565ec-c394-4c5b-8eb8-02674c30d3ba', 'down', 'Please sit down and relax.', '请坐下放松一下。'),
  ('467565ec-c394-4c5b-8eb8-02674c30d3ba-ex2', '467565ec-c394-4c5b-8eb8-02674c30d3ba', 'down', 'Production costs have come down steadily as manufacturing processes have grown more efficient.', '随着制造工艺日益高效，生产成本持续下降。'),
  ('d14bc5ca-76de-4cfb-af46-f27641e5dd63-ex1', 'd14bc5ca-76de-4cfb-af46-f27641e5dd63', 'may', 'May I come in?', '我可以进来吗？'),
  ('d14bc5ca-76de-4cfb-af46-f27641e5dd63-ex2', 'd14bc5ca-76de-4cfb-af46-f27641e5dd63', 'may', 'Investors are advised that past performance may not be indicative of future results.', '特此提醒投资者，过往业绩未必能预示未来表现。'),
  ('307a78a8-ac8c-4d96-a354-98df4941dcc2-ex1', '307a78a8-ac8c-4d96-a354-98df4941dcc2', 'after', 'Let''s meet after lunch.', '我们午饭后见吧。'),
  ('307a78a8-ac8c-4d96-a354-98df4941dcc2-ex2', '307a78a8-ac8c-4d96-a354-98df4941dcc2', 'after', 'After months of negotiation, the parties finally reached a settlement acceptable to both sides.', '经过数月谈判，双方最终达成了彼此都能接受的和解协议。'),
  ('ec189b8a-4720-41fe-b108-d4a21888d99c-ex1', 'ec189b8a-4720-41fe-b108-d4a21888d99c', 'should', 'You should drink more water.', '你应该多喝水。'),
  ('ec189b8a-4720-41fe-b108-d4a21888d99c-ex2', 'ec189b8a-4720-41fe-b108-d4a21888d99c', 'should', 'The report recommends that regulators should intervene only when market mechanisms demonstrably fail.', '报告建议，监管机构只应在市场机制明显失灵时才进行干预。'),
  ('08771dff-0745-4ef3-b3c5-3808930311e2-ex1', '08771dff-0745-4ef3-b3c5-3808930311e2', 'call', 'I will call you tonight.', '我今晚给你打电话。'),
  ('08771dff-0745-4ef3-b3c5-3808930311e2-ex2', '08771dff-0745-4ef3-b3c5-3808930311e2', 'call', 'Several advocacy groups have issued a joint call for stricter oversight of data brokers.', '多个倡导团体联合呼吁加强对数据中介机构的监管。'),
  ('602b8bc1-5749-4276-81bf-c663f682b517-ex1', '602b8bc1-5749-4276-81bf-c663f682b517', 'world', 'I want to travel around the world.', '我想环游世界。'),
  ('602b8bc1-5749-4276-81bf-c663f682b517-ex2', '602b8bc1-5749-4276-81bf-c663f682b517', 'world', 'The summit brought together leaders from across the world to address the climate emergency.', '此次峰会汇聚了世界各地的领导人，共同应对气候紧急状况。'),
  ('a7fbd675-cfbd-4e27-bef7-13db697d8dd7-ex1', 'a7fbd675-cfbd-4e27-bef7-13db697d8dd7', 'over', 'The game is over now.', '比赛现在结束了。'),
  ('a7fbd675-cfbd-4e27-bef7-13db697d8dd7-ex2', 'a7fbd675-cfbd-4e27-bef7-13db697d8dd7', 'over', 'The dispute over territorial waters has strained diplomatic relations between the two nations.', '围绕领海的争端使两国外交关系趋于紧张。'),
  ('871e6f6d-13db-4066-a771-a8bbff29fa41-ex1', '871e6f6d-13db-4066-a771-a8bbff29fa41', 'school', 'My school is near my home.', '我的学校离家很近。'),
  ('871e6f6d-13db-4066-a771-a8bbff29fa41-ex2', '871e6f6d-13db-4066-a771-a8bbff29fa41', 'school', 'The ministry announced a comprehensive plan to modernize every public school in the district.', '教育部宣布了一项全面计划，对该区所有公立学校进行现代化改造。'),
  ('6852ad1e-143a-4c01-ab36-d6b5e35d4768-ex1', '6852ad1e-143a-4c01-ab36-d6b5e35d4768', 'still', 'I am still waiting for the bus.', '我还在等公交车。'),
  ('6852ad1e-143a-4c01-ab36-d6b5e35d4768-ex2', '6852ad1e-143a-4c01-ab36-d6b5e35d4768', 'still', 'Despite decades of research, the precise mechanism of the disease still remains poorly understood.', '尽管经过数十年研究，这种疾病的确切机理仍然知之甚少。'),
  ('fbd87d85-99bc-45f3-8224-a7755e12bf41-ex1', 'fbd87d85-99bc-45f3-8224-a7755e12bf41', 'try', 'Let me try this dress on.', '让我试穿一下这条裙子。'),
  ('fbd87d85-99bc-45f3-8224-a7755e12bf41-ex2', 'fbd87d85-99bc-45f3-8224-a7755e12bf41', 'try', 'The agency will try a phased approach before committing to full-scale implementation of the reform.', '该机构将先尝试分阶段推进，然后再全面实施这项改革。'),
  ('b16e8db4-7a2c-4e0c-9543-3e103d79fd04-ex1', 'b16e8db4-7a2c-4e0c-9543-3e103d79fd04', 'last', 'I saw him last week.', '我上周见过他。'),
  ('b16e8db4-7a2c-4e0c-9543-3e103d79fd04-ex2', 'b16e8db4-7a2c-4e0c-9543-3e103d79fd04', 'last', 'The ceasefire did not last long, as hostilities resumed within a matter of days.', '停火并未持续多久，敌对行动数日之内便重新爆发。'),
  ('92054476-90ec-4b28-a983-a6c6dcad2910-ex1', '92054476-90ec-4b28-a983-a6c6dcad2910', 'ask', 'Can I ask you a question?', '我能问你一个问题吗？'),
  ('92054476-90ec-4b28-a983-a6c6dcad2910-ex2', '92054476-90ec-4b28-a983-a6c6dcad2910', 'ask', 'Shareholders intend to ask the board to justify the substantial increase in executive compensation.', '股东们打算要求董事会就高管薪酬大幅上涨作出解释。'),
  ('5493b705-6cbc-442c-a0d8-d4e1677be171-ex1', '5493b705-6cbc-442c-a0d8-d4e1677be171', 'need', 'I need some help with this.', '这件事我需要一些帮助。'),
  ('5493b705-6cbc-442c-a0d8-d4e1677be171-ex2', '5493b705-6cbc-442c-a0d8-d4e1677be171', 'need', 'The assessment highlighted an urgent need for investment in rural healthcare infrastructure.', '评估强调了对农村医疗基础设施投资的迫切需要。'),
  ('46f637fb-1760-4d76-8003-b6523d10b481-ex1', '46f637fb-1760-4d76-8003-b6523d10b481', 'too', 'This coffee is too hot.', '这咖啡太烫了。'),
  ('46f637fb-1760-4d76-8003-b6523d10b481-ex2', '46f637fb-1760-4d76-8003-b6523d10b481', 'too', 'Critics argue that the proposed standards are too lenient to deter repeat violations effectively.', '批评者认为，拟议的标准过于宽松，不足以有效遏制屡次违规行为。'),
  ('4084b462-3535-40d2-975d-57fad15b4700-ex1', '4084b462-3535-40d2-975d-57fad15b4700', 'feel', 'I feel tired today.', '我今天觉得很累。'),
  ('4084b462-3535-40d2-975d-57fad15b4700-ex2', '4084b462-3535-40d2-975d-57fad15b4700', 'feel', 'Many employees feel that their concerns were not adequately addressed during the restructuring.', '许多员工觉得他们的诉求在重组过程中没有得到充分回应。'),
  ('8e571666-3f6f-45f3-afdc-e69a0d77e63b-ex1', '8e571666-3f6f-45f3-afdc-e69a0d77e63b', 'three', 'I have three sisters.', '我有三个姐妹。'),
  ('8e571666-3f6f-45f3-afdc-e69a0d77e63b-ex2', '8e571666-3f6f-45f3-afdc-e69a0d77e63b', 'three', 'The tribunal deliberated for three weeks before delivering its unanimous verdict.', '法庭审议了三周后作出了一致裁决。'),
  ('a6e3599a-28b9-4ddf-bb7c-9cb10d4da65d-ex1', 'a6e3599a-28b9-4ddf-bb7c-9cb10d4da65d', 'state', 'The roads are in a bad state.', '这些道路状况很差。'),
  ('a6e3599a-28b9-4ddf-bb7c-9cb10d4da65d-ex2', 'a6e3599a-28b9-4ddf-bb7c-9cb10d4da65d', 'state', 'Each state retains the authority to legislate on matters not delegated to the federal government.', '凡未授予联邦政府的事务，各州保留自行立法的权力。'),
  ('6c5e4145-d89f-4114-b179-15869736eba5-ex1', '6c5e4145-d89f-4114-b179-15869736eba5', 'never', 'I have never been to Japan.', '我从来没去过日本。'),
  ('6c5e4145-d89f-4114-b179-15869736eba5-ex2', '6c5e4145-d89f-4114-b179-15869736eba5', 'never', 'The ambassador stressed that diplomatic channels should never be abandoned, even amid escalating tensions.', '大使强调，即使局势不断升级，也决不应放弃外交渠道。'),
  ('583c7eb3-0a69-4cf3-80c7-1d06420751ec-ex1', '583c7eb3-0a69-4cf3-80c7-1d06420751ec', 'become', 'She wants to become a doctor.', '她想成为一名医生。'),
  ('583c7eb3-0a69-4cf3-80c7-1d06420751ec-ex2', '583c7eb3-0a69-4cf3-80c7-1d06420751ec', 'become', 'Renewable energy has become an indispensable component of national development strategies worldwide.', '可再生能源已成为世界各国发展战略中不可或缺的组成部分。'),
  ('bbba9dc2-ae16-4ff0-a8ea-c19e9b296980-ex1', 'bbba9dc2-ae16-4ff0-a8ea-c19e9b296980', 'between', 'The bank is between two shops.', '银行在两家商店之间。'),
  ('bbba9dc2-ae16-4ff0-a8ea-c19e9b296980-ex2', 'bbba9dc2-ae16-4ff0-a8ea-c19e9b296980', 'between', 'The agreement seeks to strengthen economic cooperation between the two largest trading blocs.', '该协议旨在加强两大贸易集团之间的经济合作。'),
  ('162fb419-bc46-4be2-bc54-6687b6c5dbe2-ex1', '162fb419-bc46-4be2-bc54-6687b6c5dbe2', 'high', 'That mountain is very high.', '那座山很高。'),
  ('162fb419-bc46-4be2-bc54-6687b6c5dbe2-ex2', '162fb419-bc46-4be2-bc54-6687b6c5dbe2', 'high', 'Persistently high inflation has eroded household purchasing power across the entire region.', '持续高企的通货膨胀侵蚀了整个地区家庭的购买力。'),
  ('89f7dbac-15af-4e59-b4a7-490e39f94272-ex1', '89f7dbac-15af-4e59-b4a7-490e39f94272', 'really', 'I really like this song.', '我真的很喜欢这首歌。'),
  ('89f7dbac-15af-4e59-b4a7-490e39f94272-ex2', '89f7dbac-15af-4e59-b4a7-490e39f94272', 'really', 'The data suggest that the intervention really did produce measurable improvements in literacy rates.', '数据表明，这项干预确实使识字率得到了可衡量的提升。'),
  ('83176cfb-cdcf-4bef-ae3d-8a8c2df81bf9-ex1', '83176cfb-cdcf-4bef-ae3d-8a8c2df81bf9', 'something', 'I want to eat something sweet.', '我想吃点甜的东西。'),
  ('83176cfb-cdcf-4bef-ae3d-8a8c2df81bf9-ex2', '83176cfb-cdcf-4bef-ae3d-8a8c2df81bf9', 'something', 'There is something fundamentally problematic about evaluating schools solely on standardized test scores.', '仅凭标准化考试成绩来评价学校，存在着根本性的问题。'),
  ('16c1f3ad-eab9-4dd9-8dea-58618fdab97b-ex1', '16c1f3ad-eab9-4dd9-8dea-58618fdab97b', 'most', 'Most students passed the test.', '大多数学生通过了考试。'),
  ('16c1f3ad-eab9-4dd9-8dea-58618fdab97b-ex2', '16c1f3ad-eab9-4dd9-8dea-58618fdab97b', 'most', 'The most pressing challenge confronting the administration is restoring public trust in institutions.', '本届政府面临的最紧迫挑战是重建公众对体制机构的信任。'),
  ('94590088-2aac-474b-affd-04684b41a29e-ex1', '94590088-2aac-474b-affd-04684b41a29e', 'another', 'Can I have another cup of tea?', '我能再来一杯茶吗？'),
  ('94590088-2aac-474b-affd-04684b41a29e-ex2', '94590088-2aac-474b-affd-04684b41a29e', 'another', 'The committee postponed the vote for another month to accommodate further expert testimony.', '委员会将表决再推迟一个月，以便听取更多专家证词。'),
  ('ac6137ab-904c-46b9-9174-ebe55e23bfc2-ex1', 'ac6137ab-904c-46b9-9174-ebe55e23bfc2', 'much', 'How much does this cost?', '这个多少钱？'),
  ('ac6137ab-904c-46b9-9174-ebe55e23bfc2-ex2', 'ac6137ab-904c-46b9-9174-ebe55e23bfc2', 'much', 'Much of the recent progress in artificial intelligence derives from advances in computational capacity.', '人工智能领域近来的进展大多源于计算能力的提升。'),
  ('27bb68f6-642e-43b5-8bf9-64ecc50f637c-ex1', '27bb68f6-642e-43b5-8bf9-64ecc50f637c', 'family', 'My family lives in Shanghai.', '我的家人住在上海。'),
  ('27bb68f6-642e-43b5-8bf9-64ecc50f637c-ex2', '27bb68f6-642e-43b5-8bf9-64ecc50f637c', 'family', 'The legislation extends tax relief to every family whose income falls below the national median.', '该立法将税收减免扩大到收入低于全国中位数的每一个家庭。'),
  ('ee2daa4d-2b63-47b7-99ed-bf1f09d2e715-ex1', 'ee2daa4d-2b63-47b7-99ed-bf1f09d2e715', 'own', 'She has her own room.', '她有自己的房间。'),
  ('ee2daa4d-2b63-47b7-99ed-bf1f09d2e715-ex2', 'ee2daa4d-2b63-47b7-99ed-bf1f09d2e715', 'own', 'Citizens who own property within the designated zone will be compensated at fair market value.', '在划定区域内拥有房产的居民将按公平市价获得补偿。'),
  ('6f28b6be-a7d2-4726-b9a8-fd536b2be1a2-ex1', '6f28b6be-a7d2-4726-b9a8-fd536b2be1a2', 'leave', 'What time do you leave home?', '你几点出门？'),
  ('6f28b6be-a7d2-4726-b9a8-fd536b2be1a2-ex2', '6f28b6be-a7d2-4726-b9a8-fd536b2be1a2', 'leave', 'The directors agreed to leave the final decision to an independent arbitration panel.', '董事们同意将最终决定权交给独立仲裁小组。'),
  ('81239950-e49f-4a8e-b71b-abe1ede18305-ex1', '81239950-e49f-4a8e-b71b-abe1ede18305', 'put', 'Put your books on the desk.', '把你的书放在桌子上。'),
  ('81239950-e49f-4a8e-b71b-abe1ede18305-ex2', '81239950-e49f-4a8e-b71b-abe1ede18305', 'put', 'The crisis has put unprecedented strain on the region''s already fragile healthcare system.', '这场危机给该地区本已脆弱的医疗体系带来了前所未有的压力。'),
  ('bb29520d-09ce-48a2-afc8-5ea899df15a1-ex1', 'bb29520d-09ce-48a2-afc8-5ea899df15a1', 'old', 'My grandfather is eighty years old.', '我祖父八十岁了。'),
  ('bb29520d-09ce-48a2-afc8-5ea899df15a1-ex2', 'bb29520d-09ce-48a2-afc8-5ea899df15a1', 'old', 'The old regulatory framework proved incapable of addressing the complexities of digital commerce.', '旧的监管框架被证明无力应对数字商务的复杂性。'),
  ('80575362-d6d9-4621-8fb5-dbae7c0219ba-ex1', '80575362-d6d9-4621-8fb5-dbae7c0219ba', 'while', 'I read a book while waiting.', '我边等边看书。'),
  ('80575362-d6d9-4621-8fb5-dbae7c0219ba-ex2', '80575362-d6d9-4621-8fb5-dbae7c0219ba', 'while', 'While the reforms have broad public support, their fiscal implications remain a source of contention.', '虽然改革获得了广泛的公众支持，但其财政影响仍存在争议。'),
  ('30951cc0-59c7-4e6c-9211-f355b91370ae-ex1', '30951cc0-59c7-4e6c-9211-f355b91370ae', 'mean', 'What does this word mean?', '这个词是什么意思？'),
  ('30951cc0-59c7-4e6c-9211-f355b91370ae-ex2', '30951cc0-59c7-4e6c-9211-f355b91370ae', 'mean', 'Higher interest rates mean that many households will face substantially larger mortgage payments.', '利率上升意味着许多家庭将面临大幅增加的房贷支出。'),
  ('ed307934-1ddf-4419-8fde-568934cc5498-ex1', 'ed307934-1ddf-4419-8fde-568934cc5498', 'keep', 'Please keep the door closed.', '请保持门关闭。'),
  ('ed307934-1ddf-4419-8fde-568934cc5498-ex2', 'ed307934-1ddf-4419-8fde-568934cc5498', 'keep', 'Regulators must keep pace with technological innovation to safeguard consumers effectively.', '监管机构必须跟上技术创新的步伐，才能有效保护消费者。'),
  ('9837afc4-fedc-499f-a21f-c9d560b8967e-ex1', '9837afc4-fedc-499f-a21f-c9d560b8967e', 'student', 'She is a student at this university.', '她是这所大学的学生。'),
  ('9837afc4-fedc-499f-a21f-c9d560b8967e-ex2', '9837afc4-fedc-499f-a21f-c9d560b8967e', 'student', 'Every student admitted under the scholarship program must maintain a distinguished academic record.', '凡通过该奖学金项目录取的学生都必须保持优异的学业成绩。'),
  ('ee5a2014-21ef-422b-ab78-46ea99741e7b-ex1', 'ee5a2014-21ef-422b-ab78-46ea99741e7b', 'why', 'Why are you late today?', '你今天为什么迟到？'),
  ('ee5a2014-21ef-422b-ab78-46ea99741e7b-ex2', 'ee5a2014-21ef-422b-ab78-46ea99741e7b', 'why', 'The inquiry sought to establish why the safety mechanisms failed to activate during the incident.', '调查旨在查明事故发生时安全机制为何未能启动。'),
  ('f7dac5fc-a495-47ff-974f-8d6c20977866-ex1', 'f7dac5fc-a495-47ff-974f-8d6c20977866', 'let', 'Let me help you with that.', '让我来帮你吧。'),
  ('f7dac5fc-a495-47ff-974f-8d6c20977866-ex2', 'f7dac5fc-a495-47ff-974f-8d6c20977866', 'let', 'The court declined to let the disputed evidence be presented before the jury.', '法院拒绝让有争议的证据在陪审团面前出示。'),
  ('a00bd1ce-36b6-4c15-97c8-9e3852a417ba-ex1', 'a00bd1ce-36b6-4c15-97c8-9e3852a417ba', 'great', 'We had a great time at the party.', '我们在聚会上玩得很开心。'),
  ('a00bd1ce-36b6-4c15-97c8-9e3852a417ba-ex2', 'a00bd1ce-36b6-4c15-97c8-9e3852a417ba', 'great', 'The discovery represents a great leap forward in our understanding of cellular regeneration.', '这一发现是我们认识细胞再生机制的一次重大飞跃。'),
  ('463b2c46-0b2d-4943-983b-949215a5cad5-ex1', '463b2c46-0b2d-4943-983b-949215a5cad5', 'same', 'We go to the same school.', '我们在同一所学校上学。'),
  ('463b2c46-0b2d-4943-983b-949215a5cad5-ex2', '463b2c46-0b2d-4943-983b-949215a5cad5', 'same', 'Applicants from different regions are evaluated according to the same rigorous criteria.', '来自不同地区的申请者按照同样严格的标准接受评估。'),
  ('d280b1cc-f9df-445c-9d0b-77dabbaeee86-ex1', 'd280b1cc-f9df-445c-9d0b-77dabbaeee86', 'big', 'They live in a big house.', '他们住在一栋大房子里。'),
  ('d280b1cc-f9df-445c-9d0b-77dabbaeee86-ex2', 'd280b1cc-f9df-445c-9d0b-77dabbaeee86', 'big', 'The merger represents the biggest consolidation the telecommunications industry has seen in decades.', '此次合并是电信行业数十年来规模最大的一次整合。'),
  ('d048f23c-2497-4132-b59e-63c95d40cd2c-ex1', 'd048f23c-2497-4132-b59e-63c95d40cd2c', 'group', 'Our group has five members.', '我们小组有五名成员。'),
  ('d048f23c-2497-4132-b59e-63c95d40cd2c-ex2', 'd048f23c-2497-4132-b59e-63c95d40cd2c', 'group', 'An independent group of experts was convened to evaluate the environmental impact of the project.', '一个独立专家小组受命评估该项目的环境影响。'),
  ('94dd39dd-f27e-4fc2-9611-17d936ab0f84-ex1', '94dd39dd-f27e-4fc2-9611-17d936ab0f84', 'begin', 'The class will begin at nine.', '九点开始上课。'),
  ('94dd39dd-f27e-4fc2-9611-17d936ab0f84-ex2', '94dd39dd-f27e-4fc2-9611-17d936ab0f84', 'begin', 'Construction cannot begin until the environmental review has been formally concluded.', '在环境评审正式完成之前，工程不得开工。'),
  ('b83013d4-ca49-4a06-b94f-6b3d14964de7-ex1', 'b83013d4-ca49-4a06-b94f-6b3d14964de7', 'seem', 'You seem very happy today.', '你今天看起来很开心。'),
  ('b83013d4-ca49-4a06-b94f-6b3d14964de7-ex2', 'b83013d4-ca49-4a06-b94f-6b3d14964de7', 'seem', 'The benefits of the policy seem modest when weighed against its considerable administrative costs.', '与可观的行政成本相比，该政策的收益似乎并不显著。'),
  ('8d1bd595-d4c2-4ec6-9168-4c33f5797caf-ex1', '8d1bd595-d4c2-4ec6-9168-4c33f5797caf', 'country', 'China is a large country.', '中国是一个幅员辽阔的国家。'),
  ('8d1bd595-d4c2-4ec6-9168-4c33f5797caf-ex2', '8d1bd595-d4c2-4ec6-9168-4c33f5797caf', 'country', 'Each participating country has committed to reducing its carbon emissions by a fixed percentage.', '每个参与国都已承诺将本国碳排放量降低一个固定的百分比。'),
  ('98483dba-2a32-41c5-81b9-f98a3d185ddb-ex1', '98483dba-2a32-41c5-81b9-f98a3d185ddb', 'help', 'Can you help me move this table?', '你能帮我搬一下这张桌子吗？'),
  ('98483dba-2a32-41c5-81b9-f98a3d185ddb-ex2', '98483dba-2a32-41c5-81b9-f98a3d185ddb', 'help', 'International aid agencies mobilized swiftly to help communities devastated by the earthquake.', '国际援助机构迅速动员起来，帮助遭受地震重创的社区。'),
  ('81c3ff18-1c05-427d-8cc7-233e532c5f94-ex1', '81c3ff18-1c05-427d-8cc7-233e532c5f94', 'talk', 'Let''s talk about your plan.', '我们谈谈你的计划吧。'),
  ('81c3ff18-1c05-427d-8cc7-233e532c5f94-ex2', '81c3ff18-1c05-427d-8cc7-233e532c5f94', 'talk', 'The two governments agreed to resume talks aimed at resolving the long-standing border dispute.', '两国政府同意恢复旨在解决长期边界争端的会谈。'),
  ('914547a1-2cab-479a-9124-c2befbb6bdfc-ex1', '914547a1-2cab-479a-9124-c2befbb6bdfc', 'where', 'Where did you park the car?', '你把车停在哪里了？'),
  ('914547a1-2cab-479a-9124-c2befbb6bdfc-ex2', '914547a1-2cab-479a-9124-c2befbb6bdfc', 'where', 'The commission will determine where responsibility lies for the catastrophic system failure.', '委员会将认定这次灾难性系统故障的责任归属。'),
  ('3874e64a-893c-48c1-ac29-39f74ff95bf7-ex1', '3874e64a-893c-48c1-ac29-39f74ff95bf7', 'turn', 'Turn left at the next corner.', '在下一个路口左转。'),
  ('3874e64a-893c-48c1-ac29-39f74ff95bf7-ex2', '3874e64a-893c-48c1-ac29-39f74ff95bf7', 'turn', 'The unexpected turn of events forced negotiators to reconsider their entire strategy.', '事态的意外转变迫使谈判代表重新考虑其整体策略。'),
  ('0e4712dd-010e-4b84-94f3-7a5655d14eef-ex1', '0e4712dd-010e-4b84-94f3-7a5655d14eef', 'problem', 'I have a problem with my computer.', '我的电脑出了点问题。'),
  ('0e4712dd-010e-4b84-94f3-7a5655d14eef-ex2', '0e4712dd-010e-4b84-94f3-7a5655d14eef', 'problem', 'Addressing the problem of urban congestion requires coordinated investment in public transit.', '解决城市拥堵问题需要对公共交通进行协调一致的投资。'),
  ('a13eea63-e26d-4e1d-bce3-9bf4dcb9207b-ex1', 'a13eea63-e26d-4e1d-bce3-9bf4dcb9207b', 'every', 'I exercise every morning.', '我每天早上锻炼。'),
  ('a13eea63-e26d-4e1d-bce3-9bf4dcb9207b-ex2', 'a13eea63-e26d-4e1d-bce3-9bf4dcb9207b', 'every', 'Every provision of the contract was scrutinized by legal counsel before the signing ceremony.', '合同的每一项条款在签字仪式前都经过了法律顾问的仔细审查。'),
  ('272adeaf-209f-4fce-b0fd-8a6d364bcc4c-ex1', '272adeaf-209f-4fce-b0fd-8a6d364bcc4c', 'start', 'Let''s start the meeting now.', '我们现在开始开会吧。'),
  ('272adeaf-209f-4fce-b0fd-8a6d364bcc4c-ex2', '272adeaf-209f-4fce-b0fd-8a6d364bcc4c', 'start', 'The initiative marks the start of a long-term effort to modernize the nation''s power grid.', '这项计划标志着国家电网长期现代化改造的开端。'),
  ('7f884613-2964-47d0-8d8c-06b77d7e9250-ex1', '7f884613-2964-47d0-8d8c-06b77d7e9250', 'hand', 'Raise your hand if you know the answer.', '知道答案的请举手。'),
  ('7f884613-2964-47d0-8d8c-06b77d7e9250-ex2', '7f884613-2964-47d0-8d8c-06b77d7e9250', 'hand', 'The outgoing administration must hand over complete records to ensure an orderly transition.', '即将卸任的政府必须移交完整档案，以确保有序过渡。'),
  ('d47d6731-1c47-4b4e-8c7e-8b3238ccbc3a-ex1', 'd47d6731-1c47-4b4e-8c7e-8b3238ccbc3a', 'might', 'It might rain this afternoon.', '今天下午可能会下雨。'),
  ('d47d6731-1c47-4b4e-8c7e-8b3238ccbc3a-ex2', 'd47d6731-1c47-4b4e-8c7e-8b3238ccbc3a', 'might', 'Analysts cautioned that premature deregulation might expose consumers to significant financial risk.', '分析人士警告说，过早放松监管可能使消费者面临重大金融风险。'),
  ('343e522d-ab68-4396-a6be-810065bec533-ex1', '343e522d-ab68-4396-a6be-810065bec533', 'American', 'My teacher is American.', '我的老师是美国人。'),
  ('343e522d-ab68-4396-a6be-810065bec533-ex2', '343e522d-ab68-4396-a6be-810065bec533', 'American', 'The exhibition explores how American literature grappled with the social upheavals of the twentieth century.', '展览探讨了美国文学如何回应二十世纪的社会剧变。'),
  ('e7fcd0fc-cbf3-4aa9-8b81-50d9299e7e9b-ex1', 'e7fcd0fc-cbf3-4aa9-8b81-50d9299e7e9b', 'show', 'Can you show me the way?', '你能给我指一下路吗？'),
  ('e7fcd0fc-cbf3-4aa9-8b81-50d9299e7e9b-ex2', 'e7fcd0fc-cbf3-4aa9-8b81-50d9299e7e9b', 'show', 'The latest figures show a marked improvement in employment across the manufacturing sector.', '最新数据显示，制造业就业状况明显改善。'),
  ('6fef8b86-5b79-4e7a-b56d-3e40c9f83c7c-ex1', '6fef8b86-5b79-4e7a-b56d-3e40c9f83c7c', 'part', 'This is my favorite part of the movie.', '这是电影里我最喜欢的部分。'),
  ('6fef8b86-5b79-4e7a-b56d-3e40c9f83c7c-ex2', '6fef8b86-5b79-4e7a-b56d-3e40c9f83c7c', 'part', 'Civic engagement constitutes an essential part of any functioning democratic society.', '公民参与是任何运转良好的民主社会的重要组成部分。'),
  ('8f05825e-04b4-428c-b353-796cdf5c0c37-ex1', '8f05825e-04b4-428c-b353-796cdf5c0c37', 'against', 'We played against the best team.', '我们和最强的队比赛了。'),
  ('8f05825e-04b4-428c-b353-796cdf5c0c37-ex2', '8f05825e-04b4-428c-b353-796cdf5c0c37', 'against', 'Several member states voted against the resolution, citing concerns over national sovereignty.', '几个成员国以国家主权问题为由对该决议投了反对票。'),
  ('2f49d661-8b0d-465a-979d-8a2222a2bcc9-ex1', '2f49d661-8b0d-465a-979d-8a2222a2bcc9', 'place', 'This is a nice place for a picnic.', '这是个野餐的好地方。'),
  ('2f49d661-8b0d-465a-979d-8a2222a2bcc9-ex2', '2f49d661-8b0d-465a-979d-8a2222a2bcc9', 'place', 'Stringent safeguards were put in place to prevent the misuse of confidential client information.', '已制定严格的保障措施，防止客户机密信息被滥用。'),
  ('9934a2a7-f05c-4827-af5b-cf3afe00b291-ex1', '9934a2a7-f05c-4827-af5b-cf3afe00b291', 'such', 'I have never seen such a beautiful sunset.', '我从未见过如此美丽的日落。'),
  ('9934a2a7-f05c-4827-af5b-cf3afe00b291-ex2', '9934a2a7-f05c-4827-af5b-cf3afe00b291', 'such', 'Such conduct, if substantiated, would constitute a serious breach of professional ethics.', '此类行为一经证实，将构成对职业道德的严重违反。'),
  ('5a4bcf5a-61b5-475c-a4e9-89c6017c4667-ex1', '5a4bcf5a-61b5-475c-a4e9-89c6017c4667', 'again', 'Can you say that again?', '你能再说一遍吗？'),
  ('5a4bcf5a-61b5-475c-a4e9-89c6017c4667-ex2', '5a4bcf5a-61b5-475c-a4e9-89c6017c4667', 'again', 'The committee stressed that such oversights must never be allowed to occur again.', '委员会强调，绝不能允许此类疏漏再次发生。'),
  ('090bf064-8e76-4a22-8451-0179f3362769-ex1', '090bf064-8e76-4a22-8451-0179f3362769', 'few', 'I have a few questions.', '我有几个问题。'),
  ('090bf064-8e76-4a22-8451-0179f3362769-ex2', '090bf064-8e76-4a22-8451-0179f3362769', 'few', 'Remarkably few of the surveyed institutions had implemented the recommended security protocols.', '令人惊讶的是，受调查机构中实施了推荐安全协议的寥寥无几。'),
  ('a1b2e5e4-30d8-440d-9fa5-d6200e691216-ex1', 'a1b2e5e4-30d8-440d-9fa5-d6200e691216', 'case', 'In that case, let''s go home.', '那样的话，我们回家吧。'),
  ('a1b2e5e4-30d8-440d-9fa5-d6200e691216-ex2', 'a1b2e5e4-30d8-440d-9fa5-d6200e691216', 'case', 'The court''s ruling in this case is expected to set a precedent for similar disputes nationwide.', '法院对本案的裁决预计将为全国类似纠纷树立先例。'),
  ('30f43d2b-83ac-470c-a021-5a5fbd5cba1d-ex1', '30f43d2b-83ac-470c-a021-5a5fbd5cba1d', 'week', 'See you next week!', '下周见！'),
  ('30f43d2b-83ac-470c-a021-5a5fbd5cba1d-ex2', '30f43d2b-83ac-470c-a021-5a5fbd5cba1d', 'week', 'Within a single week, the proposal attracted endorsements from over two hundred organizations.', '短短一周之内，该提案就获得了两百多家组织的支持。'),
  ('93688956-8e36-4a53-babe-3cb4ec0dffde-ex1', '93688956-8e36-4a53-babe-3cb4ec0dffde', 'company', 'She works for a tech company.', '她在一家科技公司工作。'),
  ('93688956-8e36-4a53-babe-3cb4ec0dffde-ex2', '93688956-8e36-4a53-babe-3cb4ec0dffde', 'company', 'The company disclosed that it was under investigation for alleged violations of antitrust law.', '该公司披露，其正因涉嫌违反反垄断法而接受调查。'),
  ('7c0f256d-7141-46ed-a64d-e6ac41649bbd-ex1', '7c0f256d-7141-46ed-a64d-e6ac41649bbd', 'system', 'The heating system is broken.', '供暖系统坏了。'),
  ('7c0f256d-7141-46ed-a64d-e6ac41649bbd-ex2', '7c0f256d-7141-46ed-a64d-e6ac41649bbd', 'system', 'The proposed system integrates real-time monitoring with automated regulatory reporting.', '拟议的系统将实时监测与自动化监管报告融为一体。'),
  ('163cc0c2-5d44-4131-a9f9-1744b439d213-ex1', '163cc0c2-5d44-4131-a9f9-1744b439d213', 'each', 'Each student gets a free book.', '每个学生都能得到一本免费的书。'),
  ('163cc0c2-5d44-4131-a9f9-1744b439d213-ex2', '163cc0c2-5d44-4131-a9f9-1744b439d213', 'each', 'Each of the participating laboratories independently verified the experimental results.', '每个参与实验室都独立验证了实验结果。'),
  ('b77cc1a5-e309-4192-a72b-436d5cb3cc34-ex1', 'b77cc1a5-e309-4192-a72b-436d5cb3cc34', 'right', 'You gave the right answer.', '你给出了正确答案。'),
  ('b77cc1a5-e309-4192-a72b-436d5cb3cc34-ex2', 'b77cc1a5-e309-4192-a72b-436d5cb3cc34', 'right', 'The constitution guarantees every citizen the right to a fair and public trial.', '宪法保障每位公民获得公正、公开审判的权利。'),
  ('963adb94-65e0-418c-9914-d803960e4f9b-ex1', '963adb94-65e0-418c-9914-d803960e4f9b', 'program', 'I watched a funny TV program.', '我看了一个有趣的电视节目。'),
  ('963adb94-65e0-418c-9914-d803960e4f9b-ex2', '963adb94-65e0-418c-9914-d803960e4f9b', 'program', 'The pilot program will be expanded nationwide if the preliminary outcomes prove satisfactory.', '如果初步成效令人满意，该试点项目将推广至全国。'),
  ('53374a8a-489d-43f6-a6b2-1102cac786a4-ex1', '53374a8a-489d-43f6-a6b2-1102cac786a4', 'hear', 'Did you hear that noise?', '你听到那个声音了吗？'),
  ('53374a8a-489d-43f6-a6b2-1102cac786a4-ex2', '53374a8a-489d-43f6-a6b2-1102cac786a4', 'hear', 'The appellate court agreed to hear the case in light of newly discovered evidence.', '鉴于新发现的证据，上诉法院同意审理此案。'),
  ('9dc1b7fe-6f81-49a9-b103-1e485b9d0fc8-ex1', '9dc1b7fe-6f81-49a9-b103-1e485b9d0fc8', 'question', 'May I ask you a question?', '我可以问你一个问题吗？'),
  ('9dc1b7fe-6f81-49a9-b103-1e485b9d0fc8-ex2', '9dc1b7fe-6f81-49a9-b103-1e485b9d0fc8', 'question', 'The question of how to allocate scarce medical resources raises profound ethical dilemmas.', '如何分配稀缺医疗资源的问题引出了深刻的伦理困境。'),
  ('9084c6d1-9649-4e28-91ee-064026fc3151-ex1', '9084c6d1-9649-4e28-91ee-064026fc3151', 'during', 'Please be quiet during the movie.', '看电影时请保持安静。'),
  ('9084c6d1-9649-4e28-91ee-064026fc3151-ex2', '9084c6d1-9649-4e28-91ee-064026fc3151', 'during', 'During the deliberations, several jurors expressed reservations about the reliability of the testimony.', '审议期间，数名陪审员对证词的可靠性表示保留。'),
  ('ebb12c32-1a5b-435c-b6e9-6624d001b6ba-ex1', 'ebb12c32-1a5b-435c-b6e9-6624d001b6ba', 'play', 'The children play in the park every day.', '孩子们每天在公园里玩。'),
  ('ebb12c32-1a5b-435c-b6e9-6624d001b6ba-ex2', 'ebb12c32-1a5b-435c-b6e9-6624d001b6ba', 'play', 'Multilateral institutions play a pivotal role in coordinating responses to global crises.', '多边机构在协调应对全球危机方面发挥着关键作用。'),
  ('cc35e13d-c040-423e-9489-013c01886b10-ex1', 'cc35e13d-c040-423e-9489-013c01886b10', 'government', 'The government built a new hospital.', '政府建了一所新医院。'),
  ('cc35e13d-c040-423e-9489-013c01886b10-ex2', 'cc35e13d-c040-423e-9489-013c01886b10', 'government', 'The government announced sweeping reforms intended to restore confidence in public institutions.', '政府宣布了旨在恢复公众对公共机构信心的全面改革。'),
  ('03fb0385-0520-43c9-8b6f-03ec19677a1e-ex1', '03fb0385-0520-43c9-8b6f-03ec19677a1e', 'run', 'I run in the park every morning.', '我每天早上在公园跑步。'),
  ('03fb0385-0520-43c9-8b6f-03ec19677a1e-ex2', '03fb0385-0520-43c9-8b6f-03ec19677a1e', 'run', 'She was appointed to run the agency during a period of exceptional institutional turmoil.', '她在机构动荡异常的时期受命执掌该机构。'),
  ('031ae5d9-ef2f-467b-91dc-d1ed125f5411-ex1', '031ae5d9-ef2f-467b-91dc-d1ed125f5411', 'small', 'They live in a small apartment.', '他们住在一间小公寓里。'),
  ('031ae5d9-ef2f-467b-91dc-d1ed125f5411-ex2', '031ae5d9-ef2f-467b-91dc-d1ed125f5411', 'small', 'Small enterprises account for a disproportionate share of net job creation in emerging economies.', '在新兴经济体中，小企业在净就业创造中所占比重格外突出。'),
  ('3a7f8be8-e13a-467e-b361-6cdc72b0b225-ex1', '3a7f8be8-e13a-467e-b361-6cdc72b0b225', 'number', 'What is your phone number?', '你的电话号码是多少？'),
  ('3a7f8be8-e13a-467e-b361-6cdc72b0b225-ex2', '3a7f8be8-e13a-467e-b361-6cdc72b0b225', 'number', 'The number of applicants has risen steadily since the eligibility criteria were relaxed.', '自放宽资格标准以来，申请人数持续稳步上升。'),
  ('9bbc85f7-b731-4d8b-8092-4bd89e5edc20-ex1', '9bbc85f7-b731-4d8b-8092-4bd89e5edc20', 'off', 'Please turn off the lights.', '请关灯。'),
  ('9bbc85f7-b731-4d8b-8092-4bd89e5edc20-ex2', '9bbc85f7-b731-4d8b-8092-4bd89e5edc20', 'off', 'The board called off the merger after due diligence revealed substantial undisclosed liabilities.', '尽职调查发现大量未披露负债后，董事会取消了此次合并。'),
  ('85cd908d-5e82-4ec7-811f-9dcaa0040030-ex1', '85cd908d-5e82-4ec7-811f-9dcaa0040030', 'always', 'She always arrives on time.', '她总是准时到达。'),
  ('85cd908d-5e82-4ec7-811f-9dcaa0040030-ex2', '85cd908d-5e82-4ec7-811f-9dcaa0040030', 'always', 'Prudent investors always diversify their holdings to mitigate exposure to market volatility.', '审慎的投资者总是通过分散持仓来降低市场波动带来的风险。'),
  ('eff000e4-96d4-47bc-b3f7-2b27ccc44c30-ex1', 'eff000e4-96d4-47bc-b3f7-2b27ccc44c30', 'move', 'We plan to move to a new house.', '我们打算搬进新房子。'),
  ('eff000e4-96d4-47bc-b3f7-2b27ccc44c30-ex2', 'eff000e4-96d4-47bc-b3f7-2b27ccc44c30', 'move', 'The decision to move manufacturing operations overseas provoked strong opposition from labor unions.', '将生产业务迁往海外的决定引发了工会的强烈反对。'),
  ('dc6dbd7a-df96-4759-af91-f8f35922b583-ex1', 'dc6dbd7a-df96-4759-af91-f8f35922b583', 'night', 'I slept well last night.', '我昨晚睡得很好。'),
  ('dc6dbd7a-df96-4759-af91-f8f35922b583-ex2', 'dc6dbd7a-df96-4759-af91-f8f35922b583', 'night', 'Emergency crews worked through the night to restore power to the affected districts.', '抢修人员连夜奋战，为受影响地区恢复供电。'),
  ('39fd9cdf-fa0b-4d93-966f-0df63348c1c1-ex1', '39fd9cdf-fa0b-4d93-966f-0df63348c1c1', 'live', 'I live near the train station.', '我住在火车站附近。'),
  ('39fd9cdf-fa0b-4d93-966f-0df63348c1c1-ex2', '39fd9cdf-fa0b-4d93-966f-0df63348c1c1', 'live', 'Millions of people continue to live in conditions that fall far below internationally recognized standards.', '数以百万计的人仍生活在远低于国际公认标准的条件下。'),
  ('ce8b9eb1-0494-42c7-af8f-1d9225fcff99-ex1', 'ce8b9eb1-0494-42c7-af8f-1d9225fcff99', 'Mr', 'Mr Smith is our English teacher.', '史密斯先生是我们的英语老师。'),
  ('ce8b9eb1-0494-42c7-af8f-1d9225fcff99-ex2', 'ce8b9eb1-0494-42c7-af8f-1d9225fcff99', 'Mr', 'Mr Chairman, I respectfully request that the motion be put to an immediate vote.', '主席先生，我谨请求将该动议立即付诸表决。'),
  ('91f94b7a-2305-4e1f-a6b3-1da0d441f84e-ex1', '91f94b7a-2305-4e1f-a6b3-1da0d441f84e', 'point', 'That''s a good point.', '这个观点很好。'),
  ('91f94b7a-2305-4e1f-a6b3-1da0d441f84e-ex2', '91f94b7a-2305-4e1f-a6b3-1da0d441f84e', 'point', 'The negotiations reached a critical point when both delegations refused to compromise on tariffs.', '当双方代表团都拒绝在关税问题上让步时，谈判到达了关键节点。'),
  ('43044bda-781b-4aaf-97cc-252ae5bcc815-ex1', '43044bda-781b-4aaf-97cc-252ae5bcc815', 'believe', 'I believe you can do it.', '我相信你能做到。'),
  ('43044bda-781b-4aaf-97cc-252ae5bcc815-ex2', '43044bda-781b-4aaf-97cc-252ae5bcc815', 'believe', 'Most scholars believe that the manuscript dates from the latter half of the twelfth century.', '多数学者认为这份手稿出自十二世纪下半叶。'),
  ('02dedf47-d20d-41b7-8daf-8ced70c3f742-ex1', '02dedf47-d20d-41b7-8daf-8ced70c3f742', 'hold', 'Can you hold my bag for a second?', '你能帮我拿一下包吗？'),
  ('02dedf47-d20d-41b7-8daf-8ced70c3f742-ex2', '02dedf47-d20d-41b7-8daf-8ced70c3f742', 'hold', 'The authorities decided to hold a public inquiry into the circumstances surrounding the collapse.', '当局决定就坍塌事故的相关情况举行公开调查。'),
  ('b67a8a24-6978-428e-af69-64d47ab6cbf6-ex1', 'b67a8a24-6978-428e-af69-64d47ab6cbf6', 'today', 'Today is my birthday.', '今天是我的生日。'),
  ('b67a8a24-6978-428e-af69-64d47ab6cbf6-ex2', 'b67a8a24-6978-428e-af69-64d47ab6cbf6', 'today', 'The challenges confronting policymakers today are unprecedented in both scale and complexity.', '当今决策者面临的挑战在规模和复杂性上都是前所未有的。'),
  ('3fab4bcc-63ee-4841-bf5b-3d87af05c181-ex1', '3fab4bcc-63ee-4841-bf5b-3d87af05c181', 'bring', 'Please bring your homework tomorrow.', '明天请把作业带来。'),
  ('3fab4bcc-63ee-4841-bf5b-3d87af05c181-ex2', '3fab4bcc-63ee-4841-bf5b-3d87af05c181', 'bring', 'The reforms are expected to bring greater transparency to the management of public funds.', '预计这些改革将提高公共资金管理的透明度。'),
  ('577a0af1-f8e4-405b-a4c1-b437e5f206ea-ex1', '577a0af1-f8e4-405b-a4c1-b437e5f206ea', 'happen', 'What will happen if I press this button?', '如果我按这个按钮会发生什么？'),
  ('577a0af1-f8e4-405b-a4c1-b437e5f206ea-ex2', '577a0af1-f8e4-405b-a4c1-b437e5f206ea', 'happen', 'Investigators are still attempting to determine precisely how the breach was allowed to happen.', '调查人员仍在努力查明这起泄露事件究竟是如何发生的。'),
  ('48f361e5-f52c-4d1c-bc54-300bbbcb44f6-ex1', '48f361e5-f52c-4d1c-bc54-300bbbcb44f6', 'next', 'The next bus comes in ten minutes.', '下一班公交车十分钟后到。'),
  ('48f361e5-f52c-4d1c-bc54-300bbbcb44f6-ex2', '48f361e5-f52c-4d1c-bc54-300bbbcb44f6', 'next', 'The next phase of the project involves rigorous field testing under diverse climatic conditions.', '项目的下一阶段包括在不同气候条件下进行严格的实地测试。'),
  ('afff6809-996e-48cd-8a93-c8a3870083fa-ex1', 'afff6809-996e-48cd-8a93-c8a3870083fa', 'without', 'I can''t see without my glasses.', '不戴眼镜我看不见。'),
  ('afff6809-996e-48cd-8a93-c8a3870083fa-ex2', 'afff6809-996e-48cd-8a93-c8a3870083fa', 'without', 'No structural modifications may be undertaken without the prior written consent of the authority.', '未经主管部门事先书面同意，不得进行任何结构性改动。'),
  ('48b34e23-cb7e-4da6-8b50-b371253a240e-ex1', '48b34e23-cb7e-4da6-8b50-b371253a240e', 'before', 'Wash your hands before dinner.', '晚饭前要洗手。'),
  ('48b34e23-cb7e-4da6-8b50-b371253a240e-ex2', '48b34e23-cb7e-4da6-8b50-b371253a240e', 'before', 'All supporting documentation must be submitted before the application can be formally reviewed.', '必须先提交全部证明文件，申请才能进入正式审核。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('18d33ae2-89b0-4f99-9acb-0734b59fb7ce-ex1', '18d33ae2-89b0-4f99-9acb-0734b59fb7ce', 'large', 'They ordered a large pizza.', '他们点了一份大号披萨。'),
  ('18d33ae2-89b0-4f99-9acb-0734b59fb7ce-ex2', '18d33ae2-89b0-4f99-9acb-0734b59fb7ce', 'large', 'A large proportion of the budget has been earmarked for infrastructure modernization.', '预算中有很大一部分已指定用于基础设施现代化。'),
  ('e44e9222-2f0f-4d90-93c9-16e0e0f5a40e-ex1', 'e44e9222-2f0f-4d90-93c9-16e0e0f5a40e', 'million', 'The city has two million people.', '这座城市有两百万人口。'),
  ('e44e9222-2f0f-4d90-93c9-16e0e0f5a40e-ex2', 'e44e9222-2f0f-4d90-93c9-16e0e0f5a40e', 'million', 'The settlement requires the corporation to pay several hundred million dollars in damages.', '和解协议要求该公司支付数亿美元的赔偿金。'),
  ('337df900-78f7-43de-97c2-0d54516b55d6-ex1', '337df900-78f7-43de-97c2-0d54516b55d6', 'must', 'You must wear a seatbelt.', '你必须系安全带。'),
  ('337df900-78f7-43de-97c2-0d54516b55d6-ex2', '337df900-78f7-43de-97c2-0d54516b55d6', 'must', 'All laboratory personnel must comply strictly with the biosafety protocols at all times.', '所有实验室人员必须时刻严格遵守生物安全规程。'),
  ('d74db796-64ff-48b8-9380-62d10e71d3d6-ex1', 'd74db796-64ff-48b8-9380-62d10e71d3d6', 'home', 'I usually get home at six.', '我通常六点到家。'),
  ('d74db796-64ff-48b8-9380-62d10e71d3d6-ex2', 'd74db796-64ff-48b8-9380-62d10e71d3d6', 'home', 'The program assists elderly residents who wish to receive long-term care at home rather than in institutions.', '该项目帮助希望居家而非在机构接受长期照护的老年居民。'),
  ('d2b75963-abcd-47d9-82df-1310a8898700-ex1', 'd2b75963-abcd-47d9-82df-1310a8898700', 'under', 'The cat is under the table.', '猫在桌子底下。'),
  ('d2b75963-abcd-47d9-82df-1310a8898700-ex2', 'd2b75963-abcd-47d9-82df-1310a8898700', 'under', 'The company is currently under investigation for alleged breaches of environmental regulations.', '该公司目前正因涉嫌违反环境法规而接受调查。'),
  ('7a0db0c1-4fe0-4ed0-9e6c-a64c9c3d6d5c-ex1', '7a0db0c1-4fe0-4ed0-9e6c-a64c9c3d6d5c', 'water', 'Please drink more water.', '请多喝水。'),
  ('7a0db0c1-4fe0-4ed0-9e6c-a64c9c3d6d5c-ex2', '7a0db0c1-4fe0-4ed0-9e6c-a64c9c3d6d5c', 'water', 'Access to clean water remains a critical determinant of public health in developing regions.', '获得清洁用水仍然是发展中地区公共健康的关键决定因素。'),
  ('a4353b76-bc69-4bbf-be83-87fc0f7a7e28-ex1', 'a4353b76-bc69-4bbf-be83-87fc0f7a7e28', 'room', 'My room is on the second floor.', '我的房间在二楼。'),
  ('a4353b76-bc69-4bbf-be83-87fc0f7a7e28-ex2', 'a4353b76-bc69-4bbf-be83-87fc0f7a7e28', 'room', 'The latest findings leave little room for doubt regarding the human contribution to climate change.', '最新研究结果几乎没有为质疑人类对气候变化的影响留下余地。'),
  ('a745536b-a87f-4cca-8d7d-e0de2669e737-ex1', 'a745536b-a87f-4cca-8d7d-e0de2669e737', 'write', 'I write in my diary every night.', '我每晚都写日记。'),
  ('a745536b-a87f-4cca-8d7d-e0de2669e737-ex2', 'a745536b-a87f-4cca-8d7d-e0de2669e737', 'write', 'The commission was instructed to write a comprehensive report detailing its findings and recommendations.', '委员会受命撰写一份详尽阐述其调查结果和建议的综合报告。'),
  ('d349fb23-17b2-4c1e-8eff-6b0558a85f63-ex1', 'd349fb23-17b2-4c1e-8eff-6b0558a85f63', 'mother', 'My mother cooks delicious food.', '我妈妈做的饭很好吃。'),
  ('d349fb23-17b2-4c1e-8eff-6b0558a85f63-ex2', 'd349fb23-17b2-4c1e-8eff-6b0558a85f63', 'mother', 'The legislation guarantees every working mother the right to paid parental leave.', '该立法保障每位职场母亲享有带薪育儿假的权利。'),
  ('e9ec9476-ecda-46e7-b527-d95e9da6d445-ex1', 'e9ec9476-ecda-46e7-b527-d95e9da6d445', 'area', 'This area has many restaurants.', '这个地区有很多餐馆。'),
  ('e9ec9476-ecda-46e7-b527-d95e9da6d445-ex2', 'e9ec9476-ecda-46e7-b527-d95e9da6d445', 'area', 'The contaminated area was cordoned off pending a thorough environmental assessment.', '受污染区域已被封锁，等待进行彻底的环境评估。'),
  ('1766d4c1-dadb-4135-ae18-fa50029be93b-ex1', '1766d4c1-dadb-4135-ae18-fa50029be93b', 'national', 'Today is a national holiday.', '今天是全国性假日。'),
  ('1766d4c1-dadb-4135-ae18-fa50029be93b-ex2', '1766d4c1-dadb-4135-ae18-fa50029be93b', 'national', 'The findings prompted a national debate over the adequacy of existing food safety standards.', '这些发现引发了一场关于现行食品安全标准是否充分的全国性讨论。'),
  ('d6b0753b-9171-4a78-b11b-8fac8ce4b487-ex1', 'd6b0753b-9171-4a78-b11b-8fac8ce4b487', 'money', 'I need to save more money.', '我需要多存点钱。'),
  ('d6b0753b-9171-4a78-b11b-8fac8ce4b487-ex2', 'd6b0753b-9171-4a78-b11b-8fac8ce4b487', 'money', 'The audit revealed that substantial sums of public money had been disbursed without proper authorization.', '审计发现，大量公款在未经适当授权的情况下被支出。'),
  ('d84b198d-9031-4539-abd9-816524993f67-ex1', 'd84b198d-9031-4539-abd9-816524993f67', 'story', 'Grandma told us a funny story.', '奶奶给我们讲了一个有趣的故事。'),
  ('d84b198d-9031-4539-abd9-816524993f67-ex2', 'd84b198d-9031-4539-abd9-816524993f67', 'story', 'The newspaper''s investigative story prompted the resignation of two senior officials.', '这家报纸的调查报道促使两名高级官员辞职。'),
  ('738cec56-c050-4a10-bff8-701d7c96bc03-ex1', '738cec56-c050-4a10-bff8-701d7c96bc03', 'young', 'She is too young to drive.', '她还太小，不能开车。'),
  ('738cec56-c050-4a10-bff8-701d7c96bc03-ex2', '738cec56-c050-4a10-bff8-701d7c96bc03', 'young', 'The foundation supports young researchers whose work shows exceptional scientific promise.', '该基金会资助研究工作展现出非凡科学前景的年轻学者。'),
  ('f41eac78-daf4-4593-8120-544dae3275e0-ex1', 'f41eac78-daf4-4593-8120-544dae3275e0', 'fact', 'That is an interesting fact.', '那是一个有趣的事实。'),
  ('f41eac78-daf4-4593-8120-544dae3275e0-ex2', 'f41eac78-daf4-4593-8120-544dae3275e0', 'fact', 'The fact that the symptoms emerged gradually complicated the initial diagnosis considerably.', '症状逐渐显现这一事实使初步诊断变得相当复杂。'),
  ('73375165-5538-43b0-9400-4393905796f6-ex1', '73375165-5538-43b0-9400-4393905796f6', 'month', 'I will travel to Japan next month.', '我下个月要去日本旅行。'),
  ('73375165-5538-43b0-9400-4393905796f6-ex2', '73375165-5538-43b0-9400-4393905796f6', 'month', 'Within a month of its enactment, the regulation had already transformed industry practices.', '该法规颁布一个月内就已经改变了行业惯例。'),
  ('2bbc58bb-f6db-48a3-9f2f-df2fae4a2f9f-ex1', '2bbc58bb-f6db-48a3-9f2f-df2fae4a2f9f', 'different', 'We come from different cities.', '我们来自不同的城市。'),
  ('2bbc58bb-f6db-48a3-9f2f-df2fae4a2f9f-ex2', '2bbc58bb-f6db-48a3-9f2f-df2fae4a2f9f', 'different', 'The two studies employed fundamentally different methodologies yet arrived at remarkably similar conclusions.', '这两项研究采用了截然不同的方法，却得出了极为相似的结论。'),
  ('ff2d6ea6-fa52-4735-8ce6-ac0571cea751-ex1', 'ff2d6ea6-fa52-4735-8ce6-ac0571cea751', 'lot', 'I have a lot of homework today.', '我今天有很多作业。'),
  ('ff2d6ea6-fa52-4735-8ce6-ac0571cea751-ex2', 'ff2d6ea6-fa52-4735-8ce6-ac0571cea751', 'lot', 'A lot of the criticism directed at the policy stems from misunderstandings about its actual scope.', '针对该政策的许多批评源于对其实际范围的误解。'),
  ('f4729516-43de-4045-b268-7e6e7c868be3-ex1', 'f4729516-43de-4045-b268-7e6e7c868be3', 'study', 'I study English every day.', '我每天学英语。'),
  ('f4729516-43de-4045-b268-7e6e7c868be3-ex2', 'f4729516-43de-4045-b268-7e6e7c868be3', 'study', 'A longitudinal study spanning two decades confirmed the link between diet and cardiovascular health.', '一项跨越二十年的纵向研究证实了饮食与心血管健康之间的联系。'),
  ('0afef4a6-61b4-46d5-8da3-17e73dae5d1d-ex1', '0afef4a6-61b4-46d5-8da3-17e73dae5d1d', 'book', 'This book is really interesting.', '这本书真有意思。'),
  ('0afef4a6-61b4-46d5-8da3-17e73dae5d1d-ex2', '0afef4a6-61b4-46d5-8da3-17e73dae5d1d', 'book', 'Guests are advised to book accommodations well in advance during the peak conference season.', '建议来宾在会议旺季提前预订住宿。'),
  ('37b162c7-96f2-49dc-bef6-ebdbfc214ccf-ex1', '37b162c7-96f2-49dc-bef6-ebdbfc214ccf', 'eye', 'She has beautiful brown eyes.', '她有一双美丽的棕色眼睛。'),
  ('37b162c7-96f2-49dc-bef6-ebdbfc214ccf-ex2', '37b162c7-96f2-49dc-bef6-ebdbfc214ccf', 'eye', 'The regulatory authority is keeping a close eye on speculative activity in the housing market.', '监管机构正密切关注房地产市场的投机活动。'),
  ('c5b740ba-1edb-47f1-a214-204e46aef29f-ex1', 'c5b740ba-1edb-47f1-a214-204e46aef29f', 'job', 'He found a new job last month.', '他上个月找到了一份新工作。'),
  ('c5b740ba-1edb-47f1-a214-204e46aef29f-ex2', 'c5b740ba-1edb-47f1-a214-204e46aef29f', 'job', 'The retraining initiative aims to prepare displaced workers for jobs in emerging industries.', '该再培训计划旨在帮助失业工人胜任新兴行业的工作。'),
  ('a16db9d8-602b-481d-af03-c3adb5331408-ex1', 'a16db9d8-602b-481d-af03-c3adb5331408', 'word', 'What does this word mean?', '这个单词是什么意思？'),
  ('a16db9d8-602b-481d-af03-c3adb5331408-ex2', 'a16db9d8-602b-481d-af03-c3adb5331408', 'word', 'The ambassador chose every word with deliberate care to avoid inflaming diplomatic tensions.', '大使字斟句酌，以免加剧外交紧张局势。'),
  ('b8a1f141-71c8-4cb6-b965-92c393b21e95-ex1', 'b8a1f141-71c8-4cb6-b965-92c393b21e95', 'though', 'It was cold, though the sun was out.', '虽然出太阳了，天还是很冷。'),
  ('b8a1f141-71c8-4cb6-b965-92c393b21e95-ex2', 'b8a1f141-71c8-4cb6-b965-92c393b21e95', 'though', 'Though the evidence was largely circumstantial, the tribunal found it sufficiently compelling.', '尽管证据大多是间接的，法庭仍认为其足够有说服力。'),
  ('b0d4e4a8-e5ac-42e5-8645-5035dfb304d5-ex1', 'b0d4e4a8-e5ac-42e5-8645-5035dfb304d5', 'business', 'He runs a small business.', '他经营着一家小公司。'),
  ('b0d4e4a8-e5ac-42e5-8645-5035dfb304d5-ex2', 'b0d4e4a8-e5ac-42e5-8645-5035dfb304d5', 'business', 'The chamber of commerce warned that excessive regulation could stifle legitimate business activity.', '商会警告说，过度监管可能抑制正当的商业活动。'),
  ('d54178a8-6d4d-4602-89ea-62e01b2d5bf5-ex1', 'd54178a8-6d4d-4602-89ea-62e01b2d5bf5', 'issue', 'Climate change is a serious issue.', '气候变化是一个严重的问题。'),
  ('d54178a8-6d4d-4602-89ea-62e01b2d5bf5-ex2', 'd54178a8-6d4d-4602-89ea-62e01b2d5bf5', 'issue', 'The central bank declined to issue further guidance until the inflation data had been reviewed.', '在通胀数据审核完毕之前，央行拒绝发布进一步的指引。'),
  ('57fc6c79-f888-4af4-95e0-47ffb5f2f026-ex1', '57fc6c79-f888-4af4-95e0-47ffb5f2f026', 'side', 'Please stand on the right side.', '请站在右边。'),
  ('57fc6c79-f888-4af4-95e0-47ffb5f2f026-ex2', '57fc6c79-f888-4af4-95e0-47ffb5f2f026', 'side', 'Both sides of the dispute have agreed to submit to binding international arbitration.', '争端双方已同意接受具有约束力的国际仲裁。'),
  ('23239b62-9e83-477f-94cf-60025245c487-ex1', '23239b62-9e83-477f-94cf-60025245c487', 'kind', 'What kind of music do you like?', '你喜欢哪种音乐？'),
  ('23239b62-9e83-477f-94cf-60025245c487-ex2', '23239b62-9e83-477f-94cf-60025245c487', 'kind', 'This kind of systematic discrimination is expressly prohibited under international human rights law.', '这种系统性歧视为国际人权法所明令禁止。'),
  ('2830dd85-b9e7-4e45-84cd-f25b9f9c416c-ex1', '2830dd85-b9e7-4e45-84cd-f25b9f9c416c', 'four', 'The meeting starts at four o''clock.', '会议四点开始。'),
  ('2830dd85-b9e7-4e45-84cd-f25b9f9c416c-ex2', '2830dd85-b9e7-4e45-84cd-f25b9f9c416c', 'four', 'The framework rests on four foundational principles: transparency, accountability, equity, and sustainability.', '该框架建立在四项基本原则之上：透明、问责、公平与可持续。'),
  ('5311383e-88e6-43d5-81b9-811e4495d0ec-ex1', '5311383e-88e6-43d5-81b9-811e4495d0ec', 'head', 'My head hurts a little.', '我的头有点疼。'),
  ('5311383e-88e6-43d5-81b9-811e4495d0ec-ex2', '5311383e-88e6-43d5-81b9-811e4495d0ec', 'head', 'She was appointed head of the delegation negotiating the multilateral trade agreement.', '她被任命为多边贸易协定谈判代表团团长。'),
  ('c55f59aa-77a2-4500-95d6-ca777b3b225c-ex1', 'c55f59aa-77a2-4500-95d6-ca777b3b225c', 'far', 'The station is not far from here.', '车站离这里不远。'),
  ('c55f59aa-77a2-4500-95d6-ca777b3b225c-ex2', 'c55f59aa-77a2-4500-95d6-ca777b3b225c', 'far', 'The consequences of the policy have extended far beyond what its architects originally envisioned.', '该政策的影响已远远超出其设计者最初的设想。'),
  ('257c8cfe-cfa0-432b-b889-747631521aca-ex1', '257c8cfe-cfa0-432b-b889-747631521aca', 'black', 'She wore a black dress.', '她穿了一条黑色连衣裙。'),
  ('257c8cfe-cfa0-432b-b889-747631521aca-ex2', '257c8cfe-cfa0-432b-b889-747631521aca', 'black', 'The documentary chronicles the contributions of Black scientists whose work was long overlooked.', '这部纪录片记录了那些长期被忽视的黑人科学家的贡献。'),
  ('7b3828b9-dc13-44e2-aa61-f72ff2380a56-ex1', '7b3828b9-dc13-44e2-aa61-f72ff2380a56', 'long', 'The movie was three hours long.', '那部电影长达三个小时。'),
  ('7b3828b9-dc13-44e2-aa61-f72ff2380a56-ex2', '7b3828b9-dc13-44e2-aa61-f72ff2380a56', 'long', 'The reforms reflect a long overdue recognition that the existing framework had become obsolete.', '这些改革反映出人们终于认识到现有框架早已过时。'),
  ('0ef129c6-a514-4ab2-9d5f-3f493e4b0367-ex1', '0ef129c6-a514-4ab2-9d5f-3f493e4b0367', 'both', 'Both of my parents are teachers.', '我父母都是老师。'),
  ('0ef129c6-a514-4ab2-9d5f-3f493e4b0367-ex2', '0ef129c6-a514-4ab2-9d5f-3f493e4b0367', 'both', 'The agreement obliges both signatories to reduce tariffs on agricultural commodities progressively.', '该协议要求缔约双方逐步降低农产品关税。'),
  ('d087f8a5-04c3-420c-b5ab-bf994f10b22a-ex1', 'd087f8a5-04c3-420c-b5ab-bf994f10b22a', 'little', 'There is little milk left.', '牛奶剩得不多了。'),
  ('d087f8a5-04c3-420c-b5ab-bf994f10b22a-ex2', 'd087f8a5-04c3-420c-b5ab-bf994f10b22a', 'little', 'Remarkably little attention has been devoted to the long-term social costs of automation.', '自动化的长期社会成本所受到的关注少得惊人。'),
  ('0ae8b313-3f9d-4173-a54c-8361482cc0ec-ex1', '0ae8b313-3f9d-4173-a54c-8361482cc0ec', 'house', 'They bought a house near the school.', '他们在学校附近买了一栋房子。'),
  ('0ae8b313-3f9d-4173-a54c-8361482cc0ec-ex2', '0ae8b313-3f9d-4173-a54c-8361482cc0ec', 'house', 'The lower house of parliament approved the amendment by an overwhelming majority.', '议会下院以压倒性多数通过了该修正案。'),
  ('1d50878d-d133-4121-a9ca-5716e5d7884e-ex1', '1d50878d-d133-4121-a9ca-5716e5d7884e', 'yes', 'Yes, I would love some coffee.', '好的，我想来点咖啡。'),
  ('1d50878d-d133-4121-a9ca-5716e5d7884e-ex2', '1d50878d-d133-4121-a9ca-5716e5d7884e', 'yes', 'A clear yes from the regulatory authority is required before the trial may proceed.', '必须得到监管机构的明确批准，试验方可进行。'),
  ('65138022-c07f-4d61-85c9-efe4738444a4-ex1', '65138022-c07f-4d61-85c9-efe4738444a4', 'since', 'I have lived here since 2010.', '我从2010年起就住在这里。'),
  ('65138022-c07f-4d61-85c9-efe4738444a4-ex2', '65138022-c07f-4d61-85c9-efe4738444a4', 'since', 'Since the publication of the landmark study, screening practices have changed substantially worldwide.', '自那项里程碑式研究发表以来，世界各地的筛查方式发生了重大变化。'),
  ('aeaef7d0-dfc1-44cf-bce5-93c7599e2a62-ex1', 'aeaef7d0-dfc1-44cf-bce5-93c7599e2a62', 'provide', 'This hotel provides free breakfast.', '这家酒店提供免费早餐。'),
  ('aeaef7d0-dfc1-44cf-bce5-93c7599e2a62-ex2', 'aeaef7d0-dfc1-44cf-bce5-93c7599e2a62', 'provide', 'The statute obliges employers to provide a safe working environment for all personnel.', '该法规要求雇主为全体员工提供安全的工作环境。'),
  ('3e0aff35-ec66-4920-9086-ec5fe00595b9-ex1', '3e0aff35-ec66-4920-9086-ec5fe00595b9', 'service', 'The service at this restaurant is great.', '这家餐厅的服务很棒。'),
  ('3e0aff35-ec66-4920-9086-ec5fe00595b9-ex2', '3e0aff35-ec66-4920-9086-ec5fe00595b9', 'service', 'The agency was commended for its distinguished service to communities affected by the disaster.', '该机构因向受灾社区提供卓越服务而受到表彰。'),
  ('06e38c6d-d139-4a39-b652-976b36885cf0-ex1', '06e38c6d-d139-4a39-b652-976b36885cf0', 'around', 'We walked around the lake.', '我们绕着湖走了一圈。'),
  ('06e38c6d-d139-4a39-b652-976b36885cf0-ex2', '06e38c6d-d139-4a39-b652-976b36885cf0', 'around', 'Scholars from around the world convened to assess the implications of the discovery.', '来自世界各地的学者齐聚一堂，评估这一发现的意义。'),
  ('2b9aca6b-8bea-4056-b881-918dbd860c05-ex1', '2b9aca6b-8bea-4056-b881-918dbd860c05', 'friend', 'She is my best friend.', '她是我最好的朋友。'),
  ('2b9aca6b-8bea-4056-b881-918dbd860c05-ex2', '2b9aca6b-8bea-4056-b881-918dbd860c05', 'friend', 'The two nations have remained steadfast friends through decades of shifting geopolitical alignments.', '在数十年地缘政治格局变迁中，两国始终是坚定的朋友。'),
  ('83231b11-dc8d-4039-b702-63ca5caba4bb-ex1', '83231b11-dc8d-4039-b702-63ca5caba4bb', 'important', 'Sleep is important for your health.', '睡眠对健康很重要。'),
  ('83231b11-dc8d-4039-b702-63ca5caba4bb-ex2', '83231b11-dc8d-4039-b702-63ca5caba4bb', 'important', 'The ruling establishes an important precedent for the protection of digital privacy rights.', '这一裁决为数字隐私权的保护确立了重要先例。'),
  ('0633330e-d977-46e9-bf47-e5c102e413f1-ex1', '0633330e-d977-46e9-bf47-e5c102e413f1', 'father', 'My father taught me to ride a bike.', '我父亲教我骑自行车。'),
  ('0633330e-d977-46e9-bf47-e5c102e413f1-ex2', '0633330e-d977-46e9-bf47-e5c102e413f1', 'father', 'He is widely regarded as the father of modern computational linguistics.', '他被广泛誉为现代计算语言学之父。'),
  ('32374d5c-25fd-4f80-97da-ecf987073491-ex1', '32374d5c-25fd-4f80-97da-ecf987073491', 'sit', 'Please sit next to me.', '请坐在我旁边。'),
  ('32374d5c-25fd-4f80-97da-ecf987073491-ex2', '32374d5c-25fd-4f80-97da-ecf987073491', 'sit', 'Three retired judges will sit on the panel reviewing allegations of prosecutorial misconduct.', '三位退休法官将出任审查检方不当行为指控的小组成员。'),
  ('b87cdd72-bdfb-49ad-b700-2eb5ac947845-ex1', 'b87cdd72-bdfb-49ad-b700-2eb5ac947845', 'away', 'The beach is ten minutes away.', '海滩离这里十分钟路程。'),
  ('b87cdd72-bdfb-49ad-b700-2eb5ac947845-ex2', 'b87cdd72-bdfb-49ad-b700-2eb5ac947845', 'away', 'The committee resolved to move away from fossil fuel investments over the coming decade.', '委员会决定在未来十年逐步退出化石燃料投资。'),
  ('a10e3f6b-9bcc-4259-8384-81a1cea19da3-ex1', 'a10e3f6b-9bcc-4259-8384-81a1cea19da3', 'until', 'Wait here until I come back.', '在这里等到我回来。'),
  ('a10e3f6b-9bcc-4259-8384-81a1cea19da3-ex2', 'a10e3f6b-9bcc-4259-8384-81a1cea19da3', 'until', 'The injunction remains in force until the appellate court issues its final determination.', '该禁令在上诉法院作出最终裁定之前持续有效。'),
  ('dd6f01fb-1579-43e2-8c2b-3fa96078f74f-ex1', 'dd6f01fb-1579-43e2-8c2b-3fa96078f74f', 'power', 'The storm cut off our power.', '暴风雨把我们家的电断了。'),
  ('dd6f01fb-1579-43e2-8c2b-3fa96078f74f-ex2', 'dd6f01fb-1579-43e2-8c2b-3fa96078f74f', 'power', 'The constitution carefully circumscribes the power of the executive to act without legislative consent.', '宪法严格限制行政机关在未经立法机关同意时采取行动的权力。'),
  ('436cb3d5-f1c4-4f0e-9715-a198fa2639dd-ex1', '436cb3d5-f1c4-4f0e-9715-a198fa2639dd', 'hour', 'The meeting lasted two hours.', '会议持续了两个小时。'),
  ('436cb3d5-f1c4-4f0e-9715-a198fa2639dd-ex2', '436cb3d5-f1c4-4f0e-9715-a198fa2639dd', 'hour', 'Emergency responders arrived within the hour, a response time that undoubtedly saved lives.', '应急人员在一小时内赶到，这一响应速度无疑挽救了生命。'),
  ('a3e23140-775c-4181-a520-8e3fffd25696-ex1', 'a3e23140-775c-4181-a520-8e3fffd25696', 'game', 'Let''s play a card game.', '我们玩纸牌游戏吧。'),
  ('a3e23140-775c-4181-a520-8e3fffd25696-ex2', 'a3e23140-775c-4181-a520-8e3fffd25696', 'game', 'Analysts described the merger as a high-stakes game in which neither party could afford to retreat.', '分析人士将这次合并描述为一场双方都输不起的高风险博弈。'),
  ('217ea949-5472-4ab9-9921-fc1523e13cb5-ex1', '217ea949-5472-4ab9-9921-fc1523e13cb5', 'often', 'I often go jogging in the morning.', '我经常早上去慢跑。'),
  ('217ea949-5472-4ab9-9921-fc1523e13cb5-ex2', '217ea949-5472-4ab9-9921-fc1523e13cb5', 'often', 'Structural inequities often persist long after the discriminatory statutes themselves have been repealed.', '歧视性法律本身被废除之后，结构性不平等往往仍会长期存在。'),
  ('6f3541c8-5a9f-447e-bd00-0ee3d01f765c-ex1', '6f3541c8-5a9f-447e-bd00-0ee3d01f765c', 'yet', 'The bus has not arrived yet.', '公交车还没有到。'),
  ('6f3541c8-5a9f-447e-bd00-0ee3d01f765c-ex2', '6f3541c8-5a9f-447e-bd00-0ee3d01f765c', 'yet', 'The technology is promising, yet formidable obstacles remain before commercial deployment becomes feasible.', '这项技术前景广阔，但在商业化应用可行之前仍存在巨大障碍。'),
  ('dd9f42d0-dea4-4c1e-9ae4-d0b3da039df8-ex1', 'dd9f42d0-dea4-4c1e-9ae4-d0b3da039df8', 'line', 'Please wait in line.', '请排队等候。'),
  ('dd9f42d0-dea4-4c1e-9ae4-d0b3da039df8-ex2', 'dd9f42d0-dea4-4c1e-9ae4-d0b3da039df8', 'line', 'The verdict drew a clear line between protected expression and incitement to violence.', '该判决在受保护的言论与煽动暴力之间划出了清晰的界限。'),
  ('91c686d1-5e2b-44b4-a2dd-8c8def28c12f-ex1', '91c686d1-5e2b-44b4-a2dd-8c8def28c12f', 'political', 'He is not interested in political news.', '他对政治新闻不感兴趣。'),
  ('91c686d1-5e2b-44b4-a2dd-8c8def28c12f-ex2', '91c686d1-5e2b-44b4-a2dd-8c8def28c12f', 'political', 'The crisis exposed deep political divisions that decades of prosperity had merely concealed.', '这场危机暴露了数十年繁荣所掩盖的深刻政治分歧。'),
  ('df819fc5-f0bd-410c-a196-cca948203a62-ex1', 'df819fc5-f0bd-410c-a196-cca948203a62', 'end', 'The movie has a happy end.', '这部电影有一个圆满的结局。'),
  ('df819fc5-f0bd-410c-a196-cca948203a62-ex2', 'df819fc5-f0bd-410c-a196-cca948203a62', 'end', 'Negotiations continued until the very end of the summit without producing a binding agreement.', '谈判一直持续到峰会结束，却未能达成具有约束力的协议。'),
  ('38be202d-9047-4a09-b3dd-a9171c7cd341-ex1', '38be202d-9047-4a09-b3dd-a9171c7cd341', 'among', 'She is popular among her classmates.', '她在同学中很受欢迎。'),
  ('38be202d-9047-4a09-b3dd-a9171c7cd341-ex2', '38be202d-9047-4a09-b3dd-a9171c7cd341', 'among', 'Among the most consequential provisions is one requiring full disclosure of beneficial ownership.', '影响最深远的条款之一是要求全面披露实际受益所有权。'),
  ('6e13ac24-73f5-4cc7-abd9-fc6191d11bb9-ex1', '6e13ac24-73f5-4cc7-abd9-fc6191d11bb9', 'ever', 'Have you ever been to Paris?', '你去过巴黎吗？'),
  ('6e13ac24-73f5-4cc7-abd9-fc6191d11bb9-ex2', '6e13ac24-73f5-4cc7-abd9-fc6191d11bb9', 'ever', 'The summit produced the most ambitious climate commitments ever endorsed by the assembled nations.', '此次峰会产生了与会各国有史以来认可的最具雄心的气候承诺。'),
  ('cce7ff94-5941-485c-8edd-6102694943d8-ex1', 'cce7ff94-5941-485c-8edd-6102694943d8', 'stand', 'Please stand by the door.', '请站在门边。'),
  ('cce7ff94-5941-485c-8edd-6102694943d8-ex2', 'cce7ff94-5941-485c-8edd-6102694943d8', 'stand', 'The court''s ruling will stand unless overturned by a higher judicial authority.', '除非被更高司法机关推翻，法院的裁决将继续有效。'),
  ('cc9cba45-9f0e-49f0-aa06-4ffca4caf249-ex1', 'cc9cba45-9f0e-49f0-aa06-4ffca4caf249', 'bad', 'The weather is bad today.', '今天天气很糟。'),
  ('cc9cba45-9f0e-49f0-aa06-4ffca4caf249-ex2', 'cc9cba45-9f0e-49f0-aa06-4ffca4caf249', 'bad', 'The audit attributed the losses to bad governance rather than unfavorable market conditions.', '审计将亏损归因于治理不善，而非不利的市场环境。'),
  ('4bd6625e-8c68-4ed6-92d8-bd40ede246db-ex1', '4bd6625e-8c68-4ed6-92d8-bd40ede246db', 'lose', 'Don''t lose your keys again.', '别再把钥匙弄丢了。'),
  ('4bd6625e-8c68-4ed6-92d8-bd40ede246db-ex2', '4bd6625e-8c68-4ed6-92d8-bd40ede246db', 'lose', 'Without decisive intervention, the region stands to lose much of its remaining biodiversity.', '如果不果断干预，该地区现存的生物多样性恐将大量丧失。'),
  ('6771910c-cdbf-4e49-9db6-8dcdcb6b99f2-ex1', '6771910c-cdbf-4e49-9db6-8dcdcb6b99f2', 'however', 'I was tired; however, I kept working.', '我很累，但还是继续工作。'),
  ('6771910c-cdbf-4e49-9db6-8dcdcb6b99f2-ex2', '6771910c-cdbf-4e49-9db6-8dcdcb6b99f2', 'however', 'The proposal enjoys broad support; however, its fiscal sustainability remains open to question.', '该提案获得广泛支持；然而，其财政可持续性仍有待商榷。'),
  ('90094d3b-7556-4571-8445-9af88b5cdaba-ex1', '90094d3b-7556-4571-8445-9af88b5cdaba', 'member', 'He is a member of the chess club.', '他是国际象棋俱乐部的成员。'),
  ('90094d3b-7556-4571-8445-9af88b5cdaba-ex2', '90094d3b-7556-4571-8445-9af88b5cdaba', 'member', 'Each member state must transpose the directive into national law within two years.', '每个成员国必须在两年内将该指令转化为国内法。'),
  ('6ab58960-431c-4fe2-b509-876ff0ce31ee-ex1', '6ab58960-431c-4fe2-b509-876ff0ce31ee', 'pay', 'I will pay for dinner tonight.', '今晚的晚餐我来付钱。'),
  ('6ab58960-431c-4fe2-b509-876ff0ce31ee-ex2', '6ab58960-431c-4fe2-b509-876ff0ce31ee', 'pay', 'The tribunal ordered the company to pay substantial compensation to the affected residents.', '法庭责令该公司向受影响居民支付巨额赔偿。'),
  ('bdb65373-907a-473e-b4cd-ae10b0a4b23d-ex1', 'bdb65373-907a-473e-b4cd-ae10b0a4b23d', 'law', 'Everyone must obey the law.', '人人都必须遵守法律。'),
  ('bdb65373-907a-473e-b4cd-ae10b0a4b23d-ex2', 'bdb65373-907a-473e-b4cd-ae10b0a4b23d', 'law', 'The proposed law would impose stringent disclosure requirements on political advertising.', '拟议的法律将对政治广告施加严格的信息披露要求。'),
  ('bcc34c4c-08cb-4a15-b37f-d75aa90f27da-ex1', 'bcc34c4c-08cb-4a15-b37f-d75aa90f27da', 'meet', 'Let''s meet at the coffee shop.', '我们在咖啡店见面吧。'),
  ('bcc34c4c-08cb-4a15-b37f-d75aa90f27da-ex2', 'bcc34c4c-08cb-4a15-b37f-d75aa90f27da', 'meet', 'The infrastructure plan was designed to meet the projected demands of a rapidly growing population.', '该基础设施规划旨在满足快速增长人口的预期需求。'),
  ('85eb0874-0563-4e1e-be94-aef98715691f-ex1', '85eb0874-0563-4e1e-be94-aef98715691f', 'car', 'My car is parked outside.', '我的车停在外面。'),
  ('85eb0874-0563-4e1e-be94-aef98715691f-ex2', '85eb0874-0563-4e1e-be94-aef98715691f', 'car', 'Stricter emission standards have compelled car manufacturers to accelerate their transition to electrification.', '更严格的排放标准迫使汽车制造商加快向电动化转型。'),
  ('7ae1f6a3-74c8-4542-928e-c24c33bc0f16-ex1', '7ae1f6a3-74c8-4542-928e-c24c33bc0f16', 'city', 'Beijing is a very big city.', '北京是一座非常大的城市。'),
  ('7ae1f6a3-74c8-4542-928e-c24c33bc0f16-ex2', '7ae1f6a3-74c8-4542-928e-c24c33bc0f16', 'city', 'The city council adopted an ambitious plan to achieve carbon neutrality by mid-century.', '市议会通过了一项到本世纪中叶实现碳中和的宏伟计划。'),
  ('7b536e66-6525-4863-8902-8445fc52ab8f-ex1', '7b536e66-6525-4863-8902-8445fc52ab8f', 'almost', 'It''s almost time for lunch.', '快到午饭时间了。'),
  ('7b536e66-6525-4863-8902-8445fc52ab8f-ex2', '7b536e66-6525-4863-8902-8445fc52ab8f', 'almost', 'Almost every indicator suggests that the recovery has been more robust than initially forecast.', '几乎所有指标都表明，这轮复苏比最初预测的更为强劲。'),
  ('cc3d687b-1641-4818-bbc0-10087fe63c6c-ex1', 'cc3d687b-1641-4818-bbc0-10087fe63c6c', 'include', 'The price includes breakfast.', '这个价格包含早餐。'),
  ('cc3d687b-1641-4818-bbc0-10087fe63c6c-ex2', 'cc3d687b-1641-4818-bbc0-10087fe63c6c', 'include', 'The revised curriculum will include mandatory instruction in digital literacy and critical thinking.', '修订后的课程将包含数字素养与批判性思维的必修内容。'),
  ('316d3660-9769-4065-b0a0-b37f4395d257-ex1', '316d3660-9769-4065-b0a0-b37f4395d257', 'continue', 'Please continue with your story.', '请继续讲你的故事。'),
  ('316d3660-9769-4065-b0a0-b37f4395d257-ex2', '316d3660-9769-4065-b0a0-b37f4395d257', 'continue', 'The parties agreed to continue negotiations despite the considerable differences that remain.', '尽管仍存在重大分歧，各方同意继续谈判。'),
  ('cf1ef21a-7900-47d8-8188-b20e8d04d5a9-ex1', 'cf1ef21a-7900-47d8-8188-b20e8d04d5a9', 'set', 'I set my alarm for six o''clock.', '我把闹钟定在六点。'),
  ('cf1ef21a-7900-47d8-8188-b20e8d04d5a9-ex2', 'cf1ef21a-7900-47d8-8188-b20e8d04d5a9', 'set', 'The agreement sets binding targets for emission reductions across all major industrial sectors.', '该协议为所有主要工业部门设定了具有约束力的减排目标。'),
  ('def4c065-e853-4dbb-a6fa-00e74f4b1f6b-ex1', 'def4c065-e853-4dbb-a6fa-00e74f4b1f6b', 'later', 'I will call you later.', '我晚点给你打电话。'),
  ('def4c065-e853-4dbb-a6fa-00e74f4b1f6b-ex2', 'def4c065-e853-4dbb-a6fa-00e74f4b1f6b', 'later', 'The full implications of the ruling would become apparent only years later.', '该裁决的全部影响直到数年之后才显现出来。'),
  ('59acd3a6-18ec-4823-b334-26db0b31600d-ex1', '59acd3a6-18ec-4823-b334-26db0b31600d', 'community', 'Our community has a new library.', '我们社区有了一座新图书馆。'),
  ('59acd3a6-18ec-4823-b334-26db0b31600d-ex2', '59acd3a6-18ec-4823-b334-26db0b31600d', 'community', 'The scientific community responded to the controversial findings with calls for independent replication.', '科学界对这一有争议的发现作出回应，呼吁进行独立的重复验证。'),
  ('177088bc-3ef7-4612-b358-9c9a02360ddb-ex1', '177088bc-3ef7-4612-b358-9c9a02360ddb', 'name', 'What is your name?', '你叫什么名字？'),
  ('177088bc-3ef7-4612-b358-9c9a02360ddb-ex2', '177088bc-3ef7-4612-b358-9c9a02360ddb', 'name', 'The institute was renamed in honor of the philanthropist whose name had become synonymous with medical research.', '该研究所更名以纪念这位名字已成为医学研究代名词的慈善家。'),
  ('aaf62b36-bc6c-46d5-85c5-a41a0b613e40-ex1', 'aaf62b36-bc6c-46d5-85c5-a41a0b613e40', 'five', 'The store closes at five.', '商店五点关门。'),
  ('aaf62b36-bc6c-46d5-85c5-a41a0b613e40-ex2', 'aaf62b36-bc6c-46d5-85c5-a41a0b613e40', 'five', 'The strategic plan identifies five priority areas for investment over the coming decade.', '战略规划确定了未来十年五个优先投资领域。'),
  ('4f2c5f95-1746-419d-b8cd-40fef619f7e1-ex1', '4f2c5f95-1746-419d-b8cd-40fef619f7e1', 'once', 'I visit my grandparents once a week.', '我每周看望祖父母一次。'),
  ('4f2c5f95-1746-419d-b8cd-40fef619f7e1-ex2', '4f2c5f95-1746-419d-b8cd-40fef619f7e1', 'once', 'Once the legislation takes effect, all listed companies must comply with the new disclosure regime.', '立法一经生效，所有上市公司都必须遵守新的披露制度。'),
  ('2ce5950b-5b45-4630-a2f5-7bf5107c26c8-ex1', '2ce5950b-5b45-4630-a2f5-7bf5107c26c8', 'white', 'She lives in the white house on the corner.', '她住在街角那栋白色的房子里。'),
  ('2ce5950b-5b45-4630-a2f5-7bf5107c26c8-ex2', '2ce5950b-5b45-4630-a2f5-7bf5107c26c8', 'white', 'The report documents persistent disparities in outcomes between white and minority applicants.', '报告记录了白人申请者与少数族裔申请者之间长期存在的结果差异。'),
  ('3124aef7-45fc-44f2-8211-4cae11745619-ex1', '3124aef7-45fc-44f2-8211-4cae11745619', 'least', 'At least we tried our best.', '至少我们尽力了。'),
  ('3124aef7-45fc-44f2-8211-4cae11745619-ex2', '3124aef7-45fc-44f2-8211-4cae11745619', 'least', 'The burden of the new tariffs falls most heavily on those least equipped to absorb additional costs.', '新关税的负担最沉重地落在了最无力承受额外成本的群体身上。'),
  ('80d49c39-991f-4424-b7cd-d78825e6defb-ex1', '80d49c39-991f-4424-b7cd-d78825e6defb', 'president', 'The president gave a speech today.', '总统今天发表了讲话。'),
  ('80d49c39-991f-4424-b7cd-d78825e6defb-ex2', '80d49c39-991f-4424-b7cd-d78825e6defb', 'president', 'The university''s president announced an unprecedented expansion of need-based financial aid.', '该大学校长宣布了一项空前规模的助学金扩充计划。'),
  ('3848d8d8-b613-457b-be9b-0bb01c8bd7f5-ex1', '3848d8d8-b613-457b-be9b-0bb01c8bd7f5', 'learn', 'I want to learn how to swim.', '我想学游泳。'),
  ('3848d8d8-b613-457b-be9b-0bb01c8bd7f5-ex2', '3848d8d8-b613-457b-be9b-0bb01c8bd7f5', 'learn', 'Policymakers must learn from the failures of previous interventions before designing new programs.', '政策制定者在设计新项目之前，必须汲取以往干预措施失败的教训。'),
  ('99ef919d-d020-4c50-a46e-cc9b770627cc-ex1', '99ef919d-d020-4c50-a46e-cc9b770627cc', 'real', 'Is this a real diamond?', '这是真钻石吗？'),
  ('99ef919d-d020-4c50-a46e-cc9b770627cc-ex2', '99ef919d-d020-4c50-a46e-cc9b770627cc', 'real', 'The real challenge lies not in drafting regulations but in ensuring their consistent enforcement.', '真正的挑战不在于起草法规，而在于确保其得到一以贯之的执行。'),
  ('f50908c1-3ea6-4fdc-849d-dbd40d7b6b55-ex1', 'f50908c1-3ea6-4fdc-849d-dbd40d7b6b55', 'change', 'I need to change my clothes.', '我需要换衣服。'),
  ('f50908c1-3ea6-4fdc-849d-dbd40d7b6b55-ex2', 'f50908c1-3ea6-4fdc-849d-dbd40d7b6b55', 'change', 'The demographic change sweeping the region will reshape labor markets for generations to come.', '席卷该地区的人口结构变化将在未来几代人的时间里重塑劳动力市场。'),
  ('513629b2-ea6e-48d7-a982-1264c94c7c0d-ex1', '513629b2-ea6e-48d7-a982-1264c94c7c0d', 'team', 'Our team won the game!', '我们队赢了比赛！'),
  ('513629b2-ea6e-48d7-a982-1264c94c7c0d-ex2', '513629b2-ea6e-48d7-a982-1264c94c7c0d', 'team', 'A multidisciplinary team of specialists was assembled to oversee the complex restoration project.', '一支多学科专家团队受命监督这项复杂的修复工程。'),
  ('d518ddac-fd82-44b0-bc47-e79f947c14ad-ex1', 'd518ddac-fd82-44b0-bc47-e79f947c14ad', 'minute', 'The bus leaves in ten minutes.', '公交车十分钟后发车。'),
  ('d518ddac-fd82-44b0-bc47-e79f947c14ad-ex2', 'd518ddac-fd82-44b0-bc47-e79f947c14ad', 'minute', 'The secretary circulated the minutes of the previous meeting for formal approval.', '秘书分发了上次会议的记录以供正式批准。'),
  ('ffc624f9-974f-4eaa-9cf5-70c39cc7829b-ex1', 'ffc624f9-974f-4eaa-9cf5-70c39cc7829b', 'best', 'This is the best cake I have ever had.', '这是我吃过的最好吃的蛋糕。'),
  ('ffc624f9-974f-4eaa-9cf5-70c39cc7829b-ex2', 'ffc624f9-974f-4eaa-9cf5-70c39cc7829b', 'best', 'The committee concluded that the proposed approach represented the best available compromise.', '委员会认定，拟议方案是现有条件下最佳的折中办法。'),
  ('81875ff1-8d06-4352-bfd8-6ef1027b9d99-ex1', '81875ff1-8d06-4352-bfd8-6ef1027b9d99', 'several', 'I have read this book several times.', '这本书我读过好几遍了。'),
  ('81875ff1-8d06-4352-bfd8-6ef1027b9d99-ex2', '81875ff1-8d06-4352-bfd8-6ef1027b9d99', 'several', 'Several independent laboratories have since corroborated the original experimental findings.', '此后，多家独立实验室证实了最初的实验结果。'),
  ('b0fdaeea-18d4-4f9d-b0be-b537299b2f7b-ex1', 'b0fdaeea-18d4-4f9d-b0be-b537299b2f7b', 'idea', 'That''s a great idea!', '那真是个好主意！'),
  ('b0fdaeea-18d4-4f9d-b0be-b537299b2f7b-ex2', 'b0fdaeea-18d4-4f9d-b0be-b537299b2f7b', 'idea', 'The idea that markets invariably self-correct has been challenged by successive financial crises.', '市场总能自我修正的观念已接连受到历次金融危机的挑战。'),
  ('8b789dca-831a-41c5-88cf-cc13d24550a7-ex1', '8b789dca-831a-41c5-88cf-cc13d24550a7', 'kid', 'The kids are playing outside.', '孩子们正在外面玩。'),
  ('8b789dca-831a-41c5-88cf-cc13d24550a7-ex2', '8b789dca-831a-41c5-88cf-cc13d24550a7', 'kid', 'The initiative provides every kid in the district with access to free after-school tutoring.', '该计划让本区每个孩子都能获得免费的课后辅导。'),
  ('920f0750-e386-4888-aae7-d2aed8bb0591-ex1', '920f0750-e386-4888-aae7-d2aed8bb0591', 'body', 'Exercise is good for your body.', '锻炼对身体有好处。'),
  ('920f0750-e386-4888-aae7-d2aed8bb0591-ex2', '920f0750-e386-4888-aae7-d2aed8bb0591', 'body', 'The advisory body issued a unanimous recommendation urging immediate regulatory action.', '该咨询机构一致建议立即采取监管行动。'),
  ('9241aa94-7f4c-4f9f-81c9-f7544b58ad49-ex1', '9241aa94-7f4c-4f9f-81c9-f7544b58ad49', 'information', 'Where can I find more information?', '我在哪里能找到更多信息？'),
  ('9241aa94-7f4c-4f9f-81c9-f7544b58ad49-ex2', '9241aa94-7f4c-4f9f-81c9-f7544b58ad49', 'information', 'The act establishes strict penalties for the unauthorized disclosure of classified information.', '该法案对未经授权泄露机密信息的行为规定了严厉的处罚。'),
  ('8bfde240-7324-4a65-b181-03ab28042076-ex1', '8bfde240-7324-4a65-b181-03ab28042076', 'nothing', 'There is nothing in the box.', '盒子里什么都没有。'),
  ('8bfde240-7324-4a65-b181-03ab28042076-ex2', '8bfde240-7324-4a65-b181-03ab28042076', 'nothing', 'Nothing in the contract obliges the supplier to absorb costs arising from regulatory changes.', '合同中没有任何条款要求供应商承担因法规变化产生的成本。'),
  ('17814870-c93f-4e27-91b5-b79806e7416d-ex1', '17814870-c93f-4e27-91b5-b79806e7416d', 'ago', 'I moved here two years ago.', '我两年前搬到这里。'),
  ('17814870-c93f-4e27-91b5-b79806e7416d-ex2', '17814870-c93f-4e27-91b5-b79806e7416d', 'ago', 'Decades ago, few could have anticipated the profound social transformations wrought by the internet.', '几十年前，很少有人能预见互联网带来的深刻社会变革。'),
  ('49206e2c-a0f8-4ca6-9816-acce3e3301f8-ex1', '49206e2c-a0f8-4ca6-9816-acce3e3301f8', 'lead', 'She will lead the meeting today.', '今天她来主持会议。'),
  ('49206e2c-a0f8-4ca6-9816-acce3e3301f8-ex2', '49206e2c-a0f8-4ca6-9816-acce3e3301f8', 'lead', 'Prolonged exposure to lead, even at low concentrations, can impair cognitive development in children.', '长期接触铅，即使浓度很低，也会损害儿童的认知发育。'),
  ('fab470ed-eff5-4541-946c-2a7f9b5e8e73-ex1', 'fab470ed-eff5-4541-946c-2a7f9b5e8e73', 'social', 'She has a busy social life.', '她的社交生活很丰富。'),
  ('fab470ed-eff5-4541-946c-2a7f9b5e8e73-ex2', 'fab470ed-eff5-4541-946c-2a7f9b5e8e73', 'social', 'The reforms seek to strengthen the social safety net for the most vulnerable households.', '这些改革旨在加强针对最弱势家庭的社会保障体系。'),
  ('48043cb8-881a-4880-9ff5-87a4c22479f3-ex1', '48043cb8-881a-4880-9ff5-87a4c22479f3', 'understand', 'Do you understand the question?', '你明白这个问题吗？'),
  ('48043cb8-881a-4880-9ff5-87a4c22479f3-ex2', '48043cb8-881a-4880-9ff5-87a4c22479f3', 'understand', 'To understand the crisis fully, one must examine the regulatory failures that preceded it.', '要全面理解这场危机，必须审视此前的监管失灵。'),
  ('2f712b8c-d365-4939-8286-a13bfcd1edc3-ex1', '2f712b8c-d365-4939-8286-a13bfcd1edc3', 'whether', 'I don''t know whether he will come.', '我不知道他会不会来。'),
  ('2f712b8c-d365-4939-8286-a13bfcd1edc3-ex2', '2f712b8c-d365-4939-8286-a13bfcd1edc3', 'whether', 'The court must determine whether the statute infringes upon constitutionally protected liberties.', '法院必须裁定该法规是否侵犯了宪法保护的自由。'),
  ('344d8a57-efcf-4503-a765-b14b399681b9-ex1', '344d8a57-efcf-4503-a765-b14b399681b9', 'watch', 'We watch TV after dinner.', '我们晚饭后看电视。'),
  ('344d8a57-efcf-4503-a765-b14b399681b9-ex2', '344d8a57-efcf-4503-a765-b14b399681b9', 'watch', 'International observers will watch the election closely for any signs of irregularity.', '国际观察员将密切关注此次选举，留意任何违规迹象。'),
  ('3b75b1ed-b002-4c73-a319-f108e53ca87b-ex1', '3b75b1ed-b002-4c73-a319-f108e53ca87b', 'together', 'We had dinner together last night.', '我们昨晚一起吃了晚饭。'),
  ('3b75b1ed-b002-4c73-a319-f108e53ca87b-ex2', '3b75b1ed-b002-4c73-a319-f108e53ca87b', 'together', 'The crisis brought together former adversaries in an unprecedented coalition of cooperation.', '这场危机使昔日的对手走到一起，结成了前所未有的合作联盟。'),
  ('f7308b67-77e9-4605-a934-08619a527fbc-ex1', 'f7308b67-77e9-4605-a934-08619a527fbc', 'follow', 'Please follow me this way.', '请跟我这边走。'),
  ('f7308b67-77e9-4605-a934-08619a527fbc-ex2', 'f7308b67-77e9-4605-a934-08619a527fbc', 'follow', 'All clinical trials must follow the ethical guidelines established by the review board.', '所有临床试验都必须遵循评审委员会制定的伦理准则。'),
  ('3bfcb3ef-7f56-41cd-983e-2468391eb06b-ex1', '3bfcb3ef-7f56-41cd-983e-2468391eb06b', 'parent', 'Her parents are both doctors.', '她的父母都是医生。'),
  ('3bfcb3ef-7f56-41cd-983e-2468391eb06b-ex2', '3bfcb3ef-7f56-41cd-983e-2468391eb06b', 'parent', 'The study examined how parental involvement influences educational attainment across income groups.', '该研究考察了父母参与如何影响不同收入群体的教育成就。'),
  ('1ecd3347-6bfc-4baf-9069-f48235caf294-ex1', '1ecd3347-6bfc-4baf-9069-f48235caf294', 'stop', 'The bus stops right here.', '公交车就停在这里。'),
  ('1ecd3347-6bfc-4baf-9069-f48235caf294-ex2', '1ecd3347-6bfc-4baf-9069-f48235caf294', 'stop', 'The injunction ordered the developer to stop all construction pending the environmental review.', '禁令责令开发商在环境评审期间停止一切施工。'),
  ('88e2bda7-a138-450b-a561-197d810a8d24-ex1', '88e2bda7-a138-450b-a561-197d810a8d24', 'face', 'She had a smile on her face.', '她脸上带着微笑。'),
  ('88e2bda7-a138-450b-a561-197d810a8d24-ex2', '88e2bda7-a138-450b-a561-197d810a8d24', 'face', 'Emerging economies face the dual challenge of fostering growth while containing public debt.', '新兴经济体面临着既要促进增长又要控制公共债务的双重挑战。'),
  ('a253c472-47c5-494b-a2ca-6fbcef8bd582-ex1', 'a253c472-47c5-494b-a2ca-6fbcef8bd582', 'anything', 'Do you need anything from the store?', '你需要从商店买什么东西吗？'),
  ('a253c472-47c5-494b-a2ca-6fbcef8bd582-ex2', 'a253c472-47c5-494b-a2ca-6fbcef8bd582', 'anything', 'The witness denied any knowledge of anything resembling the transactions described in the indictment.', '证人否认知晓任何与起诉书所述交易类似的情况。'),
  ('4d334ec6-8b99-48da-a84e-d20304e3704c-ex1', '4d334ec6-8b99-48da-a84e-d20304e3704c', 'create', 'Let''s create a study plan together.', '我们一起制定一个学习计划吧。'),
  ('4d334ec6-8b99-48da-a84e-d20304e3704c-ex2', '4d334ec6-8b99-48da-a84e-d20304e3704c', 'create', 'The initiative is projected to create thousands of skilled jobs in renewable energy sectors.', '预计该计划将在可再生能源领域创造数千个技术岗位。'),
  ('073b442d-9446-4e63-86fb-526de7eb171f-ex1', '073b442d-9446-4e63-86fb-526de7eb171f', 'public', 'The park is open to the public.', '这座公园对公众开放。'),
  ('073b442d-9446-4e63-86fb-526de7eb171f-ex2', '073b442d-9446-4e63-86fb-526de7eb171f', 'public', 'Restoring public confidence in the electoral process has become a matter of urgent national priority.', '恢复公众对选举程序的信心已成为紧迫的国家要务。'),
  ('dfebe038-ecc8-4c32-b90f-fb5d5e39c8c9-ex1', 'dfebe038-ecc8-4c32-b90f-fb5d5e39c8c9', 'already', 'I have already finished my homework.', '我已经写完作业了。'),
  ('dfebe038-ecc8-4c32-b90f-fb5d5e39c8c9-ex2', 'dfebe038-ecc8-4c32-b90f-fb5d5e39c8c9', 'already', 'By the time regulators intervened, the contagion had already spread throughout the banking sector.', '等到监管机构介入时，风险传染已经蔓延至整个银行业。'),
  ('0ac30023-3319-47fd-b65a-9aa43e38a3f1-ex1', '0ac30023-3319-47fd-b65a-9aa43e38a3f1', 'speak', 'Do you speak English?', '你会说英语吗？'),
  ('0ac30023-3319-47fd-b65a-9aa43e38a3f1-ex2', '0ac30023-3319-47fd-b65a-9aa43e38a3f1', 'speak', 'The envoy was authorized to speak on behalf of the coalition during the ceasefire negotiations.', '这位特使获授权在停火谈判期间代表联盟发言。'),
  ('bc0704e6-ce76-4d85-8725-192445986901-ex1', 'bc0704e6-ce76-4d85-8725-192445986901', 'others', 'Some like coffee; others prefer tea.', '有人喜欢咖啡，有人更喜欢茶。'),
  ('bc0704e6-ce76-4d85-8725-192445986901-ex2', 'bc0704e6-ce76-4d85-8725-192445986901', 'others', 'While some institutions embraced the reforms promptly, others resisted any departure from established practice.', '一些机构迅速接受了改革，另一些则抗拒任何对既有惯例的改变。'),
  ('2d02ad9b-e473-4a3b-b584-eda6bc545c9b-ex1', '2d02ad9b-e473-4a3b-b584-eda6bc545c9b', 'read', 'I read the news every morning.', '我每天早上看新闻。'),
  ('2d02ad9b-e473-4a3b-b584-eda6bc545c9b-ex2', '2d02ad9b-e473-4a3b-b584-eda6bc545c9b', 'read', 'Counsel advised the parties to read the indemnification clauses with particular care.', '律师建议各方特别仔细地阅读赔偿条款。'),
  ('caa801ea-f90f-43ed-b2b1-4223a89c6cd0-ex1', 'caa801ea-f90f-43ed-b2b1-4223a89c6cd0', 'level', 'The water level is rising.', '水位正在上涨。'),
  ('caa801ea-f90f-43ed-b2b1-4223a89c6cd0-ex2', 'caa801ea-f90f-43ed-b2b1-4223a89c6cd0', 'level', 'Unemployment has fallen to its lowest level since records began three decades ago.', '失业率已降至三十年前有记录以来的最低水平。'),
  ('d2e07277-91ca-4782-9d13-61403eb5d842-ex1', 'd2e07277-91ca-4782-9d13-61403eb5d842', 'allow', 'My parents allow me to stay up late on weekends.', '父母允许我周末晚睡。'),
  ('d2e07277-91ca-4782-9d13-61403eb5d842-ex2', 'd2e07277-91ca-4782-9d13-61403eb5d842', 'allow', 'The amended statute would allow regulators to impose penalties proportionate to corporate revenue.', '修订后的法规将允许监管机构按企业营收比例处以罚款。'),
  ('0b69a2a4-7e80-4f93-b7ac-69dfec5ce5ff-ex1', '0b69a2a4-7e80-4f93-b7ac-69dfec5ce5ff', 'add', 'Please add some sugar to my coffee.', '请在我的咖啡里加点糖。'),
  ('0b69a2a4-7e80-4f93-b7ac-69dfec5ce5ff-ex2', '0b69a2a4-7e80-4f93-b7ac-69dfec5ce5ff', 'add', 'The commission voted to add several emerging pollutants to the list of regulated substances.', '委员会投票决定将几种新出现的污染物列入受管制物质清单。'),
  ('65561dbd-ddae-4aec-9d86-9e9f2ecda39d-ex1', '65561dbd-ddae-4aec-9d86-9e9f2ecda39d', 'office', 'Her office is on the third floor.', '她的办公室在三楼。'),
  ('65561dbd-ddae-4aec-9d86-9e9f2ecda39d-ex2', '65561dbd-ddae-4aec-9d86-9e9f2ecda39d', 'office', 'He assumed office amid the most severe fiscal crisis the municipality had ever confronted.', '他在该市遭遇史上最严重财政危机之际就任。'),
  ('f9a31071-0114-4bfc-adb8-1d1800759599-ex1', 'f9a31071-0114-4bfc-adb8-1d1800759599', 'spend', 'How do you spend your weekends?', '你周末都怎么过？'),
  ('f9a31071-0114-4bfc-adb8-1d1800759599-ex2', 'f9a31071-0114-4bfc-adb8-1d1800759599', 'spend', 'Households now spend a substantially larger share of their income on housing than a generation ago.', '与上一代人相比，如今家庭收入中用于住房的比例大幅上升。'),
  ('257e2a9c-78e7-4c2c-899f-29673e6ec90d-ex1', '257e2a9c-78e7-4c2c-899f-29673e6ec90d', 'door', 'Please close the door behind you.', '请随手关门。'),
  ('257e2a9c-78e7-4c2c-899f-29673e6ec90d-ex2', '257e2a9c-78e7-4c2c-899f-29673e6ec90d', 'door', 'The agreement opens the door to unprecedented scientific collaboration between the two nations.', '该协议为两国之间史无前例的科学合作打开了大门。'),
  ('ca4148c5-a7be-455c-8bdd-a6cafe2cd2f1-ex1', 'ca4148c5-a7be-455c-8bdd-a6cafe2cd2f1', 'health', 'Smoking is bad for your health.', '吸烟有害健康。'),
  ('ca4148c5-a7be-455c-8bdd-a6cafe2cd2f1-ex2', 'ca4148c5-a7be-455c-8bdd-a6cafe2cd2f1', 'health', 'The ministry allocated emergency funding to strengthen public health surveillance systems nationwide.', '卫生部拨出紧急资金，以加强全国公共卫生监测体系。'),
  ('b558aeb0-c756-43f4-af35-b291252e13a1-ex1', 'b558aeb0-c756-43f4-af35-b291252e13a1', 'person', 'She is a very kind person.', '她是一个非常善良的人。'),
  ('b558aeb0-c756-43f4-af35-b291252e13a1-ex2', 'b558aeb0-c756-43f4-af35-b291252e13a1', 'person', 'Under the statute, any person who knowingly facilitates such transactions commits a criminal offense.', '根据该法规，任何明知故犯协助此类交易的人均构成刑事犯罪。'),
  ('c9cc4f55-722f-4e84-91cf-3b2b73ad628a-ex1', 'c9cc4f55-722f-4e84-91cf-3b2b73ad628a', 'art', 'I love art and music.', '我喜欢艺术和音乐。'),
  ('c9cc4f55-722f-4e84-91cf-3b2b73ad628a-ex2', 'c9cc4f55-722f-4e84-91cf-3b2b73ad628a', 'art', 'The museum''s collection traces the evolution of modern art across the twentieth century.', '该博物馆的藏品追溯了现代艺术在二十世纪的演变历程。'),
  ('866f14ad-06a4-401d-b492-9b8667d4a2ed-ex1', '866f14ad-06a4-401d-b492-9b8667d4a2ed', 'sure', 'Are you sure about that?', '你确定吗？'),
  ('866f14ad-06a4-401d-b492-9b8667d4a2ed-ex2', '866f14ad-06a4-401d-b492-9b8667d4a2ed', 'sure', 'The authorities must make sure that relief supplies reach the most severely affected communities first.', '当局必须确保救援物资优先送达受灾最严重的社区。'),
  ('08cf545a-81eb-4f97-b11a-c09660ef94f0-ex1', '08cf545a-81eb-4f97-b11a-c09660ef94f0', 'war', 'My grandfather fought in the war.', '我祖父参加过那场战争。'),
  ('08cf545a-81eb-4f97-b11a-c09660ef94f0-ex2', '08cf545a-81eb-4f97-b11a-c09660ef94f0', 'war', 'The protracted war devastated the region''s infrastructure and displaced millions of civilians.', '旷日持久的战争摧毁了该地区的基础设施，致使数百万平民流离失所。'),
  ('b604e351-d330-43ab-96be-c36f546ce66b-ex1', 'b604e351-d330-43ab-96be-c36f546ce66b', 'history', 'History is my favorite subject.', '历史是我最喜欢的科目。'),
  ('b604e351-d330-43ab-96be-c36f546ce66b-ex2', 'b604e351-d330-43ab-96be-c36f546ce66b', 'history', 'The discovery compels historians to reassess a pivotal chapter in the nation''s early history.', '这一发现迫使历史学家重新评估该国早期历史中的一个关键篇章。'),
  ('6319e466-76cb-4bb6-ba6f-3266d4fe0f95-ex1', '6319e466-76cb-4bb6-ba6f-3266d4fe0f95', 'party', 'We are having a birthday party tonight.', '我们今晚要开生日聚会。'),
  ('6319e466-76cb-4bb6-ba6f-3266d4fe0f95-ex2', '6319e466-76cb-4bb6-ba6f-3266d4fe0f95', 'party', 'Each party to the contract bears responsibility for losses arising from its own negligence.', '合同各方对因自身过失造成的损失承担责任。'),
  ('20d4b657-4f7e-4149-bae3-c554bc5c0103-ex1', '20d4b657-4f7e-4149-bae3-c554bc5c0103', 'within', 'The hotel is within walking distance.', '酒店在步行可达的范围内。'),
  ('20d4b657-4f7e-4149-bae3-c554bc5c0103-ex2', '20d4b657-4f7e-4149-bae3-c554bc5c0103', 'within', 'All appeals must be lodged within thirty days of the decision being formally communicated.', '所有上诉必须在决定正式送达后三十日内提出。'),
  ('5e0d78ca-55a5-4b3c-a848-87e0ade53f84-ex1', '5e0d78ca-55a5-4b3c-a848-87e0ade53f84', 'grow', 'These plants grow very fast.', '这些植物长得很快。'),
  ('5e0d78ca-55a5-4b3c-a848-87e0ade53f84-ex2', '5e0d78ca-55a5-4b3c-a848-87e0ade53f84', 'grow', 'The economy is forecast to grow modestly despite persistent headwinds in global trade.', '尽管全球贸易持续承压，预计经济仍将温和增长。'),
  ('190966aa-1bcd-45d4-be69-ec9db1091762-ex1', '190966aa-1bcd-45d4-be69-ec9db1091762', 'result', 'The test results come out tomorrow.', '考试结果明天公布。'),
  ('190966aa-1bcd-45d4-be69-ec9db1091762-ex2', '190966aa-1bcd-45d4-be69-ec9db1091762', 'result', 'The famine was the direct result of consecutive crop failures compounded by armed conflict.', '这场饥荒是连年歉收叠加武装冲突的直接结果。'),
  ('fbfc2fa1-3d22-4847-950a-f8b4988dd604-ex1', 'fbfc2fa1-3d22-4847-950a-f8b4988dd604', 'open', 'The store is open until nine.', '这家店营业到九点。'),
  ('fbfc2fa1-3d22-4847-950a-f8b4988dd604-ex2', 'fbfc2fa1-3d22-4847-950a-f8b4988dd604', 'open', 'The chairman pledged to keep the consultation process open to all interested stakeholders.', '主席承诺让磋商过程对所有相关利益方保持开放。'),
  ('48db1059-2d5a-44c7-b629-8b5eef8fdaf1-ex1', '48db1059-2d5a-44c7-b629-8b5eef8fdaf1', 'morning', 'I drink coffee every morning.', '我每天早上喝咖啡。'),
  ('48db1059-2d5a-44c7-b629-8b5eef8fdaf1-ex2', '48db1059-2d5a-44c7-b629-8b5eef8fdaf1', 'morning', 'The announcement, released early in the morning, sent shockwaves through financial markets.', '这则清晨发布的公告在金融市场引发了剧烈震荡。'),
  ('5c2c5bbf-0fa1-491a-945e-bc2f07c14ca2-ex1', '5c2c5bbf-0fa1-491a-945e-bc2f07c14ca2', 'walk', 'Let''s walk to the park.', '我们走路去公园吧。'),
  ('5c2c5bbf-0fa1-491a-945e-bc2f07c14ca2-ex2', '5c2c5bbf-0fa1-491a-945e-bc2f07c14ca2', 'walk', 'Negotiators warned that they would walk away from the table if the preconditions were not met.', '谈判代表警告说，如果先决条件得不到满足，他们将退出谈判。'),
  ('b1488ae2-9866-4f70-a02d-cf78fef48470-ex1', 'b1488ae2-9866-4f70-a02d-cf78fef48470', 'reason', 'What is the reason for the delay?', '延误的原因是什么？'),
  ('b1488ae2-9866-4f70-a02d-cf78fef48470-ex2', 'b1488ae2-9866-4f70-a02d-cf78fef48470', 'reason', 'The court found no compelling reason to depart from the precedent established in earlier rulings.', '法院认为没有充分理由背离先前判决所确立的先例。'),
  ('7dfb57a5-e43e-4fd8-9121-b523e4552076-ex1', '7dfb57a5-e43e-4fd8-9121-b523e4552076', 'low', 'The price is very low today.', '今天价格很低。'),
  ('7dfb57a5-e43e-4fd8-9121-b523e4552076-ex2', '7dfb57a5-e43e-4fd8-9121-b523e4552076', 'low', 'Persistently low interest rates have encouraged levels of borrowing that many economists consider unsustainable.', '持续的低利率助长了许多经济学家认为不可持续的借贷水平。'),
  ('e71dbe21-4a20-4afc-92ff-7fe878da171a-ex1', 'e71dbe21-4a20-4afc-92ff-7fe878da171a', 'win', 'I hope our team wins tonight.', '我希望我们队今晚获胜。'),
  ('e71dbe21-4a20-4afc-92ff-7fe878da171a-ex2', 'e71dbe21-4a20-4afc-92ff-7fe878da171a', 'win', 'To win regulatory approval, the manufacturer must demonstrate both safety and therapeutic efficacy.', '要赢得监管批准，制造商必须同时证明产品的安全性和疗效。'),
  ('5d30b598-45e7-4360-8867-c059eec20cad-ex1', '5d30b598-45e7-4360-8867-c059eec20cad', 'research', 'She does research at the university.', '她在大学做研究。'),
  ('5d30b598-45e7-4360-8867-c059eec20cad-ex2', '5d30b598-45e7-4360-8867-c059eec20cad', 'research', 'Decades of rigorous research culminated in a treatment that has transformed patient outcomes.', '数十年的严谨研究最终促成了一种彻底改变患者预后的疗法。'),
  ('020be85e-2fc8-4b21-8d7f-41d476068c7b-ex1', '020be85e-2fc8-4b21-8d7f-41d476068c7b', 'girl', 'The little girl is drawing a picture.', '那个小女孩正在画画。'),
  ('020be85e-2fc8-4b21-8d7f-41d476068c7b-ex2', '020be85e-2fc8-4b21-8d7f-41d476068c7b', 'girl', 'The foundation funds programs designed to keep adolescent girls enrolled in secondary education.', '该基金会资助旨在让少女继续接受中学教育的项目。'),
  ('7f780ea1-f2a2-4164-8811-05affee42508-ex1', '7f780ea1-f2a2-4164-8811-05affee42508', 'guy', 'He is a really nice guy.', '他是个很不错的人。'),
  ('7f780ea1-f2a2-4164-8811-05affee42508-ex2', '7f780ea1-f2a2-4164-8811-05affee42508', 'guy', 'Witnesses described the suspect as an unassuming guy who rarely attracted attention.', '目击者称嫌疑人是个不起眼、很少引人注意的人。'),
  ('189cd4b7-0297-4b09-b794-3a159752a403-ex1', '189cd4b7-0297-4b09-b794-3a159752a403', 'early', 'I wake up early every day.', '我每天起得很早。'),
  ('189cd4b7-0297-4b09-b794-3a159752a403-ex2', '189cd4b7-0297-4b09-b794-3a159752a403', 'early', 'Early detection of the disease dramatically improves the prospects for successful treatment.', '疾病的早期发现能显著提高治疗成功的几率。'),
  ('da46e43f-77fb-4ed5-87dd-587583125b2e-ex1', 'da46e43f-77fb-4ed5-87dd-587583125b2e', 'food', 'The food at this restaurant is delicious.', '这家餐厅的食物很美味。'),
  ('da46e43f-77fb-4ed5-87dd-587583125b2e-ex2', 'da46e43f-77fb-4ed5-87dd-587583125b2e', 'food', 'Volatile commodity prices have intensified concerns about food security in import-dependent nations.', '大宗商品价格波动加剧了依赖进口国家对粮食安全的担忧。'),
  ('a00b3514-7714-412e-b917-f3e01096e423-ex1', 'a00b3514-7714-412e-b917-f3e01096e423', 'moment', 'Please wait a moment.', '请稍等片刻。'),
  ('a00b3514-7714-412e-b917-f3e01096e423-ex2', 'a00b3514-7714-412e-b917-f3e01096e423', 'moment', 'The signing of the accord marked a defining moment in the region''s long pursuit of stability.', '协议的签署是该地区长期谋求稳定进程中的决定性时刻。'),
  ('88753f38-e41c-4bd7-a19b-aa01e3886050-ex1', '88753f38-e41c-4bd7-a19b-aa01e3886050', 'himself', 'He made this cake himself.', '这个蛋糕是他自己做的。'),
  ('88753f38-e41c-4bd7-a19b-aa01e3886050-ex2', '88753f38-e41c-4bd7-a19b-aa01e3886050', 'himself', 'The minister himself acknowledged that the implementation timeline had been overly ambitious.', '部长本人也承认，实施时间表当初定得过于激进。'),
  ('41c07abf-87b6-4fa0-b066-59e970bad2d6-ex1', '41c07abf-87b6-4fa0-b066-59e970bad2d6', 'air', 'The air is fresh in the mountains.', '山里的空气很清新。'),
  ('41c07abf-87b6-4fa0-b066-59e970bad2d6-ex2', '41c07abf-87b6-4fa0-b066-59e970bad2d6', 'air', 'Deteriorating air quality has prompted municipal authorities to restrict vehicular traffic in the city center.', '空气质量恶化促使市政当局限制市中心的机动车通行。'),
  ('feddeeb3-a44c-4ae0-a605-28b7cb33bb1d-ex1', 'feddeeb3-a44c-4ae0-a605-28b7cb33bb1d', 'teacher', 'My teacher is very patient.', '我的老师非常有耐心。'),
  ('feddeeb3-a44c-4ae0-a605-28b7cb33bb1d-ex2', 'feddeeb3-a44c-4ae0-a605-28b7cb33bb1d', 'teacher', 'The reform links teacher compensation to professional development rather than seniority alone.', '这项改革将教师薪酬与专业发展挂钩，而不再仅凭资历。'),
  ('ee4063f5-a0e5-4992-8728-2003e9e77764-ex1', 'ee4063f5-a0e5-4992-8728-2003e9e77764', 'force', 'Don''t force the door open.', '别硬把门撬开。'),
  ('ee4063f5-a0e5-4992-8728-2003e9e77764-ex2', 'ee4063f5-a0e5-4992-8728-2003e9e77764', 'force', 'The treaty prohibits the use of force except in cases of legitimate self-defense.', '该条约禁止使用武力，正当自卫的情形除外。'),
  ('4a27590a-4364-41ec-8213-913e29dabba0-ex1', '4a27590a-4364-41ec-8213-913e29dabba0', 'offer', 'Can I offer you something to drink?', '我能给你拿点喝的吗？'),
  ('4a27590a-4364-41ec-8213-913e29dabba0-ex2', '4a27590a-4364-41ec-8213-913e29dabba0', 'offer', 'The university extended a formal offer of admission accompanied by a substantial fellowship.', '这所大学发出了正式录取通知，并附有丰厚的奖学金。'),
  ('d62f369e-0c59-4086-9319-369f2c66f63b-ex1', 'd62f369e-0c59-4086-9319-369f2c66f63b', 'enough', 'Do we have enough food for everyone?', '我们的食物够大家吃吗？'),
  ('d62f369e-0c59-4086-9319-369f2c66f63b-ex2', 'd62f369e-0c59-4086-9319-369f2c66f63b', 'enough', 'Critics contend that the sanctions, though symbolically significant, are not enough to alter state behavior.', '批评者认为，制裁虽具象征意义，但不足以改变国家行为。'),
  ('910ed25e-faee-4a4f-bcb5-347bc2a69689-ex1', '910ed25e-faee-4a4f-bcb5-347bc2a69689', 'education', 'Education opens many doors.', '教育能开启许多大门。'),
  ('910ed25e-faee-4a4f-bcb5-347bc2a69689-ex2', '910ed25e-faee-4a4f-bcb5-347bc2a69689', 'education', 'Sustained investment in early childhood education yields measurable returns across an individual''s lifetime.', '对幼儿教育的持续投资会在个人一生中产生可衡量的回报。'),
  ('4e335006-df9d-41e6-b7f0-d912867b25b1-ex1', '4e335006-df9d-41e6-b7f0-d912867b25b1', 'across', 'The bakery is across the street.', '面包店在街对面。'),
  ('4e335006-df9d-41e6-b7f0-d912867b25b1-ex2', '4e335006-df9d-41e6-b7f0-d912867b25b1', 'across', 'The initiative has been replicated across five continents with remarkably consistent results.', '该计划已在五大洲推广复制，成效惊人地一致。'),
  ('c4021d10-fd36-4ecb-a601-5e409ffca91a-ex1', 'c4021d10-fd36-4ecb-a601-5e409ffca91a', 'although', 'Although it was raining, we went out.', '虽然下着雨，我们还是出门了。'),
  ('c4021d10-fd36-4ecb-a601-5e409ffca91a-ex2', 'c4021d10-fd36-4ecb-a601-5e409ffca91a', 'although', 'Although the methodology has obvious limitations, the findings nonetheless merit serious consideration.', '尽管该方法存在明显局限，这些发现仍值得认真对待。'),
  ('a05e40f6-9607-4ff4-98df-727b27b0cd2c-ex1', 'a05e40f6-9607-4ff4-98df-727b27b0cd2c', 'remember', 'Do you remember my name?', '你记得我的名字吗？'),
  ('a05e40f6-9607-4ff4-98df-727b27b0cd2c-ex2', 'a05e40f6-9607-4ff4-98df-727b27b0cd2c', 'remember', 'It is essential to remember that correlation alone does not establish a causal relationship.', '必须牢记，仅有相关性并不能确立因果关系。'),
  ('259eebec-3006-47e4-955a-62a4295f410b-ex1', '259eebec-3006-47e4-955a-62a4295f410b', 'foot', 'My left foot hurts.', '我的左脚疼。'),
  ('259eebec-3006-47e4-955a-62a4295f410b-ex2', '259eebec-3006-47e4-955a-62a4295f410b', 'foot', 'The expedition traversed the glacier on foot, covering nearly forty kilometers in three days.', '探险队徒步穿越冰川，三天内行进了近四十公里。'),
  ('bba906fa-a271-4420-bcf2-b87eb4b29fd0-ex1', 'bba906fa-a271-4420-bcf2-b87eb4b29fd0', 'second', 'This is my second visit to the museum.', '这是我第二次参观这座博物馆。'),
  ('bba906fa-a271-4420-bcf2-b87eb4b29fd0-ex2', 'bba906fa-a271-4420-bcf2-b87eb4b29fd0', 'second', 'The motion was approved within seconds of being seconded by the senior delegate.', '该动议在资深代表附议后数秒内即获通过。'),
  ('bddc8a7f-0428-497e-a28a-98b7d6b6da2d-ex1', 'bddc8a7f-0428-497e-a28a-98b7d6b6da2d', 'boy', 'The boy is flying a kite.', '那个男孩在放风筝。'),
  ('bddc8a7f-0428-497e-a28a-98b7d6b6da2d-ex2', 'bddc8a7f-0428-497e-a28a-98b7d6b6da2d', 'boy', 'The novel chronicles the journey of a boy displaced by war who rebuilds his life abroad.', '这部小说讲述了一个因战争流离失所的男孩在海外重建生活的历程。'),
  ('e99f06bb-20ba-4ba1-9add-70e11c443e7f-ex1', 'e99f06bb-20ba-4ba1-9add-70e11c443e7f', 'maybe', 'Maybe we should leave earlier.', '也许我们应该早点出发。'),
  ('e99f06bb-20ba-4ba1-9add-70e11c443e7f-ex2', 'e99f06bb-20ba-4ba1-9add-70e11c443e7f', 'maybe', 'Maybe the most enduring lesson of the crisis is the danger of unchecked institutional complacency.', '这场危机最深远的教训，或许就是机构自满情绪不受约束的危险。'),
  ('dc4a8911-e729-487a-83ba-43da8b675c4e-ex1', 'dc4a8911-e729-487a-83ba-43da8b675c4e', 'toward', 'She walked toward the door.', '她朝门口走去。'),
  ('dc4a8911-e729-487a-83ba-43da8b675c4e-ex2', 'dc4a8911-e729-487a-83ba-43da8b675c4e', 'toward', 'The summit represents a significant step toward establishing a unified regional energy market.', '此次峰会是朝着建立统一区域能源市场迈出的重要一步。'),
  ('80bbc0bd-1a2b-404b-974c-50821d086123-ex1', '80bbc0bd-1a2b-404b-974c-50821d086123', 'able', 'I am able to swim across the lake.', '我能游过这个湖。'),
  ('80bbc0bd-1a2b-404b-974c-50821d086123-ex2', '80bbc0bd-1a2b-404b-974c-50821d086123', 'able', 'Only institutions able to demonstrate adequate capital reserves will be permitted to expand operations.', '只有能够证明资本储备充足的机构才会被允许扩大业务。'),
  ('4ec9367f-4c92-49cc-a15a-cb14db1fe786-ex1', '4ec9367f-4c92-49cc-a15a-cb14db1fe786', 'age', 'She started piano at the age of five.', '她五岁开始学钢琴。'),
  ('4ec9367f-4c92-49cc-a15a-cb14db1fe786-ex2', '4ec9367f-4c92-49cc-a15a-cb14db1fe786', 'age', 'In the age of instantaneous communication, misinformation can propagate faster than corrections.', '在即时通信的时代，虚假信息的传播速度可能超过更正信息。'),
  ('bea0a84b-7713-4b49-b6ae-0b9fbe050c43-ex1', 'bea0a84b-7713-4b49-b6ae-0b9fbe050c43', 'policy', 'The school has a strict attendance policy.', '学校有严格的考勤制度。'),
  ('bea0a84b-7713-4b49-b6ae-0b9fbe050c43-ex2', 'bea0a84b-7713-4b49-b6ae-0b9fbe050c43', 'policy', 'The central bank''s monetary policy has drawn criticism for prioritizing inflation control over employment.', '央行的货币政策因将控制通胀置于就业之上而受到批评。'),
  ('df229c6e-67a0-4f93-8966-bbf16e0b78ac-ex1', 'df229c6e-67a0-4f93-8966-bbf16e0b78ac', 'everything', 'Everything is ready for the party.', '聚会的一切都准备好了。'),
  ('df229c6e-67a0-4f93-8966-bbf16e0b78ac-ex2', 'df229c6e-67a0-4f93-8966-bbf16e0b78ac', 'everything', 'The investigators examined everything from procurement records to internal correspondence.', '调查人员审查了从采购记录到内部往来函件的所有材料。'),
  ('dabe82f3-c0a5-4fa2-a483-9b0d194446ee-ex1', 'dabe82f3-c0a5-4fa2-a483-9b0d194446ee', 'love', 'I love spending time with my family.', '我喜欢和家人共度时光。'),
  ('dabe82f3-c0a5-4fa2-a483-9b0d194446ee-ex2', 'dabe82f3-c0a5-4fa2-a483-9b0d194446ee', 'love', 'Her lifelong love of literature ultimately shaped a career devoted to comparative scholarship.', '她对文学的毕生热爱最终塑造了她致力于比较研究的学术生涯。'),
  ('fd2ba156-420c-40dd-87c2-9e1d578d28ab-ex1', 'fd2ba156-420c-40dd-87c2-9e1d578d28ab', 'process', 'Learning a language is a slow process.', '学习语言是一个缓慢的过程。'),
  ('fd2ba156-420c-40dd-87c2-9e1d578d28ab-ex2', 'fd2ba156-420c-40dd-87c2-9e1d578d28ab', 'process', 'The ratification process requires the assent of two-thirds of the member legislatures.', '批准程序需要获得三分之二成员立法机构的同意。'),
  ('33b6af01-1cbd-43dd-a45f-8b384f854590-ex1', '33b6af01-1cbd-43dd-a45f-8b384f854590', 'music', 'She listens to music while studying.', '她边学习边听音乐。'),
  ('33b6af01-1cbd-43dd-a45f-8b384f854590-ex2', '33b6af01-1cbd-43dd-a45f-8b384f854590', 'music', 'The symposium explored how digital distribution has fundamentally restructured the music industry.', '研讨会探讨了数字发行如何从根本上重构了音乐产业。'),
  ('80305293-ceb2-4595-b8c3-c64992a7858a-ex1', '80305293-ceb2-4595-b8c3-c64992a7858a', 'including', 'Five people came, including my brother.', '来了五个人，包括我哥哥。'),
  ('80305293-ceb2-4595-b8c3-c64992a7858a-ex2', '80305293-ceb2-4595-b8c3-c64992a7858a', 'including', 'Several jurisdictions, including two of the largest, have already adopted equivalent safeguards.', '包括两个最大辖区在内的多个司法管辖区已采取了同等的保障措施。'),
  ('e5cc7444-b416-4830-b40c-8da333691c05-ex1', 'e5cc7444-b416-4830-b40c-8da333691c05', 'consider', 'Please consider my suggestion.', '请考虑一下我的建议。'),
  ('e5cc7444-b416-4830-b40c-8da333691c05-ex2', 'e5cc7444-b416-4830-b40c-8da333691c05', 'consider', 'The board will consider whether the proposed acquisition aligns with the company''s long-term strategy.', '董事会将考量拟议的收购是否符合公司的长期战略。'),
  ('ea488342-66d3-471f-a5c6-33a60d681c29-ex1', 'ea488342-66d3-471f-a5c6-33a60d681c29', 'appear', 'Stars appear in the night sky.', '星星出现在夜空中。'),
  ('ea488342-66d3-471f-a5c6-33a60d681c29-ex2', 'ea488342-66d3-471f-a5c6-33a60d681c29', 'appear', 'The defendant failed to appear before the tribunal despite repeated formal summonses.', '尽管多次正式传唤，被告仍未到庭。'),
  ('f2e1128b-8a33-4119-b1d6-646fa40555cd-ex1', 'f2e1128b-8a33-4119-b1d6-646fa40555cd', 'actually', 'Actually, I have never met him.', '其实我从来没见过他。'),
  ('f2e1128b-8a33-4119-b1d6-646fa40555cd-ex2', 'f2e1128b-8a33-4119-b1d6-646fa40555cd', 'actually', 'The data reveal that the program actually widened the disparities it was designed to reduce.', '数据显示，该项目实际上扩大了它本应缩小的差距。'),
  ('fa75aedd-48b8-4c0d-bfb1-43b9fb001c56-ex1', 'fa75aedd-48b8-4c0d-bfb1-43b9fb001c56', 'buy', 'I want to buy a new bike.', '我想买一辆新自行车。'),
  ('fa75aedd-48b8-4c0d-bfb1-43b9fb001c56-ex2', 'fa75aedd-48b8-4c0d-bfb1-43b9fb001c56', 'buy', 'Institutional investors continued to buy government bonds despite historically low yields.', '尽管收益率处于历史低位，机构投资者仍持续买入政府债券。'),
  ('00edf1df-f0cd-420d-af74-14e854236ee3-ex1', '00edf1df-f0cd-420d-af74-14e854236ee3', 'probably', 'It will probably rain tomorrow.', '明天可能会下雨。'),
  ('00edf1df-f0cd-420d-af74-14e854236ee3-ex2', '00edf1df-f0cd-420d-af74-14e854236ee3', 'probably', 'The committee concluded that the failure was probably attributable to inadequate maintenance protocols.', '委员会认定，这次故障很可能归因于维护规程不完善。'),
  ('17ed07ad-c0f1-4829-afb4-b9cebed5b4ba-ex1', '17ed07ad-c0f1-4829-afb4-b9cebed5b4ba', 'human', 'Every human needs food and water.', '每个人都需要食物和水。'),
  ('17ed07ad-c0f1-4829-afb4-b9cebed5b4ba-ex2', '17ed07ad-c0f1-4829-afb4-b9cebed5b4ba', 'human', 'The tribunal held that the detention conditions violated fundamental human rights standards.', '法庭裁定，拘留条件违反了基本人权标准。'),
  ('271c0e3d-471c-45fe-8268-450e10912c3d-ex1', '271c0e3d-471c-45fe-8268-450e10912c3d', 'wait', 'Please wait for me at the gate.', '请在大门口等我。'),
  ('271c0e3d-471c-45fe-8268-450e10912c3d-ex2', '271c0e3d-471c-45fe-8268-450e10912c3d', 'wait', 'Investors chose to wait for the central bank''s announcement before adjusting their positions.', '投资者选择等待央行公告后再调整仓位。'),
  ('e649959e-ee72-44a8-95f9-84306c9cfcb1-ex1', 'e649959e-ee72-44a8-95f9-84306c9cfcb1', 'serve', 'This restaurant serves great noodles.', '这家餐厅的面条很好吃。'),
  ('e649959e-ee72-44a8-95f9-84306c9cfcb1-ex2', 'e649959e-ee72-44a8-95f9-84306c9cfcb1', 'serve', 'The newly established agency will serve as the principal coordinator of disaster relief operations.', '新成立的机构将作为救灾行动的主要协调方。'),
  ('4a36a0c1-7773-442f-8415-7b97d03d16c9-ex1', '4a36a0c1-7773-442f-8415-7b97d03d16c9', 'market', 'We buy vegetables at the local market.', '我们在本地市场买蔬菜。'),
  ('4a36a0c1-7773-442f-8415-7b97d03d16c9-ex2', '4a36a0c1-7773-442f-8415-7b97d03d16c9', 'market', 'The regulator imposed structural remedies to restore competition in the telecommunications market.', '监管机构实施了结构性补救措施，以恢复电信市场的竞争。'),
  ('0e72199a-d94c-4e82-92a4-81142e517ca4-ex1', '0e72199a-d94c-4e82-92a4-81142e517ca4', 'die', 'My grandmother died last year.', '我祖母去年去世了。'),
  ('0e72199a-d94c-4e82-92a4-81142e517ca4-ex2', '0e72199a-d94c-4e82-92a4-81142e517ca4', 'die', 'Thousands die annually from conditions that are entirely preventable with timely medical intervention.', '每年有数千人死于通过及时医疗干预完全可以预防的疾病。'),
  ('ca6dcffd-2142-47c8-b824-d84192b41ea0-ex1', 'ca6dcffd-2142-47c8-b824-d84192b41ea0', 'send', 'Please send me the photos.', '请把照片发给我。'),
  ('ca6dcffd-2142-47c8-b824-d84192b41ea0-ex2', 'ca6dcffd-2142-47c8-b824-d84192b41ea0', 'send', 'The council resolved to send a delegation to assess conditions in the affected provinces.', '理事会决定派遣代表团评估受灾省份的状况。'),
  ('456ff0dc-244e-41ce-9711-4824361523a2-ex1', '456ff0dc-244e-41ce-9711-4824361523a2', 'expect', 'I expect the bus to arrive soon.', '我想公交车很快就会到。'),
  ('456ff0dc-244e-41ce-9711-4824361523a2-ex2', '456ff0dc-244e-41ce-9711-4824361523a2', 'expect', 'Analysts expect the reforms to yield measurable fiscal benefits within the current parliamentary term.', '分析人士预计，这些改革将在本届议会任期内产生可衡量的财政效益。'),
  ('8205ea65-505f-46a5-96cf-7fd33be2090e-ex1', '8205ea65-505f-46a5-96cf-7fd33be2090e', 'sense', 'Dogs have a strong sense of smell.', '狗的嗅觉很灵敏。'),
  ('8205ea65-505f-46a5-96cf-7fd33be2090e-ex2', '8205ea65-505f-46a5-96cf-7fd33be2090e', 'sense', 'The amendments make little economic sense when evaluated against their projected administrative costs.', '若对照预计的行政成本来评估，这些修正案在经济上意义甚微。'),
  ('a1ba2eb3-d5f1-4b1e-8383-eb5db9be33b1-ex1', 'a1ba2eb3-d5f1-4b1e-8383-eb5db9be33b1', 'build', 'They plan to build a new school here.', '他们计划在这里建一所新学校。'),
  ('a1ba2eb3-d5f1-4b1e-8383-eb5db9be33b1-ex2', 'a1ba2eb3-d5f1-4b1e-8383-eb5db9be33b1', 'build', 'The accord seeks to build durable institutional trust between historically antagonistic parties.', '该协议旨在历史上相互敌对的各方之间建立持久的制度性信任。'),
  ('8eb0002f-51ad-4a64-bb03-e16c317d8d54-ex1', '8eb0002f-51ad-4a64-bb03-e16c317d8d54', 'stay', 'Please stay here until I return.', '请待在这里直到我回来。'),
  ('8eb0002f-51ad-4a64-bb03-e16c317d8d54-ex2', '8eb0002f-51ad-4a64-bb03-e16c317d8d54', 'stay', 'The court granted a stay of execution pending the outcome of the constitutional appeal.', '法院批准暂缓执行，以待宪法上诉的结果。'),
  ('87665932-39cd-49d2-9e2a-e478a78aab12-ex1', '87665932-39cd-49d2-9e2a-e478a78aab12', 'fall', 'Be careful not to fall on the ice.', '小心别在冰上摔倒。'),
  ('87665932-39cd-49d2-9e2a-e478a78aab12-ex2', '87665932-39cd-49d2-9e2a-e478a78aab12', 'fall', 'Commodity prices continued to fall as global demand weakened throughout the quarter.', '随着全球需求在整个季度持续疲软，大宗商品价格不断下跌。'),
  ('c214410c-8336-4a12-9398-b9c44b8b1c62-ex1', 'c214410c-8336-4a12-9398-b9c44b8b1c62', 'oh', 'Oh, I forgot my keys!', '哦，我忘带钥匙了！'),
  ('c214410c-8336-4a12-9398-b9c44b8b1c62-ex2', 'c214410c-8336-4a12-9398-b9c44b8b1c62', 'oh', 'Oh, what a profound transformation a single decade of reform has wrought upon this institution.', '啊，仅仅十年的改革就给这家机构带来了何等深刻的变化。'),
  ('1a2e05c5-4a2b-4652-9570-5d366a46fa82-ex1', '1a2e05c5-4a2b-4652-9570-5d366a46fa82', 'nation', 'The whole nation celebrated the victory.', '举国上下庆祝胜利。'),
  ('1a2e05c5-4a2b-4652-9570-5d366a46fa82-ex2', '1a2e05c5-4a2b-4652-9570-5d366a46fa82', 'nation', 'Every nation party to the convention must submit annual compliance reports to the secretariat.', '凡缔约国均须向秘书处提交年度履约报告。'),
  ('7f6d498b-23c1-4fe8-988c-8281e1c2073e-ex1', '7f6d498b-23c1-4fe8-988c-8281e1c2073e', 'plan', 'What is your plan for the weekend?', '你周末有什么计划？'),
  ('7f6d498b-23c1-4fe8-988c-8281e1c2073e-ex2', '7f6d498b-23c1-4fe8-988c-8281e1c2073e', 'plan', 'The recovery plan stipulates rigorous milestones against which progress will be independently audited.', '复苏计划规定了严格的阶段性目标，进展情况将接受独立审计。'),
  ('c767b687-534a-4d16-ae5c-6b9d7c50979c-ex1', 'c767b687-534a-4d16-ae5c-6b9d7c50979c', 'cut', 'Be careful not to cut your finger.', '小心别割到手指。'),
  ('c767b687-534a-4d16-ae5c-6b9d7c50979c-ex2', 'c767b687-534a-4d16-ae5c-6b9d7c50979c', 'cut', 'The legislature approved a substantial cut in funding for discretionary programs.', '立法机构批准大幅削减非强制性项目的拨款。'),
  ('7e57374e-0ff6-4bc0-9d68-195b1c65ee7b-ex1', '7e57374e-0ff6-4bc0-9d68-195b1c65ee7b', 'college', 'My sister is in college now.', '我姐姐现在在上大学。'),
  ('7e57374e-0ff6-4bc0-9d68-195b1c65ee7b-ex2', '7e57374e-0ff6-4bc0-9d68-195b1c65ee7b', 'college', 'Rising college tuition has prompted renewed debate over the public financing of higher education.', '大学学费上涨重新引发了关于高等教育公共资助的辩论。'),
  ('71b3aeaa-3a20-4085-ab33-733bfb2e6d86-ex1', '71b3aeaa-3a20-4085-ab33-733bfb2e6d86', 'interest', 'I have a strong interest in photography.', '我对摄影有浓厚的兴趣。'),
  ('71b3aeaa-3a20-4085-ab33-733bfb2e6d86-ex2', '71b3aeaa-3a20-4085-ab33-733bfb2e6d86', 'interest', 'Board members must disclose any financial interest that could compromise their impartiality.', '董事会成员必须披露任何可能影响其公正性的经济利益。'),
  ('1e167e91-df0e-4147-87e8-8086cbf927ee-ex1', '1e167e91-df0e-4147-87e8-8086cbf927ee', 'death', 'The news of his death shocked everyone.', '他去世的消息让所有人震惊。'),
  ('1e167e91-df0e-4147-87e8-8086cbf927ee-ex2', '1e167e91-df0e-4147-87e8-8086cbf927ee', 'death', 'The inquiry concluded that the death resulted from systemic failures in patient monitoring.', '调查认定，这起死亡事件源于患者监护方面的系统性失误。'),
  ('3b1bc728-0808-4a11-978d-797cd5b2cd01-ex1', '3b1bc728-0808-4a11-978d-797cd5b2cd01', 'course', 'I am taking a cooking course.', '我在上烹饪课。'),
  ('3b1bc728-0808-4a11-978d-797cd5b2cd01-ex2', '3b1bc728-0808-4a11-978d-797cd5b2cd01', 'course', 'Over the course of the investigation, examiners reviewed more than a million documents.', '在调查过程中，审查人员查阅了一百多万份文件。'),
  ('2dadb24c-d80e-45c4-9123-0a7bfb6a4287-ex1', '2dadb24c-d80e-45c4-9123-0a7bfb6a4287', 'someone', 'Someone left an umbrella here.', '有人把伞落在这里了。'),
  ('2dadb24c-d80e-45c4-9123-0a7bfb6a4287-ex2', '2dadb24c-d80e-45c4-9123-0a7bfb6a4287', 'someone', 'The protocol requires that someone with clinical authority countersign every prescription amendment.', '该规程要求由具有临床权限的人员对每一处处方修改进行会签。'),
  ('965c48e3-c8aa-4efd-af1c-2e9acd4cf89f-ex1', '965c48e3-c8aa-4efd-af1c-2e9acd4cf89f', 'experience', 'She has five years of teaching experience.', '她有五年的教学经验。'),
  ('965c48e3-c8aa-4efd-af1c-2e9acd4cf89f-ex2', '965c48e3-c8aa-4efd-af1c-2e9acd4cf89f', 'experience', 'Candidates must possess substantial experience in cross-border regulatory compliance.', '候选人必须具备丰富的跨境监管合规经验。'),
  ('51957ed7-f6fa-46b7-8ed1-4ce5bb40ed91-ex1', '51957ed7-f6fa-46b7-8ed1-4ce5bb40ed91', 'behind', 'The cat is hiding behind the sofa.', '猫藏在沙发后面。'),
  ('51957ed7-f6fa-46b7-8ed1-4ce5bb40ed91-ex2', '51957ed7-f6fa-46b7-8ed1-4ce5bb40ed91', 'behind', 'The report examines the structural forces behind the persistent decline in manufacturing employment.', '报告剖析了制造业就业持续下滑背后的结构性因素。'),
  ('7d9e798b-9c36-4971-a60c-d1ae0156e301-ex1', '7d9e798b-9c36-4971-a60c-d1ae0156e301', 'reach', 'Can you reach the top shelf?', '你能够到最上面的架子吗？'),
  ('7d9e798b-9c36-4971-a60c-d1ae0156e301-ex2', '7d9e798b-9c36-4971-a60c-d1ae0156e301', 'reach', 'The parties failed to reach consensus on the mechanism for verifying compliance.', '各方未能就核查履约情况的机制达成共识。'),
  ('5711bdc2-863a-42ff-bbb6-5cf2ae5c9db9-ex1', '5711bdc2-863a-42ff-bbb6-5cf2ae5c9db9', 'local', 'We ate at a local restaurant.', '我们在一家当地餐馆吃了饭。'),
  ('5711bdc2-863a-42ff-bbb6-5cf2ae5c9db9-ex2', '5711bdc2-863a-42ff-bbb6-5cf2ae5c9db9', 'local', 'The statute devolves substantial planning authority to local governments and their elected councils.', '该法规将大量规划权限下放给地方政府及其民选议会。'),
  ('dd1e5d12-2710-4b59-8c18-f528477c4c02-ex1', 'dd1e5d12-2710-4b59-8c18-f528477c4c02', 'kill', 'The frost killed all my flowers.', '霜冻把我的花全冻死了。'),
  ('dd1e5d12-2710-4b59-8c18-f528477c4c02-ex2', 'dd1e5d12-2710-4b59-8c18-f528477c4c02', 'kill', 'Conservationists warn that the proposed dam would kill critical spawning habitats downstream.', '环保人士警告说，拟建的大坝将毁灭下游关键的产卵栖息地。'),
  ('bf892c6c-3a19-43a0-a026-bd9ae36b6784-ex1', 'bf892c6c-3a19-43a0-a026-bd9ae36b6784', 'six', 'The store opens at six in the morning.', '商店早上六点开门。'),
  ('bf892c6c-3a19-43a0-a026-bd9ae36b6784-ex2', 'bf892c6c-3a19-43a0-a026-bd9ae36b6784', 'six', 'The commission comprises six independent experts appointed for non-renewable terms.', '该委员会由六名独立专家组成，任期不可连任。'),
  ('5db99b3b-68cc-4442-bf9f-f977770ca1aa-ex1', '5db99b3b-68cc-4442-bf9f-f977770ca1aa', 'remain', 'Please remain seated during the show.', '演出期间请保持就座。'),
  ('5db99b3b-68cc-4442-bf9f-f977770ca1aa-ex2', '5db99b3b-68cc-4442-bf9f-f977770ca1aa', 'remain', 'Significant obstacles remain before the agreement can be translated into enforceable legislation.', '在该协议转化为可执行的立法之前，仍存在重大障碍。'),
  ('6320e713-db17-4468-98d8-9eca68cef3da-ex1', '6320e713-db17-4468-98d8-9eca68cef3da', 'effect', 'The medicine had an immediate effect.', '这药立刻见效了。'),
  ('6320e713-db17-4468-98d8-9eca68cef3da-ex2', '6320e713-db17-4468-98d8-9eca68cef3da', 'effect', 'The new regulations take effect next quarter and will apply retroactively to pending applications.', '新规将于下季度生效，并将追溯适用于待审申请。'),
  ('f04bd486-a254-4790-9a04-3105a233cab5-ex1', 'f04bd486-a254-4790-9a04-3105a233cab5', 'yeah', 'Yeah, that sounds like a good plan.', '对，听起来是个好计划。'),
  ('f04bd486-a254-4790-9a04-3105a233cab5-ex2', 'f04bd486-a254-4790-9a04-3105a233cab5', 'yeah', '"Yeah, the figures are accurate," the analyst confirmed, "though the methodology deserves scrutiny."', '“是的，这些数字是准确的，”分析师确认道，“不过其方法值得仔细推敲。”'),
  ('2ac387a4-000c-452e-8fee-d204c3dbe79c-ex1', '2ac387a4-000c-452e-8fee-d204c3dbe79c', 'suggest', 'I suggest we leave before dark.', '我建议我们天黑前出发。'),
  ('2ac387a4-000c-452e-8fee-d204c3dbe79c-ex2', '2ac387a4-000c-452e-8fee-d204c3dbe79c', 'suggest', 'Preliminary findings suggest a robust correlation between early intervention and improved outcomes.', '初步研究结果表明，早期干预与疗效改善之间存在显著相关性。'),
  ('ca87d943-a259-42aa-8c34-bf42a370e0d0-ex1', 'ca87d943-a259-42aa-8c34-bf42a370e0d0', 'class', 'My English class starts at nine.', '我的英语课九点开始。'),
  ('ca87d943-a259-42aa-8c34-bf42a370e0d0-ex2', 'ca87d943-a259-42aa-8c34-bf42a370e0d0', 'class', 'The litigation was certified as a class action encompassing several hundred thousand claimants.', '该诉讼被认定为集体诉讼，涉及数十万名索赔人。'),
  ('ae230764-bf46-41dd-a6fa-5ceded8e0830-ex1', 'ae230764-bf46-41dd-a6fa-5ceded8e0830', 'control', 'Please keep your dog under control.', '请管好你的狗。'),
  ('ae230764-bf46-41dd-a6fa-5ceded8e0830-ex2', 'ae230764-bf46-41dd-a6fa-5ceded8e0830', 'control', 'The legislation transfers control of the port authority to an independent oversight board.', '该立法将港务局的控制权移交给一个独立的监督委员会。'),
  ('490d0c7b-f305-4ce7-abe2-3a8832dd4023-ex1', '490d0c7b-f305-4ce7-abe2-3a8832dd4023', 'raise', 'Raise your hand if you have a question.', '有问题请举手。'),
  ('490d0c7b-f305-4ce7-abe2-3a8832dd4023-ex2', '490d0c7b-f305-4ce7-abe2-3a8832dd4023', 'raise', 'The foundation launched a campaign to raise funds for research into rare pediatric diseases.', '该基金会发起了一项为罕见儿科疾病研究筹款的活动。'),
  ('fc23dc28-53b7-4bad-a541-c5c52023fa2a-ex1', 'fc23dc28-53b7-4bad-a541-c5c52023fa2a', 'care', 'Take care of yourself.', '照顾好你自己。'),
  ('fc23dc28-53b7-4bad-a541-c5c52023fa2a-ex2', 'fc23dc28-53b7-4bad-a541-c5c52023fa2a', 'care', 'The commission documented serious deficiencies in the standard of care provided at the facility.', '委员会记录了该机构护理标准方面的严重缺陷。'),
  ('94069f73-03ce-4ce4-af8e-ac395c609c8c-ex1', '94069f73-03ce-4ce4-af8e-ac395c609c8c', 'perhaps', 'Perhaps we can meet tomorrow.', '也许我们明天可以见面。'),
  ('94069f73-03ce-4ce4-af8e-ac395c609c8c-ex2', '94069f73-03ce-4ce4-af8e-ac395c609c8c', 'perhaps', 'Perhaps the most consequential reform is the one that has attracted the least public attention.', '影响最深远的改革，或许恰恰是公众关注最少的那一项。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('91267ccd-525a-45a6-8eee-11f936447435-ex1', '91267ccd-525a-45a6-8eee-11f936447435', 'late', 'Sorry, I am late for class.', '对不起，我上课迟到了。'),
  ('91267ccd-525a-45a6-8eee-11f936447435-ex2', '91267ccd-525a-45a6-8eee-11f936447435', 'late', 'The report was submitted too late to influence the committee''s final deliberations.', '报告提交得太晚，未能影响委员会的最终审议。'),
  ('e407f488-6085-4ecd-9c68-afd4dd4d95b6-ex1', 'e407f488-6085-4ecd-9c68-afd4dd4d95b6', 'hard', 'This math problem is too hard.', '这道数学题太难了。'),
  ('e407f488-6085-4ecd-9c68-afd4dd4d95b6-ex2', 'e407f488-6085-4ecd-9c68-afd4dd4d95b6', 'hard', 'The commission worked hard to reconcile the competing demands of industry and environmental groups.', '委员会竭力调和产业界与环保团体之间相互冲突的诉求。'),
  ('93f046ff-9a34-4a6c-b6a9-5ed7ad87a8e5-ex1', '93f046ff-9a34-4a6c-b6a9-5ed7ad87a8e5', 'field', 'The children are playing in the field.', '孩子们正在田野里玩耍。'),
  ('93f046ff-9a34-4a6c-b6a9-5ed7ad87a8e5-ex2', '93f046ff-9a34-4a6c-b6a9-5ed7ad87a8e5', 'field', 'Her contributions to the field of immunology have earned her the discipline''s highest honors.', '她对免疫学领域的贡献为她赢得了该学科的最高荣誉。'),
  ('7d07d74d-5d75-46f3-8b23-670dcd23d5ca-ex1', '7d07d74d-5d75-46f3-8b23-670dcd23d5ca', 'else', 'What else do you need?', '你还需要什么？'),
  ('7d07d74d-5d75-46f3-8b23-670dcd23d5ca-ex2', '7d07d74d-5d75-46f3-8b23-670dcd23d5ca', 'else', 'If nothing else, the inquiry demonstrated how easily oversight mechanisms can be circumvented.', '即便没有其他成果，这次调查至少表明监督机制何其容易被规避。'),
  ('7da50b26-5ae3-40d7-b931-2811cfe02147-ex1', '7da50b26-5ae3-40d7-b931-2811cfe02147', 'pass', 'Did you pass the driving test?', '你通过驾照考试了吗？'),
  ('7da50b26-5ae3-40d7-b931-2811cfe02147-ex2', '7da50b26-5ae3-40d7-b931-2811cfe02147', 'pass', 'The legislature failed to pass the appropriations bill before the constitutional deadline.', '立法机构未能在宪法规定的期限前通过拨款法案。'),
  ('b192332f-d5a0-4425-9118-43d6ced7e9ae-ex1', 'b192332f-d5a0-4425-9118-43d6ced7e9ae', 'former', 'I met my former teacher yesterday.', '我昨天遇到了以前的老师。'),
  ('b192332f-d5a0-4425-9118-43d6ced7e9ae-ex2', 'b192332f-d5a0-4425-9118-43d6ced7e9ae', 'former', 'The former chief executive testified that the board had been fully apprised of the risks.', '前首席执行官作证称，董事会对相关风险完全知情。'),
  ('e2572ef9-4c47-4a7f-8e0c-074f55a97cef-ex1', 'e2572ef9-4c47-4a7f-8e0c-074f55a97cef', 'sell', 'They sell fresh bread every morning.', '他们每天早上卖新鲜面包。'),
  ('e2572ef9-4c47-4a7f-8e0c-074f55a97cef-ex2', 'e2572ef9-4c47-4a7f-8e0c-074f55a97cef', 'sell', 'The conglomerate was compelled to sell several subsidiaries to satisfy antitrust requirements.', '为满足反垄断要求，该企业集团被迫出售数家子公司。'),
  ('2d38c4fc-124a-403e-adbd-689ebd28234b-ex1', '2d38c4fc-124a-403e-adbd-689ebd28234b', 'major', 'Traffic is a major problem in this city.', '交通是这座城市的一大问题。'),
  ('2d38c4fc-124a-403e-adbd-689ebd28234b-ex2', '2d38c4fc-124a-403e-adbd-689ebd28234b', 'major', 'The discovery constitutes a major advance in our understanding of neurodegenerative disease.', '这一发现是我们认识神经退行性疾病的一项重大进展。'),
  ('073326cd-5f01-4599-83e7-e1ccb0c099b0-ex1', '073326cd-5f01-4599-83e7-e1ccb0c099b0', 'sometimes', 'Sometimes I walk to work.', '有时候我走路上班。'),
  ('073326cd-5f01-4599-83e7-e1ccb0c099b0-ex2', '073326cd-5f01-4599-83e7-e1ccb0c099b0', 'sometimes', 'Even the most rigorous models sometimes fail to anticipate abrupt shifts in market sentiment.', '即使是最严谨的模型，有时也无法预见市场情绪的突变。'),
  ('2e73e8ee-1e3c-483c-a5a9-2dc7cd8bd628-ex1', '2e73e8ee-1e3c-483c-a5a9-2dc7cd8bd628', 'require', 'This recipe requires three eggs.', '这个食谱需要三个鸡蛋。'),
  ('2e73e8ee-1e3c-483c-a5a9-2dc7cd8bd628-ex2', '2e73e8ee-1e3c-483c-a5a9-2dc7cd8bd628', 'require', 'The amended regulations require all listed firms to disclose climate-related financial risks.', '修订后的法规要求所有上市公司披露与气候相关的财务风险。'),
  ('16922abb-0363-459a-bed3-7a846d8b9a7c-ex1', '16922abb-0363-459a-bed3-7a846d8b9a7c', 'along', 'We walked along the river.', '我们沿着河边散步。'),
  ('16922abb-0363-459a-bed3-7a846d8b9a7c-ex2', '16922abb-0363-459a-bed3-7a846d8b9a7c', 'along', 'The pipeline runs along the coastline, traversing several ecologically sensitive zones.', '这条管道沿海岸线铺设，穿越多个生态敏感区。'),
  ('4dd4db54-6643-4016-a15f-a2281054e4b9-ex1', '4dd4db54-6643-4016-a15f-a2281054e4b9', 'development', 'The city is planning a new housing development.', '这座城市正在规划一个新的住宅区。'),
  ('4dd4db54-6643-4016-a15f-a2281054e4b9-ex2', '4dd4db54-6643-4016-a15f-a2281054e4b9', 'development', 'Sustainable development requires balancing economic growth against the preservation of natural resources.', '可持续发展需要在经济增长与自然资源保护之间取得平衡。'),
  ('1c6a79da-e2df-4ded-86c2-efaad70e7d61-ex1', '1c6a79da-e2df-4ded-86c2-efaad70e7d61', 'themselves', 'The kids made breakfast themselves.', '孩子们自己做了早餐。'),
  ('1c6a79da-e2df-4ded-86c2-efaad70e7d61-ex2', '1c6a79da-e2df-4ded-86c2-efaad70e7d61', 'themselves', 'The auditors themselves acknowledged that the existing controls were inadequate.', '审计人员自己也承认现有的控制措施并不充分。'),
  ('008ee55f-cb6b-4daf-811b-164e6eaa4661-ex1', '008ee55f-cb6b-4daf-811b-164e6eaa4661', 'report', 'I have to finish this report by Friday.', '我必须在周五前完成这份报告。'),
  ('008ee55f-cb6b-4daf-811b-164e6eaa4661-ex2', '008ee55f-cb6b-4daf-811b-164e6eaa4661', 'report', 'The commission''s final report documents systemic failures spanning more than a decade.', '委员会的最终报告记录了延续十余年的系统性失误。'),
  ('a69f0beb-6083-428a-a87c-97f07c6d56b9-ex1', 'a69f0beb-6083-428a-a87c-97f07c6d56b9', 'role', 'She got the leading role in the play.', '她得到了剧中的主角。'),
  ('a69f0beb-6083-428a-a87c-97f07c6d56b9-ex2', 'a69f0beb-6083-428a-a87c-97f07c6d56b9', 'role', 'Civil society organizations play an indispensable role in holding governments accountable.', '民间社会组织在督促政府问责方面发挥着不可或缺的作用。'),
  ('fa4b5313-0a16-4487-86cf-54c1c188d9cd-ex1', 'fa4b5313-0a16-4487-86cf-54c1c188d9cd', 'better', 'I feel much better today.', '我今天感觉好多了。'),
  ('fa4b5313-0a16-4487-86cf-54c1c188d9cd-ex2', 'fa4b5313-0a16-4487-86cf-54c1c188d9cd', 'better', 'The evidence suggests that early intervention produces consistently better outcomes than delayed treatment.', '证据表明，早期干预的效果始终优于延迟治疗。'),
  ('e3db5dc2-0106-4878-ac05-ed734e4b7f5a-ex1', 'e3db5dc2-0106-4878-ac05-ed734e4b7f5a', 'economic', 'The country is facing economic problems.', '这个国家正面临经济问题。'),
  ('e3db5dc2-0106-4878-ac05-ed734e4b7f5a-ex2', 'e3db5dc2-0106-4878-ac05-ed734e4b7f5a', 'economic', 'The sanctions inflicted severe economic damage while producing negligible political concessions.', '制裁造成了严重的经济损失，却几乎没有换来任何政治让步。'),
  ('c5ed8e6e-62d7-4c1c-8325-c925382e0740-ex1', 'c5ed8e6e-62d7-4c1c-8325-c925382e0740', 'effort', 'It takes a lot of effort to learn a language.', '学一门语言需要付出很多努力。'),
  ('c5ed8e6e-62d7-4c1c-8325-c925382e0740-ex2', 'c5ed8e6e-62d7-4c1c-8325-c925382e0740', 'effort', 'The reconstruction effort mobilized unprecedented resources from both public and private sectors.', '重建工作动员了来自公共和私营部门的空前资源。'),
  ('e9601635-0703-4ba2-801c-281058da82ed-ex1', 'e9601635-0703-4ba2-801c-281058da82ed', 'decide', 'I can''t decide what to wear.', '我决定不了穿什么。'),
  ('e9601635-0703-4ba2-801c-281058da82ed-ex2', 'e9601635-0703-4ba2-801c-281058da82ed', 'decide', 'The arbitration panel will decide whether the contested clause remains enforceable.', '仲裁庭将裁定争议条款是否仍具可执行性。'),
  ('75ea0b60-6fcc-4fd4-b807-62e1c67a88c3-ex1', '75ea0b60-6fcc-4fd4-b807-62e1c67a88c3', 'rate', 'The hotel offers a special weekend rate.', '这家酒店提供周末特价。'),
  ('75ea0b60-6fcc-4fd4-b807-62e1c67a88c3-ex2', '75ea0b60-6fcc-4fd4-b807-62e1c67a88c3', 'rate', 'The central bank raised its benchmark rate for the third consecutive quarter to curb inflation.', '为遏制通胀，央行连续第三个季度上调基准利率。'),
  ('e4fa4fd6-8aa7-4cfc-a861-30953ab249a1-ex1', 'e4fa4fd6-8aa7-4cfc-a861-30953ab249a1', 'strong', 'He is strong enough to lift that box.', '他力气够大，能搬起那个箱子。'),
  ('e4fa4fd6-8aa7-4cfc-a861-30953ab249a1-ex2', 'e4fa4fd6-8aa7-4cfc-a861-30953ab249a1', 'strong', 'The prosecution presented a strong circumstantial case supported by extensive forensic evidence.', '控方提出了有大量法医证据支持的有力间接证据链。'),
  ('2e5f3480-187f-45e9-aea5-d1de3a6838b3-ex1', '2e5f3480-187f-45e9-aea5-d1de3a6838b3', 'possible', 'Is it possible to change my ticket?', '可以改签我的票吗？'),
  ('2e5f3480-187f-45e9-aea5-d1de3a6838b3-ex2', '2e5f3480-187f-45e9-aea5-d1de3a6838b3', 'possible', 'The taskforce was instructed to explore every possible avenue for de-escalating the conflict.', '工作组受命探索缓和冲突的一切可能途径。'),
  ('e22758a7-b92f-45a1-ac7e-c2359fc6e8a2-ex1', 'e22758a7-b92f-45a1-ac7e-c2359fc6e8a2', 'heart', 'Running is good for your heart.', '跑步对心脏有好处。'),
  ('e22758a7-b92f-45a1-ac7e-c2359fc6e8a2-ex2', 'e22758a7-b92f-45a1-ac7e-c2359fc6e8a2', 'heart', 'The dispute over resource allocation lies at the heart of the broader institutional crisis.', '资源分配之争正是这场更大范围机构危机的核心所在。'),
  ('65697847-843d-485c-ba92-27f3010be645-ex1', '65697847-843d-485c-ba92-27f3010be645', 'drug', 'This drug should be taken after meals.', '这种药应该饭后服用。'),
  ('65697847-843d-485c-ba92-27f3010be645-ex2', '65697847-843d-485c-ba92-27f3010be645', 'drug', 'The regulator approved the drug after expedited review of the clinical trial data.', '监管机构在对临床试验数据进行加速审查后批准了该药物。'),
  ('d67e78c8-3ea8-4ae9-93eb-496585173a69-ex1', 'd67e78c8-3ea8-4ae9-93eb-496585173a69', 'leader', 'She is the leader of our team.', '她是我们团队的领导。'),
  ('d67e78c8-3ea8-4ae9-93eb-496585173a69-ex2', 'd67e78c8-3ea8-4ae9-93eb-496585173a69', 'leader', 'World leaders convened an emergency summit to coordinate their response to the crisis.', '世界各国领导人召开紧急峰会，协调应对这场危机。'),
  ('163b3ced-a035-44ac-916f-2a7ed10e17ae-ex1', '163b3ced-a035-44ac-916f-2a7ed10e17ae', 'light', 'Please turn on the light.', '请开灯。'),
  ('163b3ced-a035-44ac-916f-2a7ed10e17ae-ex2', '163b3ced-a035-44ac-916f-2a7ed10e17ae', 'light', 'The disclosures cast new light on the extent of the agency''s surveillance activities.', '这些披露的信息使该机构监控活动的范围进一步浮出水面。'),
  ('ba271892-a685-4d1b-bf81-ea8f6e17bf05-ex1', 'ba271892-a685-4d1b-bf81-ea8f6e17bf05', 'voice', 'She has a beautiful singing voice.', '她的歌喉很美。'),
  ('ba271892-a685-4d1b-bf81-ea8f6e17bf05-ex2', 'ba271892-a685-4d1b-bf81-ea8f6e17bf05', 'voice', 'The reforms give minority shareholders a stronger voice in corporate governance decisions.', '这些改革让小股东在公司治理决策中拥有更大的发言权。'),
  ('b893512b-f003-426c-8e9e-d2a3c1ff4651-ex1', 'b893512b-f003-426c-8e9e-d2a3c1ff4651', 'wife', 'His wife is a doctor.', '他的妻子是医生。'),
  ('b893512b-f003-426c-8e9e-d2a3c1ff4651-ex2', 'b893512b-f003-426c-8e9e-d2a3c1ff4651', 'wife', 'The ambassador and his wife hosted a reception honoring the visiting delegation.', '大使夫妇举行招待会，欢迎来访代表团。'),
  ('00284d74-0129-447d-8b11-99ea81a6eacd-ex1', '00284d74-0129-447d-8b11-99ea81a6eacd', 'whole', 'I spent the whole day cleaning.', '我打扫了一整天。'),
  ('00284d74-0129-447d-8b11-99ea81a6eacd-ex2', '00284d74-0129-447d-8b11-99ea81a6eacd', 'whole', 'The scandal undermined confidence not merely in one firm but in the whole financial system.', '这起丑闻动摇的不仅是一家公司的信誉，而是整个金融体系的公信力。'),
  ('623b5584-a3cf-4a70-96f1-fc9b1e705f39-ex1', '623b5584-a3cf-4a70-96f1-fc9b1e705f39', 'police', 'The police arrived within minutes.', '警察几分钟内就到了。'),
  ('623b5584-a3cf-4a70-96f1-fc9b1e705f39-ex2', '623b5584-a3cf-4a70-96f1-fc9b1e705f39', 'police', 'The commission recommended sweeping reforms to strengthen civilian oversight of the police.', '委员会建议进行全面改革，以加强对警察的文职监督。'),
  ('461f3713-69fc-4376-8421-e9a8ae37ac3e-ex1', '461f3713-69fc-4376-8421-e9a8ae37ac3e', 'mind', 'Do you mind if I open the window?', '你介意我开窗吗？'),
  ('461f3713-69fc-4376-8421-e9a8ae37ac3e-ex2', '461f3713-69fc-4376-8421-e9a8ae37ac3e', 'mind', 'The committee must keep in mind the long-term fiscal consequences of any proposed exemption.', '委员会必须牢记任何拟议豁免的长期财政后果。'),
  ('a8259b4e-01c7-4122-aa16-ed53db0df17e-ex1', 'a8259b4e-01c7-4122-aa16-ed53db0df17e', 'finally', 'The bus finally arrived.', '公交车终于来了。'),
  ('a8259b4e-01c7-4122-aa16-ed53db0df17e-ex2', 'a8259b4e-01c7-4122-aa16-ed53db0df17e', 'finally', 'After years of protracted negotiation, the treaty was finally ratified by all signatories.', '经过多年旷日持久的谈判，该条约最终获得所有签署国批准。'),
  ('4dc6ff28-95b6-4394-8db6-6b5ddeca8eb3-ex1', '4dc6ff28-95b6-4394-8db6-6b5ddeca8eb3', 'pull', 'Pull the door to open it.', '拉门即可打开。'),
  ('4dc6ff28-95b6-4394-8db6-6b5ddeca8eb3-ex2', '4dc6ff28-95b6-4394-8db6-6b5ddeca8eb3', 'pull', 'The sponsor threatened to pull its funding unless governance concerns were addressed promptly.', '赞助方威胁说，除非治理问题得到及时解决，否则将撤回资助。'),
  ('7e0fe2be-65af-4b4b-82c8-ec8028abb418-ex1', '7e0fe2be-65af-4b4b-82c8-ec8028abb418', 'return', 'When do you return from your trip?', '你什么时候旅行回来？'),
  ('7e0fe2be-65af-4b4b-82c8-ec8028abb418-ex2', '7e0fe2be-65af-4b4b-82c8-ec8028abb418', 'return', 'Investors demand a higher return to compensate for the elevated political risk.', '投资者要求更高的回报，以补偿升高的政治风险。'),
  ('b0be2a33-1714-4301-9371-0f6e8054a5c5-ex1', 'b0be2a33-1714-4301-9371-0f6e8054a5c5', 'free', 'The museum is free on Sundays.', '博物馆周日免费开放。'),
  ('b0be2a33-1714-4301-9371-0f6e8054a5c5-ex2', 'b0be2a33-1714-4301-9371-0f6e8054a5c5', 'free', 'The constitution guarantees a free press as an essential check on governmental power.', '宪法保障新闻自由，将其作为制约政府权力的重要手段。'),
  ('3f7c36f8-d36e-473d-b868-cfe0377451b3-ex1', '3f7c36f8-d36e-473d-b868-cfe0377451b3', 'military', 'He served in the military for ten years.', '他在军队服役了十年。'),
  ('3f7c36f8-d36e-473d-b868-cfe0377451b3-ex2', '3f7c36f8-d36e-473d-b868-cfe0377451b3', 'military', 'The treaty imposes strict limits on military deployments within the demilitarized zone.', '该条约对非军事区内的军事部署施加了严格限制。'),
  ('9ed18b05-6db0-449b-b55b-36157bd8543b-ex1', '9ed18b05-6db0-449b-b55b-36157bd8543b', 'price', 'What is the price of this jacket?', '这件夹克多少钱？'),
  ('9ed18b05-6db0-449b-b55b-36157bd8543b-ex2', '9ed18b05-6db0-449b-b55b-36157bd8543b', 'price', 'Energy price volatility has compelled manufacturers to renegotiate long-term supply contracts.', '能源价格波动迫使制造商重新谈判长期供应合同。'),
  ('ae3c86e0-c8b8-4500-ad57-e929b4adcf59-ex1', 'ae3c86e0-c8b8-4500-ad57-e929b4adcf59', 'less', 'I should eat less sugar.', '我应该少吃糖。'),
  ('ae3c86e0-c8b8-4500-ad57-e929b4adcf59-ex2', 'ae3c86e0-c8b8-4500-ad57-e929b4adcf59', 'less', 'The revised procedure is considerably less burdensome for applicants with limited documentation.', '修订后的程序对证明文件有限的申请人来说负担明显减轻。'),
  ('fe399f95-d5ab-491f-aaf5-92bebf00b24f-ex1', 'fe399f95-d5ab-491f-aaf5-92bebf00b24f', 'according', 'According to the weather report, it will snow.', '根据天气预报，要下雪了。'),
  ('fe399f95-d5ab-491f-aaf5-92bebf00b24f-ex2', 'fe399f95-d5ab-491f-aaf5-92bebf00b24f', 'according', 'According to the audited statements, liabilities had been understated by a considerable margin.', '根据经审计的报表，负债被低估了相当大的幅度。'),
  ('f3e03719-9e52-499e-b528-39d1621314ac-ex1', 'f3e03719-9e52-499e-b528-39d1621314ac', 'decision', 'It was a difficult decision to make.', '这是一个很难做的决定。'),
  ('f3e03719-9e52-499e-b528-39d1621314ac-ex2', 'f3e03719-9e52-499e-b528-39d1621314ac', 'decision', 'The court''s decision clarifies the circumstances under which digital evidence is admissible.', '法院的判决厘清了数字证据可被采纳的具体情形。'),
  ('c891abe9-3607-461a-8800-3b538f965f7a-ex1', 'c891abe9-3607-461a-8800-3b538f965f7a', 'explain', 'Can you explain this rule to me?', '你能给我解释一下这条规则吗？'),
  ('c891abe9-3607-461a-8800-3b538f965f7a-ex2', 'c891abe9-3607-461a-8800-3b538f965f7a', 'explain', 'The agency was summoned before the committee to explain the discrepancies in its accounts.', '该机构被传唤至委员会，就账目中的不一致之处作出解释。'),
  ('cd5b0ae7-9d99-4873-a4c9-bdc925546a44-ex1', 'cd5b0ae7-9d99-4873-a4c9-bdc925546a44', 'son', 'Her son is learning to play piano.', '她儿子在学钢琴。'),
  ('cd5b0ae7-9d99-4873-a4c9-bdc925546a44-ex2', 'cd5b0ae7-9d99-4873-a4c9-bdc925546a44', 'son', 'The estate passes to the eldest son only in the absence of a valid testamentary instrument.', '只有在没有有效遗嘱文件的情况下，遗产才由长子继承。'),
  ('d078b16e-24d2-4c58-9290-3dc5fbf235dc-ex1', 'd078b16e-24d2-4c58-9290-3dc5fbf235dc', 'hope', 'I hope you feel better soon.', '希望你早日康复。'),
  ('d078b16e-24d2-4c58-9290-3dc5fbf235dc-ex2', 'd078b16e-24d2-4c58-9290-3dc5fbf235dc', 'hope', 'The breakthrough offers renewed hope to patients for whom conventional therapies have failed.', '这一突破为常规疗法无效的患者带来了新的希望。'),
  ('fac643b6-d40d-417d-8588-641d2dfd76a2-ex1', 'fac643b6-d40d-417d-8588-641d2dfd76a2', 'develop', 'Children develop quickly in their first years.', '孩子在最初几年成长很快。'),
  ('fac643b6-d40d-417d-8588-641d2dfd76a2-ex2', 'fac643b6-d40d-417d-8588-641d2dfd76a2', 'develop', 'The consortium was formed to develop vaccines against pathogens of pandemic potential.', '该联盟的成立旨在研发针对具有大流行潜力病原体的疫苗。'),
  ('2cb07abc-7a3a-4550-a982-365986ac05f1-ex1', '2cb07abc-7a3a-4550-a982-365986ac05f1', 'view', 'The room has a great view of the sea.', '这个房间能看到很美的海景。'),
  ('2cb07abc-7a3a-4550-a982-365986ac05f1-ex2', '2cb07abc-7a3a-4550-a982-365986ac05f1', 'view', 'The court took the view that the contested provision exceeded the legislature''s constitutional authority.', '法院认为，争议条款超出了立法机关的宪法权限。'),
  ('82c94959-36a7-4023-a336-415915d20e3e-ex1', '82c94959-36a7-4023-a336-415915d20e3e', 'relationship', 'They have a very close relationship.', '他们的关系非常亲密。'),
  ('82c94959-36a7-4023-a336-415915d20e3e-ex2', '82c94959-36a7-4023-a336-415915d20e3e', 'relationship', 'The study illuminates the complex relationship between socioeconomic status and health outcomes.', '该研究揭示了社会经济地位与健康结果之间的复杂关系。'),
  ('8f47e637-d4da-4430-8339-3ad4d75ad67c-ex1', '8f47e637-d4da-4430-8339-3ad4d75ad67c', 'carry', 'Let me carry that heavy bag for you.', '让我帮你提那个重包吧。'),
  ('8f47e637-d4da-4430-8339-3ad4d75ad67c-ex2', '8f47e637-d4da-4430-8339-3ad4d75ad67c', 'carry', 'Violations of the disclosure requirements carry penalties of up to ten percent of annual turnover.', '违反披露要求将面临最高相当于年营业额百分之十的处罚。'),
  ('5f9d0e3c-a0d5-4fb5-ae5c-7da612669deb-ex1', '5f9d0e3c-a0d5-4fb5-ae5c-7da612669deb', 'town', 'We live in a small town.', '我们住在一个小镇上。'),
  ('5f9d0e3c-a0d5-4fb5-ae5c-7da612669deb-ex2', '5f9d0e3c-a0d5-4fb5-ae5c-7da612669deb', 'town', 'The factory closure devastated a town whose economy had depended on manufacturing for generations.', '工厂倒闭重创了这座几代人以制造业为生的城镇。'),
  ('2ecc413d-d9c9-4a37-bf32-ee22f03f48cf-ex1', '2ecc413d-d9c9-4a37-bf32-ee22f03f48cf', 'road', 'This road leads to the airport.', '这条路通往机场。'),
  ('2ecc413d-d9c9-4a37-bf32-ee22f03f48cf-ex2', '2ecc413d-d9c9-4a37-bf32-ee22f03f48cf', 'road', 'The infrastructure bill allocates substantial funds for the rehabilitation of rural road networks.', '基础设施法案为农村公路网的修复拨付了大量资金。'),
  ('4b4794f6-2f0a-4c84-94b1-cb98de834b30-ex1', '4b4794f6-2f0a-4c84-94b1-cb98de834b30', 'drive', 'Can you drive me to the station?', '你能开车送我去车站吗？'),
  ('4b4794f6-2f0a-4c84-94b1-cb98de834b30-ex2', '4b4794f6-2f0a-4c84-94b1-cb98de834b30', 'drive', 'Technological innovation continues to drive productivity gains across the manufacturing sector.', '技术创新持续推动制造业生产率的提升。'),
  ('f7b17d9d-4953-46f2-92c5-8e37f13dc60d-ex1', 'f7b17d9d-4953-46f2-92c5-8e37f13dc60d', 'arm', 'He broke his arm playing football.', '他踢足球时摔断了胳膊。'),
  ('f7b17d9d-4953-46f2-92c5-8e37f13dc60d-ex2', 'f7b17d9d-4953-46f2-92c5-8e37f13dc60d', 'arm', 'The investigative arm of the agency operates independently of its policy divisions.', '该机构的调查部门独立于其政策部门运作。'),
  ('c1171a5a-3203-4f70-94f0-b2592abde347-ex1', 'c1171a5a-3203-4f70-94f0-b2592abde347', 'true', 'Is it true that you are moving?', '你要搬家是真的吗？'),
  ('c1171a5a-3203-4f70-94f0-b2592abde347-ex2', 'c1171a5a-3203-4f70-94f0-b2592abde347', 'true', 'The allegations, if proven true, would constitute grounds for immediate disqualification.', '这些指控一旦被证实，将构成立即取消资格的理由。'),
  ('3f541aa0-8711-4b21-860d-3aa8554b1152-ex1', '3f541aa0-8711-4b21-860d-3aa8554b1152', 'federal', 'He works for the federal government.', '他在联邦政府工作。'),
  ('3f541aa0-8711-4b21-860d-3aa8554b1152-ex2', '3f541aa0-8711-4b21-860d-3aa8554b1152', 'federal', 'The federal courts retain exclusive jurisdiction over disputes arising under the statute.', '联邦法院对依据该法规产生的争议保留专属管辖权。'),
  ('9e8ab871-3c09-4979-aeaa-9fe5c34b44d1-ex1', '9e8ab871-3c09-4979-aeaa-9fe5c34b44d1', 'break', 'Let''s take a short break.', '我们休息一下吧。'),
  ('9e8ab871-3c09-4979-aeaa-9fe5c34b44d1-ex2', '9e8ab871-3c09-4979-aeaa-9fe5c34b44d1', 'break', 'Regulators moved decisively to break the monopoly that had stifled competition for decades.', '监管机构果断出手，打破了数十年来抑制竞争的垄断格局。'),
  ('3371266c-51ca-4ba7-bdb4-f533860c50e1-ex1', '3371266c-51ca-4ba7-bdb4-f533860c50e1', 'difference', 'What is the difference between these two?', '这两个有什么区别？'),
  ('3371266c-51ca-4ba7-bdb4-f533860c50e1-ex2', '3371266c-51ca-4ba7-bdb4-f533860c50e1', 'difference', 'The study found no statistically significant difference between the treatment and control groups.', '研究发现治疗组与对照组之间没有统计学上的显著差异。'),
  ('3acc3216-c71f-4fb0-9611-70b57250f403-ex1', '3acc3216-c71f-4fb0-9611-70b57250f403', 'thank', 'Thank you for your help.', '谢谢你的帮助。'),
  ('3acc3216-c71f-4fb0-9611-70b57250f403-ex2', '3acc3216-c71f-4fb0-9611-70b57250f403', 'thank', 'I wish to thank the distinguished delegates for their constructive engagement throughout the proceedings.', '我谨感谢各位尊敬的代表在整个议程中的建设性参与。'),
  ('b6557a54-edd5-4467-a82c-6c11f9a0f6b0-ex1', 'b6557a54-edd5-4467-a82c-6c11f9a0f6b0', 'receive', 'Did you receive my email?', '你收到我的邮件了吗？'),
  ('b6557a54-edd5-4467-a82c-6c11f9a0f6b0-ex2', 'b6557a54-edd5-4467-a82c-6c11f9a0f6b0', 'receive', 'Eligible households will receive direct assistance proportionate to their documented losses.', '符合条件的家庭将按其登记在册的损失比例获得直接援助。'),
  ('0f740075-bc25-49af-ab4a-e4d79b4427ad-ex1', '0f740075-bc25-49af-ab4a-e4d79b4427ad', 'value', 'This old watch has great value to me.', '这块旧手表对我来说意义重大。'),
  ('0f740075-bc25-49af-ab4a-e4d79b4427ad-ex2', '0f740075-bc25-49af-ab4a-e4d79b4427ad', 'value', 'The acquisition was completed at a value substantially exceeding initial market estimates.', '这笔收购的成交价值大大超出了最初的市场预估。'),
  ('c3105b8c-562b-48e0-8784-423bc3facdaa-ex1', 'c3105b8c-562b-48e0-8784-423bc3facdaa', 'international', 'She works for an international company.', '她在一家国际公司工作。'),
  ('c3105b8c-562b-48e0-8784-423bc3facdaa-ex2', 'c3105b8c-562b-48e0-8784-423bc3facdaa', 'international', 'The dispute has been referred to international arbitration under the terms of the treaty.', '根据条约条款，该争端已提交国际仲裁。'),
  ('8c432ac2-2ba8-4263-838a-076e301dca1f-ex1', '8c432ac2-2ba8-4263-838a-076e301dca1f', 'building', 'Our office is in that tall building.', '我们的办公室在那栋高楼里。'),
  ('8c432ac2-2ba8-4263-838a-076e301dca1f-ex2', '8c432ac2-2ba8-4263-838a-076e301dca1f', 'building', 'The historic building was granted protected status following a lengthy preservation campaign.', '经过长期的保护运动，这座历史建筑获得了受保护地位。'),
  ('d18eaffc-af28-411a-83e5-ad855eff4dd9-ex1', 'd18eaffc-af28-411a-83e5-ad855eff4dd9', 'action', 'We need to take action now.', '我们现在需要采取行动。'),
  ('d18eaffc-af28-411a-83e5-ad855eff4dd9-ex2', 'd18eaffc-af28-411a-83e5-ad855eff4dd9', 'action', 'The regulator commenced enforcement action against several firms for systematic misreporting.', '监管机构对多家系统性虚报的公司启动了执法行动。'),
  ('d080b730-53ba-4a02-86f4-4d761b8ac8e2-ex1', 'd080b730-53ba-4a02-86f4-4d761b8ac8e2', 'full', 'The parking lot is full.', '停车场满了。'),
  ('d080b730-53ba-4a02-86f4-4d761b8ac8e2-ex2', 'd080b730-53ba-4a02-86f4-4d761b8ac8e2', 'full', 'The commission demanded full disclosure of all communications relating to the transaction.', '委员会要求全面披露与该交易有关的所有通信记录。'),
  ('e10e366d-cda4-42ae-a30a-3ef4e116df6c-ex1', 'e10e366d-cda4-42ae-a30a-3ef4e116df6c', 'model', 'She built a model of the solar system.', '她做了一个太阳系模型。'),
  ('e10e366d-cda4-42ae-a30a-3ef4e116df6c-ex2', 'e10e366d-cda4-42ae-a30a-3ef4e116df6c', 'model', 'The forecasting model integrates demographic trends with high-frequency economic indicators.', '该预测模型将人口趋势与高频经济指标相结合。'),
  ('bced2d20-1209-4aaf-a39c-ce94c0fdd6d5-ex1', 'bced2d20-1209-4aaf-a39c-ce94c0fdd6d5', 'join', 'Would you like to join us for lunch?', '你想和我们一起吃午饭吗？'),
  ('bced2d20-1209-4aaf-a39c-ce94c0fdd6d5-ex2', 'bced2d20-1209-4aaf-a39c-ce94c0fdd6d5', 'join', 'Several additional states have signaled their intention to join the regional trade compact.', '另有几个州已表示有意加入该区域贸易协定。'),
  ('d6476c36-8816-43ff-b449-4f8036cf54a2-ex1', 'd6476c36-8816-43ff-b449-4f8036cf54a2', 'season', 'Autumn is my favorite season.', '秋天是我最喜欢的季节。'),
  ('d6476c36-8816-43ff-b449-4f8036cf54a2-ex2', 'd6476c36-8816-43ff-b449-4f8036cf54a2', 'season', 'The prolonged dry season has severely depleted reservoirs across the agricultural heartland.', '持续的旱季使农业腹地各处的水库蓄水严重不足。'),
  ('35ce1cba-fc6c-46ff-9038-c00066a5404c-ex1', '35ce1cba-fc6c-46ff-9038-c00066a5404c', 'society', 'We live in a fast-changing society.', '我们生活在一个快速变化的社会中。'),
  ('35ce1cba-fc6c-46ff-9038-c00066a5404c-ex2', '35ce1cba-fc6c-46ff-9038-c00066a5404c', 'society', 'An open society depends upon institutions capable of withstanding partisan manipulation.', '开放社会有赖于能够抵御党派操纵的制度。'),
  ('7b24a3a6-303b-41b4-8191-84c9d69ce5e2-ex1', '7b24a3a6-303b-41b4-8191-84c9d69ce5e2', 'tax', 'The price includes tax.', '价格已含税。'),
  ('7b24a3a6-303b-41b4-8191-84c9d69ce5e2-ex2', '7b24a3a6-303b-41b4-8191-84c9d69ce5e2', 'tax', 'The proposed carbon tax would be levied progressively according to verified emission volumes.', '拟议的碳税将根据核实的排放量累进征收。'),
  ('465c917f-41bd-4563-88a2-1a9e6ccfa423-ex1', '465c917f-41bd-4563-88a2-1a9e6ccfa423', 'director', 'The director is shooting a new film.', '那位导演正在拍摄一部新电影。'),
  ('465c917f-41bd-4563-88a2-1a9e6ccfa423-ex2', '465c917f-41bd-4563-88a2-1a9e6ccfa423', 'director', 'The board appointed an interim director pending the outcome of the executive search.', '在高管遴选结果揭晓之前，董事会任命了一位临时主管。'),
  ('927315b6-7b5d-44a7-a815-44f69e276d89-ex1', '927315b6-7b5d-44a7-a815-44f69e276d89', 'position', 'She applied for a teaching position.', '她申请了一个教师职位。'),
  ('927315b6-7b5d-44a7-a815-44f69e276d89-ex2', '927315b6-7b5d-44a7-a815-44f69e276d89', 'position', 'The delegation reaffirmed its position that any settlement must include verifiable guarantees.', '代表团重申其立场：任何解决方案都必须包含可核查的保证。'),
  ('656aa48e-5bed-45ec-a2c3-f775289bd64a-ex1', '656aa48e-5bed-45ec-a2c3-f775289bd64a', 'player', 'He is the best player on our team.', '他是我们队最优秀的球员。'),
  ('656aa48e-5bed-45ec-a2c3-f775289bd64a-ex2', '656aa48e-5bed-45ec-a2c3-f775289bd64a', 'player', 'The company has emerged as a dominant player in the global semiconductor market.', '该公司已成为全球半导体市场的主导企业。'),
  ('c3ed9775-1461-4427-88f9-c4933765cf4c-ex1', 'c3ed9775-1461-4427-88f9-c4933765cf4c', 'agree', 'I agree with your opinion.', '我同意你的看法。'),
  ('c3ed9775-1461-4427-88f9-c4933765cf4c-ex2', 'c3ed9775-1461-4427-88f9-c4933765cf4c', 'agree', 'The parties agree to submit any unresolved disputes to binding arbitration.', '双方同意将任何未解决的争议提交具有约束力的仲裁。'),
  ('0805fdf2-9fe7-4ca2-9bbe-530cdd3654db-ex1', '0805fdf2-9fe7-4ca2-9bbe-530cdd3654db', 'especially', 'I love fruit, especially mangoes.', '我爱吃水果，尤其是芒果。'),
  ('0805fdf2-9fe7-4ca2-9bbe-530cdd3654db-ex2', '0805fdf2-9fe7-4ca2-9bbe-530cdd3654db', 'especially', 'The downturn has been especially severe in regions dependent on export manufacturing.', '经济下行在依赖出口制造业的地区尤为严重。'),
  ('2f99b35c-bae1-4e69-a4aa-755935e2c974-ex1', '2f99b35c-bae1-4e69-a4aa-755935e2c974', 'record', 'Keep a record of your spending.', '记录一下你的开支。'),
  ('2f99b35c-bae1-4e69-a4aa-755935e2c974-ex2', '2f99b35c-bae1-4e69-a4aa-755935e2c974', 'record', 'The tribunal examined the documentary record spanning more than two decades of transactions.', '法庭审查了跨越二十多年交易的书面记录。'),
  ('dbc90337-d899-49b0-bcac-d1057e95f7a5-ex1', 'dbc90337-d899-49b0-bcac-d1057e95f7a5', 'pick', 'Pick a card, any card.', '挑一张牌，随便哪张。'),
  ('dbc90337-d899-49b0-bcac-d1057e95f7a5-ex2', 'dbc90337-d899-49b0-bcac-d1057e95f7a5', 'pick', 'The committee will pick the successful candidate from a shortlist compiled by independent assessors.', '委员会将从独立评审人拟定的候选名单中选出最终人选。'),
  ('71e00bb7-b582-4a03-9515-14e352889a5c-ex1', '71e00bb7-b582-4a03-9515-14e352889a5c', 'wear', 'You should wear a coat today.', '你今天应该穿件外套。'),
  ('71e00bb7-b582-4a03-9515-14e352889a5c-ex2', '71e00bb7-b582-4a03-9515-14e352889a5c', 'wear', 'All personnel entering the facility must wear certified protective equipment at all times.', '进入该设施的所有人员必须全程佩戴经认证的防护装备。'),
  ('4eed26bb-a5e5-4a11-a401-b2f23de150a4-ex1', '4eed26bb-a5e5-4a11-a401-b2f23de150a4', 'paper', 'I need some paper to write on.', '我需要一些纸来写字。'),
  ('4eed26bb-a5e5-4a11-a401-b2f23de150a4-ex2', '4eed26bb-a5e5-4a11-a401-b2f23de150a4', 'paper', 'Her seminal paper on quantum computation has been cited several thousand times.', '她那篇关于量子计算的开创性论文已被引用数千次。'),
  ('54f95fa4-9d6e-4286-8cc7-75e16d85247c-ex1', '54f95fa4-9d6e-4286-8cc7-75e16d85247c', 'special', 'This is a special day for our family.', '今天对我们家来说是特别的日子。'),
  ('54f95fa4-9d6e-4286-8cc7-75e16d85247c-ex2', '54f95fa4-9d6e-4286-8cc7-75e16d85247c', 'special', 'The envoy was granted special authority to negotiate directly with all parties to the conflict.', '这位特使获授特别权限，可与冲突各方直接谈判。'),
  ('b92714bf-41a6-4a57-950e-6878b2dcef7d-ex1', 'b92714bf-41a6-4a57-950e-6878b2dcef7d', 'space', 'There is no space for another table.', '没有地方再放一张桌子了。'),
  ('b92714bf-41a6-4a57-950e-6878b2dcef7d-ex2', 'b92714bf-41a6-4a57-950e-6878b2dcef7d', 'space', 'The treaty governs the peaceful exploration of outer space by all signatory nations.', '该条约规范所有签署国对外层空间的和平探索。'),
  ('4cb9f40b-4d02-472d-a0d9-eaf80a56d589-ex1', '4cb9f40b-4d02-472d-a0d9-eaf80a56d589', 'ground', 'The ground is wet after the rain.', '雨后地面是湿的。'),
  ('4cb9f40b-4d02-472d-a0d9-eaf80a56d589-ex2', '4cb9f40b-4d02-472d-a0d9-eaf80a56d589', 'ground', 'The appeal was dismissed on the ground that no procedural irregularity had been established.', '上诉因未能证实存在程序违规而被驳回。'),
  ('4f95943c-5f36-47a1-89a3-d56d333172ea-ex1', '4f95943c-5f36-47a1-89a3-d56d333172ea', 'form', 'Please fill out this form.', '请填写这张表格。'),
  ('4f95943c-5f36-47a1-89a3-d56d333172ea-ex2', '4f95943c-5f36-47a1-89a3-d56d333172ea', 'form', 'The committee endorsed a revised form of the proposal that addressed earlier objections.', '委员会批准了提案的修订版本，该版本回应了此前的异议。'),
  ('98b7815d-12a5-4748-b463-efeaedd6bea5-ex1', '98b7815d-12a5-4748-b463-efeaedd6bea5', 'support', 'Thank you for your support.', '谢谢你的支持。'),
  ('98b7815d-12a5-4748-b463-efeaedd6bea5-ex2', '98b7815d-12a5-4748-b463-efeaedd6bea5', 'support', 'The resolution received overwhelming support from delegates across the political spectrum.', '该决议获得了各政治派别代表的压倒性支持。'),
  ('1bbc8c7f-6829-4e58-b5ea-cd86d42c3a8a-ex1', '1bbc8c7f-6829-4e58-b5ea-cd86d42c3a8a', 'event', 'The school is hosting a charity event.', '学校正在举办一场慈善活动。'),
  ('1bbc8c7f-6829-4e58-b5ea-cd86d42c3a8a-ex2', '1bbc8c7f-6829-4e58-b5ea-cd86d42c3a8a', 'event', 'In the event of a material breach, either party may terminate the agreement with immediate effect.', '如发生重大违约，任何一方均可立即终止本协议。'),
  ('c5b36e39-6dee-444f-af36-b0dca37246e8-ex1', 'c5b36e39-6dee-444f-af36-b0dca37246e8', 'official', 'The official opening is next week.', '正式开幕是下周。'),
  ('c5b36e39-6dee-444f-af36-b0dca37246e8-ex2', 'c5b36e39-6dee-444f-af36-b0dca37246e8', 'official', 'A senior official confirmed that the negotiations had entered their final phase.', '一位高级官员证实，谈判已进入最后阶段。'),
  ('79a5159d-6185-4e9d-b08c-dd1d65fd36b6-ex1', '79a5159d-6185-4e9d-b08c-dd1d65fd36b6', 'whose', 'Whose phone is this?', '这是谁的手机？'),
  ('79a5159d-6185-4e9d-b08c-dd1d65fd36b6-ex2', '79a5159d-6185-4e9d-b08c-dd1d65fd36b6', 'whose', 'The award honors researchers whose work has fundamentally advanced public understanding of science.', '该奖项表彰其研究从根本上增进了公众科学认知的学者。'),
  ('09e19f1c-302f-4846-9a03-45355a0e686f-ex1', '09e19f1c-302f-4846-9a03-45355a0e686f', 'matter', 'What''s the matter with you?', '你怎么了？'),
  ('09e19f1c-302f-4846-9a03-45355a0e686f-ex2', '09e19f1c-302f-4846-9a03-45355a0e686f', 'matter', 'The tribunal ruled that the matter fell squarely within its statutory jurisdiction.', '法庭裁定该事项完全属于其法定管辖范围。'),
  ('77ae4585-80dd-47a5-adc2-ac2b76802ec9-ex1', '77ae4585-80dd-47a5-adc2-ac2b76802ec9', 'everyone', 'Everyone enjoyed the party.', '每个人都玩得很开心。'),
  ('77ae4585-80dd-47a5-adc2-ac2b76802ec9-ex2', '77ae4585-80dd-47a5-adc2-ac2b76802ec9', 'everyone', 'The charter affirms that everyone is entitled to equal protection under the law.', '宪章申明人人都有权获得法律的平等保护。'),
  ('eb2bcff4-549c-488c-b838-c07bcd5b95d5-ex1', 'eb2bcff4-549c-488c-b838-c07bcd5b95d5', 'center', 'The shopping center is crowded today.', '购物中心今天很拥挤。'),
  ('eb2bcff4-549c-488c-b838-c07bcd5b95d5-ex2', 'eb2bcff4-549c-488c-b838-c07bcd5b95d5', 'center', 'The institute has become a leading center for interdisciplinary research on climate adaptation.', '该研究所已成为气候适应跨学科研究的重要中心。'),
  ('e560e5a0-6044-4502-b180-9c3856224663-ex1', 'e560e5a0-6044-4502-b180-9c3856224663', 'couple', 'The couple next door just got married.', '隔壁那对情侣刚结婚。'),
  ('e560e5a0-6044-4502-b180-9c3856224663-ex2', 'e560e5a0-6044-4502-b180-9c3856224663', 'couple', 'Within a couple of years, the technology had displaced processes that had endured for generations.', '短短几年内，这项技术就取代了沿用数代的工艺流程。'),
  ('88b103c6-dfe0-477e-8621-067c4e6636e5-ex1', '88b103c6-dfe0-477e-8621-067c4e6636e5', 'site', 'This is the site for the new library.', '这是新图书馆的选址。'),
  ('88b103c6-dfe0-477e-8621-067c4e6636e5-ex2', '88b103c6-dfe0-477e-8621-067c4e6636e5', 'site', 'Excavations at the archaeological site have yielded artifacts of extraordinary historical significance.', '这处考古遗址的发掘出土了具有重大历史意义的文物。'),
  ('b5b33669-83c6-49b4-8a59-cd65ff75726c-ex1', 'b5b33669-83c6-49b4-8a59-cd65ff75726c', 'project', 'Our science project is due Friday.', '我们的科学项目周五截止。'),
  ('b5b33669-83c6-49b4-8a59-cd65ff75726c-ex2', 'b5b33669-83c6-49b4-8a59-cd65ff75726c', 'project', 'The infrastructure project was suspended pending a comprehensive review of its environmental impact.', '该基础设施项目已暂停，等待对其环境影响进行全面评估。'),
  ('97430374-8f87-473a-8952-df28cd8dac62-ex1', '97430374-8f87-473a-8952-df28cd8dac62', 'hit', 'He hit the ball over the fence.', '他把球打过了围栏。'),
  ('97430374-8f87-473a-8952-df28cd8dac62-ex2', '97430374-8f87-473a-8952-df28cd8dac62', 'hit', 'The export sector was hit particularly hard by the abrupt imposition of retaliatory tariffs.', '报复性关税的突然实施使出口行业遭受了尤为沉重的打击。'),
  ('d8116c2b-24e7-4dce-9b1b-68ef29174079-ex1', 'd8116c2b-24e7-4dce-9b1b-68ef29174079', 'base', 'The lamp has a heavy base.', '这盏灯的底座很重。'),
  ('d8116c2b-24e7-4dce-9b1b-68ef29174079-ex2', 'd8116c2b-24e7-4dce-9b1b-68ef29174079', 'base', 'The projections are based on conservative assumptions regarding future demographic trends.', '这些预测建立在对未来人口趋势的保守假设之上。'),
  ('281b9d72-cc1a-43bb-81dd-f5a02c12a9a7-ex1', '281b9d72-cc1a-43bb-81dd-f5a02c12a9a7', 'activity', 'Swimming is my favorite activity.', '游泳是我最喜欢的活动。'),
  ('281b9d72-cc1a-43bb-81dd-f5a02c12a9a7-ex2', '281b9d72-cc1a-43bb-81dd-f5a02c12a9a7', 'activity', 'The agency monitors suspicious financial activity across multiple jurisdictions simultaneously.', '该机构同时监测多个司法管辖区内的可疑金融活动。'),
  ('6b610248-618e-4c47-ac9a-fe6dc83fe317-ex1', '6b610248-618e-4c47-ac9a-fe6dc83fe317', 'star', 'Look at the stars in the sky!', '看天上的星星！'),
  ('6b610248-618e-4c47-ac9a-fe6dc83fe317-ex2', '6b610248-618e-4c47-ac9a-fe6dc83fe317', 'star', 'The observatory documented the collapse of a massive star into an extraordinarily dense remnant.', '该天文台记录了一颗大质量恒星坍缩为致密残骸的过程。'),
  ('21962be6-ed92-489c-83f0-24d6df88adb9-ex1', '21962be6-ed92-489c-83f0-24d6df88adb9', 'table', 'The keys are on the kitchen table.', '钥匙在厨房的桌子上。'),
  ('21962be6-ed92-489c-83f0-24d6df88adb9-ex2', '21962be6-ed92-489c-83f0-24d6df88adb9', 'table', 'The delegation refused to return to the negotiating table until the preconditions were withdrawn.', '在先决条件撤回之前，代表团拒绝重返谈判桌。'),
  ('8548330d-5714-4c5f-abb1-e0f8f7dff2a4-ex1', '8548330d-5714-4c5f-abb1-e0f8f7dff2a4', 'court', 'The case will go to court next month.', '这个案子下个月开庭。'),
  ('8548330d-5714-4c5f-abb1-e0f8f7dff2a4-ex2', '8548330d-5714-4c5f-abb1-e0f8f7dff2a4', 'court', 'The supreme court agreed to review the constitutionality of the contested legislation.', '最高法院同意审查争议立法是否符合宪法。'),
  ('5aee702d-ce69-4b96-ba91-a5b9ac105eb7-ex1', '5aee702d-ce69-4b96-ba91-a5b9ac105eb7', 'produce', 'This farm produces fresh vegetables.', '这个农场生产新鲜蔬菜。'),
  ('5aee702d-ce69-4b96-ba91-a5b9ac105eb7-ex2', '5aee702d-ce69-4b96-ba91-a5b9ac105eb7', 'produce', 'The defendants were ordered to produce all internal correspondence relevant to the inquiry.', '被告被责令提交与调查相关的全部内部往来文件。'),
  ('8c32d78c-220c-4355-8898-f7d17f9babb9-ex1', '8c32d78c-220c-4355-8898-f7d17f9babb9', 'eat', 'Let''s eat dinner together tonight.', '今晚我们一起吃晚饭吧。'),
  ('8c32d78c-220c-4355-8898-f7d17f9babb9-ex2', '8c32d78c-220c-4355-8898-f7d17f9babb9', 'eat', 'Rising input costs have begun to eat into the margins of even the most efficient producers.', '不断上涨的投入成本已开始侵蚀即使是最高效生产商的利润。'),
  ('2fc63a60-57a5-49b7-8aed-f4c3c6badbfe-ex1', '2fc63a60-57a5-49b7-8aed-f4c3c6badbfe', 'teach', 'She teaches math at a high school.', '她在一所高中教数学。'),
  ('2fc63a60-57a5-49b7-8aed-f4c3c6badbfe-ex2', '2fc63a60-57a5-49b7-8aed-f4c3c6badbfe', 'teach', 'The program recruits accomplished professionals to teach in chronically understaffed rural schools.', '该项目招募资深专业人士到长期师资匮乏的乡村学校任教。'),
  ('a6e93160-018f-4f1d-a17f-3d4497902c27-ex1', 'a6e93160-018f-4f1d-a17f-3d4497902c27', 'oil', 'Add a little oil to the pan.', '往锅里加一点油。'),
  ('a6e93160-018f-4f1d-a17f-3d4497902c27-ex2', 'a6e93160-018f-4f1d-a17f-3d4497902c27', 'oil', 'The economy''s heavy dependence on oil exports leaves it acutely vulnerable to price shocks.', '该经济体对石油出口的高度依赖使其极易受到价格冲击的影响。'),
  ('a687def0-6969-4808-baf1-8ae04ea7625b-ex1', 'a687def0-6969-4808-baf1-8ae04ea7625b', 'half', 'I ate half of the apple.', '我吃了半个苹果。'),
  ('a687def0-6969-4808-baf1-8ae04ea7625b-ex2', 'a687def0-6969-4808-baf1-8ae04ea7625b', 'half', 'Nearly half of the surveyed enterprises reported difficulty in recruiting qualified technical staff.', '近半数受访企业表示在招聘合格技术人员方面存在困难。'),
  ('0fd0c71d-8328-4715-803a-d2b0f54dc16f-ex1', '0fd0c71d-8328-4715-803a-d2b0f54dc16f', 'situation', 'The situation is getting better.', '情况正在好转。'),
  ('0fd0c71d-8328-4715-803a-d2b0f54dc16f-ex2', '0fd0c71d-8328-4715-803a-d2b0f54dc16f', 'situation', 'The humanitarian situation deteriorated rapidly as supply routes into the region were severed.', '随着进入该地区的补给线被切断，人道主义局势迅速恶化。'),
  ('18b9a38f-f0a8-4e0d-9dd1-fb15bec9b238-ex1', '18b9a38f-f0a8-4e0d-9dd1-fb15bec9b238', 'easy', 'This recipe is quick and easy.', '这个食谱又快又简单。'),
  ('18b9a38f-f0a8-4e0d-9dd1-fb15bec9b238-ex2', '18b9a38f-f0a8-4e0d-9dd1-fb15bec9b238', 'easy', 'Prolonged access to easy credit encouraged levels of leverage that proved ultimately unsustainable.', '长期宽松的信贷环境助长了最终被证明不可持续的杠杆水平。'),
  ('e0fb0865-ae5d-4de3-a7e6-09882cefe294-ex1', 'e0fb0865-ae5d-4de3-a7e6-09882cefe294', 'cost', 'How much does this cost?', '这个多少钱？'),
  ('e0fb0865-ae5d-4de3-a7e6-09882cefe294-ex2', 'e0fb0865-ae5d-4de3-a7e6-09882cefe294', 'cost', 'The audit revealed that the true cost of the program had been systematically understated.', '审计显示，该项目的真实成本一直被系统性地低估。'),
  ('83ae8245-dd08-4fa1-aed5-c3f8af6c6c11-ex1', '83ae8245-dd08-4fa1-aed5-c3f8af6c6c11', 'industry', 'My uncle works in the car industry.', '我叔叔在汽车行业工作。'),
  ('83ae8245-dd08-4fa1-aed5-c3f8af6c6c11-ex2', '83ae8245-dd08-4fa1-aed5-c3f8af6c6c11', 'industry', 'The pharmaceutical industry has lobbied vigorously against the proposed pricing regulations.', '制药行业对拟议的定价法规进行了大力游说抵制。'),
  ('450a7916-db7d-405f-b6e5-cb44756f7f17-ex1', '450a7916-db7d-405f-b6e5-cb44756f7f17', 'figure', 'The sales figures look good this month.', '这个月的销售数字看起来不错。'),
  ('450a7916-db7d-405f-b6e5-cb44756f7f17-ex2', '450a7916-db7d-405f-b6e5-cb44756f7f17', 'figure', 'She remains a towering figure in twentieth-century theoretical physics.', '她仍然是二十世纪理论物理学界的一位泰斗级人物。'),
  ('cad89ec1-8c1a-4352-9521-e8e07ce3e0d9-ex1', 'cad89ec1-8c1a-4352-9521-e8e07ce3e0d9', 'street', 'The bakery is just down the street.', '面包店就在这条街往前一点。'),
  ('cad89ec1-8c1a-4352-9521-e8e07ce3e0d9-ex2', 'cad89ec1-8c1a-4352-9521-e8e07ce3e0d9', 'street', 'Thousands took to the streets to protest the abrupt repeal of the subsidies.', '数千人走上街头，抗议补贴被突然取消。'),
  ('a96f71f0-dbcb-4d5d-b7c9-4944336459d4-ex1', 'a96f71f0-dbcb-4d5d-b7c9-4944336459d4', 'image', 'The image on the screen is blurry.', '屏幕上的图像很模糊。'),
  ('a96f71f0-dbcb-4d5d-b7c9-4944336459d4-ex2', 'a96f71f0-dbcb-4d5d-b7c9-4944336459d4', 'image', 'The scandal inflicted lasting damage on the corporation''s carefully cultivated public image.', '这起丑闻对该公司精心营造的公众形象造成了持久损害。'),
  ('fa31ecc9-c244-4414-a7b5-225723393fc4-ex1', 'fa31ecc9-c244-4414-a7b5-225723393fc4', 'itself', 'The cat cleaned itself by the window.', '猫在窗边给自己梳理毛发。'),
  ('fa31ecc9-c244-4414-a7b5-225723393fc4-ex2', 'fa31ecc9-c244-4414-a7b5-225723393fc4', 'itself', 'The institution found itself unable to respond coherently to the unfolding crisis.', '该机构发现自己无法对不断发展的危机作出协调一致的回应。'),
  ('0648aefd-2092-482a-bf73-f742f0819fbc-ex1', '0648aefd-2092-482a-bf73-f742f0819fbc', 'phone', 'My phone is almost out of battery.', '我的手机快没电了。'),
  ('0648aefd-2092-482a-bf73-f742f0819fbc-ex2', '0648aefd-2092-482a-bf73-f742f0819fbc', 'phone', 'Investigators obtained judicial authorization to examine the suspect''s phone records.', '调查人员获得司法授权，查阅嫌疑人的电话记录。'),
  ('7b3031c7-e32e-4954-a41c-8871d3917ba5-ex1', '7b3031c7-e32e-4954-a41c-8871d3917ba5', 'either', 'You can sit on either side.', '你坐哪一边都可以。'),
  ('7b3031c7-e32e-4954-a41c-8871d3917ba5-ex2', '7b3031c7-e32e-4954-a41c-8871d3917ba5', 'either', 'Neither party may assign its obligations without the prior written consent of either counterpart.', '未经对方事先书面同意，任何一方均不得转让其义务。'),
  ('9762fb60-68e6-4845-990c-9b2b24c2d694-ex1', '9762fb60-68e6-4845-990c-9b2b24c2d694', 'data', 'The app collects data about your sleep.', '这个应用会收集你的睡眠数据。'),
  ('9762fb60-68e6-4845-990c-9b2b24c2d694-ex2', '9762fb60-68e6-4845-990c-9b2b24c2d694', 'data', 'The regulation imposes strict requirements on the cross-border transfer of personal data.', '该法规对个人数据的跨境传输规定了严格要求。'),
  ('d83c1619-6c26-4c28-85fd-3f1e4a38b384-ex1', 'd83c1619-6c26-4c28-85fd-3f1e4a38b384', 'cover', 'Cover the pot and let it simmer.', '盖上锅盖让它慢炖。'),
  ('d83c1619-6c26-4c28-85fd-3f1e4a38b384-ex2', 'd83c1619-6c26-4c28-85fd-3f1e4a38b384', 'cover', 'The insurance policy does not cover losses arising from acts of deliberate negligence.', '该保险单不承保因故意疏忽行为造成的损失。'),
  ('c81a5356-d552-436d-beb7-585529f3403d-ex1', 'c81a5356-d552-436d-beb7-585529f3403d', 'quite', 'The movie was quite good.', '这部电影相当不错。'),
  ('c81a5356-d552-436d-beb7-585529f3403d-ex2', 'c81a5356-d552-436d-beb7-585529f3403d', 'quite', 'The outcomes proved quite different from what the original projections had suggested.', '实际结果与最初预测所显示的情况大相径庭。'),
  ('0dedc3c1-05dc-482d-819f-dc7c04c8508d-ex1', '0dedc3c1-05dc-482d-819f-dc7c04c8508d', 'picture', 'She showed me a picture of her dog.', '她给我看了她的狗的照片。'),
  ('0dedc3c1-05dc-482d-819f-dc7c04c8508d-ex2', '0dedc3c1-05dc-482d-819f-dc7c04c8508d', 'picture', 'The leaked documents paint a troubling picture of systematic regulatory evasion.', '泄露的文件描绘出一幅系统性规避监管的令人不安的图景。'),
  ('5cf46fa1-2cb4-4f0e-b3ab-2ae53d8dc97b-ex1', '5cf46fa1-2cb4-4f0e-b3ab-2ae53d8dc97b', 'clear', 'The sky is clear tonight.', '今晚天空晴朗。'),
  ('5cf46fa1-2cb4-4f0e-b3ab-2ae53d8dc97b-ex2', '5cf46fa1-2cb4-4f0e-b3ab-2ae53d8dc97b', 'clear', 'The legislation establishes clear lines of accountability for failures in data protection.', '该立法为数据保护方面的失职确立了清晰的问责界限。'),
  ('71c0011b-0673-4348-a665-af1c0eaecd6c-ex1', '71c0011b-0673-4348-a665-af1c0eaecd6c', 'practice', 'Practice makes perfect.', '熟能生巧。'),
  ('71c0011b-0673-4348-a665-af1c0eaecd6c-ex2', '71c0011b-0673-4348-a665-af1c0eaecd6c', 'practice', 'The commission condemned the practice of awarding contracts without competitive bidding.', '委员会谴责了不经竞争性招标就授予合同的做法。'),
  ('c8a0bf9a-ebdb-469c-89c2-ab6ecbf84f80-ex1', 'c8a0bf9a-ebdb-469c-89c2-ab6ecbf84f80', 'piece', 'Would you like a piece of cake?', '你想来一块蛋糕吗？'),
  ('c8a0bf9a-ebdb-469c-89c2-ab6ecbf84f80-ex2', 'c8a0bf9a-ebdb-469c-89c2-ab6ecbf84f80', 'piece', 'The investigative piece exposed irregularities that prompted three separate official inquiries.', '这篇调查报道揭露的违规行为引发了三项独立的官方调查。'),
  ('6b4d1f77-d08d-4740-8e6b-398c31775055-ex1', '6b4d1f77-d08d-4740-8e6b-398c31775055', 'land', 'The farmers work on the land every day.', '农民们每天在田地里劳作。'),
  ('6b4d1f77-d08d-4740-8e6b-398c31775055-ex2', '6b4d1f77-d08d-4740-8e6b-398c31775055', 'land', 'The statute restricts the acquisition of agricultural land by foreign investment entities.', '该法规限制外国投资实体购置农业用地。'),
  ('be73c6f0-2c48-48ed-b2df-fc77d41bec8f-ex1', 'be73c6f0-2c48-48ed-b2df-fc77d41bec8f', 'recent', 'Have you seen any good movies in recent weeks?', '最近几周你看过什么好电影吗？'),
  ('be73c6f0-2c48-48ed-b2df-fc77d41bec8f-ex2', 'be73c6f0-2c48-48ed-b2df-fc77d41bec8f', 'recent', 'Recent advances in gene sequencing have dramatically reduced the cost of personalized diagnostics.', '基因测序的最新进展大幅降低了个性化诊断的成本。'),
  ('b04268fc-c835-4bba-a78c-c61a625a0b5b-ex1', 'b04268fc-c835-4bba-a78c-c61a625a0b5b', 'describe', 'Can you describe what he looks like?', '你能描述一下他的长相吗？'),
  ('b04268fc-c835-4bba-a78c-c61a625a0b5b-ex2', 'b04268fc-c835-4bba-a78c-c61a625a0b5b', 'describe', 'Witnesses describe a chaotic evacuation hampered by inadequate emergency planning.', '目击者描述了一场因应急规划不足而受阻的混乱疏散。'),
  ('5c893ce6-f329-4e8e-aee3-c4753a524d6a-ex1', '5c893ce6-f329-4e8e-aee3-c4753a524d6a', 'product', 'This store sells local products.', '这家店出售本地产品。'),
  ('5c893ce6-f329-4e8e-aee3-c4753a524d6a-ex2', '5c893ce6-f329-4e8e-aee3-c4753a524d6a', 'product', 'Manufacturers must demonstrate that each product complies with the harmonized safety standards.', '制造商必须证明每件产品都符合统一的安全标准。'),
  ('2249227f-bea7-41bf-a793-25508feba6a6-ex1', '2249227f-bea7-41bf-a793-25508feba6a6', 'doctor', 'You should see a doctor about that cough.', '你咳嗽应该去看医生。'),
  ('2249227f-bea7-41bf-a793-25508feba6a6-ex2', '2249227f-bea7-41bf-a793-25508feba6a6', 'doctor', 'The shortage of doctors in rural districts has reached what officials describe as crisis proportions.', '农村地区医生短缺已达到官员们所说的危机程度。'),
  ('96d8758a-7521-43c2-820b-2e7a8b35bc3d-ex1', '96d8758a-7521-43c2-820b-2e7a8b35bc3d', 'wall', 'Hang the picture on that wall.', '把画挂在那面墙上。'),
  ('96d8758a-7521-43c2-820b-2e7a8b35bc3d-ex2', '96d8758a-7521-43c2-820b-2e7a8b35bc3d', 'wall', 'Investigators discovered that the retaining wall had been constructed without engineering approval.', '调查人员发现，这堵挡土墙未经工程审批便已建造。'),
  ('b5d724ae-406b-47f7-931b-2ba122884ce8-ex1', 'b5d724ae-406b-47f7-931b-2ba122884ce8', 'patient', 'Please be patient; the bus is coming.', '请耐心点，公交车就要来了。'),
  ('b5d724ae-406b-47f7-931b-2ba122884ce8-ex2', 'b5d724ae-406b-47f7-931b-2ba122884ce8', 'patient', 'Every patient enrolled in the trial provided informed consent after extensive counseling.', '参加试验的每位患者都在充分咨询后签署了知情同意书。'),
  ('05e7ea02-719e-4837-8cee-ce552404e656-ex1', '05e7ea02-719e-4837-8cee-ce552404e656', 'worker', 'The workers are repairing the road.', '工人们正在修路。'),
  ('05e7ea02-719e-4837-8cee-ce552404e656-ex2', '05e7ea02-719e-4837-8cee-ce552404e656', 'worker', 'The legislation extends collective bargaining rights to gig economy workers for the first time.', '该立法首次将集体谈判权扩展至零工经济从业者。'),
  ('cbf5854f-3626-462c-a1bf-d138544e08a0-ex1', 'cbf5854f-3626-462c-a1bf-d138544e08a0', 'news', 'Did you watch the news last night?', '你昨晚看新闻了吗？'),
  ('cbf5854f-3626-462c-a1bf-d138544e08a0-ex2', 'cbf5854f-3626-462c-a1bf-d138544e08a0', 'news', 'The news of the merger sent the company''s share price soaring in early trading.', '合并的消息使该公司股价在早盘交易中飙升。'),
  ('c8169c4d-b4a2-4416-8c34-d3690a6d87b6-ex1', 'c8169c4d-b4a2-4416-8c34-d3690a6d87b6', 'test', 'I have a math test tomorrow.', '我明天有数学考试。'),
  ('c8169c4d-b4a2-4416-8c34-d3690a6d87b6-ex2', 'c8169c4d-b4a2-4416-8c34-d3690a6d87b6', 'test', 'The prototype must pass a rigorous battery of tests before receiving certification.', '原型机必须通过一系列严格测试才能获得认证。'),
  ('0ee34d5d-d2a1-42cd-914e-891c5fe11b1e-ex1', '0ee34d5d-d2a1-42cd-914e-891c5fe11b1e', 'movie', 'Let''s watch a movie tonight.', '我们今晚看场电影吧。'),
  ('0ee34d5d-d2a1-42cd-914e-891c5fe11b1e-ex2', '0ee34d5d-d2a1-42cd-914e-891c5fe11b1e', 'movie', 'The documentary movie galvanized public opinion and accelerated legislative reform.', '这部纪录电影激发了公众舆论，加速了立法改革。'),
  ('f5cd4532-7e37-4251-bf07-615e0a9783d6-ex1', 'f5cd4532-7e37-4251-bf07-615e0a9783d6', 'certain', 'I am certain that I locked the door.', '我确定我锁门了。'),
  ('f5cd4532-7e37-4251-bf07-615e0a9783d6-ex2', 'f5cd4532-7e37-4251-bf07-615e0a9783d6', 'certain', 'Under certain narrowly defined circumstances, the disclosure requirements may be waived.', '在某些界定严格的情形下，披露要求可以豁免。'),
  ('a69dceb3-5444-41a9-9d52-7b9821a62da4-ex1', 'a69dceb3-5444-41a9-9d52-7b9821a62da4', 'north', 'The lake is north of the city.', '湖在城市的北边。'),
  ('a69dceb3-5444-41a9-9d52-7b9821a62da4-ex2', 'a69dceb3-5444-41a9-9d52-7b9821a62da4', 'north', 'Persistent drought across the north has compelled authorities to ration agricultural water supplies.', '北部地区持续干旱，迫使当局对农业用水实行配给。'),
  ('50bdcc52-0ef9-4cbc-bc51-c6b8d0af1cff-ex1', '50bdcc52-0ef9-4cbc-bc51-c6b8d0af1cff', 'personal', 'This is my personal opinion.', '这是我的个人意见。'),
  ('50bdcc52-0ef9-4cbc-bc51-c6b8d0af1cff-ex2', '50bdcc52-0ef9-4cbc-bc51-c6b8d0af1cff', 'personal', 'The statute prohibits officials from exploiting public office for personal enrichment.', '该法规禁止官员利用公职谋取私利。'),
  ('03f091a1-781f-4271-b59b-46724b77c390-ex1', '03f091a1-781f-4271-b59b-46724b77c390', 'simply', 'Simply press this button to start.', '只需按下这个按钮即可启动。'),
  ('03f091a1-781f-4271-b59b-46724b77c390-ex2', '03f091a1-781f-4271-b59b-46724b77c390', 'simply', 'The existing infrastructure is simply incapable of accommodating the projected increase in demand.', '现有基础设施根本无法满足预计增长的需求。'),
  ('3fa3d523-9e40-46d1-899d-420b571b0c00-ex1', '3fa3d523-9e40-46d1-899d-420b571b0c00', 'third', 'Our office is on the third floor.', '我们的办公室在三楼。'),
  ('3fa3d523-9e40-46d1-899d-420b571b0c00-ex2', '3fa3d523-9e40-46d1-899d-420b571b0c00', 'third', 'Nearly a third of respondents reported experiencing discrimination during the hiring process.', '近三分之一的受访者表示在招聘过程中遭遇过歧视。'),
  ('4afb4c4a-02ca-4069-8096-12361483de7b-ex1', '4afb4c4a-02ca-4069-8096-12361483de7b', 'technology', 'Modern technology makes life easier.', '现代科技让生活更便利。'),
  ('4afb4c4a-02ca-4069-8096-12361483de7b-ex2', '4afb4c4a-02ca-4069-8096-12361483de7b', 'technology', 'The export of sensitive technology is subject to stringent licensing requirements.', '敏感技术的出口须遵守严格的许可要求。'),
  ('0f965a61-2cd4-416d-81fa-88b2a272cde5-ex1', '0f965a61-2cd4-416d-81fa-88b2a272cde5', 'catch', 'Hurry, or we will miss the train — catch it!', '快点，不然赶不上火车了——快去赶车！'),
  ('0f965a61-2cd4-416d-81fa-88b2a272cde5-ex2', '0f965a61-2cd4-416d-81fa-88b2a272cde5', 'catch', 'The reforms aim to catch fraudulent transactions before funds leave the jurisdiction.', '这些改革旨在赶在资金离开辖区之前截获欺诈性交易。'),
  ('b4da9704-c156-4c48-b28a-b4c96341d744-ex1', 'b4da9704-c156-4c48-b28a-b4c96341d744', 'step', 'Watch your step on the stairs.', '上楼梯时小心脚下。'),
  ('b4da9704-c156-4c48-b28a-b4c96341d744-ex2', 'b4da9704-c156-4c48-b28a-b4c96341d744', 'step', 'The agreement constitutes a decisive step toward the normalization of bilateral relations.', '该协议是迈向双边关系正常化的决定性一步。'),
  ('bd790532-6642-409a-beb4-25f1d785c14c-ex1', 'bd790532-6642-409a-beb4-25f1d785c14c', 'baby', 'The baby is sleeping in the next room.', '宝宝在隔壁房间睡觉。'),
  ('bd790532-6642-409a-beb4-25f1d785c14c-ex2', 'bd790532-6642-409a-beb4-25f1d785c14c', 'baby', 'The study tracked developmental outcomes for every baby born in the region over a decade.', '该研究追踪了该地区十年间出生的每个婴儿的发育状况。'),
  ('6f2bfbe8-3060-4918-a189-db0c4fb0a3df-ex1', '6f2bfbe8-3060-4918-a189-db0c4fb0a3df', 'computer', 'I use my computer for work and games.', '我用电脑工作和玩游戏。'),
  ('6f2bfbe8-3060-4918-a189-db0c4fb0a3df-ex2', '6f2bfbe8-3060-4918-a189-db0c4fb0a3df', 'computer', 'Advances in computer architecture have enabled simulations of unprecedented complexity.', '计算机体系结构的进步使前所未有的复杂模拟成为可能。'),
  ('100bebf3-0329-4c87-9cff-ec9d4d6f5285-ex1', '100bebf3-0329-4c87-9cff-ec9d4d6f5285', 'type', 'What type of music do you like?', '你喜欢哪种类型的音乐？'),
  ('100bebf3-0329-4c87-9cff-ec9d4d6f5285-ex2', '100bebf3-0329-4c87-9cff-ec9d4d6f5285', 'type', 'The classification system distinguishes each type of transaction according to its risk profile.', '该分类体系根据风险特征对每种交易类型加以区分。'),
  ('c02150a1-9cee-4196-8ad7-792958698571-ex1', 'c02150a1-9cee-4196-8ad7-792958698571', 'attention', 'Pay attention to the teacher.', '注意听老师讲课。'),
  ('c02150a1-9cee-4196-8ad7-792958698571-ex2', 'c02150a1-9cee-4196-8ad7-792958698571', 'attention', 'The report drew international attention to conditions in the region''s detention facilities.', '该报告使该地区拘留设施的状况受到国际关注。'),
  ('bb404f63-5669-4062-b516-077bf8a13a38-ex1', 'bb404f63-5669-4062-b516-077bf8a13a38', 'draw', 'She loves to draw animals.', '她喜欢画动物。'),
  ('bb404f63-5669-4062-b516-077bf8a13a38-ex2', 'bb404f63-5669-4062-b516-077bf8a13a38', 'draw', 'It would be premature to draw definitive conclusions from such a limited dataset.', '从如此有限的数据集中得出决定性结论还为时过早。'),
  ('78b42608-59d0-4b2e-b869-97b6fa8428d6-ex1', '78b42608-59d0-4b2e-b869-97b6fa8428d6', 'film', 'We saw a great film last weekend.', '我们上周末看了一部很棒的电影。'),
  ('78b42608-59d0-4b2e-b869-97b6fa8428d6-ex2', '78b42608-59d0-4b2e-b869-97b6fa8428d6', 'film', 'The film was lauded at international festivals for its unflinching portrayal of displacement.', '这部影片因毫不回避地刻画流离失所而在国际电影节上广受赞誉。'),
  ('c8dfc847-b94c-4afd-a001-d2a36b23101c-ex1', 'c8dfc847-b94c-4afd-a001-d2a36b23101c', 'Republican', 'He is a Republican senator.', '他是一位共和党参议员。'),
  ('c8dfc847-b94c-4afd-a001-d2a36b23101c-ex2', 'c8dfc847-b94c-4afd-a001-d2a36b23101c', 'Republican', 'Several Republican lawmakers broke ranks to support the bipartisan infrastructure compromise.', '几位共和党议员打破党派界限，支持两党就基础设施达成的折中方案。'),
  ('605f4268-bbe2-4f00-9a75-8bd17d271b40-ex1', '605f4268-bbe2-4f00-9a75-8bd17d271b40', 'tree', 'The kids climbed the old tree.', '孩子们爬上了那棵老树。'),
  ('605f4268-bbe2-4f00-9a75-8bd17d271b40-ex2', '605f4268-bbe2-4f00-9a75-8bd17d271b40', 'tree', 'The ordinance prohibits the removal of any mature tree without municipal authorization.', '该条例禁止未经市政许可砍伐任何成年树木。'),
  ('62a7a88d-7131-4b50-9070-fc8bb8147560-ex1', '62a7a88d-7131-4b50-9070-fc8bb8147560', 'source', 'The sun is our main source of energy.', '太阳是我们主要的能量来源。'),
  ('62a7a88d-7131-4b50-9070-fc8bb8147560-ex2', '62a7a88d-7131-4b50-9070-fc8bb8147560', 'source', 'The journalist declined to reveal the source of the leaked documents, citing professional privilege.', '这名记者以职业特权为由，拒绝透露泄露文件的消息来源。'),
  ('6de30f58-22cf-4df9-bfe9-7d8267ab2d60-ex1', '6de30f58-22cf-4df9-bfe9-7d8267ab2d60', 'red', 'She wore a red scarf today.', '她今天戴了一条红围巾。'),
  ('6de30f58-22cf-4df9-bfe9-7d8267ab2d60-ex2', '6de30f58-22cf-4df9-bfe9-7d8267ab2d60', 'red', 'The project''s finances slipped deep into the red following successive cost overruns.', '在接连超支之后，该项目的财务状况陷入严重赤字。'),
  ('4ee9733b-8c6c-42b8-b303-71f4b95ea365-ex1', '4ee9733b-8c6c-42b8-b303-71f4b95ea365', 'nearly', 'It is nearly midnight.', '快到午夜了。'),
  ('4ee9733b-8c6c-42b8-b303-71f4b95ea365-ex2', '4ee9733b-8c6c-42b8-b303-71f4b95ea365', 'nearly', 'Nearly two-thirds of the allocated funds remained unspent at the close of the fiscal year.', '财政年度结束时，拨付资金中有近三分之二尚未使用。'),
  ('b8b96cd6-425c-4c75-b886-79c5c33f8f06-ex1', 'b8b96cd6-425c-4c75-b886-79c5c33f8f06', 'organization', 'She works for a charity organization.', '她在一家慈善组织工作。'),
  ('b8b96cd6-425c-4c75-b886-79c5c33f8f06-ex2', 'b8b96cd6-425c-4c75-b886-79c5c33f8f06', 'organization', 'The organization operates under a mandate conferred by the international community.', '该组织根据国际社会授予的职权运作。'),
  ('7a623bfb-690e-496b-939c-16bc90d27ff1-ex1', '7a623bfb-690e-496b-939c-16bc90d27ff1', 'choose', 'Choose any seat you like.', '你喜欢哪个座位就选哪个。'),
  ('7a623bfb-690e-496b-939c-16bc90d27ff1-ex2', '7a623bfb-690e-496b-939c-16bc90d27ff1', 'choose', 'Voters will choose among candidates whose platforms diverge sharply on fiscal policy.', '选民将在财政政策主张截然不同的候选人中作出选择。'),
  ('c79ca732-567a-46c8-b26f-8dc757d0f2dd-ex1', 'c79ca732-567a-46c8-b26f-8dc757d0f2dd', 'cause', 'What was the cause of the fire?', '火灾的原因是什么？'),
  ('c79ca732-567a-46c8-b26f-8dc757d0f2dd-ex2', 'c79ca732-567a-46c8-b26f-8dc757d0f2dd', 'cause', 'Investigators concluded that mechanical fatigue was the proximate cause of the structural failure.', '调查人员认定，机械疲劳是这次结构失效的直接原因。'),
  ('a3fd0008-dd93-40e1-80d9-5cf9af8946f5-ex1', 'a3fd0008-dd93-40e1-80d9-5cf9af8946f5', 'hair', 'She has long black hair.', '她有一头黑色长发。'),
  ('a3fd0008-dd93-40e1-80d9-5cf9af8946f5-ex2', 'a3fd0008-dd93-40e1-80d9-5cf9af8946f5', 'hair', 'Forensic analysis of a single hair recovered at the scene proved decisive in securing the conviction.', '对现场提取的一根毛发的法医分析对定罪起到了决定性作用。'),
  ('5688e972-d79b-4187-9785-472989df8da3-ex1', '5688e972-d79b-4187-9785-472989df8da3', 'century', 'This building is over a century old.', '这栋建筑已有一百多年历史。'),
  ('5688e972-d79b-4187-9785-472989df8da3-ex2', '5688e972-d79b-4187-9785-472989df8da3', 'century', 'The manuscript, dating from the fourteenth century, offers rare insight into medieval commerce.', '这份十四世纪的手稿为了解中世纪商业提供了珍贵线索。'),
  ('0da66316-2138-43a7-8128-f1eec858193c-ex1', '0da66316-2138-43a7-8128-f1eec858193c', 'evidence', 'The police found new evidence.', '警方发现了新证据。'),
  ('0da66316-2138-43a7-8128-f1eec858193c-ex2', '0da66316-2138-43a7-8128-f1eec858193c', 'evidence', 'The tribunal ruled that evidence obtained through coercion is inadmissible in any proceeding.', '法庭裁定，通过胁迫获得的证据在任何诉讼中均不可采纳。'),
  ('c306584f-2629-4bc4-adca-34c507acce88-ex1', 'c306584f-2629-4bc4-adca-34c507acce88', 'window', 'Please open the window for some fresh air.', '请打开窗户透透气。'),
  ('c306584f-2629-4bc4-adca-34c507acce88-ex2', 'c306584f-2629-4bc4-adca-34c507acce88', 'window', 'The negotiations offer a narrow window of opportunity that may not recur for a generation.', '这次谈判提供了一个稍纵即逝的机会窗口，错过可能一代人都不会再有。'),
  ('7c392c56-cdf1-42d0-bf68-4156496ebd25-ex1', '7c392c56-cdf1-42d0-bf68-4156496ebd25', 'difficult', 'This puzzle is too difficult for me.', '这个谜题对我来说太难了。'),
  ('7c392c56-cdf1-42d0-bf68-4156496ebd25-ex2', '7c392c56-cdf1-42d0-bf68-4156496ebd25', 'difficult', 'The committee faces the difficult task of reconciling fiscal discipline with urgent social needs.', '委员会面临着协调财政纪律与紧迫社会需求的艰巨任务。'),
  ('34541a0e-aa48-45e2-b350-8875f5ba9fff-ex1', '34541a0e-aa48-45e2-b350-8875f5ba9fff', 'listen', 'I listen to music on my way to work.', '我上班路上听音乐。'),
  ('34541a0e-aa48-45e2-b350-8875f5ba9fff-ex2', '34541a0e-aa48-45e2-b350-8875f5ba9fff', 'listen', 'Effective policymakers listen carefully to communities affected by their decisions.', '高效的决策者会认真倾听受其决策影响的社区的声音。'),
  ('019fbbbe-c507-4dc5-b555-281abf374b54-ex1', '019fbbbe-c507-4dc5-b555-281abf374b54', 'soon', 'Dinner will be ready soon.', '晚饭很快就好。'),
  ('019fbbbe-c507-4dc5-b555-281abf374b54-ex2', '019fbbbe-c507-4dc5-b555-281abf374b54', 'soon', 'The provisions will take effect as soon as the implementing regulations are promulgated.', '实施细则一经颁布，这些条款即行生效。'),
  ('bada0135-8c37-414d-9b45-c330057a5d14-ex1', 'bada0135-8c37-414d-9b45-c330057a5d14', 'culture', 'I enjoy learning about different cultures.', '我喜欢了解不同的文化。'),
  ('bada0135-8c37-414d-9b45-c330057a5d14-ex2', 'bada0135-8c37-414d-9b45-c330057a5d14', 'culture', 'The inquiry attributed the failures to an entrenched culture of institutional complacency.', '调查将这些失误归咎于根深蒂固的机构自满文化。'),
  ('ffed377e-f207-4898-86d6-492b67fecdc7-ex1', 'ffed377e-f207-4898-86d6-492b67fecdc7', 'billion', 'The company is worth a billion dollars.', '这家公司价值十亿美元。'),
  ('ffed377e-f207-4898-86d6-492b67fecdc7-ex2', 'ffed377e-f207-4898-86d6-492b67fecdc7', 'billion', 'The reconstruction package allocates several billion dollars to rebuilding critical infrastructure.', '重建方案拨款数十亿美元用于重建关键基础设施。'),
  ('2192ef9e-016b-4ed3-a137-87a70947c888-ex1', '2192ef9e-016b-4ed3-a137-87a70947c888', 'chance', 'Give me one more chance.', '再给我一次机会。'),
  ('2192ef9e-016b-4ed3-a137-87a70947c888-ex2', '2192ef9e-016b-4ed3-a137-87a70947c888', 'chance', 'The settlement offers displaced families a realistic chance of rebuilding their livelihoods.', '该和解方案为流离失所的家庭提供了重建生计的现实机会。'),
  ('d7e9e039-960a-4719-bf7f-653530833328-ex1', 'd7e9e039-960a-4719-bf7f-653530833328', 'brother', 'My brother is two years older than me.', '我哥哥比我大两岁。'),
  ('d7e9e039-960a-4719-bf7f-653530833328-ex2', 'd7e9e039-960a-4719-bf7f-653530833328', 'brother', 'His brother assumed control of the family enterprise following decades of joint stewardship.', '在数十年共同经营之后，他的兄弟接掌了家族企业。'),
  ('6f5cc64e-5ba2-4fda-9b43-4b4fd6405497-ex1', '6f5cc64e-5ba2-4fda-9b43-4b4fd6405497', 'energy', 'Kids have so much energy.', '孩子们精力真旺盛。'),
  ('6f5cc64e-5ba2-4fda-9b43-4b4fd6405497-ex2', '6f5cc64e-5ba2-4fda-9b43-4b4fd6405497', 'energy', 'The transition to renewable energy will require sustained investment in grid modernization.', '向可再生能源转型需要对电网现代化进行持续投资。'),
  ('114aa6d3-9b2e-4bff-84a3-a40cd1de343e-ex1', '114aa6d3-9b2e-4bff-84a3-a40cd1de343e', 'period', 'The class lasts for two periods.', '这节课持续两个课时。'),
  ('114aa6d3-9b2e-4bff-84a3-a40cd1de343e-ex2', '114aa6d3-9b2e-4bff-84a3-a40cd1de343e', 'period', 'The contract stipulates a transition period during which both regulatory regimes apply.', '合同规定了一个过渡期，期间两套监管制度同时适用。'),
  ('04518fc3-1e47-41b1-95f4-500ca26a665d-ex1', '04518fc3-1e47-41b1-95f4-500ca26a665d', 'summer', 'We go swimming every summer.', '我们每年夏天都去游泳。'),
  ('04518fc3-1e47-41b1-95f4-500ca26a665d-ex2', '04518fc3-1e47-41b1-95f4-500ca26a665d', 'summer', 'The record-breaking summer intensified debate over the adequacy of climate adaptation measures.', '创纪录的炎夏使关于气候适应措施是否充分的辩论愈发激烈。'),
  ('9ce73540-a57d-46eb-a581-41689716497c-ex1', '9ce73540-a57d-46eb-a581-41689716497c', 'realize', 'I didn''t realize how late it was.', '我没意识到已经这么晚了。'),
  ('9ce73540-a57d-46eb-a581-41689716497c-ex2', '9ce73540-a57d-46eb-a581-41689716497c', 'realize', 'Policymakers were slow to realize the systemic implications of interconnected financial markets.', '政策制定者迟迟才认识到金融市场相互关联所带来的系统性影响。'),
  ('3be1c066-b19a-43ab-9f06-3ec6f83fb24d-ex1', '3be1c066-b19a-43ab-9f06-3ec6f83fb24d', 'hundred', 'This book has three hundred pages.', '这本书有三百页。'),
  ('3be1c066-b19a-43ab-9f06-3ec6f83fb24d-ex2', '3be1c066-b19a-43ab-9f06-3ec6f83fb24d', 'hundred', 'Several hundred delegates endorsed the resolution at the conclusion of the plenary session.', '全体会议结束时，数百名代表对该决议表示支持。'),
  ('fc70f595-edaf-4c40-9911-0318fdd12653-ex1', 'fc70f595-edaf-4c40-9911-0318fdd12653', 'available', 'Is this seat available?', '这个座位有人吗？'),
  ('fc70f595-edaf-4c40-9911-0318fdd12653-ex2', 'fc70f595-edaf-4c40-9911-0318fdd12653', 'available', 'Compensation is available only to claimants who can document their losses adequately.', '只有能充分证明损失的索赔人才能获得赔偿。'),
  ('be8c96c2-1692-4a3c-a160-817f03d64955-ex1', 'be8c96c2-1692-4a3c-a160-817f03d64955', 'plant', 'Water the plants twice a week.', '每周给植物浇两次水。'),
  ('be8c96c2-1692-4a3c-a160-817f03d64955-ex2', 'be8c96c2-1692-4a3c-a160-817f03d64955', 'plant', 'The manufacturing plant was idled pending an investigation into repeated safety violations.', '在对屡次安全违规的调查结束之前，该制造工厂已停工。'),
  ('b474fd8f-edd4-4ae5-8c4b-5869591772a8-ex1', 'b474fd8f-edd4-4ae5-8c4b-5869591772a8', 'likely', 'It is likely to rain this afternoon.', '今天下午可能会下雨。'),
  ('b474fd8f-edd4-4ae5-8c4b-5869591772a8-ex2', 'b474fd8f-edd4-4ae5-8c4b-5869591772a8', 'likely', 'Analysts consider a negotiated settlement more likely than a protracted legal confrontation.', '分析人士认为，谈判和解比旷日持久的法律对抗更有可能。'),
  ('20b98460-984b-43f8-b464-593045ba0a54-ex1', '20b98460-984b-43f8-b464-593045ba0a54', 'opportunity', 'This job is a great opportunity for me.', '这份工作对我来说是个很好的机会。'),
  ('20b98460-984b-43f8-b464-593045ba0a54-ex2', '20b98460-984b-43f8-b464-593045ba0a54', 'opportunity', 'The scholarship program creates opportunity for students historically excluded from higher education.', '该奖学金项目为历来被高等教育排斥在外的学生创造了机会。'),
  ('1331f315-9857-4de4-86e6-20221259cce9-ex1', '1331f315-9857-4de4-86e6-20221259cce9', 'term', 'The new term starts in September.', '新学期九月开始。'),
  ('1331f315-9857-4de4-86e6-20221259cce9-ex2', '1331f315-9857-4de4-86e6-20221259cce9', 'term', 'The parties renegotiated the terms governing liability for consequential damages.', '双方重新谈判了有关间接损害赔偿责任的条款。'),
  ('fcc5e089-72d3-4146-bbae-b00f91afaafb-ex1', 'fcc5e089-72d3-4146-bbae-b00f91afaafb', 'short', 'The meeting was short and useful.', '会议简短而有效。'),
  ('fcc5e089-72d3-4146-bbae-b00f91afaafb-ex2', 'fcc5e089-72d3-4146-bbae-b00f91afaafb', 'short', 'The agency fell short of its statutory obligations in several material respects.', '该机构在若干重大方面未能履行其法定义务。'),
  ('5804c021-9f9a-4bd4-8135-a74dc5f3c28f-ex1', '5804c021-9f9a-4bd4-8135-a74dc5f3c28f', 'letter', 'I wrote a letter to my grandmother.', '我给祖母写了一封信。'),
  ('5804c021-9f9a-4bd4-8135-a74dc5f3c28f-ex2', '5804c021-9f9a-4bd4-8135-a74dc5f3c28f', 'letter', 'The signatories issued an open letter urging immediate ratification of the convention.', '签署者发表公开信，敦促立即批准该公约。'),
  ('fcc2917c-2a1e-4f49-b9d5-b251e679f93e-ex1', 'fcc2917c-2a1e-4f49-b9d5-b251e679f93e', 'condition', 'The car is old but in good condition.', '这辆车虽旧但车况良好。'),
  ('fcc2917c-2a1e-4f49-b9d5-b251e679f93e-ex2', 'fcc2917c-2a1e-4f49-b9d5-b251e679f93e', 'condition', 'The loan was extended on the condition that the borrower implement specified governance reforms.', '贷款的发放以借款方实施特定治理改革为条件。'),
  ('9e5b96ee-ccef-4b09-8f0d-f5db431a85a2-ex1', '9e5b96ee-ccef-4b09-8f0d-f5db431a85a2', 'choice', 'Good choice! That dish is delicious.', '选得好！那道菜很好吃。'),
  ('9e5b96ee-ccef-4b09-8f0d-f5db431a85a2-ex2', '9e5b96ee-ccef-4b09-8f0d-f5db431a85a2', 'choice', 'The ruling affirms that patients retain the ultimate choice regarding their course of treatment.', '该裁决确认，患者对自身治疗方案保留最终选择权。'),
  ('60434a0e-1a9e-4ca2-80b9-3aa9e3751d0c-ex1', '60434a0e-1a9e-4ca2-80b9-3aa9e3751d0c', 'single', 'There is not a single cloud in the sky.', '天空中一朵云都没有。'),
  ('60434a0e-1a9e-4ca2-80b9-3aa9e3751d0c-ex2', '60434a0e-1a9e-4ca2-80b9-3aa9e3751d0c', 'single', 'The directive consolidates the previously fragmented procedures into a single unified framework.', '该指令将以往零散的程序整合为单一的统一框架。'),
  ('19d0f7ca-3c11-43ea-8587-ebdbb79b7fe4-ex1', '19d0f7ca-3c11-43ea-8587-ebdbb79b7fe4', 'rule', 'Follow the rules of the game.', '遵守游戏规则。'),
  ('19d0f7ca-3c11-43ea-8587-ebdbb79b7fe4-ex2', '19d0f7ca-3c11-43ea-8587-ebdbb79b7fe4', 'rule', 'The court declined to rule on the broader constitutional question raised by the petitioners.', '法院拒绝就请愿人提出的更广泛的宪法问题作出裁决。'),
  ('c62aea07-3a29-42a5-91fe-85d261f3f7a7-ex1', 'c62aea07-3a29-42a5-91fe-85d261f3f7a7', 'daughter', 'Their daughter just started school.', '他们的女儿刚上学。'),
  ('c62aea07-3a29-42a5-91fe-85d261f3f7a7-ex2', 'c62aea07-3a29-42a5-91fe-85d261f3f7a7', 'daughter', 'She established the foundation in memory of her daughter, a tireless advocate for literacy.', '她为纪念毕生倡导扫盲事业的女儿而创立了这个基金会。'),
  ('fc4948da-9e4a-4cca-9cb1-d8152c7839c5-ex1', 'fc4948da-9e4a-4cca-9cb1-d8152c7839c5', 'administration', 'The school administration approved the trip.', '学校行政部门批准了这次出行。'),
  ('fc4948da-9e4a-4cca-9cb1-d8152c7839c5-ex2', 'fc4948da-9e4a-4cca-9cb1-d8152c7839c5', 'administration', 'The administration faces mounting pressure to clarify its position on the proposed sanctions.', '行政当局面临越来越大的压力，需就拟议制裁阐明立场。'),
  ('66bddb10-205f-4859-8bc7-3a51a2f638fc-ex1', '66bddb10-205f-4859-8bc7-3a51a2f638fc', 'south', 'Birds fly south in the winter.', '鸟儿冬天飞往南方。'),
  ('66bddb10-205f-4859-8bc7-3a51a2f638fc-ex2', '66bddb10-205f-4859-8bc7-3a51a2f638fc', 'south', 'Investment has flowed disproportionately to the south, exacerbating long-standing regional disparities.', '投资过度流向南部，加剧了长期存在的区域差距。'),
  ('19d9ed4c-c7df-408d-901f-b7f71ac7aae7-ex1', '19d9ed4c-c7df-408d-901f-b7f71ac7aae7', 'husband', 'Her husband cooks dinner on weekends.', '她丈夫周末做晚饭。'),
  ('19d9ed4c-c7df-408d-901f-b7f71ac7aae7-ex2', '19d9ed4c-c7df-408d-901f-b7f71ac7aae7', 'husband', 'The pension provisions entitle a surviving husband to benefits accrued during the marriage.', '养老金条款规定，在世丈夫有权获得婚姻存续期间累积的待遇。'),
  ('09cb2392-dc76-4431-93f9-a48bbe0557da-ex1', '09cb2392-dc76-4431-93f9-a48bbe0557da', 'Congress', 'Congress will vote on the bill tomorrow.', '国会明天将对该法案进行表决。'),
  ('09cb2392-dc76-4431-93f9-a48bbe0557da-ex2', '09cb2392-dc76-4431-93f9-a48bbe0557da', 'Congress', 'Congress retains the constitutional authority to override a presidential veto by supermajority.', '国会保有以绝对多数推翻总统否决的宪法权力。'),
  ('f7b8264f-d367-424d-b906-e1c370de6444-ex1', 'f7b8264f-d367-424d-b906-e1c370de6444', 'floor', 'The cat is sleeping on the floor.', '猫正睡在地板上。'),
  ('f7b8264f-d367-424d-b906-e1c370de6444-ex2', 'f7b8264f-d367-424d-b906-e1c370de6444', 'floor', 'The amendment establishes a statutory floor below which the minimum wage may not fall.', '该修正案设定了最低工资不得低于的法定下限。'),
  ('1d884451-e5ae-4302-9e93-f3a55293fc7c-ex1', '1d884451-e5ae-4302-9e93-f3a55293fc7c', 'campaign', 'The campaign starts next month.', '活动下个月开始。'),
  ('1d884451-e5ae-4302-9e93-f3a55293fc7c-ex2', '1d884451-e5ae-4302-9e93-f3a55293fc7c', 'campaign', 'The vaccination campaign reached remote communities through an unprecedented logistical effort.', '这场疫苗接种运动通过空前的后勤努力覆盖到了偏远社区。'),
  ('2caa47aa-b09f-47ad-9952-020054f04a52-ex1', '2caa47aa-b09f-47ad-9952-020054f04a52', 'material', 'This jacket is made of waterproof material.', '这件夹克由防水材料制成。'),
  ('2caa47aa-b09f-47ad-9952-020054f04a52-ex2', '2caa47aa-b09f-47ad-9952-020054f04a52', 'material', 'The prosecution alleged that the omissions constituted material misrepresentation under securities law.', '控方指控这些隐瞒行为构成证券法所规定的重大虚假陈述。'),
  ('0fcb968c-eefa-45b7-8dde-9f4b968eb96b-ex1', '0fcb968c-eefa-45b7-8dde-9f4b968eb96b', 'population', 'The population of this city is growing.', '这座城市的人口在增长。'),
  ('0fcb968c-eefa-45b7-8dde-9f4b968eb96b-ex2', '0fcb968c-eefa-45b7-8dde-9f4b968eb96b', 'population', 'An aging population places escalating demands on pension systems and healthcare infrastructure.', '人口老龄化对养老金体系和医疗基础设施提出了不断升级的要求。'),
  ('122eebe1-eec9-48e6-afce-94980ee43d67-ex1', '122eebe1-eec9-48e6-afce-94980ee43d67', 'economy', 'The economy is doing well this year.', '今年经济形势不错。'),
  ('122eebe1-eec9-48e6-afce-94980ee43d67-ex2', '122eebe1-eec9-48e6-afce-94980ee43d67', 'economy', 'The economy''s resilience surprised forecasters who had anticipated a far deeper contraction.', '经济的韧性令预测者感到意外，他们原本预计衰退会严重得多。'),
  ('b9c5533f-0e85-401e-ad12-f8867e23c9ff-ex1', 'b9c5533f-0e85-401e-ad12-f8867e23c9ff', 'medical', 'She is studying for a medical degree.', '她正在攻读医学学位。'),
  ('b9c5533f-0e85-401e-ad12-f8867e23c9ff-ex2', 'b9c5533f-0e85-401e-ad12-f8867e23c9ff', 'medical', 'The tribunal heard extensive medical testimony regarding the long-term effects of the exposure.', '法庭听取了关于这种接触的长期影响的大量医学证词。'),
  ('04ec84a5-e417-4e80-b121-100b50621bec-ex1', '04ec84a5-e417-4e80-b121-100b50621bec', 'hospital', 'The hospital is five minutes away.', '医院离这里五分钟路程。'),
  ('04ec84a5-e417-4e80-b121-100b50621bec-ex2', '04ec84a5-e417-4e80-b121-100b50621bec', 'hospital', 'The hospital implemented stringent infection control protocols following the outbreak.', '疫情爆发后，这家医院实施了严格的感染控制规程。'),
  ('055269c4-325b-4fc8-9d7d-d0a59730e9ba-ex1', '055269c4-325b-4fc8-9d7d-d0a59730e9ba', 'church', 'They go to church every Sunday.', '他们每周日去教堂。'),
  ('055269c4-325b-4fc8-9d7d-d0a59730e9ba-ex2', '055269c4-325b-4fc8-9d7d-d0a59730e9ba', 'church', 'The medieval church was painstakingly restored using traditional craftsmanship and materials.', '这座中世纪教堂采用传统工艺和材料得到了精心修复。'),
  ('cddf9123-0de0-4881-a460-5dd4a5e8bb8b-ex1', 'cddf9123-0de0-4881-a460-5dd4a5e8bb8b', 'close', 'Please close the door quietly.', '请轻轻把门关上。'),
  ('cddf9123-0de0-4881-a460-5dd4a5e8bb8b-ex2', 'cddf9123-0de0-4881-a460-5dd4a5e8bb8b', 'close', 'Regulators maintain close scrutiny of institutions deemed systemically important.', '监管机构对被认定具有系统重要性的机构保持密切审查。'),
  ('b08d2215-7332-47af-9269-7b62d781de65-ex1', 'b08d2215-7332-47af-9269-7b62d781de65', 'thousand', 'This town has about five thousand people.', '这个镇大约有五千人。'),
  ('b08d2215-7332-47af-9269-7b62d781de65-ex2', 'b08d2215-7332-47af-9269-7b62d781de65', 'thousand', 'Several thousand pages of internal correspondence were disclosed during the discovery process.', '在证据开示过程中，数千页内部往来文件被披露。'),
  ('06ebc7ed-b9f2-43b5-ab37-5f2a3ee48bdb-ex1', '06ebc7ed-b9f2-43b5-ab37-5f2a3ee48bdb', 'risk', 'Don''t risk your health for work.', '别为了工作拿健康冒险。'),
  ('06ebc7ed-b9f2-43b5-ab37-5f2a3ee48bdb-ex2', '06ebc7ed-b9f2-43b5-ab37-5f2a3ee48bdb', 'risk', 'The framework obliges banks to hold capital commensurate with their aggregate risk exposure.', '该框架要求银行持有与其总体风险敞口相称的资本。'),
  ('a07bd88e-9c91-4b0e-81f3-881585378a7a-ex1', 'a07bd88e-9c91-4b0e-81f3-881585378a7a', 'current', 'The current weather is perfect for hiking.', '现在的天气非常适合远足。'),
  ('a07bd88e-9c91-4b0e-81f3-881585378a7a-ex2', 'a07bd88e-9c91-4b0e-81f3-881585378a7a', 'current', 'The current regulatory regime predates the technologies it is now expected to govern.', '现行监管制度的制定时间早于它如今需要管辖的技术。'),
  ('cc4bbac0-42fa-4494-82cb-e61f408f2cbf-ex1', 'cc4bbac0-42fa-4494-82cb-e61f408f2cbf', 'fire', 'The fire kept us warm all night.', '炉火让我们整晚都很温暖。'),
  ('cc4bbac0-42fa-4494-82cb-e61f408f2cbf-ex2', 'cc4bbac0-42fa-4494-82cb-e61f408f2cbf', 'fire', 'The company came under fire for its handling of the contamination disclosure.', '该公司因处理污染信息披露的方式而备受抨击。'),
  ('6e3cbf1a-9a10-451f-b03d-4623bcc63805-ex1', '6e3cbf1a-9a10-451f-b03d-4623bcc63805', 'future', 'What are your plans for the future?', '你对未来有什么计划？'),
  ('6e3cbf1a-9a10-451f-b03d-4623bcc63805-ex2', '6e3cbf1a-9a10-451f-b03d-4623bcc63805', 'future', 'The charter commits signatories to safeguarding resources for future generations.', '宪章要求签署方承诺为子孙后代守护资源。'),
  ('c2a71ea8-6260-4854-9d2f-b7cad0e61590-ex1', 'c2a71ea8-6260-4854-9d2f-b7cad0e61590', 'wrong', 'I took the wrong bus this morning.', '我今天早上坐错了公交车。'),
  ('c2a71ea8-6260-4854-9d2f-b7cad0e61590-ex2', 'c2a71ea8-6260-4854-9d2f-b7cad0e61590', 'wrong', 'The inquiry sought to establish precisely what went wrong in the hours preceding the collapse.', '调查力求查明坍塌前数小时究竟出了什么问题。'),
  ('ec4ddb5a-d4f6-4643-ae4e-5e5fa6df4103-ex1', 'ec4ddb5a-d4f6-4643-ae4e-5e5fa6df4103', 'involve', 'The job involves a lot of travel.', '这份工作需要经常出差。'),
  ('ec4ddb5a-d4f6-4643-ae4e-5e5fa6df4103-ex2', 'ec4ddb5a-d4f6-4643-ae4e-5e5fa6df4103', 'involve', 'The proceedings involve allegations of misconduct spanning multiple jurisdictions.', '这些诉讼涉及跨越多个司法管辖区的不当行为指控。'),
  ('09581629-2b89-4534-a12b-ae0fa0c2f536-ex1', '09581629-2b89-4534-a12b-ae0fa0c2f536', 'defense', 'The team has a strong defense.', '这支球队防守很强。'),
  ('09581629-2b89-4534-a12b-ae0fa0c2f536-ex2', '09581629-2b89-4534-a12b-ae0fa0c2f536', 'defense', 'Counsel for the defense moved to exclude testimony obtained without proper authorization.', '辩方律师申请排除未经适当授权获取的证词。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('721b126d-e0e1-4a7d-924a-72f9ea007107-ex1', '721b126d-e0e1-4a7d-924a-72f9ea007107', 'anyone', 'Is anyone home?', '有人在家吗？'),
  ('721b126d-e0e1-4a7d-924a-72f9ea007107-ex2', '721b126d-e0e1-4a7d-924a-72f9ea007107', 'anyone', 'The whistleblower statute protects anyone who reports misconduct in good faith.', '举报人保护法保护任何善意举报不当行为的人。'),
  ('9f8089a2-e824-4cdb-8ab2-71710571f64f-ex1', '9f8089a2-e824-4cdb-8ab2-71710571f64f', 'increase', 'Prices increase every year.', '物价每年都在上涨。'),
  ('9f8089a2-e824-4cdb-8ab2-71710571f64f-ex2', '9f8089a2-e824-4cdb-8ab2-71710571f64f', 'increase', 'The data document a marked increase in extreme weather events over the past three decades.', '数据记录了过去三十年极端天气事件的显著增加。'),
  ('cd94fcb8-1ffa-44bb-a26b-2a3bdafd14b2-ex1', 'cd94fcb8-1ffa-44bb-a26b-2a3bdafd14b2', 'security', 'Please show your ID to security.', '请向保安出示证件。'),
  ('cd94fcb8-1ffa-44bb-a26b-2a3bdafd14b2-ex2', 'cd94fcb8-1ffa-44bb-a26b-2a3bdafd14b2', 'security', 'The council convened an emergency session to address the deteriorating security situation.', '安理会召开紧急会议，应对不断恶化的安全局势。'),
  ('c184fb46-cd74-4397-abab-6f3eacb7cf4a-ex1', 'c184fb46-cd74-4397-abab-6f3eacb7cf4a', 'bank', 'I need to go to the bank today.', '我今天得去趟银行。'),
  ('c184fb46-cd74-4397-abab-6f3eacb7cf4a-ex2', 'c184fb46-cd74-4397-abab-6f3eacb7cf4a', 'bank', 'The central bank intervened decisively to stabilize the currency amid mounting speculative pressure.', '面对不断加剧的投机压力，央行果断干预以稳定汇率。'),
  ('64d41227-f614-48b0-88d5-7c2ea4582809-ex1', '64d41227-f614-48b0-88d5-7c2ea4582809', 'myself', 'I made this cake myself.', '这个蛋糕是我自己做的。'),
  ('64d41227-f614-48b0-88d5-7c2ea4582809-ex2', '64d41227-f614-48b0-88d5-7c2ea4582809', 'myself', 'I have satisfied myself that the procedures were followed in every material respect.', '我已确信，相关程序在所有重大方面均得到遵守。'),
  ('6c159897-7e62-46be-8b05-1218ed5fc3de-ex1', '6c159897-7e62-46be-8b05-1218ed5fc3de', 'certainly', 'Certainly, I can help you with that.', '当然，我可以帮你。'),
  ('6c159897-7e62-46be-8b05-1218ed5fc3de-ex2', '6c159897-7e62-46be-8b05-1218ed5fc3de', 'certainly', 'The findings certainly warrant further investigation before any regulatory action is taken.', '在采取任何监管行动之前，这些发现确实有必要进一步调查。'),
  ('a089b5a3-ed8b-4ee0-a4c7-4efa8519e3c6-ex1', 'a089b5a3-ed8b-4ee0-a4c7-4efa8519e3c6', 'west', 'The sun sets in the west.', '太阳从西边落下。'),
  ('a089b5a3-ed8b-4ee0-a4c7-4efa8519e3c6-ex2', 'a089b5a3-ed8b-4ee0-a4c7-4efa8519e3c6', 'west', 'Trade routes linking the west with emerging markets have acquired renewed strategic significance.', '连接西方与新兴市场的贸易通道重新获得了战略意义。'),
  ('8b334635-0b34-4fcc-abb1-5f2527aa9240-ex1', '8b334635-0b34-4fcc-abb1-5f2527aa9240', 'sport', 'Basketball is my favorite sport.', '篮球是我最喜欢的运动。'),
  ('8b334635-0b34-4fcc-abb1-5f2527aa9240-ex2', '8b334635-0b34-4fcc-abb1-5f2527aa9240', 'sport', 'The governing body imposed lifetime bans for doping violations that compromised the sport''s integrity.', '管理机构对损害这项运动公信力的兴奋剂违规行为处以终身禁赛。'),
  ('2d79471a-6351-4c1d-a826-0f81a3847566-ex1', '2d79471a-6351-4c1d-a826-0f81a3847566', 'board', 'Write your name on the board.', '把你的名字写在黑板上。'),
  ('2d79471a-6351-4c1d-a826-0f81a3847566-ex2', '2d79471a-6351-4c1d-a826-0f81a3847566', 'board', 'The board unanimously approved the acquisition following months of confidential negotiations.', '经过数月秘密谈判，董事会一致批准了这项收购。'),
  ('86f37d4f-38f3-45c7-86ad-65298c8d1dd9-ex1', '86f37d4f-38f3-45c7-86ad-65298c8d1dd9', 'seek', 'You should seek advice from a doctor.', '你应该向医生咨询。'),
  ('86f37d4f-38f3-45c7-86ad-65298c8d1dd9-ex2', '86f37d4f-38f3-45c7-86ad-65298c8d1dd9', 'seek', 'The plaintiffs seek compensatory damages as well as injunctive relief against further violations.', '原告寻求补偿性赔偿，并请求禁令以制止进一步侵权。'),
  ('32ce6753-a580-4ff2-90e4-265568657738-ex1', '32ce6753-a580-4ff2-90e4-265568657738', 'per', 'The speed limit is sixty kilometers per hour.', '限速是每小时六十公里。'),
  ('32ce6753-a580-4ff2-90e4-265568657738-ex2', '32ce6753-a580-4ff2-90e4-265568657738', 'per', 'Consumption per capita has risen steadily despite repeated calls for conservation.', '尽管多次呼吁节约，人均消费量仍持续上升。'),
  ('cbc3fdee-30c9-4ed6-b862-a775bac79c42-ex1', 'cbc3fdee-30c9-4ed6-b862-a775bac79c42', 'subject', 'Math is my favorite subject.', '数学是我最喜欢的科目。'),
  ('cbc3fdee-30c9-4ed6-b862-a775bac79c42-ex2', 'cbc3fdee-30c9-4ed6-b862-a775bac79c42', 'subject', 'All transactions remain subject to review by the competition authority.', '所有交易仍须接受竞争管理机构的审查。'),
  ('5b9d7b23-4b22-4ce8-b169-d4521dd987e0-ex1', '5b9d7b23-4b22-4ce8-b169-d4521dd987e0', 'officer', 'The police officer helped us find the way.', '警察帮我们找到了路。'),
  ('5b9d7b23-4b22-4ce8-b169-d4521dd987e0-ex2', '5b9d7b23-4b22-4ce8-b169-d4521dd987e0', 'officer', 'The compliance officer is obligated to report suspected violations directly to the board.', '合规官有义务将疑似违规行为直接报告董事会。'),
  ('beff000f-6f22-4bcc-8a46-3705ecd92b44-ex1', 'beff000f-6f22-4bcc-8a46-3705ecd92b44', 'private', 'This is a private conversation.', '这是私人谈话。'),
  ('beff000f-6f22-4bcc-8a46-3705ecd92b44-ex2', 'beff000f-6f22-4bcc-8a46-3705ecd92b44', 'private', 'The memorandum blurs the boundary between public duties and private commercial interests.', '这份备忘录模糊了公共职责与私人商业利益之间的界限。'),
  ('1691e9ee-d5c0-416f-a4d0-b211801f3e50-ex1', '1691e9ee-d5c0-416f-a4d0-b211801f3e50', 'rest', 'You should rest after the long trip.', '长途旅行后你应该休息一下。'),
  ('1691e9ee-d5c0-416f-a4d0-b211801f3e50-ex2', '1691e9ee-d5c0-416f-a4d0-b211801f3e50', 'rest', 'The rest of the funds will be disbursed once the audit conditions have been satisfied.', '其余资金将在审计条件满足后拨付。'),
  ('ea1bec69-1e74-4556-9b25-d764401196ba-ex1', 'ea1bec69-1e74-4556-9b25-d764401196ba', 'behavior', 'The teacher praised the students'' good behavior.', '老师表扬了学生们的良好表现。'),
  ('ea1bec69-1e74-4556-9b25-d764401196ba-ex2', 'ea1bec69-1e74-4556-9b25-d764401196ba', 'behavior', 'The study examines how incentive structures shape institutional behavior under uncertainty.', '该研究考察激励结构如何塑造不确定条件下的机构行为。'),
  ('59d43b17-2713-40fe-96da-a5fd6e82be8a-ex1', '59d43b17-2713-40fe-96da-a5fd6e82be8a', 'deal', 'We got a great deal on the hotel.', '我们订酒店拿到了很优惠的价格。'),
  ('59d43b17-2713-40fe-96da-a5fd6e82be8a-ex2', '59d43b17-2713-40fe-96da-a5fd6e82be8a', 'deal', 'The two conglomerates concluded a deal that reshapes the competitive landscape of the industry.', '两大集团达成的交易重塑了该行业的竞争格局。'),
  ('53b1d45a-8dbd-4538-9e01-2e2eb1e58eda-ex1', '53b1d45a-8dbd-4538-9e01-2e2eb1e58eda', 'performance', 'The band gave an amazing performance.', '乐队的演出非常精彩。'),
  ('53b1d45a-8dbd-4538-9e01-2e2eb1e58eda-ex2', '53b1d45a-8dbd-4538-9e01-2e2eb1e58eda', 'performance', 'Executive compensation is now linked explicitly to long-term environmental performance.', '高管薪酬现已与长期环境绩效明确挂钩。'),
  ('9bf44b47-6abb-42e3-b025-7051af7026a9-ex1', '9bf44b47-6abb-42e3-b025-7051af7026a9', 'fight', 'The two boys had a fight at school.', '那两个男孩在学校打了一架。'),
  ('9bf44b47-6abb-42e3-b025-7051af7026a9-ex2', '9bf44b47-6abb-42e3-b025-7051af7026a9', 'fight', 'The coalition pledged to intensify the fight against transnational financial crime.', '该联盟承诺加大打击跨国金融犯罪的力度。'),
  ('13b73510-0d54-46a5-bf45-d08927077c82-ex1', '13b73510-0d54-46a5-bf45-d08927077c82', 'throw', 'Throw the ball to me!', '把球扔给我！'),
  ('13b73510-0d54-46a5-bf45-d08927077c82-ex2', '13b73510-0d54-46a5-bf45-d08927077c82', 'throw', 'Critics accused the agency of attempting to throw a veil of secrecy over the proceedings.', '批评者指责该机构试图给这些程序蒙上一层保密的面纱。'),
  ('494d6c9f-3381-4944-afd7-d004ed0ffd45-ex1', '494d6c9f-3381-4944-afd7-d004ed0ffd45', 'top', 'The book is on top of the shelf.', '书在架子顶上。'),
  ('494d6c9f-3381-4944-afd7-d004ed0ffd45-ex2', '494d6c9f-3381-4944-afd7-d004ed0ffd45', 'top', 'Reform of the judicial appointment process remains at the top of the legislative agenda.', '司法任命程序改革仍居立法议程之首。'),
  ('41d899e9-4bd8-4631-9316-b24976e35948-ex1', '41d899e9-4bd8-4631-9316-b24976e35948', 'quickly', 'She finished her homework quickly.', '她很快写完了作业。'),
  ('41d899e9-4bd8-4631-9316-b24976e35948-ex2', '41d899e9-4bd8-4631-9316-b24976e35948', 'quickly', 'Containment measures must be deployed quickly to prevent localized outbreaks from spreading.', '必须迅速部署防控措施，以防局部疫情扩散。'),
  ('a9ad92d9-f579-4312-aacd-569f1d23895c-ex1', 'a9ad92d9-f579-4312-aacd-569f1d23895c', 'past', 'The bus drove past our stop.', '公交车开过了我们的站。'),
  ('a9ad92d9-f579-4312-aacd-569f1d23895c-ex2', 'a9ad92d9-f579-4312-aacd-569f1d23895c', 'past', 'Reconciling with the past is a precondition for building durable institutions of justice.', '正视历史是建立持久司法制度的前提。'),
  ('ee646b56-190b-46be-affb-9752639c5795-ex1', 'ee646b56-190b-46be-affb-9752639c5795', 'goal', 'He scored the winning goal.', '他打进了制胜一球。'),
  ('ee646b56-190b-46be-affb-9752639c5795-ex2', 'ee646b56-190b-46be-affb-9752639c5795', 'goal', 'The declaration commits member states to ambitious goals for poverty reduction by 2040.', '该宣言要求成员国承诺到2040年实现宏伟的减贫目标。'),
  ('b52527da-241d-445f-8db5-5b3ae0ad9ac7-ex1', 'b52527da-241d-445f-8db5-5b3ae0ad9ac7', 'bed', 'I go to bed at ten every night.', '我每晚十点睡觉。'),
  ('b52527da-241d-445f-8db5-5b3ae0ad9ac7-ex2', 'b52527da-241d-445f-8db5-5b3ae0ad9ac7', 'bed', 'Sediment accumulated on the river bed has substantially reduced the channel''s carrying capacity.', '河床上淤积的泥沙大幅降低了河道的过流能力。'),
  ('a3631b1f-2574-4fa1-9f3b-67fba0c52638-ex1', 'a3631b1f-2574-4fa1-9f3b-67fba0c52638', 'order', 'May I take your order?', '请问您要点什么？'),
  ('a3631b1f-2574-4fa1-9f3b-67fba0c52638-ex2', 'a3631b1f-2574-4fa1-9f3b-67fba0c52638', 'order', 'The court issued an order compelling the disclosure of the documents within fourteen days.', '法院发布命令，要求在十四天内披露这些文件。'),
  ('807f743b-5d88-4379-9716-bc3ecda2c0cf-ex1', '807f743b-5d88-4379-9716-bc3ecda2c0cf', 'author', 'Who is the author of this book?', '这本书的作者是谁？'),
  ('807f743b-5d88-4379-9716-bc3ecda2c0cf-ex2', '807f743b-5d88-4379-9716-bc3ecda2c0cf', 'author', 'The author of the report declined to speculate beyond what the evidence could support.', '报告作者拒绝做超出证据支持范围的推测。'),
  ('14bf8e01-c53a-4f05-9507-e13394b3e2e4-ex1', '14bf8e01-c53a-4f05-9507-e13394b3e2e4', 'fill', 'Please fill the bottle with water.', '请把瓶子装满水。'),
  ('14bf8e01-c53a-4f05-9507-e13394b3e2e4-ex2', '14bf8e01-c53a-4f05-9507-e13394b3e2e4', 'fill', 'The appointment is intended to fill a critical gap in the agency''s technical leadership.', '这项任命旨在填补该机构技术领导层的关键空缺。'),
  ('3346c74a-41d3-4c94-908a-cd887991c5b2-ex1', '3346c74a-41d3-4c94-908a-cd887991c5b2', 'represent', 'These stars represent the five continents.', '这些星星代表五大洲。'),
  ('3346c74a-41d3-4c94-908a-cd887991c5b2-ex2', '3346c74a-41d3-4c94-908a-cd887991c5b2', 'represent', 'Counsel was appointed to represent claimants unable to retain private legal services.', '法院指定律师代理无力聘请私人律师的索赔人。'),
  ('0c89dc77-aef0-40aa-9cb6-02d5016372bc-ex1', '0c89dc77-aef0-40aa-9cb6-02d5016372bc', 'focus', 'Please focus on your homework.', '请专心写作业。'),
  ('0c89dc77-aef0-40aa-9cb6-02d5016372bc-ex2', '0c89dc77-aef0-40aa-9cb6-02d5016372bc', 'focus', 'The inquiry will focus on the adequacy of the supervisory framework then in force.', '调查将聚焦于当时实施的监管框架是否充分。'),
  ('1387c921-783d-4f41-93aa-07af521de55d-ex1', '1387c921-783d-4f41-93aa-07af521de55d', 'foreign', 'She loves learning foreign languages.', '她喜欢学外语。'),
  ('1387c921-783d-4f41-93aa-07af521de55d-ex2', '1387c921-783d-4f41-93aa-07af521de55d', 'foreign', 'The legislation tightens scrutiny of foreign investment in critical infrastructure sectors.', '该立法加强了对关键基础设施领域外国投资的审查。'),
  ('e7f34ef3-eec8-4c25-bfda-7c2d7514d396-ex1', 'e7f34ef3-eec8-4c25-bfda-7c2d7514d396', 'drop', 'Be careful not to drop the glass.', '小心别把杯子摔了。'),
  ('e7f34ef3-eec8-4c25-bfda-7c2d7514d396-ex2', 'e7f34ef3-eec8-4c25-bfda-7c2d7514d396', 'drop', 'The prosecution agreed to drop the lesser charges in exchange for full cooperation.', '控方同意撤销较轻的指控，以换取全面合作。'),
  ('b8000c8b-1a02-4ad6-9bf9-cbfb424b985d-ex1', 'b8000c8b-1a02-4ad6-9bf9-cbfb424b985d', 'blood', 'The nurse took a blood sample.', '护士抽了血样。'),
  ('b8000c8b-1a02-4ad6-9bf9-cbfb424b985d-ex2', 'b8000c8b-1a02-4ad6-9bf9-cbfb424b985d', 'blood', 'Improved screening of donated blood has virtually eliminated transfusion-related infections.', '献血筛查的改进几乎消除了输血相关感染。'),
  ('df747ef8-1767-45ad-860a-573725db0b80-ex1', 'df747ef8-1767-45ad-860a-573725db0b80', 'upon', 'Once upon a time, there was a king.', '从前有一位国王。'),
  ('df747ef8-1767-45ad-860a-573725db0b80-ex2', 'df747ef8-1767-45ad-860a-573725db0b80', 'upon', 'The obligations take effect upon ratification by the requisite number of member states.', '这些义务在获得规定数量成员国批准后即行生效。'),
  ('f9eb40d4-09f9-4ea8-bc67-561a04ccd99b-ex1', 'f9eb40d4-09f9-4ea8-bc67-561a04ccd99b', 'agency', 'She found the job through an agency.', '她通过中介找到了这份工作。'),
  ('f9eb40d4-09f9-4ea8-bc67-561a04ccd99b-ex2', 'f9eb40d4-09f9-4ea8-bc67-561a04ccd99b', 'agency', 'The agency exceeded its statutory mandate by imposing requirements the legislature never authorized.', '该机构施加了立法机关从未授权的要求，超越了其法定职权。'),
  ('d752c513-d065-43f5-902f-09f831a35386-ex1', 'd752c513-d065-43f5-902f-09f831a35386', 'push', 'Push the door to open it.', '推门即可打开。'),
  ('d752c513-d065-43f5-902f-09f831a35386-ex2', 'd752c513-d065-43f5-902f-09f831a35386', 'push', 'Advocacy groups continue to push for binding targets rather than voluntary commitments.', '倡导团体继续推动制定有约束力的目标，而非自愿承诺。'),
  ('2e9e3c2b-8d10-4c7d-ba6f-f831e8c21c2c-ex1', '2e9e3c2b-8d10-4c7d-ba6f-f831e8c21c2c', 'nature', 'We enjoy spending time in nature.', '我们喜欢亲近大自然。'),
  ('2e9e3c2b-8d10-4c7d-ba6f-f831e8c21c2c-ex2', '2e9e3c2b-8d10-4c7d-ba6f-f831e8c21c2c', 'nature', 'The confidential nature of the negotiations precludes any public comment at this stage.', '谈判的保密性质决定了现阶段不能发表任何公开评论。'),
  ('668f56fd-1d3e-4586-8ca3-2f842a749dff-ex1', '668f56fd-1d3e-4586-8ca3-2f842a749dff', 'color', 'What is your favorite color?', '你最喜欢什么颜色？'),
  ('668f56fd-1d3e-4586-8ca3-2f842a749dff-ex2', '668f56fd-1d3e-4586-8ca3-2f842a749dff', 'color', 'The constitution prohibits discrimination on the basis of color, creed, or national origin.', '宪法禁止基于肤色、信仰或民族出身的歧视。'),
  ('faca235e-39fb-4de2-a357-8fddcdc5b8d7-ex1', 'faca235e-39fb-4de2-a357-8fddcdc5b8d7', 'recently', 'I recently started learning guitar.', '我最近开始学吉他。'),
  ('faca235e-39fb-4de2-a357-8fddcdc5b8d7-ex2', 'faca235e-39fb-4de2-a357-8fddcdc5b8d7', 'recently', 'Recently declassified documents shed new light on the diplomatic maneuvering of that era.', '最近解密的文件为那个时代的外交博弈提供了新的线索。'),
  ('7f5afd37-9b71-4348-b321-2faaa97b5f97-ex1', '7f5afd37-9b71-4348-b321-2faaa97b5f97', 'store', 'The store closes at nine tonight.', '商店今晚九点关门。'),
  ('7f5afd37-9b71-4348-b321-2faaa97b5f97-ex2', '7f5afd37-9b71-4348-b321-2faaa97b5f97', 'store', 'The facility was designed to store hazardous materials under rigorously controlled conditions.', '该设施旨在严格受控的条件下储存危险物质。'),
  ('72b243af-1f5d-4a14-ac84-c60c2aa906f6-ex1', '72b243af-1f5d-4a14-ac84-c60c2aa906f6', 'reduce', 'We should reduce our use of plastic.', '我们应该减少塑料的使用。'),
  ('72b243af-1f5d-4a14-ac84-c60c2aa906f6-ex2', '72b243af-1f5d-4a14-ac84-c60c2aa906f6', 'reduce', 'The accord obliges signatories to reduce emissions by forty percent within fifteen years.', '该协定要求签署国在十五年内将排放量减少百分之四十。'),
  ('9cb1168b-5609-4135-bb3e-b811ef0fb3e5-ex1', '9cb1168b-5609-4135-bb3e-b811ef0fb3e5', 'sound', 'I heard a strange sound outside.', '我听到外面有奇怪的声音。'),
  ('9cb1168b-5609-4135-bb3e-b811ef0fb3e5-ex2', '9cb1168b-5609-4135-bb3e-b811ef0fb3e5', 'sound', 'The recommendations rest on sound empirical foundations established through replicated studies.', '这些建议建立在经重复研究确立的坚实实证基础之上。'),
  ('2ece170f-b432-45db-b7e2-d537f14d2d37-ex1', '2ece170f-b432-45db-b7e2-d537f14d2d37', 'note', 'I left a note on your desk.', '我在你桌上留了张便条。'),
  ('2ece170f-b432-45db-b7e2-d537f14d2d37-ex2', '2ece170f-b432-45db-b7e2-d537f14d2d37', 'note', 'It is important to note that the sample excluded institutions below a certain asset threshold.', '需要指出的是，样本排除了资产低于一定门槛的机构。'),
  ('ca2f45b9-5519-47ee-9af8-3376ec9cd129-ex1', 'ca2f45b9-5519-47ee-9af8-3376ec9cd129', 'fine', 'Don''t worry, everything is fine.', '别担心，一切都很好。'),
  ('ca2f45b9-5519-47ee-9af8-3376ec9cd129-ex2', 'ca2f45b9-5519-47ee-9af8-3376ec9cd129', 'fine', 'The regulator imposed a record fine for systematic breaches of anti-money-laundering rules.', '监管机构因系统性违反反洗钱规定开出了创纪录的罚单。'),
  ('d5192d79-c83b-494c-9303-e415a69cd0e9-ex1', 'd5192d79-c83b-494c-9303-e415a69cd0e9', 'near', 'Is there a bank near here?', '这附近有银行吗？'),
  ('d5192d79-c83b-494c-9303-e415a69cd0e9-ex2', 'd5192d79-c83b-494c-9303-e415a69cd0e9', 'near', 'The facility''s proximity near protected wetlands raised substantial environmental objections.', '该设施紧邻受保护湿地，引发了强烈的环保异议。'),
  ('5b766b07-f67f-4b42-a52b-437fad8f29a4-ex1', '5b766b07-f67f-4b42-a52b-437fad8f29a4', 'movement', 'I saw a movement in the bushes.', '我看到灌木丛里有动静。'),
  ('5b766b07-f67f-4b42-a52b-437fad8f29a4-ex2', '5b766b07-f67f-4b42-a52b-437fad8f29a4', 'movement', 'The reform movement gathered momentum as successive scandals eroded public confidence.', '随着接连不断的丑闻侵蚀公众信心，改革运动声势日增。'),
  ('5c031a99-c3a0-4ead-9640-cf4e5426cb22-ex1', '5c031a99-c3a0-4ead-9640-cf4e5426cb22', 'page', 'Open your books to page ten.', '把书翻到第十页。'),
  ('5c031a99-c3a0-4ead-9640-cf4e5426cb22-ex2', '5c031a99-c3a0-4ead-9640-cf4e5426cb22', 'page', 'The treaty''s operative provisions occupy barely a page, yet their implications are far-reaching.', '条约的实质性条款仅一页篇幅，其影响却极为深远。'),
  ('5a598864-f9d0-4276-ad49-a9e2b5e5ac41-ex1', '5a598864-f9d0-4276-ad49-a9e2b5e5ac41', 'enter', 'Please knock before you enter.', '进来前请敲门。'),
  ('5a598864-f9d0-4276-ad49-a9e2b5e5ac41-ex2', '5a598864-f9d0-4276-ad49-a9e2b5e5ac41', 'enter', 'Firms seeking to enter the regulated market must first obtain the requisite licenses.', '希望进入受监管市场的企业必须先取得必要的许可证。'),
  ('7eceaf78-adcf-459e-86d1-b665286996a1-ex1', '7eceaf78-adcf-459e-86d1-b665286996a1', 'share', 'Let''s share this pizza.', '我们分着吃这个披萨吧。'),
  ('7eceaf78-adcf-459e-86d1-b665286996a1-ex2', '7eceaf78-adcf-459e-86d1-b665286996a1', 'share', 'Member states agreed to share intelligence relating to cross-border financial crime.', '成员国同意共享有关跨境金融犯罪的情报。'),
  ('e19fa5f4-24c1-4e62-9b51-96a309d5c57c-ex1', 'e19fa5f4-24c1-4e62-9b51-96a309d5c57c', 'common', 'We have many common interests.', '我们有很多共同的兴趣。'),
  ('e19fa5f4-24c1-4e62-9b51-96a309d5c57c-ex2', 'e19fa5f4-24c1-4e62-9b51-96a309d5c57c', 'common', 'The directive establishes common standards applicable across all member jurisdictions.', '该指令确立了适用于所有成员辖区的统一标准。'),
  ('22ba0901-5624-4293-a932-37ecbde28930-ex1', '22ba0901-5624-4293-a932-37ecbde28930', 'poor', 'The soil here is too poor for farming.', '这里的土壤太贫瘠，不适合耕种。'),
  ('22ba0901-5624-4293-a932-37ecbde28930-ex2', '22ba0901-5624-4293-a932-37ecbde28930', 'poor', 'The audit attributed the project''s failure to poor governance and inadequate oversight.', '审计将项目失败归因于治理不善和监督不力。'),
  ('b6833752-2174-4f77-8afa-b7fc283edda5-ex1', 'b6833752-2174-4f77-8afa-b7fc283edda5', 'natural', 'This juice contains only natural ingredients.', '这种果汁只含天然成分。'),
  ('b6833752-2174-4f77-8afa-b7fc283edda5-ex2', 'b6833752-2174-4f77-8afa-b7fc283edda5', 'natural', 'The region''s natural resources have been depleted at a rate that alarms conservationists.', '该地区自然资源的消耗速度令环保人士深感忧虑。'),
  ('fbd8c41e-9cb6-41e1-a378-5111e5335d14-ex1', 'fbd8c41e-9cb6-41e1-a378-5111e5335d14', 'race', 'He won the race by two seconds.', '他以两秒的优势赢得了比赛。'),
  ('fbd8c41e-9cb6-41e1-a378-5111e5335d14-ex2', 'fbd8c41e-9cb6-41e1-a378-5111e5335d14', 'race', 'The commission documented persistent disparities in sentencing correlated with race.', '委员会记录了与种族相关的、长期存在的量刑差异。'),
  ('fb8fc9b6-0960-4bb9-81ac-3d29eb777b6b-ex1', 'fb8fc9b6-0960-4bb9-81ac-3d29eb777b6b', 'concern', 'Thank you for your concern.', '谢谢你的关心。'),
  ('fb8fc9b6-0960-4bb9-81ac-3d29eb777b6b-ex2', 'fb8fc9b6-0960-4bb9-81ac-3d29eb777b6b', 'concern', 'The auditors expressed grave concern regarding the entity''s ability to continue as a going concern.', '审计师对该实体的持续经营能力表示严重关切。'),
  ('d90da9af-9629-49dd-b8af-f1d307ef4828-ex1', 'd90da9af-9629-49dd-b8af-f1d307ef4828', 'series', 'I am watching a new TV series.', '我在追一部新剧。'),
  ('d90da9af-9629-49dd-b8af-f1d307ef4828-ex2', 'd90da9af-9629-49dd-b8af-f1d307ef4828', 'series', 'A series of coordinated interventions stabilized the currency within a matter of weeks.', '一系列协调干预在数周内稳定了汇率。'),
  ('b99843c9-ad4f-4f06-ae70-fb0d2b5a4edb-ex1', 'b99843c9-ad4f-4f06-ae70-fb0d2b5a4edb', 'significant', 'There has been a significant change in the weather.', '天气发生了显著变化。'),
  ('b99843c9-ad4f-4f06-ae70-fb0d2b5a4edb-ex2', 'b99843c9-ad4f-4f06-ae70-fb0d2b5a4edb', 'significant', 'The tribunal found significant procedural irregularities that vitiated the original award.', '法庭发现了使原裁决无效的重大程序违规。'),
  ('d77abb79-7d6a-4c96-8f54-063898d35da3-ex1', 'd77abb79-7d6a-4c96-8f54-063898d35da3', 'similar', 'Your bag is similar to mine.', '你的包和我的很像。'),
  ('d77abb79-7d6a-4c96-8f54-063898d35da3-ex2', 'd77abb79-7d6a-4c96-8f54-063898d35da3', 'similar', 'Jurisdictions facing similar demographic pressures have adopted markedly divergent policy responses.', '面临类似人口压力的辖区采取了截然不同的政策应对。'),
  ('da7a53f6-1461-4ab7-a92c-148027f9d9af-ex1', 'da7a53f6-1461-4ab7-a92c-148027f9d9af', 'hot', 'Be careful, the soup is very hot.', '小心，汤很烫。'),
  ('da7a53f6-1461-4ab7-a92c-148027f9d9af-ex2', 'da7a53f6-1461-4ab7-a92c-148027f9d9af', 'hot', 'Negotiations over water rights have become a hot issue in the increasingly arid region.', '在日益干旱的地区，水权谈判已成为热点议题。'),
  ('fb48fdb3-342f-4ce7-9727-fc90689916b8-ex1', 'fb48fdb3-342f-4ce7-9727-fc90689916b8', 'language', 'English is a global language.', '英语是一门全球性语言。'),
  ('fb48fdb3-342f-4ce7-9727-fc90689916b8-ex2', 'fb48fdb3-342f-4ce7-9727-fc90689916b8', 'language', 'The statute''s ambiguous language has generated extensive litigation over its proper interpretation.', '该法规措辞含糊，引发了大量关于其正确解释的诉讼。'),
  ('2c2032eb-ac95-4561-b29e-aadde80339dd-ex1', '2c2032eb-ac95-4561-b29e-aadde80339dd', 'usually', 'I usually get up at seven.', '我通常七点起床。'),
  ('2c2032eb-ac95-4561-b29e-aadde80339dd-ex2', '2c2032eb-ac95-4561-b29e-aadde80339dd', 'usually', 'Structural reforms of this magnitude usually require years of sustained political commitment.', '如此规模的结构性改革通常需要多年持续的政治投入。'),
  ('2e93265a-8d6f-41ba-bceb-ac96295a1828-ex1', '2e93265a-8d6f-41ba-bceb-ac96295a1828', 'response', 'I am still waiting for her response.', '我还在等她的回复。'),
  ('2e93265a-8d6f-41ba-bceb-ac96295a1828-ex2', '2e93265a-8d6f-41ba-bceb-ac96295a1828', 'response', 'The coordinated international response prevented the outbreak from escalating into a pandemic.', '协调一致的国际应对阻止了疫情升级为大流行。'),
  ('d751b715-3646-4224-a67e-547652a53379-ex1', 'd751b715-3646-4224-a67e-547652a53379', 'dead', 'The battery is dead.', '电池没电了。'),
  ('d751b715-3646-4224-a67e-547652a53379-ex2', 'd751b715-3646-4224-a67e-547652a53379', 'dead', 'The negotiations were declared dead after the final compromise proposal was rejected.', '最后的折中方案遭拒后，谈判被宣告破裂。'),
  ('7909dcb3-28e8-4a5d-8611-6cad88162cf2-ex1', '7909dcb3-28e8-4a5d-8611-6cad88162cf2', 'rise', 'Prices continue to rise.', '物价持续上涨。'),
  ('7909dcb3-28e8-4a5d-8611-6cad88162cf2-ex2', '7909dcb3-28e8-4a5d-8611-6cad88162cf2', 'rise', 'The rise of algorithmic trading has fundamentally altered the dynamics of capital markets.', '算法交易的兴起从根本上改变了资本市场的运行规律。'),
  ('af2e9bc5-f5b6-433e-8514-0f2aad31b87b-ex1', 'af2e9bc5-f5b6-433e-8514-0f2aad31b87b', 'animal', 'My favorite animal is the panda.', '我最喜欢的动物是熊猫。'),
  ('af2e9bc5-f5b6-433e-8514-0f2aad31b87b-ex2', 'af2e9bc5-f5b6-433e-8514-0f2aad31b87b', 'animal', 'The legislation imposes criminal penalties for trafficking in endangered animal species.', '该立法对贩运濒危动物物种的行为规定了刑事处罚。'),
  ('69bec38b-2d93-4832-8795-870f28a072ab-ex1', '69bec38b-2d93-4832-8795-870f28a072ab', 'factor', 'Weather is an important factor in farming.', '天气是农业的重要因素。'),
  ('69bec38b-2d93-4832-8795-870f28a072ab-ex2', '69bec38b-2d93-4832-8795-870f28a072ab', 'factor', 'Demographic decline has emerged as the decisive factor constraining long-term growth projections.', '人口下降已成为制约长期增长预期的决定性因素。'),
  ('022c4dab-03c5-4cdd-9d3a-23f19e765f7c-ex1', '022c4dab-03c5-4cdd-9d3a-23f19e765f7c', 'decade', 'They have been friends for a decade.', '他们已经是十年的朋友了。'),
  ('022c4dab-03c5-4cdd-9d3a-23f19e765f7c-ex2', '022c4dab-03c5-4cdd-9d3a-23f19e765f7c', 'decade', 'Over the past decade, renewable generation capacity has expanded at an unprecedented pace.', '过去十年，可再生能源发电能力以前所未有的速度扩张。'),
  ('daa3fd63-bba1-4901-b301-8bdea5a09c5e-ex1', 'daa3fd63-bba1-4901-b301-8bdea5a09c5e', 'article', 'I read an interesting article today.', '我今天读了一篇有趣的文章。'),
  ('daa3fd63-bba1-4901-b301-8bdea5a09c5e-ex2', 'daa3fd63-bba1-4901-b301-8bdea5a09c5e', 'article', 'Article seven of the convention obliges states to provide effective judicial remedies.', '公约第七条要求各国提供有效的司法救济。'),
  ('9852eefc-f54d-4403-9690-135582c67ead-ex1', '9852eefc-f54d-4403-9690-135582c67ead', 'shoot', 'He can shoot the basketball really well.', '他投篮投得很准。'),
  ('9852eefc-f54d-4403-9690-135582c67ead-ex2', '9852eefc-f54d-4403-9690-135582c67ead', 'shoot', 'The directive prohibits officers from electing to shoot except in defense of life.', '该指令禁止警员开枪，保护生命安全的情形除外。'),
  ('d7efed1b-5523-4fee-95e9-a79fc906a255-ex1', 'd7efed1b-5523-4fee-95e9-a79fc906a255', 'east', 'The sun rises in the east.', '太阳从东方升起。'),
  ('d7efed1b-5523-4fee-95e9-a79fc906a255-ex2', 'd7efed1b-5523-4fee-95e9-a79fc906a255', 'east', 'Infrastructure investment has shifted markedly toward the rapidly industrializing east.', '基础设施投资明显转向快速工业化的东部地区。'),
  ('48e6d8e7-b7c9-4eb0-9cdf-22aa62efdce7-ex1', '48e6d8e7-b7c9-4eb0-9cdf-22aa62efdce7', 'save', 'I am trying to save money for a trip.', '我正在为旅行存钱。'),
  ('48e6d8e7-b7c9-4eb0-9cdf-22aa62efdce7-ex2', '48e6d8e7-b7c9-4eb0-9cdf-22aa62efdce7', 'save', 'Early warning systems are credited with helping save thousands of lives during the floods.', '预警系统被认为在洪灾期间帮助挽救了数千人的生命。'),
  ('55072a77-b8ff-4c08-bd7f-fa945fc90132-ex1', '55072a77-b8ff-4c08-bd7f-fa945fc90132', 'seven', 'The store opens at seven.', '商店七点开门。'),
  ('55072a77-b8ff-4c08-bd7f-fa945fc90132-ex2', '55072a77-b8ff-4c08-bd7f-fa945fc90132', 'seven', 'The panel comprises seven jurists drawn from distinct legal traditions.', '该评审团由来自不同法律传统的七位法学家组成。'),
  ('61d56b47-9569-4b5f-835c-62fadc6e1ae7-ex1', '61d56b47-9569-4b5f-835c-62fadc6e1ae7', 'artist', 'She is a talented young artist.', '她是一位有才华的年轻艺术家。'),
  ('61d56b47-9569-4b5f-835c-62fadc6e1ae7-ex2', '61d56b47-9569-4b5f-835c-62fadc6e1ae7', 'artist', 'The retrospective traces the artist''s evolution across five decades of restless experimentation.', '这次回顾展追溯了这位艺术家五十年不懈探索的艺术历程。'),
  ('a4694bdc-3b71-4603-a21c-06c219022a50-ex1', 'a4694bdc-3b71-4603-a21c-06c219022a50', 'scene', 'The opening scene of the movie is amazing.', '电影的开场画面非常震撼。'),
  ('a4694bdc-3b71-4603-a21c-06c219022a50-ex2', 'a4694bdc-3b71-4603-a21c-06c219022a50', 'scene', 'Forensic specialists secured the scene pending the arrival of the investigating magistrate.', '法医专家封锁了现场，等待预审法官到来。'),
  ('bffca573-1982-4b33-a75d-c437c543799c-ex1', 'bffca573-1982-4b33-a75d-c437c543799c', 'stock', 'The stock market went up today.', '今天股市上涨了。'),
  ('bffca573-1982-4b33-a75d-c437c543799c-ex2', 'bffca573-1982-4b33-a75d-c437c543799c', 'stock', 'The company''s stock plummeted following disclosure of the accounting irregularities.', '会计违规问题披露后，该公司股价暴跌。'),
  ('7cb7eddf-4119-4b53-8d1f-0d5f6f05a971-ex1', '7cb7eddf-4119-4b53-8d1f-0d5f6f05a971', 'career', 'She has a successful career in law.', '她在法律界事业有成。'),
  ('7cb7eddf-4119-4b53-8d1f-0d5f6f05a971-ex2', '7cb7eddf-4119-4b53-8d1f-0d5f6f05a971', 'career', 'His distinguished career spanned four decades of public service across three administrations.', '他的杰出职业生涯横跨三届政府、长达四十年的公共服务。'),
  ('b1d01c16-7e14-42e0-9482-86222755e14c-ex1', 'b1d01c16-7e14-42e0-9482-86222755e14c', 'despite', 'We went hiking despite the rain.', '尽管下雨，我们还是去远足了。'),
  ('b1d01c16-7e14-42e0-9482-86222755e14c-ex2', 'b1d01c16-7e14-42e0-9482-86222755e14c', 'despite', 'Despite repeated assurances, the promised structural reforms never materialized.', '尽管一再保证，承诺的结构性改革始终未能落实。'),
  ('be30be90-a52e-4165-a4e5-6df927d688f6-ex1', 'be30be90-a52e-4165-a4e5-6df927d688f6', 'central', 'We met in the central square.', '我们在中心广场见面。'),
  ('be30be90-a52e-4165-a4e5-6df927d688f6-ex2', 'be30be90-a52e-4165-a4e5-6df927d688f6', 'central', 'Transparency is central to the legitimacy of any regulatory institution.', '透明度对任何监管机构的公信力都至关重要。'),
  ('2c2d0519-5f04-4902-ab95-9394c26e90ee-ex1', '2c2d0519-5f04-4902-ab95-9394c26e90ee', 'eight', 'The train leaves at eight.', '火车八点发车。'),
  ('2c2d0519-5f04-4902-ab95-9394c26e90ee-ex2', '2c2d0519-5f04-4902-ab95-9394c26e90ee', 'eight', 'The accord was ratified by all eight signatory states within a single legislative session.', '该协定在一个立法会期内获得全部八个签署国批准。'),
  ('fea43360-5e56-430d-8f7d-835774426a4d-ex1', 'fea43360-5e56-430d-8f7d-835774426a4d', 'thus', 'He was ill, and thus could not come.', '他病了，因此没能来。'),
  ('fea43360-5e56-430d-8f7d-835774426a4d-ex2', 'fea43360-5e56-430d-8f7d-835774426a4d', 'thus', 'The defect originated in design rather than manufacture; thus liability rests with the contractor.', '缺陷源于设计而非制造，因此责任由承包商承担。'),
  ('41e3d50c-9c9d-419e-aae5-d77423584074-ex1', '41e3d50c-9c9d-419e-aae5-d77423584074', 'treatment', 'The new treatment is working well.', '新的治疗方法效果很好。'),
  ('41e3d50c-9c9d-419e-aae5-d77423584074-ex2', '41e3d50c-9c9d-419e-aae5-d77423584074', 'treatment', 'The protocol guarantees equal treatment for all applicants regardless of national origin.', '该协议保障所有申请人不分国籍一律平等对待。'),
  ('b3dbebdd-bd1d-49ad-9522-3389b66ec4db-ex1', 'b3dbebdd-bd1d-49ad-9522-3389b66ec4db', 'beyond', 'The village is just beyond the hill.', '村子就在山的那一边。'),
  ('b3dbebdd-bd1d-49ad-9522-3389b66ec4db-ex2', 'b3dbebdd-bd1d-49ad-9522-3389b66ec4db', 'beyond', 'The consequences of the decision extend far beyond the immediate parties to the dispute.', '这一裁决的影响远远超出争端当事方本身。'),
  ('8852623e-e2e6-4995-92bd-5d6b6204b3df-ex1', '8852623e-e2e6-4995-92bd-5d6b6204b3df', 'happy', 'I am so happy to see you!', '见到你我太高兴了！'),
  ('8852623e-e2e6-4995-92bd-5d6b6204b3df-ex2', '8852623e-e2e6-4995-92bd-5d6b6204b3df', 'happy', 'The mediator declared herself happy with the constructive tone of the preliminary talks.', '调解人表示对初步会谈的建设性基调感到满意。'),
  ('5feaa4f5-c28b-4360-8b88-cf40f67da034-ex1', '5feaa4f5-c28b-4360-8b88-cf40f67da034', 'exactly', 'That is exactly what I meant.', '我就是这个意思。'),
  ('5feaa4f5-c28b-4360-8b88-cf40f67da034-ex2', '5feaa4f5-c28b-4360-8b88-cf40f67da034', 'exactly', 'The commission sought to determine exactly when senior management became aware of the defect.', '委员会力图查明高级管理层究竟何时知晓该缺陷。'),
  ('106beaa4-d276-440c-a071-5b110d5e1841-ex1', '106beaa4-d276-440c-a071-5b110d5e1841', 'protect', 'Wear a helmet to protect your head.', '戴上头盔保护头部。'),
  ('106beaa4-d276-440c-a071-5b110d5e1841-ex2', '106beaa4-d276-440c-a071-5b110d5e1841', 'protect', 'The statute is designed to protect whistleblowers from retaliatory dismissal.', '该法规旨在保护举报人免遭报复性解雇。'),
  ('423b7acd-3758-4e66-a485-8daeaa45990c-ex1', '423b7acd-3758-4e66-a485-8daeaa45990c', 'approach', 'Winter is approaching quickly.', '冬天很快就要到了。'),
  ('423b7acd-3758-4e66-a485-8daeaa45990c-ex2', '423b7acd-3758-4e66-a485-8daeaa45990c', 'approach', 'The regulator adopted a risk-based approach that concentrates scrutiny on systemically important firms.', '监管机构采取了基于风险的方法，将审查重点放在具有系统重要性的公司上。'),
  ('ad6c30a1-38d6-4979-8b33-18714e13ea26-ex1', 'ad6c30a1-38d6-4979-8b33-18714e13ea26', 'lie', 'Don''t lie to me.', '别对我撒谎。'),
  ('ad6c30a1-38d6-4979-8b33-18714e13ea26-ex2', 'ad6c30a1-38d6-4979-8b33-18714e13ea26', 'lie', 'The root causes of the crisis lie in decades of underinvestment and regulatory neglect.', '危机的根源在于数十年的投资不足和监管缺位。'),
  ('b5427906-dcc5-4c7b-9c61-460ca7ed6d55-ex1', 'b5427906-dcc5-4c7b-9c61-460ca7ed6d55', 'size', 'What size shoes do you wear?', '你穿多大码的鞋？'),
  ('b5427906-dcc5-4c7b-9c61-460ca7ed6d55-ex2', 'b5427906-dcc5-4c7b-9c61-460ca7ed6d55', 'size', 'The sheer size of the settlement reflects the gravity of the misconduct involved.', '和解金额之巨反映了所涉不当行为的严重程度。'),
  ('3bdf0a85-03d1-4557-a842-809d06b1fb96-ex1', '3bdf0a85-03d1-4557-a842-809d06b1fb96', 'dog', 'My dog loves playing in the park.', '我的狗喜欢在公园里玩。'),
  ('3bdf0a85-03d1-4557-a842-809d06b1fb96-ex2', '3bdf0a85-03d1-4557-a842-809d06b1fb96', 'dog', 'Specially trained dogs are deployed to detect contraband at major ports of entry.', '经过特殊训练的犬只被部署在主要入境口岸侦测违禁品。'),
  ('ebc86d79-8a57-4f80-88be-796ba37c0d2f-ex1', 'ebc86d79-8a57-4f80-88be-796ba37c0d2f', 'fund', 'We are raising funds for the school library.', '我们正在为学校图书馆筹款。'),
  ('ebc86d79-8a57-4f80-88be-796ba37c0d2f-ex2', 'ebc86d79-8a57-4f80-88be-796ba37c0d2f', 'fund', 'The sovereign wealth fund divested its holdings in companies failing environmental benchmarks.', '该主权财富基金减持了未达环境基准企业的股份。'),
  ('b5dc4882-c1d8-4200-8b62-9b2cb0c68a7d-ex1', 'b5dc4882-c1d8-4200-8b62-9b2cb0c68a7d', 'serious', 'Are you serious about moving abroad?', '你真的想移居国外吗？'),
  ('b5dc4882-c1d8-4200-8b62-9b2cb0c68a7d-ex2', 'b5dc4882-c1d8-4200-8b62-9b2cb0c68a7d', 'serious', 'The breach constitutes a serious violation warranting referral to the enforcement division.', '这一违规行为情节严重，应移交执法部门处理。'),
  ('9227d960-5257-48b5-8ac8-dc824d47ad96-ex1', '9227d960-5257-48b5-8ac8-dc824d47ad96', 'occur', 'Accidents can occur at any time.', '事故随时可能发生。'),
  ('9227d960-5257-48b5-8ac8-dc824d47ad96-ex2', '9227d960-5257-48b5-8ac8-dc824d47ad96', 'occur', 'Should a material breach occur, the aggrieved party may invoke the termination clause.', '如发生重大违约，受损方可援引终止条款。'),
  ('7f068cd6-30d8-4a72-9dc8-970d8008d0b9-ex1', '7f068cd6-30d8-4a72-9dc8-970d8008d0b9', 'media', 'The story spread quickly on social media.', '这个故事在社交媒体上迅速传播。'),
  ('7f068cd6-30d8-4a72-9dc8-970d8008d0b9-ex2', '7f068cd6-30d8-4a72-9dc8-970d8008d0b9', 'media', 'The commission examined the role of media consolidation in narrowing the diversity of public discourse.', '委员会审视了媒体兼并在压缩公共话语多样性方面的作用。'),
  ('793ef5d2-1bab-46b2-884b-c57bc1b49b03-ex1', '793ef5d2-1bab-46b2-884b-c57bc1b49b03', 'ready', 'Dinner is ready!', '晚饭好了！'),
  ('793ef5d2-1bab-46b2-884b-c57bc1b49b03-ex2', '793ef5d2-1bab-46b2-884b-c57bc1b49b03', 'ready', 'The contingency plans must be ready for activation at the first indication of systemic stress.', '应急预案必须随时待命，一旦出现系统性压力迹象即可启动。'),
  ('355c9ade-6b41-4d67-8749-a372864df491-ex1', '355c9ade-6b41-4d67-8749-a372864df491', 'sign', 'Please sign your name here.', '请在这里签名。'),
  ('355c9ade-6b41-4d67-8749-a372864df491-ex2', '355c9ade-6b41-4d67-8749-a372864df491', 'sign', 'Both heads of state will sign the accord at a ceremony attended by regional leaders.', '两国元首将在地区领导人出席的仪式上签署该协定。'),
  ('357f007b-653f-4ceb-ad07-be4ac09cf6f1-ex1', '357f007b-653f-4ceb-ad07-be4ac09cf6f1', 'thought', 'I just had a funny thought.', '我刚想到一件有趣的事。'),
  ('357f007b-653f-4ceb-ad07-be4ac09cf6f1-ex2', '357f007b-653f-4ceb-ad07-be4ac09cf6f1', 'thought', 'The proposal reflects careful thought regarding the long-term sustainability of public finances.', '该提案体现了对公共财政长期可持续性的深思熟虑。'),
  ('b569d93f-8c27-4728-bba5-ca13b6eacdbe-ex1', 'b569d93f-8c27-4728-bba5-ca13b6eacdbe', 'list', 'I made a list of things to buy.', '我列了一张购物清单。'),
  ('b569d93f-8c27-4728-bba5-ca13b6eacdbe-ex2', 'b569d93f-8c27-4728-bba5-ca13b6eacdbe', 'list', 'The agency maintains a list of entities subject to enhanced due diligence requirements.', '该机构维护着一份须接受强化尽职调查的实体名单。'),
  ('348b34f3-2fd7-4645-a75f-37c179e37d4b-ex1', '348b34f3-2fd7-4645-a75f-37c179e37d4b', 'individual', 'Each individual has different needs.', '每个人都有不同的需求。'),
  ('348b34f3-2fd7-4645-a75f-37c179e37d4b-ex2', '348b34f3-2fd7-4645-a75f-37c179e37d4b', 'individual', 'The charter affirms that every individual possesses rights no government may lawfully abridge.', '宪章申明，每个人都拥有任何政府均不得合法剥夺的权利。'),
  ('a9f544a4-9daa-4c4b-85db-eeeec22b80ff-ex1', 'a9f544a4-9daa-4c4b-85db-eeeec22b80ff', 'simple', 'The instructions are simple to follow.', '这些说明很容易照着做。'),
  ('a9f544a4-9daa-4c4b-85db-eeeec22b80ff-ex2', 'a9f544a4-9daa-4c4b-85db-eeeec22b80ff', 'simple', 'The elegance of the solution lies in its simple yet rigorously generalizable formulation.', '该解决方案的精妙之处在于其简洁而又可严格推广的表述。'),
  ('19e7aa16-3a84-4231-978b-0a467cd0e57e-ex1', '19e7aa16-3a84-4231-978b-0a467cd0e57e', 'quality', 'This shop sells high quality goods.', '这家店卖的商品质量很好。'),
  ('19e7aa16-3a84-4231-978b-0a467cd0e57e-ex2', '19e7aa16-3a84-4231-978b-0a467cd0e57e', 'quality', 'Accreditation depends upon demonstrable improvements in the quality of patient care.', '资质认证取决于患者护理质量的切实改善。'),
  ('b9a1ba77-cfc2-4867-a69b-810ad7406be9-ex1', 'b9a1ba77-cfc2-4867-a69b-810ad7406be9', 'pressure', 'The water pressure in the shower is low.', '淋浴的水压很低。'),
  ('b9a1ba77-cfc2-4867-a69b-810ad7406be9-ex2', 'b9a1ba77-cfc2-4867-a69b-810ad7406be9', 'pressure', 'Mounting diplomatic pressure ultimately compelled the regime to permit international inspections.', '不断加大的外交压力最终迫使该政权允许国际核查。'),
  ('fee99afb-016e-43d7-bc8f-403518644204-ex1', 'fee99afb-016e-43d7-bc8f-403518644204', 'accept', 'Please accept my apology.', '请接受我的道歉。'),
  ('fee99afb-016e-43d7-bc8f-403518644204-ex2', 'fee99afb-016e-43d7-bc8f-403518644204', 'accept', 'The committee voted to accept the auditor''s findings without amendment.', '委员会投票决定不加修改地采纳审计师的调查结果。'),
  ('baf6f050-eaae-4718-899a-6f40aa090ae7-ex1', 'baf6f050-eaae-4718-899a-6f40aa090ae7', 'answer', 'I don''t know the answer to this question.', '我不知道这个问题的答案。'),
  ('baf6f050-eaae-4718-899a-6f40aa090ae7-ex2', 'baf6f050-eaae-4718-899a-6f40aa090ae7', 'answer', 'The minister declined to answer questions concerning the ongoing criminal investigation.', '部长拒绝回答有关正在进行的刑事调查的问题。'),
  ('83373e0c-bf46-410d-b3d5-1ea34ca9bd3f-ex1', '83373e0c-bf46-410d-b3d5-1ea34ca9bd3f', 'resource', 'The library is a great resource for students.', '图书馆对学生来说是很好的资源。'),
  ('83373e0c-bf46-410d-b3d5-1ea34ca9bd3f-ex2', '83373e0c-bf46-410d-b3d5-1ea34ca9bd3f', 'resource', 'Equitable allocation of scarce resources remains the central challenge of public health planning.', '稀缺资源的公平分配仍是公共卫生规划的核心挑战。'),
  ('a55c9397-11df-4c48-b62f-ffc799f61f65-ex1', 'a55c9397-11df-4c48-b62f-ffc799f61f65', 'identify', 'Can you identify your bag among these?', '你能在这些包里认出你的吗？'),
  ('a55c9397-11df-4c48-b62f-ffc799f61f65-ex2', 'a55c9397-11df-4c48-b62f-ffc799f61f65', 'identify', 'The audit was commissioned to identify systemic weaknesses in the procurement process.', '这次审计旨在查明采购流程中的系统性薄弱环节。'),
