  ('ef49f29a-56d3-4a2b-8e4e-a9c0e2f7092c-ex2', 'ef49f29a-56d3-4a2b-8e4e-a9c0e2f7092c', 'analysis', 'A rigorous cost-benefit analysis preceded the adoption of the new emission standards.', '在采用新排放标准之前，进行了严格的成本效益分析。'),
  ('d111fc55-2c0e-4c52-9ab7-38fbb56b0978-ex1', 'd111fc55-2c0e-4c52-9ab7-38fbb56b0978', 'benefit', 'Exercise has many health benefits.', '锻炼对健康有很多好处。'),
  ('d111fc55-2c0e-4c52-9ab7-38fbb56b0978-ex2', 'd111fc55-2c0e-4c52-9ab7-38fbb56b0978', 'benefit', 'The amendments extend unemployment benefits to categories of workers previously excluded.', '修正案将失业救济扩大到此前被排除在外的劳动者群体。'),
  ('85745937-745f-4bb5-bc6c-0410178e2230-ex1', '85745937-745f-4bb5-bc6c-0410178e2230', 'sex', 'Please indicate your sex on the form.', '请在表格上注明性别。'),
  ('85745937-745f-4bb5-bc6c-0410178e2230-ex2', '85745937-745f-4bb5-bc6c-0410178e2230', 'sex', 'The act prohibits discrimination on the basis of sex in employment and education.', '该法案禁止在就业和教育领域基于性别的歧视。'),
  ('41473986-165b-4d1e-a51d-50b0f0e1b3ef-ex1', '41473986-165b-4d1e-a51d-50b0f0e1b3ef', 'forward', 'Please step forward when your name is called.', '叫到名字时请向前一步。'),
  ('41473986-165b-4d1e-a51d-50b0f0e1b3ef-ex2', '41473986-165b-4d1e-a51d-50b0f0e1b3ef', 'forward', 'The taskforce will carry the recommendations forward into the legislative drafting phase.', '工作组将把这些建议推进到立法起草阶段。'),
  ('7e03caea-4f88-4862-bfcd-d8b353ffe557-ex1', '7e03caea-4f88-4862-bfcd-d8b353ffe557', 'lawyer', 'You should talk to a lawyer about this.', '这件事你应该咨询律师。'),
  ('7e03caea-4f88-4862-bfcd-d8b353ffe557-ex2', '7e03caea-4f88-4862-bfcd-d8b353ffe557', 'lawyer', 'The defendant''s lawyer moved to suppress evidence obtained without a valid warrant.', '被告律师申请排除未经有效搜查令获取的证据。'),
  ('4a391349-30cc-4b59-8a2f-5b9721e54486-ex1', '4a391349-30cc-4b59-8a2f-5b9721e54486', 'present', 'Thank you for the birthday present!', '谢谢你的生日礼物！'),
  ('4a391349-30cc-4b59-8a2f-5b9721e54486-ex2', '4a391349-30cc-4b59-8a2f-5b9721e54486', 'present', 'The prosecution will present forensic evidence linking the defendant to the transactions.', '控方将出示把被告与这些交易联系起来的法医证据。'),
  ('36ed8459-1986-45a8-816f-502d8b164380-ex1', '36ed8459-1986-45a8-816f-502d8b164380', 'section', 'The sports section is at the back of the newspaper.', '体育版在报纸的后面。'),
  ('36ed8459-1986-45a8-816f-502d8b164380-ex2', '36ed8459-1986-45a8-816f-502d8b164380', 'section', 'Section twelve of the act empowers the regulator to impose interim measures.', '该法案第十二条授权监管机构采取临时措施。'),
  ('591ad3be-0ed7-40c8-bfc4-6473db20e9eb-ex1', '591ad3be-0ed7-40c8-bfc4-6473db20e9eb', 'environmental', 'We should raise environmental awareness.', '我们应该提高环保意识。'),
  ('591ad3be-0ed7-40c8-bfc4-6473db20e9eb-ex2', '591ad3be-0ed7-40c8-bfc4-6473db20e9eb', 'environmental', 'The project was halted pending completion of a statutory environmental impact assessment.', '该项目已暂停，待法定环境影响评估完成。'),
  ('f47dbce5-470c-4da8-b7cd-2251d0d76561-ex1', 'f47dbce5-470c-4da8-b7cd-2251d0d76561', 'glass', 'Could I have a glass of water?', '能给我一杯水吗？'),
  ('f47dbce5-470c-4da8-b7cd-2251d0d76561-ex2', 'f47dbce5-470c-4da8-b7cd-2251d0d76561', 'glass', 'The skyscraper''s glass facade was engineered to withstand seismic loads well beyond code requirements.', '这座摩天大楼的玻璃幕墙按远超规范要求的抗震载荷设计。'),
  ('4fde667c-8ff7-4619-9af7-aee2bbc6211f-ex1', '4fde667c-8ff7-4619-9af7-aee2bbc6211f', 'skill', 'Cooking is a useful skill.', '烹饪是一项有用的技能。'),
  ('4fde667c-8ff7-4619-9af7-aee2bbc6211f-ex2', '4fde667c-8ff7-4619-9af7-aee2bbc6211f', 'skill', 'The curriculum reform prioritizes analytical skills over rote memorization.', '课程改革将分析能力置于死记硬背之上。'),
  ('d3ed21fa-a02f-4276-87d8-3fd8b8be8ac4-ex1', 'd3ed21fa-a02f-4276-87d8-3fd8b8be8ac4', 'sister', 'My sister lives in another city.', '我姐姐住在另一座城市。'),
  ('d3ed21fa-a02f-4276-87d8-3fd8b8be8ac4-ex2', 'd3ed21fa-a02f-4276-87d8-3fd8b8be8ac4', 'sister', 'The two sister institutions coordinate their research agendas through a joint secretariat.', '这两家姊妹机构通过联合秘书处协调各自的研究议程。'),
  ('a6c5db8b-a697-4b16-9531-4615c3f1bab9-ex1', 'a6c5db8b-a697-4b16-9531-4615c3f1bab9', 'PM', 'The meeting is at 3 PM.', '会议在下午三点。'),
  ('a6c5db8b-a697-4b16-9531-4615c3f1bab9-ex2', 'a6c5db8b-a697-4b16-9531-4615c3f1bab9', 'PM', 'Trading was suspended at 2 PM following an unprecedented surge in sell orders.', '在卖单空前激增之后，交易于下午两点暂停。'),
  ('6a1d5157-d6ac-4ca3-8373-63527141f45d-ex1', '6a1d5157-d6ac-4ca3-8373-63527141f45d', 'professor', 'Our professor explains things clearly.', '我们的教授讲解得很清楚。'),
  ('6a1d5157-d6ac-4ca3-8373-63527141f45d-ex2', '6a1d5157-d6ac-4ca3-8373-63527141f45d', 'professor', 'The professor''s testimony proved decisive in establishing the scientific consensus before the court.', '这位教授的证词对在法庭上确立科学共识起到了决定性作用。'),
  ('66e07b06-0c9a-42b6-be6b-cc95d63e2197-ex1', '66e07b06-0c9a-42b6-be6b-cc95d63e2197', 'operation', 'The operation took three hours.', '手术持续了三个小时。'),
  ('66e07b06-0c9a-42b6-be6b-cc95d63e2197-ex2', '66e07b06-0c9a-42b6-be6b-cc95d63e2197', 'operation', 'The rescue operation mobilized assets from civilian and military agencies alike.', '这次救援行动同时调动了民用和军方机构的力量。'),
  ('facd449b-38a2-4717-97a6-98154c7b22d7-ex1', 'facd449b-38a2-4717-97a6-98154c7b22d7', 'financial', 'He gives me good financial advice.', '他给我很好的理财建议。'),
  ('facd449b-38a2-4717-97a6-98154c7b22d7-ex2', 'facd449b-38a2-4717-97a6-98154c7b22d7', 'financial', 'The financial statements were restated following the discovery of material misclassifications.', '在发现重大分类错误后，财务报表予以重述。'),
  ('2c8b5925-ad21-4de9-9dc2-7f1d5fb7fea8-ex1', '2c8b5925-ad21-4de9-9dc2-7f1d5fb7fea8', 'crime', 'The police are investigating the crime.', '警方正在调查这起案件。'),
  ('2c8b5925-ad21-4de9-9dc2-7f1d5fb7fea8-ex2', '2c8b5925-ad21-4de9-9dc2-7f1d5fb7fea8', 'crime', 'The convention obliges states to criminalize cross-border environmental crime.', '该公约要求各国将跨境环境犯罪定为刑事犯罪。'),
  ('ebbe4085-6a96-48fa-9aa3-4fa0743f283b-ex1', 'ebbe4085-6a96-48fa-9aa3-4fa0743f283b', 'stage', 'The singer walked onto the stage.', '歌手走上了舞台。'),
  ('ebbe4085-6a96-48fa-9aa3-4fa0743f283b-ex2', 'ebbe4085-6a96-48fa-9aa3-4fa0743f283b', 'stage', 'The negotiations have reached a stage at which substantive concessions become unavoidable.', '谈判已进入实质性让步不可避免的阶段。'),
  ('440c2ea1-b785-4907-8e67-c22866e01726-ex1', '440c2ea1-b785-4907-8e67-c22866e01726', 'ok', 'OK, let''s meet at noon.', '好的，我们中午见。'),
  ('440c2ea1-b785-4907-8e67-c22866e01726-ex2', '440c2ea1-b785-4907-8e67-c22866e01726', 'ok', 'The committee deemed the interim arrangements OK pending formal ratification of the protocol.', '委员会认为，在议定书正式批准之前，临时安排尚可接受。'),
  ('474afb36-c392-4127-9064-5d840ed81758-ex1', '474afb36-c392-4127-9064-5d840ed81758', 'compare', 'Compare the two prices before you buy.', '买之前比较一下两个价格。'),
  ('474afb36-c392-4127-9064-5d840ed81758-ex2', '474afb36-c392-4127-9064-5d840ed81758', 'compare', 'The study compares regulatory outcomes across jurisdictions with divergent enforcement traditions.', '该研究比较了执法传统各异的司法管辖区的监管成效。'),
  ('1cfecb43-dac3-4d82-9ce2-25304df59650-ex1', '1cfecb43-dac3-4d82-9ce2-25304df59650', 'authority', 'You should report this to the authorities.', '你应该向有关部门报告此事。'),
  ('1cfecb43-dac3-4d82-9ce2-25304df59650-ex2', '1cfecb43-dac3-4d82-9ce2-25304df59650', 'authority', 'The tribunal held that the agency had acted beyond its delegated authority.', '法庭裁定该机构的行为超出了其获授权限。'),
  ('9471879b-d0ce-488d-9c5f-99e422795b86-ex1', '9471879b-d0ce-488d-9c5f-99e422795b86', 'miss', 'Hurry up, or we will miss the train.', '快点，不然我们要错过火车了。'),
  ('9471879b-d0ce-488d-9c5f-99e422795b86-ex2', '9471879b-d0ce-488d-9c5f-99e422795b86', 'miss', 'The auditors did not miss the discrepancy between reported and actual inventories.', '审计人员没有放过账面库存与实际库存之间的差异。'),
  ('88e2bb9a-24c7-4cdf-94bc-238e22dec4e4-ex1', '88e2bb9a-24c7-4cdf-94bc-238e22dec4e4', 'design', 'I love the design of this chair.', '我喜欢这把椅子的设计。'),
  ('88e2bb9a-24c7-4cdf-94bc-238e22dec4e4-ex2', '88e2bb9a-24c7-4cdf-94bc-238e22dec4e4', 'design', 'The bridge''s innovative design earned international recognition for structural ingenuity.', '这座桥的创新设计因结构上的巧思而获得国际赞誉。'),
  ('3cec870f-0f4d-48b9-8d03-8a321b4c4512-ex1', '3cec870f-0f4d-48b9-8d03-8a321b4c4512', 'sort', 'What sort of music do you like?', '你喜欢哪类音乐？'),
  ('3cec870f-0f4d-48b9-8d03-8a321b4c4512-ex2', '3cec870f-0f4d-48b9-8d03-8a321b4c4512', 'sort', 'The legislation addresses precisely the sort of conflict of interest exposed by the scandal.', '该立法所针对的正是这起丑闻暴露出的那类利益冲突。'),
  ('f9f268de-b262-43d3-b1d2-a710f8fe819b-ex1', 'f9f268de-b262-43d3-b1d2-a710f8fe819b', 'act', 'The magician''s act amazed the children.', '魔术师的表演让孩子们惊叹不已。'),
  ('f9f268de-b262-43d3-b1d2-a710f8fe819b-ex2', 'f9f268de-b262-43d3-b1d2-a710f8fe819b', 'act', 'The act empowers regulators to intervene preemptively where systemic risk is identified.', '该法案授权监管机构在发现系统性风险时先行干预。'),
  ('f9c8f098-ef56-476d-8b85-69b9fed56ed8-ex1', 'f9c8f098-ef56-476d-8b85-69b9fed56ed8', 'ten', 'The store opens in ten minutes.', '商店十分钟后开门。'),
  ('f9c8f098-ef56-476d-8b85-69b9fed56ed8-ex2', 'f9c8f098-ef56-476d-8b85-69b9fed56ed8', 'ten', 'The strategic plan articulates ten priorities to be pursued over the coming decade.', '战略规划阐明了未来十年要推进的十项优先任务。'),
  ('2cd3ce3b-b327-4877-a2f7-0e25db32cd58-ex1', '2cd3ce3b-b327-4877-a2f7-0e25db32cd58', 'knowledge', 'Reading expands your knowledge.', '阅读能拓展你的知识。'),
  ('2cd3ce3b-b327-4877-a2f7-0e25db32cd58-ex2', '2cd3ce3b-b327-4877-a2f7-0e25db32cd58', 'knowledge', 'The defendants acted with full knowledge of the regulatory prohibitions then in force.', '被告在完全知晓当时有效监管禁令的情况下实施了行为。'),
  ('673addd7-e5db-4f47-9cdb-32636f300bc0-ex1', '673addd7-e5db-4f47-9cdb-32636f300bc0', 'gun', 'The police officer carries a gun.', '那名警察佩带枪支。'),
  ('673addd7-e5db-4f47-9cdb-32636f300bc0-ex2', '673addd7-e5db-4f47-9cdb-32636f300bc0', 'gun', 'The legislation imposes comprehensive background checks on all gun transfers.', '该立法对所有枪支转让实施全面背景审查。'),
  ('14b64967-9c9a-47bf-9161-ce75e5a99487-ex1', '14b64967-9c9a-47bf-9161-ce75e5a99487', 'station', 'I will meet you at the train station.', '我在火车站等你。'),
  ('14b64967-9c9a-47bf-9161-ce75e5a99487-ex2', '14b64967-9c9a-47bf-9161-ce75e5a99487', 'station', 'The monitoring station records seismic activity across the entire fault system.', '该监测站记录整个断层系统的地震活动。'),
  ('0d5eb07f-59ed-4640-91d8-fe83912d608c-ex1', '0d5eb07f-59ed-4640-91d8-fe83912d608c', 'blue', 'The sky is bright blue today.', '今天天空湛蓝。'),
  ('0d5eb07f-59ed-4640-91d8-fe83912d608c-ex2', '0d5eb07f-59ed-4640-91d8-fe83912d608c', 'blue', 'The report arrived out of the blue, upending months of carefully laid legislative strategy.', '这份报告不期而至，打乱了数月来精心筹划的立法策略。'),
  ('4b15fe5a-fb04-47d9-8fb3-9eeac832acfe-ex1', '4b15fe5a-fb04-47d9-8fb3-9eeac832acfe', 'strategy', 'We need a new strategy to win.', '我们需要新的策略才能获胜。'),
  ('4b15fe5a-fb04-47d9-8fb3-9eeac832acfe-ex2', '4b15fe5a-fb04-47d9-8fb3-9eeac832acfe', 'strategy', 'The national strategy integrates defense, diplomacy, and development objectives.', '国家战略将国防、外交与发展目标融为一体。'),
  ('dfae4a50-f879-49b7-bd7e-2b023e07754b-ex1', 'dfae4a50-f879-49b7-bd7e-2b023e07754b', 'clearly', 'Please speak clearly into the microphone.', '请对着麦克风清楚地讲话。'),
  ('dfae4a50-f879-49b7-bd7e-2b023e07754b-ex2', 'dfae4a50-f879-49b7-bd7e-2b023e07754b', 'clearly', 'The evidence clearly establishes a pattern of deliberate and sustained regulatory evasion.', '证据清楚地表明存在蓄意且持续规避监管的行为模式。'),
  ('ace1047c-5c2d-46e4-9ec4-d9818ccd7dcb-ex1', 'ace1047c-5c2d-46e4-9ec4-d9818ccd7dcb', 'discuss', 'Let''s discuss this over dinner.', '我们边吃晚饭边讨论吧。'),
  ('ace1047c-5c2d-46e4-9ec4-d9818ccd7dcb-ex2', 'ace1047c-5c2d-46e4-9ec4-d9818ccd7dcb', 'discuss', 'The parties convened to discuss mechanisms for verifying compliance with the accord.', '各方召开会议，讨论核查协定履行情况的机制。'),
  ('49087860-b29a-46c1-ad06-862efea49700-ex1', '49087860-b29a-46c1-ad06-862efea49700', 'indeed', 'It was indeed a wonderful trip.', '那确实是一次很棒的旅行。'),
  ('49087860-b29a-46c1-ad06-862efea49700-ex2', '49087860-b29a-46c1-ad06-862efea49700', 'indeed', 'The risks were indeed foreseeable, as internal correspondence subsequently demonstrated.', '正如后来的内部往来文件所证明的，这些风险确实可以预见。'),
  ('e6bb0569-a0f5-4989-a830-a8d354b539f0-ex1', 'e6bb0569-a0f5-4989-a830-a8d354b539f0', 'truth', 'Always tell the truth.', '要永远说真话。'),
  ('e6bb0569-a0f5-4989-a830-a8d354b539f0-ex2', 'e6bb0569-a0f5-4989-a830-a8d354b539f0', 'truth', 'The commission was established to ascertain the truth concerning the disputed events.', '该委员会的设立旨在查明争议事件的真相。'),
  ('6d3c59ab-da26-408c-9175-496e5fdd7821-ex1', '6d3c59ab-da26-408c-9175-496e5fdd7821', 'song', 'This song always makes me happy.', '这首歌总能让我开心。'),
  ('6d3c59ab-da26-408c-9175-496e5fdd7821-ex2', '6d3c59ab-da26-408c-9175-496e5fdd7821', 'song', 'The anthem began as a protest song before acquiring its present ceremonial status.', '这首颂歌最初是一首抗议歌曲，后来才获得如今的仪式地位。'),
  ('9dbc5319-f35a-491a-aa17-224bc54ffce7-ex1', '9dbc5319-f35a-491a-aa17-224bc54ffce7', 'example', 'Can you give me an example?', '你能给我举个例子吗？'),
  ('9dbc5319-f35a-491a-aa17-224bc54ffce7-ex2', '9dbc5319-f35a-491a-aa17-224bc54ffce7', 'example', 'The ruling stands as a cautionary example of the consequences of inadequate due diligence.', '这一裁决是尽职调查不充分后果的警示性案例。'),
  ('4a3434b5-4689-4635-8d7c-600c7c6ff762-ex1', '4a3434b5-4689-4635-8d7c-600c7c6ff762', 'democratic', 'The club made the decision in a democratic way.', '俱乐部以民主的方式做出了决定。'),
  ('4a3434b5-4689-4635-8d7c-600c7c6ff762-ex2', '4a3434b5-4689-4635-8d7c-600c7c6ff762', 'democratic', 'Independent courts constitute an indispensable pillar of any democratic order.', '独立的法院是任何民主秩序不可或缺的支柱。'),
  ('508905ea-9333-4067-a24e-e02a04dab7b7-ex1', '508905ea-9333-4067-a24e-e02a04dab7b7', 'check', 'Please check your answers before submitting.', '提交前请检查你的答案。'),
  ('508905ea-9333-4067-a24e-e02a04dab7b7-ex2', '508905ea-9333-4067-a24e-e02a04dab7b7', 'check', 'The framework institutes regular checks on the concentration of executive power.', '该框架对行政权力的集中确立了定期制衡机制。'),
  ('edd4b6c5-e1a6-4e6a-a6ad-895442512f22-ex1', 'edd4b6c5-e1a6-4e6a-a6ad-895442512f22', 'environment', 'We must protect the environment.', '我们必须保护环境。'),
  ('edd4b6c5-e1a6-4e6a-a6ad-895442512f22-ex2', 'edd4b6c5-e1a6-4e6a-a6ad-895442512f22', 'environment', 'The regulatory environment has grown markedly more stringent following the disclosures.', '信息披露之后，监管环境明显趋严。'),
  ('7bc28e89-9993-49c2-8c2c-f26e9e7a6cf3-ex1', '7bc28e89-9993-49c2-8c2c-f26e9e7a6cf3', 'leg', 'I hurt my leg playing soccer.', '我踢足球伤了腿。'),
  ('7bc28e89-9993-49c2-8c2c-f26e9e7a6cf3-ex2', '7bc28e89-9993-49c2-8c2c-f26e9e7a6cf3', 'leg', 'The final leg of the negotiations addressed the contentious issue of dispute resolution.', '谈判的最后阶段处理了争端解决这一棘手议题。'),
  ('c32ebe47-9dff-48bd-9b36-195dafe4fbe9-ex1', 'c32ebe47-9dff-48bd-9b36-195dafe4fbe9', 'dark', 'It gets dark early in winter.', '冬天天黑得早。'),
  ('c32ebe47-9dff-48bd-9b36-195dafe4fbe9-ex2', 'c32ebe47-9dff-48bd-9b36-195dafe4fbe9', 'dark', 'The memoir illuminates a dark chapter of institutional abuse long concealed from public view.', '这部回忆录揭示了长期不为公众所知的机构虐待的黑暗篇章。'),
  ('35dde522-cb84-47fc-abf9-ec4d398daf01-ex1', '35dde522-cb84-47fc-abf9-ec4d398daf01', 'various', 'The shop sells various kinds of tea.', '这家店出售各种各样的茶。'),
  ('35dde522-cb84-47fc-abf9-ec4d398daf01-ex2', '35dde522-cb84-47fc-abf9-ec4d398daf01', 'various', 'The committee consulted various stakeholders before finalizing the regulatory framework.', '委员会在敲定监管框架之前咨询了各类利益相关方。'),
  ('6be73529-757a-4c7e-ac52-53f5a9755a2e-ex1', '6be73529-757a-4c7e-ac52-53f5a9755a2e', 'rather', 'I would rather stay home tonight.', '今晚我宁愿待在家里。'),
  ('6be73529-757a-4c7e-ac52-53f5a9755a2e-ex2', '6be73529-757a-4c7e-ac52-53f5a9755a2e', 'rather', 'The findings reflect structural deficiencies rather than isolated individual failings.', '这些发现反映的是结构性缺陷，而非个别的孤立过失。'),
  ('b17ed9c2-2b68-428f-b828-ae08d5eb7665-ex1', 'b17ed9c2-2b68-428f-b828-ae08d5eb7665', 'laugh', 'Her jokes always make me laugh.', '她的笑话总能逗我笑。'),
  ('b17ed9c2-2b68-428f-b828-ae08d5eb7665-ex2', 'b17ed9c2-2b68-428f-b828-ae08d5eb7665', 'laugh', 'The proposal was initially met with laughter, yet within a decade it had become orthodoxy.', '该提议起初遭人讥笑，但不到十年便成为主流共识。'),
  ('f0458697-e088-40de-bba1-33da549ae59c-ex1', 'f0458697-e088-40de-bba1-33da549ae59c', 'guess', 'Guess how old I am!', '猜猜我多大了！'),
  ('f0458697-e088-40de-bba1-33da549ae59c-ex2', 'f0458697-e088-40de-bba1-33da549ae59c', 'guess', 'Analysts can only guess at the full extent of the undisclosed liabilities.', '分析人士只能猜测未披露负债的全部规模。'),
  ('99b671ad-679f-4c6d-8055-269dd38a02aa-ex1', '99b671ad-679f-4c6d-8055-269dd38a02aa', 'executive', 'She is a senior executive at the company.', '她是公司的高级主管。'),
  ('99b671ad-679f-4c6d-8055-269dd38a02aa-ex2', '99b671ad-679f-4c6d-8055-269dd38a02aa', 'executive', 'The doctrine of separation of powers constrains executive encroachment on legislative prerogatives.', '三权分立原则制约着行政权对立法特权的侵蚀。'),
  ('9f6e2bc8-7cb1-4430-ba95-bd048e563124-ex1', '9f6e2bc8-7cb1-4430-ba95-bd048e563124', 'prove', 'Can you prove that you were there?', '你能证明你当时在场吗？'),
  ('9f6e2bc8-7cb1-4430-ba95-bd048e563124-ex2', '9f6e2bc8-7cb1-4430-ba95-bd048e563124', 'prove', 'The prosecution must prove every element of the offense beyond reasonable doubt.', '控方必须以排除合理怀疑的标准证明犯罪的每一构成要件。'),
  ('0b828946-7296-4d2e-91f3-ea53d10c3c88-ex1', '0b828946-7296-4d2e-91f3-ea53d10c3c88', 'hang', 'Hang your coat on the hook.', '把外套挂在挂钩上。'),
  ('0b828946-7296-4d2e-91f3-ea53d10c3c88-ex2', '0b828946-7296-4d2e-91f3-ea53d10c3c88', 'hang', 'The outcome of the appeal will hang on the interpretation of a single contractual clause.', '上诉的结果将取决于对一项合同条款的解释。'),
  ('db0145f4-a5af-4da3-a532-a98c783c088f-ex1', 'db0145f4-a5af-4da3-a532-a98c783c088f', 'entire', 'I spent the entire day reading.', '我一整天都在看书。'),
  ('db0145f4-a5af-4da3-a532-a98c783c088f-ex2', 'db0145f4-a5af-4da3-a532-a98c783c088f', 'entire', 'The contagion threatened to destabilize the entire regional banking system.', '这场风险传染可能动摇整个区域银行体系。'),
  ('0c9384b6-00da-491b-89be-f476fa86573f-ex1', '0c9384b6-00da-491b-89be-f476fa86573f', 'rock', 'The children climbed over the rocks.', '孩子们爬过了岩石。'),
  ('0c9384b6-00da-491b-89be-f476fa86573f-ex2', '0c9384b6-00da-491b-89be-f476fa86573f', 'rock', 'The revelations continue to rock an institution long regarded as beyond reproach.', '这些爆料持续震撼着这个长期被视为无可指摘的机构。'),
  ('8ace1b38-5422-4c66-943a-f6d7913624bb-ex1', '8ace1b38-5422-4c66-943a-f6d7913624bb', 'forget', 'Don''t forget to lock the door.', '别忘了锁门。'),
  ('8ace1b38-5422-4c66-943a-f6d7913624bb-ex2', '8ace1b38-5422-4c66-943a-f6d7913624bb', 'forget', 'One should not forget that the precedent was established under very different economic conditions.', '不应忘记，该先例是在迥然不同的经济条件下确立的。'),
  ('a2d4d2db-35d0-495f-ab26-2fd2ee1be0b1-ex1', 'a2d4d2db-35d0-495f-ab26-2fd2ee1be0b1', 'claim', 'He claims he saw a wolf in the woods.', '他声称在树林里看到了一只狼。'),
  ('a2d4d2db-35d0-495f-ab26-2fd2ee1be0b1-ex2', 'a2d4d2db-35d0-495f-ab26-2fd2ee1be0b1', 'claim', 'The insurer rejected the claim on the ground of material non-disclosure.', '保险公司以重大事项未披露为由拒绝了这项索赔。'),
  ('8a307bcc-764a-4640-9a31-e55fbab4cca1-ex1', '8a307bcc-764a-4640-9a31-e55fbab4cca1', 'remove', 'Please remove your shoes at the door.', '请在门口脱鞋。'),
  ('8a307bcc-764a-4640-9a31-e55fbab4cca1-ex2', '8a307bcc-764a-4640-9a31-e55fbab4cca1', 'remove', 'The board voted to remove the director for persistent breaches of fiduciary duty.', '董事会投票罢免了这名屡次违反信义义务的董事。'),
  ('7845885c-46ce-4105-b659-51fa0b55a7bd-ex1', '7845885c-46ce-4105-b659-51fa0b55a7bd', 'manager', 'The manager will see you now.', '经理现在可以见你了。'),
  ('7845885c-46ce-4105-b659-51fa0b55a7bd-ex2', '7845885c-46ce-4105-b659-51fa0b55a7bd', 'manager', 'The fund manager bears fiduciary responsibility for the prudent stewardship of client assets.', '基金经理对客户资产的审慎管理负有信义责任。'),
  ('d93c5fa1-1d13-4f3d-b786-273e4f133d0b-ex1', 'd93c5fa1-1d13-4f3d-b786-273e4f133d0b', 'enjoy', 'I enjoy reading before bed.', '我喜欢睡前阅读。'),
  ('d93c5fa1-1d13-4f3d-b786-273e4f133d0b-ex2', 'd93c5fa1-1d13-4f3d-b786-273e4f133d0b', 'enjoy', 'Diplomatic envoys enjoy immunities codified in the Vienna Convention.', '外交使节享有《维也纳公约》所规定的豁免权。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('4818145a-8ab2-45df-a20e-ace1ebe18ed6-ex1', '4818145a-8ab2-45df-a20e-ace1ebe18ed6', 'network', 'The Wi-Fi network is down again.', '无线网络又断了。'),
  ('4818145a-8ab2-45df-a20e-ace1ebe18ed6-ex2', '4818145a-8ab2-45df-a20e-ace1ebe18ed6', 'network', 'Investigators dismantled a sophisticated network engaged in cross-border financial fraud.', '调查人员摧毁了一个从事跨境金融诈骗的复杂网络。'),
  ('681cdd7f-fa0d-40d6-96a6-246bb1802425-ex1', '681cdd7f-fa0d-40d6-96a6-246bb1802425', 'legal', 'Is it legal to park here?', '在这里停车合法吗？'),
  ('681cdd7f-fa0d-40d6-96a6-246bb1802425-ex2', '681cdd7f-fa0d-40d6-96a6-246bb1802425', 'legal', 'The merger remains contingent upon legal clearance from competition authorities in three jurisdictions.', '此次合并仍有待三个司法管辖区竞争主管机构的法律批准。'),
  ('9c28e98a-72e4-40fd-93de-cfd31be68649-ex1', '9c28e98a-72e4-40fd-93de-cfd31be68649', 'religious', 'She comes from a religious family.', '她来自一个虔诚的宗教家庭。'),
  ('9c28e98a-72e4-40fd-93de-cfd31be68649-ex2', '9c28e98a-72e4-40fd-93de-cfd31be68649', 'religious', 'The constitution guarantees religious liberty while maintaining strict institutional neutrality.', '宪法在保持严格制度中立的同时保障宗教自由。'),
  ('ef10e088-bb10-47ee-b10a-a61c770d290f-ex1', 'ef10e088-bb10-47ee-b10a-a61c770d290f', 'cold', 'It is very cold outside today.', '今天外面很冷。'),
  ('ef10e088-bb10-47ee-b10a-a61c770d290f-ex2', 'ef10e088-bb10-47ee-b10a-a61c770d290f', 'cold', 'Relations between the two governments have remained distinctly cold since the expulsions.', '自驱逐事件以来，两国政府关系一直明显冷淡。'),
  ('5b5444a1-81e5-4ede-bac2-1cf3737fb3db-ex1', '5b5444a1-81e5-4ede-bac2-1cf3737fb3db', 'final', 'The final exam is next week.', '期末考试在下周。'),
  ('5b5444a1-81e5-4ede-bac2-1cf3737fb3db-ex2', '5b5444a1-81e5-4ede-bac2-1cf3737fb3db', 'final', 'The arbitral award is final and binding upon all parties to the proceedings.', '仲裁裁决为终局裁决，对诉讼各方均具约束力。'),
  ('4d9e7f17-925f-4e63-86d7-6991f7bbcc61-ex1', '4d9e7f17-925f-4e63-86d7-6991f7bbcc61', 'main', 'The main entrance is around the corner.', '正门在拐角处。'),
  ('4d9e7f17-925f-4e63-86d7-6991f7bbcc61-ex2', '4d9e7f17-925f-4e63-86d7-6991f7bbcc61', 'main', 'The main impediment to ratification remains the unresolved question of enforcement jurisdiction.', '批准的主要障碍仍是悬而未决的执行管辖权问题。'),
  ('4d1e73a5-5936-4295-baaf-0176ad466645-ex1', '4d1e73a5-5936-4295-baaf-0176ad466645', 'science', 'Science is my favorite subject at school.', '科学是我在学校最喜欢的科目。'),
  ('4d1e73a5-5936-4295-baaf-0176ad466645-ex2', '4d1e73a5-5936-4295-baaf-0176ad466645', 'science', 'Sound public policy must rest on rigorously validated science rather than expedient conjecture.', '健全的公共政策必须建立在经过严格验证的科学之上，而非权宜的臆测。'),
  ('377c4c4e-dce8-4c7d-9d06-bea6ef48a575-ex1', '377c4c4e-dce8-4c7d-9d06-bea6ef48a575', 'green', 'The grass is so green in spring.', '春天的草特别绿。'),
  ('377c4c4e-dce8-4c7d-9d06-bea6ef48a575-ex2', '377c4c4e-dce8-4c7d-9d06-bea6ef48a575', 'green', 'The fund channels capital exclusively toward certified green infrastructure projects.', '该基金将资本专门投向经认证的绿色基础设施项目。'),
  ('40e09ce2-729a-4922-bdb6-209e9ee070de-ex1', '40e09ce2-729a-4922-bdb6-209e9ee070de', 'memory', 'I have a good memory for faces.', '我记人脸记得很牢。'),
  ('40e09ce2-729a-4922-bdb6-209e9ee070de-ex2', '40e09ce2-729a-4922-bdb6-209e9ee070de', 'memory', 'The memorial preserves the memory of those who perished in the industrial disaster.', '纪念碑铭记着在那场工业灾难中罹难的人们。'),
  ('37dddb50-261e-43f0-9b95-2a49105bb372-ex1', '37dddb50-261e-43f0-9b95-2a49105bb372', 'card', 'Can I pay by card?', '我可以刷卡支付吗？'),
  ('37dddb50-261e-43f0-9b95-2a49105bb372-ex2', '37dddb50-261e-43f0-9b95-2a49105bb372', 'card', 'The disclosure rules apply equally to card issuers and third-party payment processors.', '披露规则同等适用于发卡机构和第三方支付处理机构。'),
  ('eb1278d8-53e3-4f1f-bbaf-831623425e49-ex1', 'eb1278d8-53e3-4f1f-bbaf-831623425e49', 'above', 'The picture hangs above the sofa.', '画挂在沙发上方。'),
  ('eb1278d8-53e3-4f1f-bbaf-831623425e49-ex2', 'eb1278d8-53e3-4f1f-bbaf-831623425e49', 'above', 'The tribunal emphasized that no official, however senior, stands above the law.', '法庭强调，任何官员无论职位多高，都不能凌驾于法律之上。'),
  ('426cc869-9a19-4840-88d8-7208f8a33dde-ex1', '426cc869-9a19-4840-88d8-7208f8a33dde', 'seat', 'Is this seat taken?', '这个座位有人吗？'),
  ('426cc869-9a19-4840-88d8-7208f8a33dde-ex2', '426cc869-9a19-4840-88d8-7208f8a33dde', 'seat', 'The party secured enough seats to govern without entering a formal coalition.', '该党赢得了足够席位，无需组建正式联盟即可执政。'),
  ('0677c311-fba3-441c-bab3-7ebfd29c1b2c-ex1', '0677c311-fba3-441c-bab3-7ebfd29c1b2c', 'cell', 'Your cell phone is ringing.', '你的手机响了。'),
  ('0677c311-fba3-441c-bab3-7ebfd29c1b2c-ex2', '0677c311-fba3-441c-bab3-7ebfd29c1b2c', 'cell', 'The therapy reprograms immune cells to recognize and destroy malignant tissue.', '该疗法对免疫细胞重新编程，使其识别并摧毁恶性组织。'),
  ('cf7c036d-75fa-4017-8385-89538b2de5f6-ex1', 'cf7c036d-75fa-4017-8385-89538b2de5f6', 'establish', 'The school was established in 1950.', '这所学校建于1950年。'),
  ('cf7c036d-75fa-4017-8385-89538b2de5f6-ex2', 'cf7c036d-75fa-4017-8385-89538b2de5f6', 'establish', 'The treaty seeks to establish a permanent mechanism for the peaceful resolution of disputes.', '该条约旨在建立和平解决争端的常设机制。'),
  ('1f90df03-c3f7-4297-8d37-7e442c1e51ce-ex1', '1f90df03-c3f7-4297-8d37-7e442c1e51ce', 'nice', 'Have a nice weekend!', '周末愉快！'),
  ('1f90df03-c3f7-4297-8d37-7e442c1e51ce-ex2', '1f90df03-c3f7-4297-8d37-7e442c1e51ce', 'nice', 'The figures draw a nice distinction between cyclical fluctuation and structural decline.', '这些数据在周期性波动与结构性衰退之间作出了精准的区分。'),
  ('cc43cd72-e4bf-42af-aba0-d53a5c5aef12-ex1', 'cc43cd72-e4bf-42af-aba0-d53a5c5aef12', 'trial', 'The trial begins next Monday.', '审判下周一开始。'),
  ('cc43cd72-e4bf-42af-aba0-d53a5c5aef12-ex2', 'cc43cd72-e4bf-42af-aba0-d53a5c5aef12', 'trial', 'The clinical trial enrolled patients across forty sites under a harmonized protocol.', '这项临床试验依据统一方案在四十个研究中心招募患者。'),
  ('a3e05ac3-5026-4c39-892a-6eb92a375807-ex1', 'a3e05ac3-5026-4c39-892a-6eb92a375807', 'expert', 'She is an expert in Chinese history.', '她是中国历史方面的专家。'),
  ('a3e05ac3-5026-4c39-892a-6eb92a375807-ex2', 'a3e05ac3-5026-4c39-892a-6eb92a375807', 'expert', 'The panel of independent experts concluded that the risk assessment was fundamentally flawed.', '独立专家组认定该风险评估存在根本性缺陷。'),
  ('0b0b2aec-64c9-4034-bbce-93975cc69840-ex1', '0b0b2aec-64c9-4034-bbce-93975cc69840', 'spring', 'The flowers bloom in spring.', '花儿在春天开放。'),
  ('0b0b2aec-64c9-4034-bbce-93975cc69840-ex2', '0b0b2aec-64c9-4034-bbce-93975cc69840', 'spring', 'The reforms spring from a recognition that the existing framework had outlived its purpose.', '这些改革源于一种认识：现有框架已不再适用。'),
  ('00f81ab9-2ca6-427d-8f13-a47b06dacda6-ex1', '00f81ab9-2ca6-427d-8f13-a47b06dacda6', 'firm', 'The law firm is hiring new staff.', '那家律师事务所正在招聘新员工。'),
  ('00f81ab9-2ca6-427d-8f13-a47b06dacda6-ex2', '00f81ab9-2ca6-427d-8f13-a47b06dacda6', 'firm', 'The audit firm faces sanctions for failing to detect the systematic misstatements.', '这家审计事务所因未能发现系统性错报而面临处罚。'),
  ('8a4f5bfb-67ac-4d66-91b2-d7439cfd7854-ex1', '8a4f5bfb-67ac-4d66-91b2-d7439cfd7854', 'Democrat', 'She is a Democrat from California.', '她是来自加利福尼亚州的民主党人。'),
  ('8a4f5bfb-67ac-4d66-91b2-d7439cfd7854-ex2', '8a4f5bfb-67ac-4d66-91b2-d7439cfd7854', 'Democrat', 'Several Democrats joined the opposition in demanding an independent ethics inquiry.', '几位民主党人与反对派一道，要求开展独立的道德操守调查。'),
  ('baf14b3f-ed86-4026-93d2-7ea90e277dea-ex1', 'baf14b3f-ed86-4026-93d2-7ea90e277dea', 'radio', 'I listen to the radio while driving.', '我开车时听广播。'),
  ('baf14b3f-ed86-4026-93d2-7ea90e277dea-ex2', 'baf14b3f-ed86-4026-93d2-7ea90e277dea', 'radio', 'Emergency broadcasts over shortwave radio remained the sole channel of communication.', '短波电台的应急广播是当时唯一的通信渠道。'),
  ('49b615cf-1787-4823-82af-bccbf9388520-ex1', '49b615cf-1787-4823-82af-bccbf9388520', 'visit', 'We plan to visit my grandparents this weekend.', '我们打算这周末去看望祖父母。'),
  ('49b615cf-1787-4823-82af-bccbf9388520-ex2', '49b615cf-1787-4823-82af-bccbf9388520', 'visit', 'The state visit was intended to signal a thaw in long-strained bilateral relations.', '这次国事访问旨在释放长期紧张的双边关系出现缓和的信号。'),
  ('0f54fde5-c0d9-4e7e-8a58-745c3cb34a92-ex1', '0f54fde5-c0d9-4e7e-8a58-745c3cb34a92', 'management', 'The restaurant is under new management.', '这家餐厅换了新的管理层。'),
  ('0f54fde5-c0d9-4e7e-8a58-745c3cb34a92-ex2', '0f54fde5-c0d9-4e7e-8a58-745c3cb34a92', 'management', 'The report criticizes senior management for disregarding repeated internal warnings.', '报告批评高级管理层无视屡次的内部警告。'),
  ('b854ce97-8bea-4e3e-9d02-e72df97f3095-ex1', 'b854ce97-8bea-4e3e-9d02-e72df97f3095', 'avoid', 'Avoid drinking coffee before bed.', '睡前避免喝咖啡。'),
  ('b854ce97-8bea-4e3e-9d02-e72df97f3095-ex2', 'b854ce97-8bea-4e3e-9d02-e72df97f3095', 'avoid', 'The settlement structure was designed to avoid triggering mandatory disclosure obligations.', '该和解结构的设计意在避免触发强制披露义务。'),
  ('731dbfab-1bd4-476d-8acc-a7382cf919d8-ex1', '731dbfab-1bd4-476d-8acc-a7382cf919d8', 'imagine', 'Imagine you are on a beautiful beach.', '想象你正在美丽的沙滩上。'),
  ('731dbfab-1bd4-476d-8acc-a7382cf919d8-ex2', '731dbfab-1bd4-476d-8acc-a7382cf919d8', 'imagine', 'Few could imagine the institutional transformations the following decade would bring.', '很少有人能想象随后十年将带来的制度变革。'),
  ('0530190e-bf83-4f03-8a73-546c04e1b33b-ex1', '0530190e-bf83-4f03-8a73-546c04e1b33b', 'tonight', 'What are you doing tonight?', '你今晚做什么？'),
  ('0530190e-bf83-4f03-8a73-546c04e1b33b-ex2', '0530190e-bf83-4f03-8a73-546c04e1b33b', 'tonight', 'The legislature will convene an extraordinary session tonight to address the funding lapse.', '立法机构今晚将召开特别会议，处理拨款中断问题。'),
  ('8d6775ab-9001-46ea-889f-337dc6ba2152-ex1', '8d6775ab-9001-46ea-889f-337dc6ba2152', 'huge', 'They live in a huge house.', '他们住在一栋很大的房子里。'),
  ('8d6775ab-9001-46ea-889f-337dc6ba2152-ex2', '8d6775ab-9001-46ea-889f-337dc6ba2152', 'huge', 'The verdict carries huge implications for the allocation of liability across the supply chain.', '该判决对供应链各环节的责任分配具有重大影响。'),
  ('599e4469-3c32-4835-ba87-21d31408f655-ex1', '599e4469-3c32-4835-ba87-21d31408f655', 'ball', 'The kids are playing with a ball.', '孩子们在玩球。'),
  ('599e4469-3c32-4835-ba87-21d31408f655-ex2', '599e4469-3c32-4835-ba87-21d31408f655', 'ball', 'With the regulator''s decision pending, the ball now rests squarely in the government''s court.', '监管机构的决定尚未出炉，如今主动权完全掌握在政府手中。'),
  ('6824a1c8-2f0d-4847-b3dc-6d850c671c8c-ex1', '6824a1c8-2f0d-4847-b3dc-6d850c671c8c', 'finish', 'Did you finish your homework?', '你写完作业了吗？'),
  ('6824a1c8-2f0d-4847-b3dc-6d850c671c8c-ex2', '6824a1c8-2f0d-4847-b3dc-6d850c671c8c', 'finish', 'The contractor failed to finish the works within the period stipulated in the agreement.', '承包商未能在协议规定的期限内完成工程。'),
  ('5043c521-f076-46e4-ae2c-7a1bc7de5be9-ex1', '5043c521-f076-46e4-ae2c-7a1bc7de5be9', 'yourself', 'Please help yourself to some fruit.', '请随便吃点水果。'),
  ('5043c521-f076-46e4-ae2c-7a1bc7de5be9-ex2', '5043c521-f076-46e4-ae2c-7a1bc7de5be9', 'yourself', 'Before signing, you should satisfy yourself that every material term has been disclosed.', '签署之前，您应确信所有重要条款均已披露。'),
  ('4e914239-48b1-4ce2-84a5-aa42c9873f76-ex1', '4e914239-48b1-4ce2-84a5-aa42c9873f76', 'theory', 'That is a good theory, but can you prove it?', '这个理论不错，但你能证明吗？'),
  ('4e914239-48b1-4ce2-84a5-aa42c9873f76-ex2', '4e914239-48b1-4ce2-84a5-aa42c9873f76', 'theory', 'The prevailing theory attributes the collapse to a confluence of leverage and illiquidity.', '主流理论将这次崩盘归因于高杠杆与流动性枯竭的叠加。'),
  ('edd652b0-38d8-4785-94c0-270545952668-ex1', 'edd652b0-38d8-4785-94c0-270545952668', 'impact', 'The new rule has a big impact on students.', '新规定对学生影响很大。'),
  ('edd652b0-38d8-4785-94c0-270545952668-ex2', 'edd652b0-38d8-4785-94c0-270545952668', 'impact', 'The tariffs have had a measurable impact on consumer prices across multiple sectors.', '关税已对多个行业的消费价格产生了可衡量的影响。'),
  ('e0572817-88e8-4705-9650-a364e741e6e1-ex1', 'e0572817-88e8-4705-9650-a364e741e6e1', 'respond', 'She didn''t respond to my message.', '她没有回复我的消息。'),
  ('e0572817-88e8-4705-9650-a364e741e6e1-ex2', 'e0572817-88e8-4705-9650-a364e741e6e1', 'respond', 'The agency failed to respond adequately to early indications of systemic distress.', '该机构未能对系统性风险的早期迹象作出充分回应。'),
  ('045c0c80-5702-4c0b-9c8a-71369b38c6cc-ex1', '045c0c80-5702-4c0b-9c8a-71369b38c6cc', 'statement', 'The company released a short statement.', '公司发布了一份简短声明。'),
  ('045c0c80-5702-4c0b-9c8a-71369b38c6cc-ex2', '045c0c80-5702-4c0b-9c8a-71369b38c6cc', 'statement', 'The audited financial statements disclosed contingent liabilities of unprecedented magnitude.', '经审计的财务报表披露了规模空前的或有负债。'),
  ('ae361d51-1ffe-4a84-91d4-1bf1c4636c0e-ex1', 'ae361d51-1ffe-4a84-91d4-1bf1c4636c0e', 'maintain', 'It is important to maintain a healthy diet.', '保持健康的饮食很重要。'),
  ('ae361d51-1ffe-4a84-91d4-1bf1c4636c0e-ex2', 'ae361d51-1ffe-4a84-91d4-1bf1c4636c0e', 'maintain', 'The operator is contractually obliged to maintain the infrastructure to prescribed standards.', '运营方负有按规定标准维护基础设施的合同义务。'),
  ('e60fcf9f-af08-426a-aafa-ac03ccf62a08-ex1', 'e60fcf9f-af08-426a-aafa-ac03ccf62a08', 'charge', 'Is there an extra charge for delivery?', '送货要额外收费吗？'),
  ('e60fcf9f-af08-426a-aafa-ac03ccf62a08-ex2', 'e60fcf9f-af08-426a-aafa-ac03ccf62a08', 'charge', 'The prosecutors filed charges alleging a sustained conspiracy to defraud investors.', '检察官提起指控，称存在持续合谋欺诈投资者的行为。'),
  ('1059e227-377e-44d9-b5aa-f07a21c99928-ex1', '1059e227-377e-44d9-b5aa-f07a21c99928', 'popular', 'This song is very popular right now.', '这首歌现在很流行。'),
  ('1059e227-377e-44d9-b5aa-f07a21c99928-ex2', '1059e227-377e-44d9-b5aa-f07a21c99928', 'popular', 'The measures, though fiscally prudent, proved deeply unpopular with the electorate.', '这些措施虽然在财政上审慎，却极不受选民欢迎。'),
  ('b39fdd6c-44c5-4053-9dba-1c9fb79a7215-ex1', 'b39fdd6c-44c5-4053-9dba-1c9fb79a7215', 'traditional', 'We had a traditional family dinner.', '我们吃了一顿传统的家庭晚餐。'),
  ('b39fdd6c-44c5-4053-9dba-1c9fb79a7215-ex2', 'b39fdd6c-44c5-4053-9dba-1c9fb79a7215', 'traditional', 'The ruling extends legal recognition to traditional forms of communal land tenure.', '该裁决对传统的社区土地保有形式给予法律承认。'),
  ('de679e1a-cbeb-4700-9c70-fd55f9bddf00-ex1', 'de679e1a-cbeb-4700-9c70-fd55f9bddf00', 'onto', 'The cat jumped onto the table.', '猫跳到了桌子上。'),
  ('de679e1a-cbeb-4700-9c70-fd55f9bddf00-ex2', 'de679e1a-cbeb-4700-9c70-fd55f9bddf00', 'onto', 'The crisis pushed previously marginal policy proposals onto the national agenda.', '这场危机将此前边缘化的政策主张推上了国家议程。'),
  ('ba499aa5-3ded-420b-abe4-a345a421744c-ex1', 'ba499aa5-3ded-420b-abe4-a345a421744c', 'reveal', 'The test results will reveal the problem.', '检查结果会揭示问题所在。'),
  ('ba499aa5-3ded-420b-abe4-a345a421744c-ex2', 'ba499aa5-3ded-420b-abe4-a345a421744c', 'reveal', 'The leaked documents reveal a coordinated effort to circumvent the sanctions regime.', '泄露的文件揭示了规避制裁机制的协同行动。'),
  ('0d54e37a-a1c4-409e-ae27-150d78f48622-ex1', '0d54e37a-a1c4-409e-ae27-150d78f48622', 'direction', 'We are driving in the wrong direction.', '我们开错方向了。'),
  ('0d54e37a-a1c4-409e-ae27-150d78f48622-ex2', '0d54e37a-a1c4-409e-ae27-150d78f48622', 'direction', 'Under her direction, the institute redefined the methodological standards of the field.', '在她的领导下，该研究所重新定义了这一领域的方法论标准。'),
  ('0e254d0d-9c28-4450-8700-985b74677917-ex1', '0e254d0d-9c28-4450-8700-985b74677917', 'weapon', 'The police found the weapon in the river.', '警方在河里找到了凶器。'),
  ('0e254d0d-9c28-4450-8700-985b74677917-ex2', '0e254d0d-9c28-4450-8700-985b74677917', 'weapon', 'The convention prohibits the development and stockpiling of biological weapons.', '该公约禁止生物武器的研发与储存。'),
  ('157b9b51-25e7-48ed-933a-126b7ec3f9fa-ex1', '157b9b51-25e7-48ed-933a-126b7ec3f9fa', 'employee', 'The company has fifty employees.', '这家公司有五十名员工。'),
  ('157b9b51-25e7-48ed-933a-126b7ec3f9fa-ex2', '157b9b51-25e7-48ed-933a-126b7ec3f9fa', 'employee', 'Every employee is entitled to protection against retaliatory dismissal for protected disclosures.', '每位员工就受保护的举报行为享有免遭报复性解雇的保障。'),
  ('280a94c2-cdb2-4c77-9d86-ff68f369d83f-ex1', '280a94c2-cdb2-4c77-9d86-ff68f369d83f', 'cultural', 'The city has a rich cultural life.', '这座城市文化生活丰富。'),
  ('280a94c2-cdb2-4c77-9d86-ff68f369d83f-ex2', '280a94c2-cdb2-4c77-9d86-ff68f369d83f', 'cultural', 'The convention obliges states to safeguard cultural heritage situated within their territories.', '该公约要求各国保护其境内的文化遗产。'),
  ('e3600d23-fa73-4765-b1ab-7eca45015f5f-ex1', 'e3600d23-fa73-4765-b1ab-7eca45015f5f', 'contain', 'This box contains old photos.', '这个盒子里装着旧照片。'),
  ('e3600d23-fa73-4765-b1ab-7eca45015f5f-ex2', 'e3600d23-fa73-4765-b1ab-7eca45015f5f', 'contain', 'Authorities struggled to contain the contagion as interbank lending seized up.', '随着银行间拆借陷入停滞，当局难以遏制风险蔓延。'),
  ('05c02d59-98a6-42be-a374-da0a3f7604e1-ex1', '05c02d59-98a6-42be-a374-da0a3f7604e1', 'peace', 'I enjoy the peace of the early morning.', '我喜欢清晨的宁静。'),
  ('05c02d59-98a6-42be-a374-da0a3f7604e1-ex2', '05c02d59-98a6-42be-a374-da0a3f7604e1', 'peace', 'The accord laid the institutional foundations for a durable peace in the region.', '该协定为该地区的持久和平奠定了制度基础。'),
  ('2ef0563a-fbf3-4fbc-af59-28d7c3e680c6-ex1', '2ef0563a-fbf3-4fbc-af59-28d7c3e680c6', 'pain', 'I have a pain in my lower back.', '我腰部疼痛。'),
  ('2ef0563a-fbf3-4fbc-af59-28d7c3e680c6-ex2', '2ef0563a-fbf3-4fbc-af59-28d7c3e680c6', 'pain', 'The adjustment program imposed considerable economic pain on the most vulnerable households.', '调整方案给最弱势的家庭带来了相当大的经济痛苦。'),
  ('be313d6e-bdf6-4854-b8fd-a08b22e2adba-ex1', 'be313d6e-bdf6-4854-b8fd-a08b22e2adba', 'apply', 'I want to apply for this job.', '我想申请这份工作。'),
  ('be313d6e-bdf6-4854-b8fd-a08b22e2adba-ex2', 'be313d6e-bdf6-4854-b8fd-a08b22e2adba', 'apply', 'The enhanced disclosure requirements apply to all entities exceeding the statutory thresholds.', '强化的披露要求适用于所有超过法定门槛的实体。'),
  ('f836752e-0134-4ff5-9af8-2d17bae74a17-ex1', 'f836752e-0134-4ff5-9af8-2d17bae74a17', 'measure', 'Measure the room before buying furniture.', '买家具前先量一下房间。'),
  ('f836752e-0134-4ff5-9af8-2d17bae74a17-ex2', 'f836752e-0134-4ff5-9af8-2d17bae74a17', 'measure', 'The emergency measures were extended pending a comprehensive review of their proportionality.', '在对其相称性进行全面审查之前，紧急措施获得延长。'),
  ('c6e4f37a-6d13-4407-857c-8c6662045875-ex1', 'c6e4f37a-6d13-4407-857c-8c6662045875', 'wide', 'The river is very wide here.', '这里的河面很宽。'),
  ('c6e4f37a-6d13-4407-857c-8c6662045875-ex2', 'c6e4f37a-6d13-4407-857c-8c6662045875', 'wide', 'The consultation drew responses from a wide spectrum of institutional stakeholders.', '这次磋商收到了各类机构利益相关方的广泛回应。'),
  ('20a1b6fa-6e4e-4b55-8e5a-7b95a311d969-ex1', '20a1b6fa-6e4e-4b55-8e5a-7b95a311d969', 'shake', 'Shake the bottle before opening.', '打开前先摇一摇瓶子。'),
  ('20a1b6fa-6e4e-4b55-8e5a-7b95a311d969-ex2', '20a1b6fa-6e4e-4b55-8e5a-7b95a311d969', 'shake', 'The revelations threatened to shake public confidence in the supervisory authorities.', '这些爆料可能动摇公众对监管当局的信心。'),
  ('4267e39b-8a03-43d0-80ab-5d43e1d3c910-ex1', '4267e39b-8a03-43d0-80ab-5d43e1d3c910', 'fly', 'We will fly to Beijing tomorrow.', '我们明天飞往北京。'),
  ('4267e39b-8a03-43d0-80ab-5d43e1d3c910-ex2', '4267e39b-8a03-43d0-80ab-5d43e1d3c910', 'fly', 'Critics contend that the projections fly in the face of established demographic evidence.', '批评者认为，这些预测公然违背了既有的人口学证据。'),
  ('dc05c22b-9ba0-43ab-a91c-24bb8c5d4d5a-ex1', 'dc05c22b-9ba0-43ab-a91c-24bb8c5d4d5a', 'interview', 'I have a job interview tomorrow.', '我明天有一场求职面试。'),
  ('dc05c22b-9ba0-43ab-a91c-24bb8c5d4d5a-ex2', 'dc05c22b-9ba0-43ab-a91c-24bb8c5d4d5a', 'interview', 'Investigators conducted structured interviews with every official involved in the procurement.', '调查人员对参与采购的每位官员进行了结构化访谈。'),
  ('9e1f769d-48e6-43e3-985b-c8077c12ca92-ex1', '9e1f769d-48e6-43e3-985b-c8077c12ca92', 'manage', 'How do you manage to stay so calm?', '你是怎么做到这么冷静的？'),
  ('9e1f769d-48e6-43e3-985b-c8077c12ca92-ex2', '9e1f769d-48e6-43e3-985b-c8077c12ca92', 'manage', 'The trustee is appointed to manage the estate in the exclusive interest of the beneficiaries.', '受托人受命完全为受益人的利益管理这笔遗产。'),
  ('a87e225b-754c-4eb5-a38f-c6283cf88117-ex1', 'a87e225b-754c-4eb5-a38f-c6283cf88117', 'chair', 'Pull up a chair and join us.', '拉把椅子过来加入我们吧。'),
  ('a87e225b-754c-4eb5-a38f-c6283cf88117-ex2', 'a87e225b-754c-4eb5-a38f-c6283cf88117', 'chair', 'As chair of the committee, she wields considerable influence over the legislative agenda.', '作为委员会主席，她对立法议程拥有相当大的影响力。'),
  ('042e65d4-d8c2-4e32-b674-61efa7cc98d1-ex1', '042e65d4-d8c2-4e32-b674-61efa7cc98d1', 'fish', 'We caught three fish at the lake.', '我们在湖里钓到了三条鱼。'),
  ('042e65d4-d8c2-4e32-b674-61efa7cc98d1-ex2', '042e65d4-d8c2-4e32-b674-61efa7cc98d1', 'fish', 'Declining fish stocks have compelled regulators to impose stringent quota reductions.', '鱼类资源的减少迫使监管机构大幅压缩捕捞配额。'),
  ('5360e87a-8ee4-41a0-bd32-1c801ec7cab0-ex1', '5360e87a-8ee4-41a0-bd32-1c801ec7cab0', 'particular', 'Is there a particular dish you recommend?', '你有特别推荐的菜吗？'),
  ('5360e87a-8ee4-41a0-bd32-1c801ec7cab0-ex2', '5360e87a-8ee4-41a0-bd32-1c801ec7cab0', 'particular', 'The audit drew particular attention to transactions executed in the final quarter.', '审计特别关注了最后一个季度执行的交易。'),
  ('36b56016-a500-4ee5-93c8-674c8667d424-ex1', '36b56016-a500-4ee5-93c8-674c8667d424', 'camera', 'I forgot to bring my camera.', '我忘了带相机。'),
  ('36b56016-a500-4ee5-93c8-674c8667d424-ex2', '36b56016-a500-4ee5-93c8-674c8667d424', 'camera', 'Footage from the surveillance cameras proved instrumental in reconstructing the sequence of events.', '监控摄像头的录像对还原事件经过起到了关键作用。'),
  ('aa883e71-685b-4231-9df0-1b75f0504050-ex1', 'aa883e71-685b-4231-9df0-1b75f0504050', 'structure', 'The structure of the building is very strong.', '这栋建筑的结构非常坚固。'),
  ('aa883e71-685b-4231-9df0-1b75f0504050-ex2', 'aa883e71-685b-4231-9df0-1b75f0504050', 'structure', 'The reform fundamentally alters the governance structure of state-owned enterprises.', '这项改革从根本上改变了国有企业的治理结构。'),
  ('c2605c63-633a-420c-bd0f-56991e71c48f-ex1', 'c2605c63-633a-420c-bd0f-56991e71c48f', 'politics', 'They never talk about politics at dinner.', '他们吃饭时从不谈政治。'),
  ('c2605c63-633a-420c-bd0f-56991e71c48f-ex2', 'c2605c63-633a-420c-bd0f-56991e71c48f', 'politics', 'The scandal transformed the politics of regulatory reform almost overnight.', '这起丑闻几乎在一夜之间改变了监管改革的政治格局。'),
  ('92d7efc9-3dd6-49b9-b0f8-18b6ffd99755-ex1', '92d7efc9-3dd6-49b9-b0f8-18b6ffd99755', 'perform', 'The band will perform at the festival.', '乐队将在音乐节上演出。'),
  ('92d7efc9-3dd6-49b9-b0f8-18b6ffd99755-ex2', '92d7efc9-3dd6-49b9-b0f8-18b6ffd99755', 'perform', 'Only accredited laboratories may perform the assays required for certification.', '只有获得认可的实验室才能进行认证所需的检测。'),
  ('8364f6d6-ef78-4ce2-85fa-6ebb3aa76a3b-ex1', '8364f6d6-ef78-4ce2-85fa-6ebb3aa76a3b', 'bit', 'I am a bit tired today.', '我今天有点累。'),
  ('8364f6d6-ef78-4ce2-85fa-6ebb3aa76a3b-ex2', '8364f6d6-ef78-4ce2-85fa-6ebb3aa76a3b', 'bit', 'The negotiations advanced bit by bit toward a framework acceptable to all parties.', '谈判一点一点地朝着各方都能接受的框架推进。'),
  ('364833b4-04d0-48b3-80fd-a8e3b5a99956-ex1', '364833b4-04d0-48b3-80fd-a8e3b5a99956', 'weight', 'The doctor checked my weight.', '医生测了我的体重。'),
  ('364833b4-04d0-48b3-80fd-a8e3b5a99956-ex2', '364833b4-04d0-48b3-80fd-a8e3b5a99956', 'weight', 'The appellate court accorded substantial weight to the newly admitted forensic evidence.', '上诉法院对新采纳的法医证据给予了相当大的权重。'),
  ('8339fd2d-1299-4ae7-8772-39ece969d93a-ex1', '8339fd2d-1299-4ae7-8772-39ece969d93a', 'suddenly', 'The weather changed suddenly.', '天气突然变了。'),
  ('8339fd2d-1299-4ae7-8772-39ece969d93a-ex2', '8339fd2d-1299-4ae7-8772-39ece969d93a', 'suddenly', 'Liquidity that had seemed abundant evaporated suddenly as counterparties withdrew credit lines.', '随着交易对手撤回信贷额度，原本看似充裕的流动性骤然蒸发。'),
  ('7b93e582-00f7-4963-b534-6d9ce87a73e7-ex1', '7b93e582-00f7-4963-b534-6d9ce87a73e7', 'discover', 'Did you discover anything interesting?', '你发现什么有趣的东西了吗？'),
  ('7b93e582-00f7-4963-b534-6d9ce87a73e7-ex2', '7b93e582-00f7-4963-b534-6d9ce87a73e7', 'discover', 'Auditors discovered that material liabilities had been concealed through off-balance-sheet entities.', '审计人员发现，重大负债被通过表外实体加以隐瞒。'),
  ('d3fcd89f-45be-49f7-87f1-783a745d1682-ex1', 'd3fcd89f-45be-49f7-87f1-783a745d1682', 'candidate', 'She is the best candidate for the job.', '她是这份工作的最佳人选。'),
  ('d3fcd89f-45be-49f7-87f1-783a745d1682-ex2', 'd3fcd89f-45be-49f7-87f1-783a745d1682', 'candidate', 'Each candidate must disclose campaign contributions exceeding the statutory threshold.', '每位候选人都必须披露超过法定限额的竞选捐款。'),
  ('f579c002-2d64-4705-8d9d-a3bb2a2f6571-ex1', 'f579c002-2d64-4705-8d9d-a3bb2a2f6571', 'production', 'The factory increased its production this year.', '工厂今年提高了产量。'),
  ('f579c002-2d64-4705-8d9d-a3bb2a2f6571-ex2', 'f579c002-2d64-4705-8d9d-a3bb2a2f6571', 'production', 'The court compelled the production of documents previously withheld on grounds of privilege.', '法院强制要求提交此前以特权为由扣留的文件。'),
  ('4ab18585-19cb-43da-a1f7-c8cc33a99757-ex1', '4ab18585-19cb-43da-a1f7-c8cc33a99757', 'treat', 'Let me treat you to dinner.', '让我请你吃晚饭吧。'),
  ('4ab18585-19cb-43da-a1f7-c8cc33a99757-ex2', '4ab18585-19cb-43da-a1f7-c8cc33a99757', 'treat', 'The framework obliges states to treat asylum claims in accordance with due process.', '该框架要求各国按照正当程序处理庇护申请。'),
  ('05121cac-080f-41e2-b323-a4af840285f0-ex1', '05121cac-080f-41e2-b323-a4af840285f0', 'trip', 'How was your trip to Japan?', '你的日本之行怎么样？'),
  ('05121cac-080f-41e2-b323-a4af840285f0-ex2', '05121cac-080f-41e2-b323-a4af840285f0', 'trip', 'The fact-finding trip documented conditions in detention facilities across the region.', '这次实地考察记录了该地区各拘留设施的状况。'),
  ('75fca5ce-33ca-4eb4-84d0-d2bc6362acfd-ex1', '75fca5ce-33ca-4eb4-84d0-d2bc6362acfd', 'evening', 'We took a walk in the evening.', '我们傍晚散了步。'),
  ('75fca5ce-33ca-4eb4-84d0-d2bc6362acfd-ex2', '75fca5ce-33ca-4eb4-84d0-d2bc6362acfd', 'evening', 'The communiqué was released late in the evening to coincide with market closures.', '公报特意在深夜发布，以配合市场收盘时间。'),
  ('88f50a29-1017-45cb-8241-cebaa0be83f0-ex1', '88f50a29-1017-45cb-8241-cebaa0be83f0', 'affect', 'The weather can affect your mood.', '天气会影响你的心情。'),
  ('88f50a29-1017-45cb-8241-cebaa0be83f0-ex2', '88f50a29-1017-45cb-8241-cebaa0be83f0', 'affect', 'The ruling will affect thousands of pending claims arising from similar circumstances.', '该裁决将影响数千件因类似情形产生的未决索赔。'),
  ('d68e6940-1e00-4a82-91f0-9e53f43a9d4f-ex1', 'd68e6940-1e00-4a82-91f0-9e53f43a9d4f', 'inside', 'It is warm inside the house.', '屋子里很暖和。'),
  ('d68e6940-1e00-4a82-91f0-9e53f43a9d4f-ex2', 'd68e6940-1e00-4a82-91f0-9e53f43a9d4f', 'inside', 'The investigation relied on testimony from individuals inside the organization itself.', '调查依靠的是来自该组织内部人员的证词。'),
  ('e7bf0156-5ba8-4873-8ba7-bb5c27765e47-ex1', 'e7bf0156-5ba8-4873-8ba7-bb5c27765e47', 'conference', 'She is attending a conference in Shanghai.', '她正在上海参加一个会议。'),
  ('e7bf0156-5ba8-4873-8ba7-bb5c27765e47-ex2', 'e7bf0156-5ba8-4873-8ba7-bb5c27765e47', 'conference', 'The conference adopted a declaration committing signatories to binding emission targets.', '会议通过宣言，要求签署方承诺履行有约束力的减排目标。'),
  ('4dba9a29-7843-495b-8c2e-2be10bbd1546-ex1', '4dba9a29-7843-495b-8c2e-2be10bbd1546', 'unit', 'This apartment has ten units.', '这栋公寓楼有十个单元。'),
  ('4dba9a29-7843-495b-8c2e-2be10bbd1546-ex2', '4dba9a29-7843-495b-8c2e-2be10bbd1546', 'unit', 'The intensive care unit operated beyond capacity throughout the surge.', '在疫情高峰期间，重症监护病房一直超负荷运转。'),
  ('ed0ef735-9f49-4774-ac04-1b01338e6b77-ex1', 'ed0ef735-9f49-4774-ac04-1b01338e6b77', 'style', 'I like your style of writing.', '我喜欢你的写作风格。'),
  ('ed0ef735-9f49-4774-ac04-1b01338e6b77-ex2', 'ed0ef735-9f49-4774-ac04-1b01338e6b77', 'style', 'Her management style emphasizes delegation supported by rigorous accountability.', '她的管理风格强调授权，并辅以严格的问责。'),
  ('7b971a78-3172-45e3-b48f-73bffa5d5288-ex1', '7b971a78-3172-45e3-b48f-73bffa5d5288', 'adult', 'Tickets are ten dollars for adults.', '成人票十美元一张。'),
  ('7b971a78-3172-45e3-b48f-73bffa5d5288-ex2', '7b971a78-3172-45e3-b48f-73bffa5d5288', 'adult', 'The statute distinguishes sharply between offenses committed by adults and by juveniles.', '该法规对成年人与未成年人实施的犯罪作出明确区分。'),
  ('99224634-8913-416a-8d98-382bb5fc1f21-ex1', '99224634-8913-416a-8d98-382bb5fc1f21', 'worry', 'Don''t worry about the small stuff.', '别为小事担心。'),
  ('99224634-8913-416a-8d98-382bb5fc1f21-ex2', '99224634-8913-416a-8d98-382bb5fc1f21', 'worry', 'Analysts worry that concentrated exposures could amplify any localized credit shock.', '分析人士担心，集中的风险敞口可能放大任何局部信贷冲击。'),
  ('a2669616-7aec-404d-bb4d-67edab3ceb83-ex1', 'a2669616-7aec-404d-bb4d-67edab3ceb83', 'range', 'The store offers a wide range of products.', '这家店提供种类繁多的商品。'),
  ('a2669616-7aec-404d-bb4d-67edab3ceb83-ex2', 'a2669616-7aec-404d-bb4d-67edab3ceb83', 'range', 'The sanctions encompass a broad range of financial and technological restrictions.', '制裁涵盖了广泛的金融和技术限制。'),
  ('59753720-bbb9-45ae-aea1-d0eb1795f504-ex1', '59753720-bbb9-45ae-aea1-d0eb1795f504', 'mention', 'Did she mention the meeting time?', '她提到会议时间了吗？'),
  ('59753720-bbb9-45ae-aea1-d0eb1795f504-ex2', '59753720-bbb9-45ae-aea1-d0eb1795f504', 'mention', 'The prospectus failed to mention contingent liabilities material to any informed investment decision.', '招股书未提及对任何知情投资决策都至关重要的或有负债。'),
  ('129bcd40-9f97-4be9-bc23-0bbcbd97def6-ex1', '129bcd40-9f97-4be9-bc23-0bbcbd97def6', 'deep', 'The lake is very deep here.', '这里的湖水很深。'),
  ('129bcd40-9f97-4be9-bc23-0bbcbd97def6-ex2', '129bcd40-9f97-4be9-bc23-0bbcbd97def6', 'deep', 'The crisis exposed deep structural imbalances that prosperity had long obscured.', '这场危机暴露了长期被繁荣掩盖的深层结构性失衡。'),
  ('fa5192e9-8f0c-4bd7-bd05-e3db2b80d415-ex1', 'fa5192e9-8f0c-4bd7-bd05-e3db2b80d415', 'edge', 'Don''t put the glass near the edge of the table.', '别把杯子放在桌子边缘。'),
  ('fa5192e9-8f0c-4bd7-bd05-e3db2b80d415-ex2', 'fa5192e9-8f0c-4bd7-bd05-e3db2b80d415', 'edge', 'Proprietary data confers a decisive competitive edge in algorithmic trading.', '专有数据在算法交易中赋予决定性的竞争优势。'),
  ('80a99df0-e089-41a9-8567-34db21ef53ed-ex1', '80a99df0-e089-41a9-8567-34db21ef53ed', 'specific', 'Can you give me a specific example?', '你能给我举个具体的例子吗？'),
  ('80a99df0-e089-41a9-8567-34db21ef53ed-ex2', '80a99df0-e089-41a9-8567-34db21ef53ed', 'specific', 'The directive imposes specific obligations regarding the retention and disposal of records.', '该指令就记录的保存与销毁规定了具体义务。'),
  ('717942e3-12dc-4f55-9cdd-cf3644c2cb52-ex1', '717942e3-12dc-4f55-9cdd-cf3644c2cb52', 'writer', 'She is a writer of children''s books.', '她是一位儿童读物作家。'),
  ('717942e3-12dc-4f55-9cdd-cf3644c2cb52-ex2', '717942e3-12dc-4f55-9cdd-cf3644c2cb52', 'writer', 'The writer''s archives were acquired by the national library after protracted negotiation.', '经过长期磋商，这位作家的档案被国家图书馆收藏。'),
  ('2cbacdbf-9ccd-4df0-bdd8-d9167fa6a7d3-ex1', '2cbacdbf-9ccd-4df0-bdd8-d9167fa6a7d3', 'trouble', 'I am having trouble with my computer.', '我的电脑出了点问题。'),
  ('2cbacdbf-9ccd-4df0-bdd8-d9167fa6a7d3-ex2', '2cbacdbf-9ccd-4df0-bdd8-d9167fa6a7d3', 'trouble', 'The early warning indicators signaled trouble long before the formal default occurred.', '早在正式违约之前，预警指标就已发出警示。'),
  ('9068d945-16d3-4755-addb-9dd4b82bd7ef-ex1', '9068d945-16d3-4755-addb-9dd4b82bd7ef', 'necessary', 'Bring only the necessary items.', '只带必需品。'),
  ('9068d945-16d3-4755-addb-9dd4b82bd7ef-ex2', '9068d945-16d3-4755-addb-9dd4b82bd7ef', 'necessary', 'The court held that the restrictions were neither necessary nor proportionate.', '法院裁定，这些限制既无必要，也不相称。'),
  ('7e9d7819-d1e4-416e-8172-7aa7ab3c6c6c-ex1', '7e9d7819-d1e4-416e-8172-7aa7ab3c6c6c', 'throughout', 'The store is open throughout the year.', '这家店全年营业。'),
  ('7e9d7819-d1e4-416e-8172-7aa7ab3c6c6c-ex2', '7e9d7819-d1e4-416e-8172-7aa7ab3c6c6c', 'throughout', 'Compliance standards must be applied uniformly throughout the corporate group.', '合规标准必须在整个企业集团内统一执行。'),
  ('c14c0430-bb64-4d2a-8ff2-18ca21f13cd4-ex1', 'c14c0430-bb64-4d2a-8ff2-18ca21f13cd4', 'challenge', 'Learning a new language is a challenge.', '学习一门新语言是个挑战。'),
  ('c14c0430-bb64-4d2a-8ff2-18ca21f13cd4-ex2', 'c14c0430-bb64-4d2a-8ff2-18ca21f13cd4', 'challenge', 'The petitioners mounted a constitutional challenge to the emergency legislation.', '请愿人对紧急立法提起了违宪审查之诉。'),
  ('6d9b924c-6cf7-42db-909e-343a17ac89b4-ex1', '6d9b924c-6cf7-42db-909e-343a17ac89b4', 'fear', 'She has a fear of heights.', '她恐高。'),
  ('6d9b924c-6cf7-42db-909e-343a17ac89b4-ex2', '6d9b924c-6cf7-42db-909e-343a17ac89b4', 'fear', 'The measures were enacted amid fears of contagion spreading to adjacent markets.', '这些措施是在对风险蔓延至邻近市场的担忧中出台的。'),
  ('e2eec323-f46d-4ee8-8163-9716eed99ae8-ex1', 'e2eec323-f46d-4ee8-8163-9716eed99ae8', 'shoulder', 'He carried the bag on his shoulder.', '他把包扛在肩上。'),
  ('e2eec323-f46d-4ee8-8163-9716eed99ae8-ex2', 'e2eec323-f46d-4ee8-8163-9716eed99ae8', 'shoulder', 'Smaller member states shoulder a disproportionate share of the adjustment burden.', '较小的成员国承担着不成比例的调整负担。'),
  ('958adf1d-92a6-4d05-9cf0-8886bb4ba452-ex1', '958adf1d-92a6-4d05-9cf0-8886bb4ba452', 'institution', 'The university is a respected institution.', '这所大学是一所受人尊敬的学府。'),
  ('958adf1d-92a6-4d05-9cf0-8886bb4ba452-ex2', '958adf1d-92a6-4d05-9cf0-8886bb4ba452', 'institution', 'Durable democracies depend on institutions insulated from partisan capture.', '持久的民主制度有赖于不受党派操控的机构。'),
  ('cd61c2db-42c6-412a-867c-affcdef7a34f-ex1', 'cd61c2db-42c6-412a-867c-affcdef7a34f', 'middle', 'He woke up in the middle of the night.', '他半夜醒了。'),
  ('cd61c2db-42c6-412a-867c-affcdef7a34f-ex2', 'cd61c2db-42c6-412a-867c-affcdef7a34f', 'middle', 'The mediator occupies a delicate position in the middle of two irreconcilable demands.', '调解人处在两个无法调和的诉求之间，立场微妙。'),
  ('833fe8a1-4080-494b-bb55-701a51e195a0-ex1', '833fe8a1-4080-494b-bb55-701a51e195a0', 'sea', 'We spent the day by the sea.', '我们在海边度过了一天。'),
  ('833fe8a1-4080-494b-bb55-701a51e195a0-ex2', '833fe8a1-4080-494b-bb55-701a51e195a0', 'sea', 'The convention codifies navigational rights across territorial seas and international straits.', '该公约对领海和国际海峡的航行权作了成文规定。'),
  ('12fd6c63-5c07-45ac-b318-65f7569b034b-ex1', '12fd6c63-5c07-45ac-b318-65f7569b034b', 'dream', 'I had a strange dream last night.', '我昨晚做了一个奇怪的梦。'),
  ('12fd6c63-5c07-45ac-b318-65f7569b034b-ex2', '12fd6c63-5c07-45ac-b318-65f7569b034b', 'dream', 'The declaration articulates a collective dream of prosperity grounded in shared institutions.', '宣言表达了一个以共同制度为基础的共同繁荣愿景。'),
  ('5455cc55-de9e-4113-b181-5e870b809caa-ex1', '5455cc55-de9e-4113-b181-5e870b809caa', 'bar', 'We met at a bar near the office.', '我们在办公室附近的一家酒吧见了面。'),
  ('5455cc55-de9e-4113-b181-5e870b809caa-ex2', '5455cc55-de9e-4113-b181-5e870b809caa', 'bar', 'The ruling raises the bar for establishing causation in environmental liability claims.', '该裁决提高了环境责任索赔中因果关系的认定门槛。'),
  ('3fffd23c-165c-4b59-a698-fc85a4f451f2-ex1', '3fffd23c-165c-4b59-a698-fc85a4f451f2', 'beautiful', 'What a beautiful sunset!', '多美的日落啊！'),
  ('3fffd23c-165c-4b59-a698-fc85a4f451f2-ex2', '3fffd23c-165c-4b59-a698-fc85a4f451f2', 'beautiful', 'The restoration returned the cathedral to its original beautiful proportions.', '修复工程使大教堂恢复了最初的优美比例。'),
  ('cf45c70b-e3b8-4fdd-91b7-d72fcb2c6a6b-ex1', 'cf45c70b-e3b8-4fdd-91b7-d72fcb2c6a6b', 'property', 'This property belongs to my family.', '这处房产属于我们家。'),
  ('cf45c70b-e3b8-4fdd-91b7-d72fcb2c6a6b-ex2', 'cf45c70b-e3b8-4fdd-91b7-d72fcb2c6a6b', 'property', 'The statute strengthens protections for intellectual property registered in member states.', '该法规加强了对在成员国注册的知识产权的保护。'),
  ('708b0036-e7cf-480d-96c5-3d6bc6d92243-ex1', '708b0036-e7cf-480d-96c5-3d6bc6d92243', 'instead', 'Let''s walk instead of taking the bus.', '我们走路吧，别坐公交了。'),
  ('708b0036-e7cf-480d-96c5-3d6bc6d92243-ex2', '708b0036-e7cf-480d-96c5-3d6bc6d92243', 'instead', 'The committee opted for phased implementation instead of an abrupt regulatory transition.', '委员会选择分阶段实施，而不是突然的监管转换。'),
  ('cd942fa7-5111-4dc6-bdf9-5f55d9d1f4cc-ex1', 'cd942fa7-5111-4dc6-bdf9-5f55d9d1f4cc', 'improve', 'Practice will improve your English.', '练习会提高你的英语水平。'),
  ('cd942fa7-5111-4dc6-bdf9-5f55d9d1f4cc-ex2', 'cd942fa7-5111-4dc6-bdf9-5f55d9d1f4cc', 'improve', 'The reforms are designed to improve transparency in the allocation of public contracts.', '这些改革旨在提高公共合同分配的透明度。'),
  ('ae2662ce-7a16-40be-8338-3aba5b4586b8-ex1', 'ae2662ce-7a16-40be-8338-3aba5b4586b8', 'stuff', 'Put your stuff in the locker.', '把你的东西放进储物柜。'),
  ('ae2662ce-7a16-40be-8338-3aba5b4586b8-ex2', 'ae2662ce-7a16-40be-8338-3aba5b4586b8', 'stuff', 'The seized materials included stuff ranging from forged documents to counterfeit currency.', '查获的物品包括从伪造文件到假币的各类东西。'),
  ('462ad074-168e-4174-b0e5-f37221c19fd8-ex1', '462ad074-168e-4174-b0e5-f37221c19fd8', 'detail', 'Tell me every detail of the trip.', '把旅行的每个细节都告诉我。'),
  ('462ad074-168e-4174-b0e5-f37221c19fd8-ex2', '462ad074-168e-4174-b0e5-f37221c19fd8', 'detail', 'The annex sets out in exhaustive detail the procedures governing verification.', '附件详尽地规定了核查所适用的程序。'),
  ('c4be3482-a2f3-4a1b-b04f-b122e2edd70d-ex1', 'c4be3482-a2f3-4a1b-b04f-b122e2edd70d', 'method', 'This is a simple method for making bread.', '这是一种做面包的简单方法。'),
  ('c4be3482-a2f3-4a1b-b04f-b122e2edd70d-ex2', 'c4be3482-a2f3-4a1b-b04f-b122e2edd70d', 'method', 'The study''s method was independently validated by laboratories on three continents.', '该研究的方法得到了三大洲实验室的独立验证。'),
  ('55406f14-6ecb-4a63-af23-584eea94a6ed-ex1', '55406f14-6ecb-4a63-af23-584eea94a6ed', 'somebody', 'Somebody left the door open.', '有人没关门。'),
  ('55406f14-6ecb-4a63-af23-584eea94a6ed-ex2', '55406f14-6ecb-4a63-af23-584eea94a6ed', 'somebody', 'The protocol requires that somebody with senior authority countersign every exception.', '该规程要求由具有高级权限的人员对每项例外进行会签。'),
  ('432b6bbb-bb52-4f31-973b-aff9c48306e6-ex1', '432b6bbb-bb52-4f31-973b-aff9c48306e6', 'magazine', 'I read about it in a magazine.', '我在一本杂志上读到过这件事。'),
  ('432b6bbb-bb52-4f31-973b-aff9c48306e6-ex2', '432b6bbb-bb52-4f31-973b-aff9c48306e6', 'magazine', 'The magazine''s investigative report precipitated parliamentary hearings on procurement fraud.', '这家杂志的调查报道引发了关于采购舞弊的议会听证。'),
  ('7ee5596c-ed28-4f0c-9842-2a4a8d0245e3-ex1', '7ee5596c-ed28-4f0c-9842-2a4a8d0245e3', 'hotel', 'We stayed at a hotel near the beach.', '我们住在海滩附近的一家酒店。'),
  ('7ee5596c-ed28-4f0c-9842-2a4a8d0245e3-ex2', '7ee5596c-ed28-4f0c-9842-2a4a8d0245e3', 'hotel', 'The hotel chain divested its underperforming properties to refocus on premium markets.', '这家连锁酒店剥离了业绩不佳的物业，重新聚焦高端市场。'),
  ('2bc2fe5e-a38b-4142-81e3-010e89a9552c-ex1', '2bc2fe5e-a38b-4142-81e3-010e89a9552c', 'soldier', 'The soldier returned home after two years.', '那名士兵两年后回到了家。'),
  ('2bc2fe5e-a38b-4142-81e3-010e89a9552c-ex2', '2bc2fe5e-a38b-4142-81e3-010e89a9552c', 'soldier', 'The tribunal affirmed that every soldier bears individual responsibility for unlawful orders executed.', '法庭确认，每名军人对执行非法命令负有个人责任。'),
  ('9cd9e1e3-688a-4d8f-b8da-3c7dd5ebe83e-ex1', '9cd9e1e3-688a-4d8f-b8da-3c7dd5ebe83e', 'reflect', 'The lake reflects the mountains.', '湖面倒映着群山。'),
  ('9cd9e1e3-688a-4d8f-b8da-3c7dd5ebe83e-ex2', '9cd9e1e3-688a-4d8f-b8da-3c7dd5ebe83e', 'reflect', 'The revised figures reflect adjustments mandated by the new accounting standards.', '修订后的数字反映了新会计准则要求的调整。'),
  ('bd5a6192-97d6-4b6e-a88f-ea6f151a11bd-ex1', 'bd5a6192-97d6-4b6e-a88f-ea6f151a11bd', 'heavy', 'This suitcase is too heavy for me.', '这个行李箱对我来说太重了。'),
  ('bd5a6192-97d6-4b6e-a88f-ea6f151a11bd-ex2', 'bd5a6192-97d6-4b6e-a88f-ea6f151a11bd', 'heavy', 'The sector sustained heavy losses as commodity prices collapsed across the board.', '随着大宗商品价格全线崩跌，该行业蒙受了惨重损失。'),
  ('1d1fd18d-49e4-4cb8-a182-7cda237da6c9-ex1', '1d1fd18d-49e4-4cb8-a182-7cda237da6c9', 'sexual', 'The course covers sexual health education.', '这门课程包含性健康教育。'),
  ('1d1fd18d-49e4-4cb8-a182-7cda237da6c9-ex2', '1d1fd18d-49e4-4cb8-a182-7cda237da6c9', 'sexual', 'The statute criminalizes sexual harassment and mandates institutional reporting mechanisms.', '该法规将性骚扰定为犯罪，并强制要求建立机构报告机制。'),
  ('122cd5c0-9eb0-4f32-8dce-9e9fd5a23a70-ex1', '122cd5c0-9eb0-4f32-8dce-9e9fd5a23a70', 'bag', 'I left my bag on the bus.', '我把包落在公交车上了。'),
  ('122cd5c0-9eb0-4f32-8dce-9e9fd5a23a70-ex2', '122cd5c0-9eb0-4f32-8dce-9e9fd5a23a70', 'bag', 'Customs officers intercepted a diplomatic bag allegedly containing undeclared currency.', '海关官员截获了一个据称装有未申报货币的外交邮袋。'),
  ('852ade38-15e7-477b-ac2b-73085f3ab733-ex1', '852ade38-15e7-477b-ac2b-73085f3ab733', 'heat', 'The heat is unbearable this summer.', '今年夏天热得难以忍受。'),
  ('852ade38-15e7-477b-ac2b-73085f3ab733-ex2', '852ade38-15e7-477b-ac2b-73085f3ab733', 'heat', 'Prolonged extreme heat has placed unprecedented strain on the region''s power grid.', '持续的极端高温给该地区电网带来了前所未有的压力。'),
  ('8d6091ee-9425-4b05-a40b-732d75cda5ca-ex1', '8d6091ee-9425-4b05-a40b-732d75cda5ca', 'marriage', 'They have a happy marriage.', '他们的婚姻很幸福。'),
  ('8d6091ee-9425-4b05-a40b-732d75cda5ca-ex2', '8d6091ee-9425-4b05-a40b-732d75cda5ca', 'marriage', 'The ruling extends equal legal recognition to marriages contracted in other jurisdictions.', '该裁决对在其他司法管辖区缔结的婚姻给予平等的法律承认。'),
  ('5cb0a847-2254-46ee-86a3-e61a18f0b2ef-ex1', '5cb0a847-2254-46ee-86a3-e61a18f0b2ef', 'tough', 'It was a tough decision to make.', '这是一个艰难的决定。'),
  ('5cb0a847-2254-46ee-86a3-e61a18f0b2ef-ex2', '5cb0a847-2254-46ee-86a3-e61a18f0b2ef', 'tough', 'The regulator adopted a markedly tougher stance following the sequence of compliance failures.', '在接连出现合规失误之后，监管机构的立场明显趋于强硬。'),
  ('021a54c2-8cf1-4412-b39e-ddd2492786fa-ex1', '021a54c2-8cf1-4412-b39e-ddd2492786fa', 'sing', 'She loves to sing in the shower.', '她喜欢洗澡时唱歌。'),
  ('021a54c2-8cf1-4412-b39e-ddd2492786fa-ex2', '021a54c2-8cf1-4412-b39e-ddd2492786fa', 'sing', 'The choir was invited to sing at the commemoration attended by visiting heads of state.', '合唱团应邀在多国元首出席的纪念仪式上演唱。'),
  ('8e88d974-f0bb-4216-8e1b-c2d9e9727c58-ex1', '8e88d974-f0bb-4216-8e1b-c2d9e9727c58', 'surface', 'Wipe the surface of the table.', '擦一下桌面。'),
  ('8e88d974-f0bb-4216-8e1b-c2d9e9727c58-ex2', '8e88d974-f0bb-4216-8e1b-c2d9e9727c58', 'surface', 'Beneath the surface of apparent consensus lay deep disagreements over implementation.', '在表面共识之下，隐藏着关于执行问题的深刻分歧。'),
  ('b1f9d6f2-998c-4b53-bbe9-6b73cef9508b-ex1', 'b1f9d6f2-998c-4b53-bbe9-6b73cef9508b', 'purpose', 'What is the purpose of your visit?', '你此行的目的是什么？'),
  ('b1f9d6f2-998c-4b53-bbe9-6b73cef9508b-ex2', 'b1f9d6f2-998c-4b53-bbe9-6b73cef9508b', 'purpose', 'Funds appropriated for one purpose may not be redirected without legislative authorization.', '为特定用途拨付的资金未经立法授权不得挪作他用。'),
  ('6de5cf38-8140-41ed-b199-423059ddf5ea-ex1', '6de5cf38-8140-41ed-b199-423059ddf5ea', 'exist', 'Do aliens really exist?', '外星人真的存在吗？'),
  ('6de5cf38-8140-41ed-b199-423059ddf5ea-ex2', '6de5cf38-8140-41ed-b199-423059ddf5ea', 'exist', 'No adequate mechanism currently exists for adjudicating such cross-border claims.', '目前尚不存在裁决此类跨境索赔的适当机制。'),
  ('b43c73ea-12df-480b-85b7-12d18c6f1473-ex1', 'b43c73ea-12df-480b-85b7-12d18c6f1473', 'pattern', 'I like the pattern on your shirt.', '我喜欢你衬衫上的图案。'),
  ('b43c73ea-12df-480b-85b7-12d18c6f1473-ex2', 'b43c73ea-12df-480b-85b7-12d18c6f1473', 'pattern', 'The audit identified a recurring pattern of transactions structured to evade reporting thresholds.', '审计发现了一种为规避申报门槛而设计交易的反复出现的模式。'),
  ('04750900-4adb-4164-a2d3-eefe09d0b8dd-ex1', '04750900-4adb-4164-a2d3-eefe09d0b8dd', 'whom', 'To whom should I address this letter?', '这封信我该写给谁？'),
  ('04750900-4adb-4164-a2d3-eefe09d0b8dd-ex2', '04750900-4adb-4164-a2d3-eefe09d0b8dd', 'whom', 'The committee summoned the officials upon whom responsibility for oversight had rested.', '委员会传唤了负有监督职责的官员。'),
  ('ddd16962-2f34-445a-97af-22d240231a32-ex1', 'ddd16962-2f34-445a-97af-22d240231a32', 'skin', 'Protect your skin from the sun.', '保护皮肤免受阳光伤害。'),
  ('ddd16962-2f34-445a-97af-22d240231a32-ex2', 'ddd16962-2f34-445a-97af-22d240231a32', 'skin', 'The investigators had skin in the game, a fact that compromised their ostensible neutrality.', '调查人员自身利益牵涉其中，这一事实损害了他们表面上的中立性。'),
  ('6c166c11-71a0-4ef1-be10-9e828f6eb414-ex1', '6c166c11-71a0-4ef1-be10-9e828f6eb414', 'agent', 'The travel agent booked our flights.', '旅行社代理帮我们订了机票。'),
  ('6c166c11-71a0-4ef1-be10-9e828f6eb414-ex2', '6c166c11-71a0-4ef1-be10-9e828f6eb414', 'agent', 'The indictment alleges that the defendant acted as an unregistered agent of a foreign power.', '起诉书指控被告充当外国势力的未登记代理人。'),
  ('e42766e5-4405-4eef-87d9-dea131ddf994-ex1', 'e42766e5-4405-4eef-87d9-dea131ddf994', 'owner', 'Who is the owner of this car?', '这辆车的车主是谁？'),
  ('e42766e5-4405-4eef-87d9-dea131ddf994-ex2', 'e42766e5-4405-4eef-87d9-dea131ddf994', 'owner', 'The registry discloses the beneficial owner of every entity incorporated in the jurisdiction.', '登记系统披露在该辖区注册的每个实体的实际受益所有人。'),
  ('2add7661-fcea-4a54-a522-8ee404f7e6f1-ex1', '2add7661-fcea-4a54-a522-8ee404f7e6f1', 'machine', 'The washing machine is broken again.', '洗衣机又坏了。'),
  ('2add7661-fcea-4a54-a522-8ee404f7e6f1-ex2', '2add7661-fcea-4a54-a522-8ee404f7e6f1', 'machine', 'The party machine mobilized resources on a scale that overwhelmed independent challengers.', '政党机器动员资源的规模令独立挑战者难以匹敌。'),
  ('bf7b72bc-b20b-44fe-a5c2-8c317dc81f77-ex1', 'bf7b72bc-b20b-44fe-a5c2-8c317dc81f77', 'gas', 'We need to stop for gas.', '我们得停车加油。'),
  ('bf7b72bc-b20b-44fe-a5c2-8c317dc81f77-ex2', 'bf7b72bc-b20b-44fe-a5c2-8c317dc81f77', 'gas', 'The pipeline dispute disrupted gas supplies to several import-dependent economies.', '管道争端中断了对几个依赖进口经济体的天然气供应。'),
  ('f641fa1b-8a8c-458a-8f74-e4a5d972f821-ex1', 'f641fa1b-8a8c-458a-8f74-e4a5d972f821', 'ahead', 'The road ahead is closed.', '前方道路封闭。'),
  ('f641fa1b-8a8c-458a-8f74-e4a5d972f821-ex2', 'f641fa1b-8a8c-458a-8f74-e4a5d972f821', 'ahead', 'The commission warned of formidable challenges ahead despite the encouraging preliminary results.', '委员会警告说，尽管初步结果令人鼓舞，未来仍面临严峻挑战。'),
  ('edced00c-bcf7-4f04-9a38-f5237e8b4b63-ex1', 'edced00c-bcf7-4f04-9a38-f5237e8b4b63', 'generation', 'My generation grew up with the internet.', '我们这一代人是伴着互联网长大的。'),
  ('edced00c-bcf7-4f04-9a38-f5237e8b4b63-ex2', 'edced00c-bcf7-4f04-9a38-f5237e8b4b63', 'generation', 'The debt incurred today will burden a generation that had no voice in the decision.', '今天欠下的债务将压在对这一决定毫无发言权的一代人身上。'),
  ('c0f73d7a-8fb4-4897-8dc9-1ad2d531b93b-ex1', 'c0f73d7a-8fb4-4897-8dc9-1ad2d531b93b', 'commercial', 'I saw a funny commercial on TV.', '我在电视上看到一个有趣的广告。'),
  ('c0f73d7a-8fb4-4897-8dc9-1ad2d531b93b-ex2', 'c0f73d7a-8fb4-4897-8dc9-1ad2d531b93b', 'commercial', 'The treaty distinguishes between sovereign acts and purely commercial transactions.', '该条约对主权行为与纯商业交易作出区分。'),
  ('18647456-a13b-4cdc-a9fd-e9a129cdfad3-ex1', '18647456-a13b-4cdc-a9fd-e9a129cdfad3', 'address', 'What is your home address?', '你的家庭住址是什么？'),
  ('18647456-a13b-4cdc-a9fd-e9a129cdfad3-ex2', '18647456-a13b-4cdc-a9fd-e9a129cdfad3', 'address', 'The summit failed to address the underlying drivers of the migration crisis.', '峰会未能解决移民危机的深层动因。'),
  ('bc124a0a-70ff-4ecb-9d3f-1bd758c24e69-ex1', 'bc124a0a-70ff-4ecb-9d3f-1bd758c24e69', 'cancer', 'Early screening can detect cancer.', '早期筛查可以发现癌症。'),
  ('bc124a0a-70ff-4ecb-9d3f-1bd758c24e69-ex2', 'bc124a0a-70ff-4ecb-9d3f-1bd758c24e69', 'cancer', 'The registry tracks cancer incidence across demographic groups to guide prevention policy.', '该登记系统追踪不同人口群体的癌症发病率，为预防政策提供依据。'),
  ('126fa329-3f76-40f0-8020-9f44d9ff1dd9-ex1', '126fa329-3f76-40f0-8020-9f44d9ff1dd9', 'item', 'Check each item on the list.', '核对清单上的每一项。'),
  ('126fa329-3f76-40f0-8020-9f44d9ff1dd9-ex2', '126fa329-3f76-40f0-8020-9f44d9ff1dd9', 'item', 'The contested item was withdrawn from the agenda pending further consultation.', '这一争议事项已从议程中撤下，待进一步磋商。'),
  ('6c86cb32-3d95-408c-b69e-77bc9a483ce9-ex1', '6c86cb32-3d95-408c-b69e-77bc9a483ce9', 'reality', 'His dream finally became a reality.', '他的梦想终于成真了。'),
  ('6c86cb32-3d95-408c-b69e-77bc9a483ce9-ex2', '6c86cb32-3d95-408c-b69e-77bc9a483ce9', 'reality', 'The projections bore little resemblance to the fiscal reality that subsequently unfolded.', '这些预测与随后显现的财政现实相去甚远。'),
  ('12f0fe05-3bea-48ef-a28f-c9558150ced1-ex1', '12f0fe05-3bea-48ef-a28f-c9558150ced1', 'coach', 'Our coach makes us train every day.', '我们的教练让我们每天训练。'),
  ('12f0fe05-3bea-48ef-a28f-c9558150ced1-ex2', '12f0fe05-3bea-48ef-a28f-c9558150ced1', 'coach', 'The federation suspended the coach pending an investigation into recruitment improprieties.', '在对招募违规行为的调查结束之前，该协会暂停了这名教练的职务。'),
  ('837b9359-04aa-4fb5-b189-fbfa9c8c991b-ex1', '837b9359-04aa-4fb5-b189-fbfa9c8c991b', 'Mrs', 'Mrs Lee teaches us music.', '李太太教我们音乐。'),
  ('837b9359-04aa-4fb5-b189-fbfa9c8c991b-ex2', '837b9359-04aa-4fb5-b189-fbfa9c8c991b', 'Mrs', 'Mrs Thompson''s bequest endowed the scholarship fund that bears her family''s name.', '汤普森夫人的遗赠设立了以其家族命名的奖学金基金。'),
  ('9da49d17-7105-4464-a253-87a57a38cd25-ex1', '9da49d17-7105-4464-a253-87a57a38cd25', 'yard', 'The kids are playing in the yard.', '孩子们在院子里玩。'),
  ('9da49d17-7105-4464-a253-87a57a38cd25-ex2', '9da49d17-7105-4464-a253-87a57a38cd25', 'yard', 'The shipyard secured contracts that guarantee employment for a decade.', '这家造船厂获得的合同保障了十年的就业。'),
  ('2c2670d2-596d-4d71-a4aa-f9069d891129-ex1', '2c2670d2-596d-4d71-a4aa-f9069d891129', 'beat', 'Our team beat them three to one.', '我们队三比一赢了他们。'),
  ('2c2670d2-596d-4d71-a4aa-f9069d891129-ex2', '2c2670d2-596d-4d71-a4aa-f9069d891129', 'beat', 'The auditors confirmed that the fund consistently beat its benchmark through unhedged currency exposure.', '审计师证实，该基金凭借未对冲的货币敞口持续跑赢基准。'),
  ('3b77f994-f436-4712-85b3-8245f085b413-ex1', '3b77f994-f436-4712-85b3-8245f085b413', 'violence', 'The movie contains scenes of violence.', '这部电影包含暴力场面。'),
  ('3b77f994-f436-4712-85b3-8245f085b413-ex2', '3b77f994-f436-4712-85b3-8245f085b413', 'violence', 'The commission documented systematic violence perpetrated against civilian populations.', '委员会记录了针对平民的系统性暴力行为。'),
  ('0fc4bd91-7819-4ce9-8ce5-f92d23e17d83-ex1', '0fc4bd91-7819-4ce9-8ce5-f92d23e17d83', 'total', 'The total comes to fifty dollars.', '总共五十美元。'),
  ('0fc4bd91-7819-4ce9-8ce5-f92d23e17d83-ex2', '0fc4bd91-7819-4ce9-8ce5-f92d23e17d83', 'total', 'Total liabilities exceeded reported assets by a margin that stunned even seasoned analysts.', '负债总额超出账面资产的幅度连资深分析师都为之震惊。'),
  ('80269cb2-ddab-4642-b962-fb4ccba72638-ex1', '80269cb2-ddab-4642-b962-fb4ccba72638', 'tend', 'I tend to wake up early.', '我往往起得很早。'),
  ('80269cb2-ddab-4642-b962-fb4ccba72638-ex2', '80269cb2-ddab-4642-b962-fb4ccba72638', 'tend', 'Concentrated markets tend toward pricing behavior that disadvantages consumers.', '高度集中的市场往往出现损害消费者利益的定价行为。'),
  ('88419eba-b621-43cc-8a6f-b524bc0e046c-ex1', '88419eba-b621-43cc-8a6f-b524bc0e046c', 'investment', 'Buying a house is a big investment.', '买房是一项很大的投资。'),
  ('88419eba-b621-43cc-8a6f-b524bc0e046c-ex2', '88419eba-b621-43cc-8a6f-b524bc0e046c', 'investment', 'The treaty shields foreign investment from expropriation without prompt and adequate compensation.', '该条约保护外国投资免遭无及时充分补偿的征收。'),
  ('5d37240e-83e6-448d-8dcc-dbee5b7fcb90-ex1', '5d37240e-83e6-448d-8dcc-dbee5b7fcb90', 'discussion', 'We had a long discussion about the plan.', '我们就这个计划进行了长时间的讨论。'),
  ('5d37240e-83e6-448d-8dcc-dbee5b7fcb90-ex2', '5d37240e-83e6-448d-8dcc-dbee5b7fcb90', 'discussion', 'The communiqué reflects months of confidential discussion among senior officials.', '这份公报凝聚了高级官员数月的秘密磋商。'),
  ('4592b97c-c434-4beb-abe5-1765beaf8199-ex1', '4592b97c-c434-4beb-abe5-1765beaf8199', 'finger', 'I cut my finger while cooking.', '我做饭时切到了手指。'),
  ('4592b97c-c434-4beb-abe5-1765beaf8199-ex2', '4592b97c-c434-4beb-abe5-1765beaf8199', 'finger', 'Early reports pointed the finger at maintenance lapses rather than design defects.', '早期报告将矛头指向维护疏漏，而非设计缺陷。'),
  ('5f669ed4-dbe1-432e-849b-886f5f68d31c-ex1', '5f669ed4-dbe1-432e-849b-886f5f68d31c', 'garden', 'She grows vegetables in her garden.', '她在自家花园里种菜。'),
  ('5f669ed4-dbe1-432e-849b-886f5f68d31c-ex2', '5f669ed4-dbe1-432e-849b-886f5f68d31c', 'garden', 'The botanical garden maintains seed banks critical to global conservation efforts.', '这座植物园维护着对全球保护工作至关重要的种子库。'),
  ('cbd6b29d-7ddf-435a-919a-f7b35e8e4ee0-ex1', 'cbd6b29d-7ddf-435a-919a-f7b35e8e4ee0', 'notice', 'Did you notice anything different?', '你注意到什么不同了吗？'),
  ('cbd6b29d-7ddf-435a-919a-f7b35e8e4ee0-ex2', 'cbd6b29d-7ddf-435a-919a-f7b35e8e4ee0', 'notice', 'The tenancy may be terminated only upon ninety days'' written notice to all parties.', '租约只有在提前九十天书面通知各方后方可终止。'),
  ('34ba74ef-a23e-4dcd-b045-04f929e93bd6-ex1', '34ba74ef-a23e-4dcd-b045-04f929e93bd6', 'collection', 'He has a large collection of stamps.', '他收藏了大量邮票。'),
  ('34ba74ef-a23e-4dcd-b045-04f929e93bd6-ex2', '34ba74ef-a23e-4dcd-b045-04f929e93bd6', 'collection', 'The museum''s collection was catalogued and digitized under an international preservation grant.', '在一项国际保护资助下，该博物馆的藏品完成了编目和数字化。'),
  ('f780a78d-aa4e-4611-a179-1911d71fc4bd-ex1', 'f780a78d-aa4e-4611-a179-1911d71fc4bd', 'modern', 'The apartment has a modern kitchen.', '这套公寓有一个现代化的厨房。'),
  ('f780a78d-aa4e-4611-a179-1911d71fc4bd-ex2', 'f780a78d-aa4e-4611-a179-1911d71fc4bd', 'modern', 'Modern supply chains exhibit interdependencies that amplify localized disruptions globally.', '现代供应链的相互依存性会将局部中断的影响放大至全球。'),
  ('b9b28111-3825-4b67-8513-e3e7bd600e5d-ex1', 'b9b28111-3825-4b67-8513-e3e7bd600e5d', 'task', 'Cleaning the garage is a big task.', '打扫车库是项大工程。'),
  ('b9b28111-3825-4b67-8513-e3e7bd600e5d-ex2', 'b9b28111-3825-4b67-8513-e3e7bd600e5d', 'task', 'The committee was tasked with reconciling fiscal restraint and urgent infrastructure needs.', '委员会的任务是在财政紧缩与紧迫的基础设施需求之间求得平衡。'),
  ('75ba715f-ed79-4ec6-a550-2c0356be53a0-ex1', '75ba715f-ed79-4ec6-a550-2c0356be53a0', 'partner', 'She is my partner for the science project.', '她是我科学项目的搭档。'),
  ('75ba715f-ed79-4ec6-a550-2c0356be53a0-ex2', '75ba715f-ed79-4ec6-a550-2c0356be53a0', 'partner', 'Each managing partner bears joint and several liability for the firm''s obligations.', '每位执行合伙人对事务所的债务承担连带责任。'),
  ('5d513527-db2e-4d75-be9b-857665823f5e-ex1', '5d513527-db2e-4d75-be9b-857665823f5e', 'positive', 'Try to stay positive!', '尽量保持乐观！'),
  ('5d513527-db2e-4d75-be9b-857665823f5e-ex2', '5d513527-db2e-4d75-be9b-857665823f5e', 'positive', 'The pilot program produced demonstrably positive outcomes across every measured indicator.', '试点项目在每项测量指标上都产生了明显的积极成效。'),
  ('f0feed7a-a052-421c-901b-1fb3d8cee19a-ex1', 'f0feed7a-a052-421c-901b-1fb3d8cee19a', 'civil', 'Please keep the discussion civil.', '请保持讨论的礼貌。'),
  ('f0feed7a-a052-421c-901b-1fb3d8cee19a-ex2', 'f0feed7a-a052-421c-901b-1fb3d8cee19a', 'civil', 'The plaintiffs pursued civil remedies after the criminal prosecution was discontinued.', '刑事诉讼中止后，原告转而寻求民事救济。'),
  ('5a48da9d-3b05-4bdb-ba7d-e21213b2807b-ex1', '5a48da9d-3b05-4bdb-ba7d-e21213b2807b', 'kitchen', 'Dinner smells great from the kitchen.', '厨房里飘来晚饭的香味。'),
  ('5a48da9d-3b05-4bdb-ba7d-e21213b2807b-ex2', '5a48da9d-3b05-4bdb-ba7d-e21213b2807b', 'kitchen', 'The inspection found that the commercial kitchen failed multiple food safety standards.', '检查发现这间商用厨房多项食品安全标准不达标。'),
  ('34a6204c-3d56-4d24-8aff-cd959a4485f4-ex1', '34a6204c-3d56-4d24-8aff-cd959a4485f4', 'consumer', 'Consumers are buying more online.', '消费者越来越多地在网上购物。'),
  ('34a6204c-3d56-4d24-8aff-cd959a4485f4-ex2', '34a6204c-3d56-4d24-8aff-cd959a4485f4', 'consumer', 'The statute empowers consumers to seek collective redress for deceptive practices.', '该法规赋予消费者就欺诈行为寻求集体救济的权利。'),
  ('4729b354-bbbc-4bab-a98e-065455b0b307-ex1', '4729b354-bbbc-4bab-a98e-065455b0b307', 'shot', 'That was a great shot!', '好球！'),
  ('4729b354-bbbc-4bab-a98e-065455b0b307-ex2', '4729b354-bbbc-4bab-a98e-065455b0b307', 'shot', 'The single administered shot confers immunity that persists for at least a decade.', '单剂注射即可产生至少持续十年的免疫力。'),
  ('5b4be73f-2ede-403b-907e-d85623b2971a-ex1', '5b4be73f-2ede-403b-907e-d85623b2971a', 'budget', 'We are on a tight budget this month.', '我们这个月预算很紧。'),
  ('5b4be73f-2ede-403b-907e-d85623b2971a-ex2', '5b4be73f-2ede-403b-907e-d85623b2971a', 'budget', 'The proposed budget reallocates discretionary spending toward long-deferred infrastructure.', '拟议预算将非强制性支出重新分配给长期搁置的基础设施。'),
  ('10207d0f-68bc-48b1-af63-734294166124-ex1', '10207d0f-68bc-48b1-af63-734294166124', 'wish', 'Make a wish and blow out the candles.', '许个愿，吹灭蜡烛吧。'),
  ('10207d0f-68bc-48b1-af63-734294166124-ex2', '10207d0f-68bc-48b1-af63-734294166124', 'wish', 'The testator''s expressed wishes govern the distribution of the residuary estate.', '立遗嘱人明示的意愿决定剩余遗产的分配。'),
  ('252578c2-4002-4011-b4ae-a4d27e8779d9-ex1', '252578c2-4002-4011-b4ae-a4d27e8779d9', 'painting', 'This painting is over a hundred years old.', '这幅画已有一百多年历史。'),
  ('252578c2-4002-4011-b4ae-a4d27e8779d9-ex2', '252578c2-4002-4011-b4ae-a4d27e8779d9', 'painting', 'The painting was repatriated after decades of litigation over its wartime provenance.', '在围绕其战时来源的数十年诉讼之后，这幅画得以归还原属国。'),
  ('51f30b05-5780-4857-8280-c96f30d3bdd3-ex1', '51f30b05-5780-4857-8280-c96f30d3bdd3', 'scientist', 'The scientist works in a laboratory.', '这位科学家在实验室工作。'),
  ('51f30b05-5780-4857-8280-c96f30d3bdd3-ex2', '51f30b05-5780-4857-8280-c96f30d3bdd3', 'scientist', 'Leading scientists issued a consensus statement urging immediate precautionary measures.', '知名科学家发表共识声明，敦促立即采取预防措施。'),
  ('fc24ba9b-8fe6-4149-9bb2-0f02df88fdcd-ex1', 'fc24ba9b-8fe6-4149-9bb2-0f02df88fdcd', 'safe', 'Keep your passport in a safe place.', '把护照放在安全的地方。'),
  ('fc24ba9b-8fe6-4149-9bb2-0f02df88fdcd-ex2', 'fc24ba9b-8fe6-4149-9bb2-0f02df88fdcd', 'safe', 'The regulator established safe harbor provisions for firms that self-report violations.', '监管机构为主动自报违规的公司设立了安全港条款。'),
  ('c8f25ac8-c332-409e-ba6b-5484ed6f36f1-ex1', 'c8f25ac8-c332-409e-ba6b-5484ed6f36f1', 'agreement', 'We finally reached an agreement.', '我们终于达成了一致。'),
  ('c8f25ac8-c332-409e-ba6b-5484ed6f36f1-ex2', 'c8f25ac8-c332-409e-ba6b-5484ed6f36f1', 'agreement', 'The agreement enters into force upon ratification by two-thirds of the signatories.', '该协议在三分之二签署方批准后生效。'),
  ('e9e7e3b9-fde1-4a9a-a4d9-2b3de227a285-ex1', 'e9e7e3b9-fde1-4a9a-a4d9-2b3de227a285', 'capital', 'Beijing is the capital of China.', '北京是中国的首都。'),
  ('e9e7e3b9-fde1-4a9a-a4d9-2b3de227a285-ex2', 'e9e7e3b9-fde1-4a9a-a4d9-2b3de227a285', 'capital', 'The directive requires banks to hold capital commensurate with their risk-weighted assets.', '该指令要求银行持有与其风险加权资产相称的资本。'),
  ('c458ac5d-4ed6-465e-b17c-33b37ed34138-ex1', 'c458ac5d-4ed6-465e-b17c-33b37ed34138', 'mouth', 'Don''t talk with your mouth full.', '嘴里有东西时别说话。'),
  ('c458ac5d-4ed6-465e-b17c-33b37ed34138-ex2', 'c458ac5d-4ed6-465e-b17c-33b37ed34138', 'mouth', 'The delta forms where the river''s mouth meets the tidal estuary.', '三角洲形成于河口与潮汐河口湾的交汇处。'),
  ('b244bad3-6d43-43ec-899b-34baf6e30c06-ex1', 'b244bad3-6d43-43ec-899b-34baf6e30c06', 'nor', 'I have neither time nor money.', '我既没时间也没钱。'),
  ('b244bad3-6d43-43ec-899b-34baf6e30c06-ex2', 'b244bad3-6d43-43ec-899b-34baf6e30c06', 'nor', 'Neither the regulator nor the auditors detected the irregularities before the collapse.', '在崩盘之前，监管机构和审计师都未发现这些违规行为。'),
  ('63125757-9f45-4778-af5f-3a7873d0aee6-ex1', '63125757-9f45-4778-af5f-3a7873d0aee6', 'victim', 'The victim was taken to hospital.', '伤者被送往医院。'),
  ('63125757-9f45-4778-af5f-3a7873d0aee6-ex2', '63125757-9f45-4778-af5f-3a7873d0aee6', 'victim', 'The compensation scheme prioritizes victims who suffered permanent incapacity.', '赔偿方案优先照顾遭受永久性丧失能力的受害者。'),
  ('15493a95-96b3-4a26-b2c9-e0c9ce79a9d8-ex1', '15493a95-96b3-4a26-b2c9-e0c9ce79a9d8', 'newspaper', 'My dad reads the newspaper every morning.', '我爸爸每天早上看报纸。'),
  ('15493a95-96b3-4a26-b2c9-e0c9ce79a9d8-ex2', '15493a95-96b3-4a26-b2c9-e0c9ce79a9d8', 'newspaper', 'The newspaper successfully defended the defamation claim on grounds of public interest.', '这家报纸以公共利益为由成功抗辩了诽谤指控。'),
  ('48fd60a0-fc8f-47b3-ae03-ccbd88ca9154-ex1', '48fd60a0-fc8f-47b3-ae03-ccbd88ca9154', 'threat', 'The dark clouds are a threat of rain.', '乌云预示着可能要下雨。'),
  ('48fd60a0-fc8f-47b3-ae03-ccbd88ca9154-ex2', '48fd60a0-fc8f-47b3-ae03-ccbd88ca9154', 'threat', 'The assessment identifies cyber intrusion as the foremost threat to critical infrastructure.', '评估将网络入侵列为关键基础设施面临的首要威胁。'),
  ('767562d2-bb79-426d-af0f-f648eff87d1a-ex1', '767562d2-bb79-426d-af0f-f648eff87d1a', 'responsibility', 'Feeding the dog is your responsibility.', '喂狗是你的责任。'),
  ('767562d2-bb79-426d-af0f-f648eff87d1a-ex2', '767562d2-bb79-426d-af0f-f648eff87d1a', 'responsibility', 'Ultimate responsibility for compliance rests with the board, not with delegated officers.', '合规的最终责任在于董事会，而非受托的高管。'),
  ('983198c8-d0d2-4063-b6e1-d07d5baf204f-ex1', '983198c8-d0d2-4063-b6e1-d07d5baf204f', 'smile', 'She greeted us with a warm smile.', '她以温暖的微笑迎接我们。'),
  ('983198c8-d0d2-4063-b6e1-d07d5baf204f-ex2', '983198c8-d0d2-4063-b6e1-d07d5baf204f', 'smile', 'Behind the diplomatic smiles, the two delegations remained entrenched in their positions.', '在外交式微笑的背后，两国代表团依然各执己见。'),
  ('ff177d99-2d12-4faa-bd5d-4d220717f221-ex1', 'ff177d99-2d12-4faa-bd5d-4d220717f221', 'attorney', 'You should speak to an attorney first.', '你应该先咨询律师。'),
  ('ff177d99-2d12-4faa-bd5d-4d220717f221-ex2', 'ff177d99-2d12-4faa-bd5d-4d220717f221', 'attorney', 'The attorney general announced a coordinated multistate action against the manufacturers.', '总检察长宣布对这些制造商提起多州协同诉讼。'),
  ('08a92044-46f7-45d9-8eb4-d0f99561bb54-ex1', '08a92044-46f7-45d9-8eb4-d0f99561bb54', 'score', 'What was the final score of the game?', '比赛最终比分是多少？'),
  ('08a92044-46f7-45d9-8eb4-d0f99561bb54-ex2', '08a92044-46f7-45d9-8eb4-d0f99561bb54', 'score', 'Composite credit scores increasingly determine access to housing and employment alike.', '综合信用评分日益决定着住房和就业机会的获得。'),
  ('857e0ec3-8f40-42f4-a7f1-ac5ceebf89d2-ex1', '857e0ec3-8f40-42f4-a7f1-ac5ceebf89d2', 'account', 'I opened a new bank account.', '我开了一个新的银行账户。'),
  ('857e0ec3-8f40-42f4-a7f1-ac5ceebf89d2-ex2', '857e0ec3-8f40-42f4-a7f1-ac5ceebf89d2', 'account', 'The published account of the negotiations diverges materially from the contemporaneous records.', '公开发表的谈判记述与当时的记录存在重大出入。'),
  ('e28de83f-afc6-4d15-8018-17b2d9a58c1b-ex1', 'e28de83f-afc6-4d15-8018-17b2d9a58c1b', 'interesting', 'That is an interesting question.', '这是个有趣的问题。'),
  ('e28de83f-afc6-4d15-8018-17b2d9a58c1b-ex2', 'e28de83f-afc6-4d15-8018-17b2d9a58c1b', 'interesting', 'The case presents interesting questions concerning the extraterritorial reach of domestic law.', '该案就国内法的域外效力提出了值得探讨的问题。'),
  ('dc3a1c97-0dfc-4734-bd69-9b3307c396af-ex1', 'dc3a1c97-0dfc-4734-bd69-9b3307c396af', 'audience', 'The audience clapped loudly.', '观众热烈鼓掌。'),
  ('dc3a1c97-0dfc-4734-bd69-9b3307c396af-ex2', 'dc3a1c97-0dfc-4734-bd69-9b3307c396af', 'audience', 'The findings were presented to an audience of regulators and institutional investors.', '研究结果向监管机构和机构投资者发布。'),
  ('fb70682a-368a-4c43-8d23-66b63be44600-ex1', 'fb70682a-368a-4c43-8d23-66b63be44600', 'rich', 'The soup has a rich flavor.', '这汤味道浓郁。'),
  ('fb70682a-368a-4c43-8d23-66b63be44600-ex2', 'fb70682a-368a-4c43-8d23-66b63be44600', 'rich', 'The widening divide between rich and poor regions threatens national cohesion.', '贫富地区差距的扩大威胁着国家凝聚力。'),
  ('334599d9-e840-4f52-b2ea-a5a209ba39f5-ex1', '334599d9-e840-4f52-b2ea-a5a209ba39f5', 'dinner', 'We are having fish for dinner.', '我们晚饭吃鱼。'),
  ('334599d9-e840-4f52-b2ea-a5a209ba39f5-ex2', '334599d9-e840-4f52-b2ea-a5a209ba39f5', 'dinner', 'The state dinner honored the visiting delegation at the conclusion of the trade talks.', '贸易谈判结束之际，国宴款待了来访代表团。'),
  ('fcec3757-45d1-482d-a80f-533c1bb43f10-ex1', 'fcec3757-45d1-482d-a80f-533c1bb43f10', 'vote', 'Did you vote in the election?', '你在选举中投票了吗？'),
  ('fcec3757-45d1-482d-a80f-533c1bb43f10-ex2', 'fcec3757-45d1-482d-a80f-533c1bb43f10', 'vote', 'The amendment passed by a single vote after hours of procedural maneuvering.', '经过数小时的程序博弈，修正案以一票之差获得通过。'),
  ('3e6181d8-aefa-4958-b894-51794f4b1558-ex1', '3e6181d8-aefa-4958-b894-51794f4b1558', 'western', 'We watched an old western movie.', '我们看了一部老西部片。'),
  ('3e6181d8-aefa-4958-b894-51794f4b1558-ex2', '3e6181d8-aefa-4958-b894-51794f4b1558', 'western', 'Western financial institutions face heightened scrutiny of their emerging-market exposures.', '西方金融机构的新兴市场敞口正受到更严格的审视。'),
  ('5cad2e91-9cc4-4531-a664-cc162267b420-ex1', '5cad2e91-9cc4-4531-a664-cc162267b420', 'relate', 'I can relate to how you feel.', '我能体会你的感受。'),
  ('5cad2e91-9cc4-4531-a664-cc162267b420-ex2', '5cad2e91-9cc4-4531-a664-cc162267b420', 'relate', 'The disclosures relate to transactions executed through intermediaries in three jurisdictions.', '披露的信息涉及通过三个司法管辖区的中介执行的交易。'),
  ('3fb7c5f6-50c1-479f-9b38-c26414327402-ex1', '3fb7c5f6-50c1-479f-9b38-c26414327402', 'travel', 'I love to travel during the holidays.', '我喜欢在假期旅行。'),
  ('3fb7c5f6-50c1-479f-9b38-c26414327402-ex2', '3fb7c5f6-50c1-479f-9b38-c26414327402', 'travel', 'The advisory restricts non-essential travel to regions affected by the outbreak.', '该公告限制前往疫情影响地区的非必要旅行。'),
  ('b3c4d0c8-6494-4261-b2db-8170608f3000-ex1', 'b3c4d0c8-6494-4261-b2db-8170608f3000', 'debate', 'The debate lasted for two hours.', '辩论持续了两个小时。'),
  ('b3c4d0c8-6494-4261-b2db-8170608f3000-ex2', 'b3c4d0c8-6494-4261-b2db-8170608f3000', 'debate', 'The ruling reignited the debate over the constitutional limits of executive power.', '这一裁决重新点燃了关于行政权力宪法边界的辩论。'),
  ('8a24b60e-fdc8-4bbf-aaf5-f1d27a719309-ex1', '8a24b60e-fdc8-4bbf-aaf5-f1d27a719309', 'prevent', 'Wash your hands to prevent illness.', '勤洗手预防疾病。'),
  ('8a24b60e-fdc8-4bbf-aaf5-f1d27a719309-ex2', '8a24b60e-fdc8-4bbf-aaf5-f1d27a719309', 'prevent', 'The safeguards are designed to prevent the recurrence of systemic failures.', '这些保障措施旨在防止系统性失灵再次发生。'),
  ('4b8ad1de-b1a7-45cc-81b1-04eef3ef6221-ex1', '4b8ad1de-b1a7-45cc-81b1-04eef3ef6221', 'citizen', 'He became a citizen last year.', '他去年入了籍。'),
  ('4b8ad1de-b1a7-45cc-81b1-04eef3ef6221-ex2', '4b8ad1de-b1a7-45cc-81b1-04eef3ef6221', 'citizen', 'Every citizen enjoys standing to petition for judicial review of administrative action.', '每位公民都有权就行政行为申请司法审查。'),
  ('eea32fb0-deb3-4048-b568-071c87d21226-ex1', 'eea32fb0-deb3-4048-b568-071c87d21226', 'majority', 'The majority of students passed the exam.', '大多数学生通过了考试。'),
  ('eea32fb0-deb3-4048-b568-071c87d21226-ex2', 'eea32fb0-deb3-4048-b568-071c87d21226', 'majority', 'The coalition commands a working majority sufficient to enact its legislative program.', '该联盟掌握着足以推行其立法计划的有效多数。'),
  ('0d50041f-3b1d-4bd2-8c08-d557cab2b319-ex1', '0d50041f-3b1d-4bd2-8c08-d557cab2b319', 'none', 'None of the answers is correct.', '没有一个答案是正确的。'),
  ('0d50041f-3b1d-4bd2-8c08-d557cab2b319-ex2', '0d50041f-3b1d-4bd2-8c08-d557cab2b319', 'none', 'Of the remedies proposed, none adequately addresses the underlying structural deficiency.', '在提出的补救措施中，没有一项能充分解决深层的结构性缺陷。'),
  ('2650e80e-051f-4dd4-af63-8b9d6101ce0c-ex1', '2650e80e-051f-4dd4-af63-8b9d6101ce0c', 'front', 'Please wait at the front door.', '请在前门等候。'),
  ('2650e80e-051f-4dd4-af63-8b9d6101ce0c-ex2', '2650e80e-051f-4dd4-af63-8b9d6101ce0c', 'front', 'The shell companies served as fronts for transactions designed to evade sanctions.', '这些空壳公司充当了规避制裁交易的幌子。'),
  ('56396935-b13d-464c-bcb6-d0807e92a300-ex1', '56396935-b13d-464c-bcb6-d0807e92a300', 'born', 'She was born in April.', '她出生在四月。'),
  ('56396935-b13d-464c-bcb6-d0807e92a300-ex2', '56396935-b13d-464c-bcb6-d0807e92a300', 'born', 'The agency was born of the recognition that fragmented oversight had failed.', '该机构的诞生源于一种认识：碎片化的监管已经失败。'),
  ('94907d66-9b96-404a-a466-1ad1d99320eb-ex1', '94907d66-9b96-404a-a466-1ad1d99320eb', 'admit', 'I admit that I was wrong.', '我承认我错了。'),
  ('94907d66-9b96-404a-a466-1ad1d99320eb-ex2', '94907d66-9b96-404a-a466-1ad1d99320eb', 'admit', 'The institution declined to admit liability while nonetheless agreeing to compensate claimants.', '该机构虽同意赔偿索赔人，却拒绝承认负有责任。'),
  ('769c7c29-40ff-4f89-9a86-58981ec940c8-ex1', '769c7c29-40ff-4f89-9a86-58981ec940c8', 'senior', 'My grandfather is a senior citizen.', '我祖父是老年人。'),
  ('769c7c29-40ff-4f89-9a86-58981ec940c8-ex2', '769c7c29-40ff-4f89-9a86-58981ec940c8', 'senior', 'Several senior officials resigned amid allegations of improper influence over procurement.', '多名高级官员因被指不当干预采购而辞职。'),
  ('dcaa25f3-3491-4d69-a6e8-bffeca6e9fd0-ex1', 'dcaa25f3-3491-4d69-a6e8-bffeca6e9fd0', 'assume', 'Don''t assume the worst.', '别往最坏处想。'),
  ('dcaa25f3-3491-4d69-a6e8-bffeca6e9fd0-ex2', 'dcaa25f3-3491-4d69-a6e8-bffeca6e9fd0', 'assume', 'The successor entity will assume all liabilities arising under the existing contracts.', '继任实体将承接现有合同项下产生的全部债务。'),
  ('bb9e6723-1e6f-4594-9da2-03c70e9bae13-ex1', 'bb9e6723-1e6f-4594-9da2-03c70e9bae13', 'wind', 'The wind blew my hat off.', '风把我的帽子吹掉了。'),
  ('bb9e6723-1e6f-4594-9da2-03c70e9bae13-ex2', 'bb9e6723-1e6f-4594-9da2-03c70e9bae13', 'wind', 'Offshore wind capacity has expanded faster than any other generation technology.', '海上风电装机容量的增长速度超过了任何其他发电技术。'),
  ('e641e696-33cd-46b0-ae8a-1f2dde94935b-ex1', 'e641e696-33cd-46b0-ae8a-1f2dde94935b', 'key', 'I lost my house key.', '我把家门钥匙弄丢了。'),
  ('e641e696-33cd-46b0-ae8a-1f2dde94935b-ex2', 'e641e696-33cd-46b0-ae8a-1f2dde94935b', 'key', 'Transparency constitutes the key safeguard against the abuse of delegated authority.', '透明度是防止滥用授权的关键保障。'),
  ('fc42fb59-c7d1-406c-9f75-d69a8404dcf5-ex1', 'fc42fb59-c7d1-406c-9f75-d69a8404dcf5', 'professional', 'She is a professional photographer.', '她是一名专业摄影师。'),
  ('fc42fb59-c7d1-406c-9f75-d69a8404dcf5-ex2', 'fc42fb59-c7d1-406c-9f75-d69a8404dcf5', 'professional', 'The tribunal found that the conduct fell below accepted professional standards.', '法庭认定该行为低于公认的职业标准。'),
  ('0d5b87d6-6448-4be8-8a28-b3cb843488e5-ex1', '0d5b87d6-6448-4be8-8a28-b3cb843488e5', 'mission', 'Our mission is to help students learn.', '我们的使命是帮助学生学习。'),
  ('0d5b87d6-6448-4be8-8a28-b3cb843488e5-ex2', '0d5b87d6-6448-4be8-8a28-b3cb843488e5', 'mission', 'The peacekeeping mission operates under a mandate renewed annually by the council.', '维和特派团根据安理会每年延长的授权开展行动。'),
  ('b5fbf9c0-ed39-4cfb-a459-17a13e23542c-ex1', 'b5fbf9c0-ed39-4cfb-a459-17a13e23542c', 'fast', 'He runs really fast.', '他跑得真快。'),
  ('b5fbf9c0-ed39-4cfb-a459-17a13e23542c-ex2', 'b5fbf9c0-ed39-4cfb-a459-17a13e23542c', 'fast', 'The contagion spread so fast that conventional containment protocols proved ineffective.', '风险蔓延之快使常规的遏制方案完全失效。'),
  ('56646b8b-b54e-4cd2-80fd-b404bdc39456-ex1', '56646b8b-b54e-4cd2-80fd-b404bdc39456', 'alone', 'She lives alone with her cat.', '她独自和猫住在一起。'),
  ('56646b8b-b54e-4cd2-80fd-b404bdc39456-ex2', '56646b8b-b54e-4cd2-80fd-b404bdc39456', 'alone', 'Market mechanisms alone cannot remedy externalities of this magnitude.', '仅靠市场机制无法纠正如此规模的外部性问题。'),
  ('80d0b817-264b-4735-bb41-9c78b9de8e62-ex1', '80d0b817-264b-4735-bb41-9c78b9de8e62', 'customer', 'The customer is always right.', '顾客永远是对的。'),
  ('80d0b817-264b-4735-bb41-9c78b9de8e62-ex2', '80d0b817-264b-4735-bb41-9c78b9de8e62', 'customer', 'The bank must verify the identity of every customer under the due diligence rules.', '根据尽职调查规则，银行必须核实每位客户的身份。'),
  ('c331d629-ae99-4186-9cf2-8a78b44e127c-ex1', 'c331d629-ae99-4186-9cf2-8a78b44e127c', 'suffer', 'She suffers from bad headaches.', '她饱受头痛困扰。'),
  ('c331d629-ae99-4186-9cf2-8a78b44e127c-ex2', 'c331d629-ae99-4186-9cf2-8a78b44e127c', 'suffer', 'Communities downstream continue to suffer the consequences of decades of unregulated discharge.', '下游社区仍在承受数十年无序排放的后果。'),
  ('60cb9f04-96c1-4232-9f2f-bcc3ddfe7de9-ex1', '60cb9f04-96c1-4232-9f2f-bcc3ddfe7de9', 'speech', 'He gave a short speech at the wedding.', '他在婚礼上做了简短的致辞。'),
  ('60cb9f04-96c1-4232-9f2f-bcc3ddfe7de9-ex2', '60cb9f04-96c1-4232-9f2f-bcc3ddfe7de9', 'speech', 'The constitution protects political speech against governmental restriction.', '宪法保护政治言论免受政府限制。'),
  ('fceb6c25-2056-4213-accd-171585fff07a-ex1', 'fceb6c25-2056-4213-accd-171585fff07a', 'successful', 'The surgery was successful.', '手术很成功。'),
  ('fceb6c25-2056-4213-accd-171585fff07a-ex2', 'fceb6c25-2056-4213-accd-171585fff07a', 'successful', 'The successful bidder must furnish performance guarantees before contract execution.', '中标方必须在合同签署前提供履约担保。'),
  ('14c1d8f8-8d72-4880-acfd-5028dcd09683-ex1', '14c1d8f8-8d72-4880-acfd-5028dcd09683', 'option', 'You have two options: bus or train.', '你有两个选择：坐公交或坐火车。'),
  ('14c1d8f8-8d72-4880-acfd-5028dcd09683-ex2', '14c1d8f8-8d72-4880-acfd-5028dcd09683', 'option', 'The board retained the option of divesting the subsidiary should conditions deteriorate.', '董事会保留了在形势恶化时剥离该子公司的选择权。'),
  ('f56350e3-7c5f-4d7b-af28-3412111c574c-ex1', 'f56350e3-7c5f-4d7b-af28-3412111c574c', 'participant', 'Each participant will receive a certificate.', '每位参与者都将获得证书。'),
  ('f56350e3-7c5f-4d7b-af28-3412111c574c-ex2', 'f56350e3-7c5f-4d7b-af28-3412111c574c', 'participant', 'Every participant in the trial provided documented informed consent.', '试验的每位参与者都签署了书面知情同意书。'),
  ('14f2d82f-e7b5-4993-803b-f02ff887fd6e-ex1', '14f2d82f-e7b5-4993-803b-f02ff887fd6e', 'southern', 'They moved to a southern city last year.', '他们去年搬到了南方的一座城市。'),
  ('14f2d82f-e7b5-4993-803b-f02ff887fd6e-ex2', '14f2d82f-e7b5-4993-803b-f02ff887fd6e', 'southern', 'Drought conditions across the southern provinces have devastated this season''s harvest.', '南部各省的干旱重创了本季收成。'),
  ('00408421-c8e9-4957-9876-4cc1fdf660c3-ex1', '00408421-c8e9-4957-9876-4cc1fdf660c3', 'fresh', 'I bought some fresh vegetables.', '我买了一些新鲜蔬菜。'),
  ('00408421-c8e9-4957-9876-4cc1fdf660c3-ex2', '00408421-c8e9-4957-9876-4cc1fdf660c3', 'fresh', 'The appellate ruling provides fresh grounds for reopening previously dismissed claims.', '上诉裁决为重启此前被驳回的索赔提供了新的依据。')
